/*
/****** Object:  StoredProcedure [dbo].[owp_PaymentshieldCommission_backupPR20230822]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE procedure [dbo].[owp_PaymentshieldCommission_backupPR20230822]
	@debug  varchar(1) = 'N'
with recompile
as

/********************************************************************************

Object  	  : procedure
Name    	  : owp_PaymentshieldCommission
Created By	  : Paul Robathan
Created 	  : 22/09/2007

Amendment History
-----------------
Date		  Author	  Description
----		  ------      -----------
05/10/2009	A Groves	  1) Added debug lines to identify UAT perf prob
						  2) Deleted _BYO from BranchNo
10/11/2009  A Harrison		Create index on temporary #currtotals table
03/03/2010	A Groves		Enhancement to Paul Robathan's fix of a year
  						    ago to include another condition for leap year.
23/09/2010  M Cawood    1) To allow more than one GI file to be loaded in a month 
                           (e.g. GHL) the new owt_PaymentShieldImportControl table
                           holds the FileID to be held as CreateDate on each row
                           loaded onto the owt_PaymentshieldCommissionPayments table. 
                        2) The FileID is then used by the procedure
                           owp_PaymentshieldAdviserListingExtract to select the 
                           data to be extracted from the
                           owt_PaymentshieldCommissionPayments table.
                        3) No data is now deleted by this procedure. The data held
                           on the owt_PaymentShieldImport table is now appended to
                           the owt_PaymentshieldCommissionPayments table.
25/10/2010  M Cawood    Move Month forward one month. For example, if data loaded
                        with [Period] = 'April, 2010' then derive the Month and Period
                        End Date for May 2010 (i.e. 2010/06/01 and 2010/06/09 resp).
25/09/2012	A Groves	1) Break-fix: Take 1st 65 characters only from column
							owt_PaymentshieldImport.ClientName.
22/02/2013	A Groves	1) All these suffixes found in the Paymentshield file:
							_BYO, _BYO2, _BYO_BYO, _BYO2_BYO, BYO3, _BYO_BYO_BYO
							They also appear in the Seller Log.  All variations of BYO
							are now removed from both the Paymentshield file and the
							Seller Log to improve the match rate.
						2) DACommRate changed from 32.5 to 35.0 if look up fails.
08/03/2013	Mike Cawood	SR207107 - Calculate new metric ELITE Points
08/04/2013	A Groves	Changes required to load new Paymentshield Panel file.
18/04/2013	A Groves	Changes for new values of CommType and Status.
22/04/2013	A Groves	Openwork DA increased from 35% to 39% so a further tweak
						was required when calculatin DARate, CommRate & UpliftRate. 
23/04/2013	A Groves	Additional tweaks to the above change required for double indemnity. 
						ELITE_Initial calculation corrected.
30/04/2013	A Groves	SR224597 - Processing previously assumed title was present. When 
						not present as with adviser Alison Herbert, then her Seller Name
						was changed to Herbert rather than left as Alison Herbert.
26/06/2013	A Groves	SR227174. Populate the seller code using fuzzy matching techniques.
						This is required to enable recognition to be counted correctly
						for each adviser. 
						This change includes a bug fix to ensure that the post table load
						updates operate on just the file being loaded and not every
						row for the commission period which could have included data loaded 
						by previous runs of this proc on other files.
05/07/2013	A Groves	Improve selection of unique match keys by using Code rather
						than Descn as Descn often changes over time causing a seller
						to dupe with themselves - leading them to be excluded from matching. 
22/11/2013	A Groves	Paymentshield have used _BY0 (zero) instead of BYO (oh) so matching
						has been amended to cope.
19/06/2014	A Groves	Improved coding to strip unwanted characters after either an 
						underscore or a hyphen. This improves matching between the
						Paymentshield Branch Number and the Openwork Business UID.
25/04/2015	A Groves	SR371343. New ELITE points calculation based on margin instead
						of adviser payment.
06/11/2015	A Groves	SR380390 - Load Paymentshield Owl payments. New column SourceID
						added to table owt_PaymentshieldCommissionPayments but set to NULL
						in this proc because the source table gets cleared down. However,
						the Owl table doesn't get cleared down because it sources the
						data for the ASM Override Statements.
05/09/2017	A Groves	SR464996. Replace DTS with SSIS. Comma in column "Period" was
						originally removed by the DTS script. The SSIS replacement does
						not do this to keep it simple. Instead it is done in this proc.
30/06/2021  P Reed      Addition to capture sellercode and PESN fields and save in a new unmatched table - 
						[dbo].[owt_PaymentshieldImportUnmatched]
***********************************************************************************/

declare	@RowCount		int,			-- AG 26/06/2013
		@Process		nvarchar(100),	-- AG 26/06/2013
		@ProviderOrig	varchar(30),	-- AG 26/06/2013
		@ProviderPanel	varchar(30),	-- AG 26/06/2013
		@Provider		varchar(30),    -- AG 26/06/2013
		@Panelfile     varchar(10)      -- Pr 30/06/2021

set @Panelfile='no';
exec msp_ProcessLog 'START', 'owp_PaymentshieldCommission', null, 'PaymentShield', 'Openwork'

if @debug = 'Y' exec msp_ProcessLog 'START', '00) Remove _BYO from BranchNo', null, 'PaymentShield', 'Openwork'

-- AG 22/02/2013 Start

-- Strip out all text that includes and follows "_BYO". 
--update owhot_PaymentshieldSwiftAgentXRef
--		set PayshieldAgent = stuff(PayshieldAgent,patindex('%_BYO%',replace(PayshieldAgent,'_BY0','_BYO')),50,'')	-- AG 22/11/2013
--where patindex('%_BYO%',replace(PayshieldAgent,'_BY0','_BYO')) > 0													-- AG 22/11/2013

-- AG 19/06/2014 Start. Improved coding to strip unwanted characters after either an underscore or a hyphen.
update dbo.owhot_PaymentshieldSwiftAgentXref
	set PayshieldAgent = stuff(PayshieldAgent,patindex('%[-_]%',PayshieldAgent),100,'')
where patindex('%[-_]%',PayshieldAgent) > 0
-- AG 19/06/2014 End.

-- Since stripping out the _BYO derivatives, there are now dupes in the table. This step removes the dupes.
select	Xref.*
into	#owhot_PayshieldSwiftAgentXref
from	owhot_PaymentshieldSwiftAgentXref Xref
		inner join	(select PayshieldAgent, max(ID) as MaxID
						from owhot_PaymentshieldSwiftAgentXref
						group by PayshieldAgent) as DedupedPayshieldAgent
					on DedupedPayshieldAgent.MaxID = Xref.ID

-- AG 05/10/2009 Start

--update owt_paymentshieldimport
--		set BranchNo = stuff(BranchNo,patindex('%_BYO%',replace(BranchNo,'_BY0','_BYO')),50,'')		-- AG 22/11/2013
--where patindex('%_BYO%',replace(BranchNo,'_BY0','_BYO')) > 0										-- AG 22/11/2013

-- AG 05/10/2009 End
-- AG 22/02/2013 End

-- AG 19/06/2014 Start. Improved coding to strip unwanted characters after either an underscore or a hyphen.
update owt_paymentshieldimport
	set BranchNo = stuff(BranchNo,patindex('%[-_]%',BranchNo),100,'')
where patindex('%[-_]%',BranchNo) > 0
-- AG 19/06/2014 End.

--AG 05/09/2017 Start
--Remove comma in the Period field to enable it to be matched to the commission statement periods.
update owt_paymentshieldimport
	set Period = REPLACE(Period,',','')
--AG 05/09/2017 End

if @debug = 'Y' exec msp_ProcessLog 'START', '01) @PeriodCount derived', null, 'PaymentShield', 'Openwork'

select 
	distinct [Period] as 'Periods',
	convert (datetime, NULL,103) as 'PeriodMonth',
	convert (datetime, NULL,103) as 'BACSDate'
into #Months
from owt_PaymentshieldImport

-- AG 26/06/2013 Start

set @ProviderOrig	= 'Payment Shield'
set @ProviderPanel	= 'Payment Shield Panel'

if (select count(*) from owt_PaymentshieldImportPanel) > 1
	set @Provider = @ProviderPanel
else
	set @Provider = @ProviderOrig		

-- AG 26/06/2013 End

declare @PeriodCount  int
set @PeriodCount = (select Count(*) from #Months)

if @PeriodCount > 0 
begin

	if @debug = 'Y' exec msp_ProcessLog 'START', '02) Update #Months', null, 'PaymentShield', 'Openwork'

	update #Months
		set PeriodMonth = cp.Month,
		    BACSDate = cp.PeriodEndDate
	from #Months m
	inner join msit_CommissionStatementPeriods cp on cp.MonthName = m.Periods 

--MPC: 25/10/2010 Move PeriodMonth and BACSDate forward one month
	update #Months
		set PeriodMonth = cp.Month,
		    BACSDate = cp.PeriodEndDate
	from #Months m
	inner join msit_CommissionStatementPeriods cp on cp.Month = dateadd(mm,1,m.PeriodMonth) 
	
	declare @MonthCount  int
	set @MonthCount  = (select Count(*) from #Months where PeriodMonth is NOT NULL)

	if @debug = 'Y' exec msp_ProcessLog 'START', '03) @MonthCount derived', null, 'PaymentShield', 'Openwork'

	if @MonthCount  > 0 
	begin

		if @debug = 'Y' exec msp_ProcessLog 'START', '04) Delete from #Months', null, 'PaymentShield', 'Openwork'

		delete from #Months where PeriodMonth is NULL

		if @debug = 'Y' exec msp_ProcessLog 'START', '05) Delete from owt_PaymentshieldCommissionPayments', null, 'PaymentShield', 'Openwork'

		--Derive unique FileID to be recorded against each row inserted --MPC: 23/09/2010
		declare @FileID datetime;                                       --MPC: 23/09/2010
		set @FileID = getdate();                                        --MPC: 23/09/2010

		--delete from owt_PaymentshieldCommissionPayments               --MPC: 23/09/2010
		--where [Month] in (select PeriodMonth from #Months)            --MPC: 23/09/2010

		--Maintain table that controls msit_OpenworkAdviserListing      --MPC: 23/09/2010
		truncate table dbo.owt_PaymentshieldImportControl;              --MPC: 23/09/2010
    
		insert into dbo.owt_PaymentshieldImportControl                  --MPC: 23/09/2010
		Select [FileID] = @FileID;                                      --MPC: 23/09/2010

		if @debug = 'Y' exec msp_ProcessLog 'START', '06) insert into owt_PaymentshieldCommissionPayments', null, 'PaymentShield', 'Openwork'

		insert into owt_PaymentshieldCommissionPayments 
		select
		x.AgentCode,
		Rtrim(isnull(a.TradingName,a.DESCN)),
		a.OscarAgentPrefix + a.OscarAgentSerial + a.OscarAgentSuffix,
		PSI.BranchNo,
		NULL,
--		AG 30/04/2013 Start
--		case when charindex(' ', RTrim(PSI.SellerName)) = 0 then PSI.SellerName
--			else Rtrim(Substring(RTrim(PSI.SellerName), charindex(' ', RTrim(PSI.SellerName)) + 1, Len(RTrim(PSI.SellerName)) - charindex(' ', RTrim(PSI.SellerName))))
--			end,
		case when MICodes.Code is null	-- No match on person title so title assumed not present
			then ltrim(rtrim(PSI.SellerName))												-- AG 26/06/2013
			else ltrim(rtrim(stuff(replace(PSI.SellerName,'.',''),1,len(MICodes.Code),''))) 
		end as SellerName,
--		AG 30/04/2013 End
		NULL,
		NULL,
		NULL,
		substring(Rtrim(PSI.ClientName),1,65),						-- AG 25/09/2012
		case when charindex(' ', RTrim(PSI.ClientName)) = 0 then NULL
			else Rtrim(Substring(RTrim(PSI.ClientName), charindex(' ', RTrim(PSI.ClientName))+1,1))
			end,
		case when charindex(' ', RTrim(PSI.ClientName)) = 0 then NULL
			else Rtrim(Right(RTrim(PSI.ClientName),charindex(' ', Reverse(RTrim(PSI.ClientName)))-1))
			end,
		NULL,
		PSI.PolicyReference,
		Left(PSI.Product,8),
		'PY_' + Left(PSI.Product,5),
		PSI.StartDate,
	 	m.PeriodMonth,
		case 
			when PSI.StartDate >= convert(datetime,'1 ' + left(PSI.Period,3) + ' ' + right(PSI.Period,4),106) then PSI.StartDate
			when PSI.StartDate < convert(datetime,'1 ' + left(PSI.Period,3) + ' ' + right(PSI.Period,4),106) and Month(PSI.StartDate) < Month(PSI.Period) then 
				case when Day(PSI.StartDate) = 29 and Month(PSI.StartDate) = 2 then 
						convert(datetime,'28/02/' +  Cast(Year(PSI.Period) as varchar(4)),103)
					 else
						convert(datetime,Cast(Day(PSI.StartDate) as varchar(2)) + '/' +  Cast(Month(PSI.StartDate) as varchar(2)) + '/' +  Cast(Year(PSI.Period) as varchar(4)),103)
				end			
			else 
				case when Day(PSI.StartDate) = 29 and Month(PSI.StartDate) = 2 then					-- AG 03/03/2010
						convert(datetime,'28/02/' +  Cast(Year(PSI.Period)-1 as varchar(4)),103)	-- AG 03/03/2010
					 else																			-- AG 03/03/2010
						convert(datetime,Cast(Day(PSI.StartDate) as varchar(2)) + '/' +  Cast(Month(PSI.StartDate) as varchar(2)) + '/' +  Cast(Year(PSI.Period)-1 as varchar(4)),103)
				end
		end,
		-- AG 08/04/2013 Start
		case when Panel.UniqueRowID is null
			then 'M'
			else case when left(Panel.TermOfContract,6) = 'ANNUAL'
					then 'A'
					else 'M'
				 end
		end as Frequency, 
		case when Panel.UniqueRowID is null
			then Abs(PSI.Premium) * 12
			else case when left(Panel.TermOfContract,6) = 'ANNUAL' 
						then 1 
						else 12 
				 end * abs(PSI.Premium)
		end as Premium,		
		-- AG 08/04/2013 End
		0,
		isnull ((select APE_Flag from mstt_ProductHierarchy where ProductType = 'Payshield' and ProductCode = 'PY_' + Left(PSI.Product,5)),'N'),
		0,
		0,
		case when PSI.Margin > 0 then PSI.Margin 
			 when PSI.Premium <> 0 then Abs((PSI.Fee*100)/(PSI.Premium *	case												-- AG 18/04/2013
																				when left(Panel.TermOfContract,6) = 'ANNUAL'	-- AG 18/04/2013
																				then 1											-- AG 18/04/2013
																				else 12											-- AG 18/04/2013
																			end))												-- AG 18/04/2013
			 else 7.5 
		end,
		isnull((select cast(Description as float) from msit_MIWarehouseCodesAndDescriptions d where d.ColumnName = 'Paymentshield_Source' and d.Code = PSI.Source),35.0),		-- AG 22/02/2013	Old value = 32.5
		isnull((select cast(LongDescription as float) from msit_MIWarehouseCodesAndDescriptions d where d.ColumnName = 'Paymentshield_Source' and d.Code = PSI.Source),27.5),
		1,
		0,
		0,
		NULL,
		0,
		0,
		0,
		0,
		0,
		PSI.Fee,
		0,
		case when PSI.CommType in ('Double Indemnity','Dind','Dind2') then 24 else 12 end,								-- AG 18/04/2013
		case when PSI.CommType in ('Indemnity','Double Indemnity','Aind','Dind','Dind2') then 'T' else 'F' end,			-- AG 18/04/2013
		case when PSI.CommType in ('Indemnity','Double Indemnity','Aind','Dind','Dind2') then 'IT' else 'Accrual' end,	-- AG 18/04/2013
		100,
		case when PSI.CommType in ('Adjustment','Awaiting Start') or PSI.Status in ('AWAITING START','MTA') then 'Adj' else 'IC' end,	-- AG 18/04/2013
		-- AG 08/04/2013 Start
		case when Panel.UniqueRowID is null
			then @ProviderOrig					-- AG 26/06/2013
			else @ProviderPanel					-- AG 26/06/2013
		end as Provider,
		-- AG 08/04/2013 End
		'PYMTSHLD',
		m.PeriodMonth,
		'Payshield',
		--getdate(),      --MPC: 23/09/2010
		@FileID,          --MPC: 23/09/2010
		PSI.CommType,
		PSI.Status,
		NULL as ELITE_Initial,			--MPC: 20/02/2013 SR207107
		NULL as ELITE_Category,			--MPC: 20/02/2013 SR207107
		ltrim(rtrim(PSI.SellerName)),	-- AG 26/06/2013
		psi.UniqueRowID as SourceID				-- AG 06/11/2015   --PR 30/06/2021 CHANGED FROM NULL TO THE IMPORT RECORDID (NOTE THIS WILL LATER BE SET BACK TO NULL FOR SAFETY REASONS)
		from owt_PaymentshieldImport PSI
--		inner join owhot_PaymentshieldSwiftAgentXRef x on x.PayshieldAgent = PSI.BranchNo			AG 22/02/2012
		inner join #owhot_PayshieldSwiftAgentXref x on x.PayshieldAgent = PSI.BranchNo				-- AG 22/02/2012
		inner join mstt_Agents a on a.CODE = x.AgentCode
		inner join #Months m on m.Periods = PSI.Period
		left join owt_PaymentshieldImportPanel Panel on Panel.UniqueRowID = PSI.UniqueRowID			-- AG 08/04/2013
		left join dbo.msit_MIWarehouseCodesAndDescriptions MICodes									-- AG 30/04/2013
						on  MICodes.ColumnName = 'PersonTitle' 
						and ltrim(rtrim(replace(PSI.SellerName,'.',''))) like MICodes.Code + ' %'	-- AG 26/06/2013
		where x.Deleted <> 'Y'

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '06) insert into owt_PaymentshieldCommissionPayments. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- AG 08/04/2013. Truncate Panel table to ensure it is not incorrectly
		-- used during a non-Panel File load. 
		---------------------------------------------------------------------------
		select @panelfile='Yes' from owt_PaymentshieldImportPanel where UniqueRowID is not null; --if there is a pesn then the last file loaded must be a panel file --PR 30/06/2021
		truncate table owt_PaymentshieldImportPanel	

		---------------------------------------------------------------------------
		-- Update Sales Measures #1		AG 22/04/2013 & 23/04/2013
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '07) Update Sales Measures #1', null, 'PaymentShield', 'Openwork'

		update	owt_PaymentshieldCommissionPayments 
			set	DACommRate	= case when case when PCP.origcommtype like '%DIND%' and round(PCP.MarginCommRate,2) > 11.5 then 0.5 else 1 end * round(PCP.MarginCommRate,2) > 7.5 then 4.0 else 0.0 end + PCP.DACommRate,
				CommRate	= case when case when PCP.origcommtype like '%DIND%' and round(PCP.MarginCommRate,2) > 11.5 then 0.5 else 1 end * round(PCP.MarginCommRate,2) > 7.5 then 4.0 else 0.0 end + PCP.DACommRate - (case when PCP.origcommtype like '%DIND%' and round(PCP.MarginCommRate,2) > 11.5 then 0.5 else 1 end * PCP.MarginCommRate),
				UpliftRate	= (case when case when PCP.origcommtype like '%DIND%' and round(PCP.MarginCommRate,2) > 11.5 then 0.5 else 1 end * round(PCP.MarginCommRate,2) > 7.5 then 4.0 else 0.0 end + PCP.DACommRate - (case when PCP.origcommtype like '%DIND%' and round(PCP.MarginCommRate,2) > 11.5 then 0.5 else 1 end * PCP.MarginCommRate))/PCP.BaseCommRate
		from	owt_PaymentshieldCommissionPayments PCP
				INNER JOIN #Months m on m.PeriodMonth = PCP.[Month]
		where	PCP.CreateDate = @FileID								-- AG 26/06/2013

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '07) Update Sales Measures #1. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- Update Sales Measures #2
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '08) Update Sales Measures #2', null, 'PaymentShield', 'Openwork'

		update owt_PaymentshieldCommissionPayments 
                        set PaymentAmount = case	  
						  when PCP.MarginCommRate > 0 then PCP.Margin * (PCP.CommRate/PCP.MarginCommRate)
						  else PCP.PaymentAmount
				  	    end
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
		where	PCP.CreateDate = @FileID								-- AG 26/06/2013

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '08) Update Sales Measures #2. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- Update incomplete data
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '09) Update incomplete data', null, 'PaymentShield', 'Openwork'

		update owt_PaymentshieldCommissionPayments 
			set PayBasisCode = isnull((select	top 1 PayBasisCode 
										from	owt_PaymentshieldCommissionPayments o 
										where	o.BusinessCode = PCP.BusinessCode
										and		o.Provider = @Provider			-- AG 26/06/2013 
										and		o.Policy = PCP.Policy 
										and		o.Premium <> 0 
										and		o.Month < m.PeriodMonth
										order by o.Month Desc), PCP.PayBasisCode),
			    PayBasis = isnull((select	top 1 PayBasis 
									from	owt_PaymentshieldCommissionPayments o 
									where	o.BusinessCode = PCP.BusinessCode
									and		o.Provider = @Provider				-- AG 26/06/2013 
									and		o.Policy = PCP.Policy 
									and		o.Premium <> 0 
									and		o.Month < m.PeriodMonth 
									order by o.Month Desc), PCP.PayBasis),
			    Premium = isnull((select	top 1 Premium 
									from	owt_PaymentshieldCommissionPayments o 
									where	o.BusinessCode = PCP.BusinessCode
									and		o.Provider = @Provider				-- AG 26/06/2013 
									and		o.Policy = PCP.Policy 
									and		o.Premium <> 0 
									and		o.Month < m.PeriodMonth 
									order by o.Month Desc), PCP.Premium),
			    InitialPeriod = isnull((select	top 1 InitialPeriod 
										from	owt_PaymentshieldCommissionPayments o 
										where	o.BusinessCode = PCP.BusinessCode
										and		o.Provider = @Provider			-- AG 26/06/2013 
										and		o.Policy = PCP.Policy 
										and		o.Premium <> 0 
										and		o.Month < m.PeriodMonth 
										order by o.Month Desc), PCP.InitialPeriod) 	
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
		where  PCP.CreateDate = @FileID														-- AG 26/06/2013
		and	   (PCP.OrigCommType in ('Clawback','Adjustment','Cancelled','Cancelled Case')	-- AG 18/04/2013 
		or		PCP.Premium = 0
		or		PCP.OrigStatus in ('CANCELLATION','CANCELLED','MTA'))						-- AG 18/04/2013	

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '09) Update incomplete data. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- create temporary table to hold current totals 
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '10) Populate #currtotals', null, 'PaymentShield', 'Openwork'

		select	isnull(SUM(b.PaymentAmount),0) as 'CURR_FEE',a.BusinessCode,a.Policy,a.LatestAnniversary, a.[Month], Count(*) as 'CURR_COUNT'
		into	#currtotals
		from	owt_PaymentshieldCommissionPayments a 
				inner join owt_PaymentshieldCommissionPayments b 
						on a.BusinessCode = b.BusinessCode 
						and a.Policy = b.Policy 
						and a.LatestAnniversary = b.LatestAnniversary 
						and a.Provider = b.Provider					-- AG 26/06/2013
		where	a.OrigCommType not in ('Awaiting Start','Earn Off')
		and		a.Provider = @Provider								-- AG 26/06/2013
		group	by a.BusinessCode,a.Policy,a.LatestAnniversary, a.[Month]

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '10) Populate #currtotals. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------
		-- Create index on temporary table
		---------------------------------------------

		CREATE  INDEX [idx_BusinessCode] ON [dbo].[#currtotals]([BusinessCode],[Policy],[LatestAnniversary],[Month]) 

		---------------------------------------------------------------------------
		-- Update SalesMoveFlag 
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '11) Update SalesMoveFlag', null, 'PaymentShield', 'Openwork'

		update owt_PaymentshieldCommissionPayments 
			set SalesMoveFlag = case 
					when PCP.PayBasisCode = 'F' and PCP.Margin > 0 and PCP.LatestAnniversary > PCP.StartDate and ct.CURR_COUNT = 1 then 'Y'
					when PCP.PayBasisCode = 'F' and PCP.Margin > 0 and PCP.LatestAnniversary = PCP.StartDate and ct.CURR_COUNT = 1 then 'Y' 
					when PCP.PayBasisCode = 'T' and PCP.Margin > 0 then 'Y' 
					when PCP.OrigCommType in ('Cancelled','Clawback','Cancelled Case') or PCP.OrigStatus in ('CANCELLATION','CANCELLED') then case when ct.CURR_FEE = 0 then 'Y' else 'X' end	-- AG 18/04/2013
					when PCP.OrigCommType in ('Awaiting Start','Earn Off') then 'N'
					else 'X'
				    end 
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
				inner join #currtotals ct on ct.BusinessCode = PCP.BusinessCode 
											and ct.Policy = PCP.Policy 
											and ct.LatestAnniversary = PCP.LatestAnniversary 
											and ct.[Month] = PCP.[Month] 
		where  PCP.CreateDate = @FileID													-- AG 26/06/2013

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '11) Update SalesMoveFlag. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- Update Sales Measures #3
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '12) Update Sales Measures #3', null, 'PaymentShield', 'Openwork'

		update owt_PaymentshieldCommissionPayments 
			set TotalFeeDue = case 
								when PCP.SalesMoveFlag  = 'N' then PCP.TotalFeeDue
								else case	  
										when PCP.PaymentAmount < 0 or PCP.PayBasis = 'IT' then PCP.PaymentAmount 
										else PCP.PaymentAmount * case when PCP.Frequency = 'A' then 1 else 12 end	-- AG 18/04/2013
									 end	  
				  			   end
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
		where	PCP.CreateDate = @FileID												-- AG 26/06/2013

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '12) Update Sales Measures #3. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- now use current table to update ICPaidToDate and StilltoAccrue 
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '13) Update ICPaidToDate and StilltoAccrue', null, 'PaymentShield', 'Openwork'

		update	owt_PaymentshieldCommissionPayments 
			set ICPaidToDate = CURR_FEE,
			    StilltoAccrue = PCP.TotalFeeDue - CURR_FEE
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
				inner join #currtotals ct on ct.BusinessCode = PCP.BusinessCode 
											and ct.Policy = PCP.Policy 
											and ct.LatestAnniversary = PCP.LatestAnniversary 
							                and ct.[Month] = PCP.[Month] 
		where	PCP.PaymentAmount > 0 
		and		PCP.PayBasisCode = 'F'
		and		PCP.CreateDate = @FileID												-- AG 26/06/2013

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '13) Update ICPaidToDate and StilltoAccrue. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- Update Sales Measures #4
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '14) Update Sales Measures #4', null, 'PaymentShield', 'Openwork'

		update owt_PaymentshieldCommissionPayments 
			set 
				DA = Abs(PCP.TotalFeeDue) * (PCP.DACommRate/PCP.CommRate) * case when PCP.PaymentAmount < 0 then -1 else 1 end,
	    		EnhancedNBI = Abs(PCP.TotalFeeDue) * case when PCP.PaymentAmount < 0 then -1 else 1 end,
		    	BaseNBI = (Abs(PCP.TotalFeeDue)/PCP.UpliftRate) *  case when PCP.PaymentAmount < 0 then -1 else 1 end,
		    	Turnover =	case
			 	  				when PCP.APEFlag = 'Y' then Abs(PCP.Premium) * case when PCP.PaymentAmount < 0 then -1 else 1 end
			 	  				else Abs(PCP.TotalFeeDue) * (PCP.DACommRate/PCP.CommRate)  * case when PCP.PaymentAmount < 0 then -1 else 1 end
							end,
		    	APE =	case
			 				when PCP.APEFlag = 'Y' and PCP.SalesMoveFlag = 'Y' then Abs(PCP.Premium) * case when PCP.PaymentAmount < 0 then -1 else 1 end
			 				else PCP.APE  
						end,
				ELITE_Initial = 
					case when PCP.Month >= '2015-02-01'									--AG 25/04/2015
					then case															--AG 25/04/2015
							when PCP.PaymentAmount < 0									--AG 25/04/2015
							then round(isnull(-ABS(PCP.Margin * ELF.Multiplier),0),4)	--AG 25/04/2015
							else round(isnull(PCP.Margin * ELF.Multiplier,0),4)			--AG 25/04/2015
						  end															--AG 25/04/2015
					else																--AG 25/04/2015
						round( ELF.Factor * ELF.Multiplier *							--MPC: 20/02/2013 SR207107
						( ( Abs(PCP.TotalFeeDue)/PCP.UpliftRate )						--MPC: 20/02/2013 SR207107
						* case when PCP.PaymentAmount < 0 then -1 else 1 end ),2)		--MPC: 20/02/2013 SR207107
					end,																--AG 25/04/2015
				ELITE_Category = ELF.Category											--MPC: 20/02/2013 SR207107
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
				left join msit_CommissionStatementPeriods CSP on m.PeriodMonth = CSP.Month	--MPC: 20/02/2013 SR207107
				left join owt_ELITEFactors ELF on ELF.FeeType = 'Initial' and ELF.Category = 'GI' and CSP.Year between ELF.StartYear and ELF.EndYear		--MPC: 20/02/2013 SR207107
		where	PCP.SalesMoveFlag  = 'Y'
		and		PCP.CreateDate = @FileID										-- AG 26/06/2013	

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '14) Update Sales Measures #4. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		----------------------------------------------------------------------------------
		-- Populate temporary table with exact and fuzzy matched sellers for current month
		----------------------------------------------------------------------------------

		-- AG 26/06/2013 Start

		if @debug = 'Y' exec msp_ProcessLog 'START', '15) Populate #FuzzyMatchedSellers', null, 'PaymentShield', 'Openwork'

		select	distinct	-- joins are to all rows on AgentsHistory to match to past
							-- employers.  This will create a lot of duplicate rows 
							-- hence distinct to remove them.
				PCP.BusinessCode as PaymentshieldBusinessCode,
				PCP.SellerName as PaymentshieldSellerName, 
				coalesce(AgHist.Code,FuzzyNotExact.Code) as SwiftSellerUID, 
				coalesce(ltrim(rtrim(AgHist.DESCN)),FuzzyNotExact.descn) as SwiftSellerName
		into	#FuzzyMatchedSellers
		From	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
				left join	mstt_AgentsHistory AgHist	-- Exact match of this seller in this business either now or in the past 
								on ltrim(rtrim(AgHist.DESCN)) = ltrim(rtrim(PCP.SellerName))
								and AgHist.AgentType in (4,43,46,49,51)
								and AgHist.Firm = PCP.BusinessCode
				left join	(	select	advisers.code, advisers.Firm, 
										ltrim(rtrim(advisers.Descn)) as descn, 
										dbo.owf_Soundex(advisers.descn,'F') as SoundexDescnForename,
										dbo.owf_Soundex(advisers.descn,'L') as SoundexDescnSurname
								from	mstt_AgentsHistory advisers
										inner join	(					
														select	a.Firm, a.SoundexDescnSurname, a.FirstInitial
														from	
																(
																	select	distinct -- Unique permutations of sellers and their fuzzy match key hence distinct
																			sellers.Firm, 
																			--ltrim(rtrim(sellers.Descn)) as Descn,	-- AG 05/07/2013
																			Sellers.Code,							-- AG 05/07/2013 
																			dbo.owf_Soundex(sellers.descn,'L') As SoundexDescnSurname,
																			substring(sellers.descn,1,1) as FirstInitial 
																	from mstt_AgentsHistory sellers		-- Use Agent History to exclude anyone who has ever swapped businesses
																	where sellers.AgentType in (4,43,46,49,51)
																	and isnull(sellers.Firm,'') <> ''
																) a 
														group	by a.Firm, a.SoundexDescnSurname, a.FirstInitial
														having	count(*) = 1	-- We only want one occurrence of a fuzzy match key to avoid over-matching
													)	Fuzzy   on  Fuzzy.Firm = advisers.Firm 
																and Fuzzy.SoundexDescnSurname = dbo.owf_Soundex(advisers.descn,'L')
																and	Fuzzy.FirstInitial = substring(advisers.descn,1,1)
								where	advisers.AgentType in (4,43,46,49,51)
								and		isnull(advisers.Firm,'') <> ''	
							) FuzzyNotExact on FuzzyNotExact.Firm = PCP.BusinessCode
											and FuzzyNotExact.Descn <> PCP.SellerName
											-- First two characters of forename soundex must be the same
											-- Thus Michael and Mike match but Michael and Matthew don't match
											and (substring(FuzzyNotExact.SoundexDescnForename,1,2) = substring(dbo.owf_Soundex(PCP.SellerName,'F'),1,2)	
											or	 dbo.owf_AbbreviatedMatch(FuzzyNotExact.descn,PCP.SellerName) = 1)
											and FuzzyNotExact.SoundexDescnSurname = dbo.owf_Soundex(PCP.SellerName,'L')		-- Soundex of surname must match
		where	(FuzzyNotExact.Code is not null or AgHist.Code is not null)
		and		PCP.CreateDate = @FileID	

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '15) Populate #FuzzyMatchedSellers. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- Update PCP with the exact and fuzzy matched sellers for current month
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '16) Update SellerCode with UID matches', null, 'PaymentShield', 'Openwork'

		update	PCP
			set SellerCode		= FMS.SwiftSellerUID,
				SellerName		= FMS.SwiftSellerName + ' - ' + FMS.SwiftSellerUID,
				SellerForename	= dbo.owf_FirstWord(FMS.SwiftSellerName),
				SellerSurname	= dbo.owf_MixCase(dbo.owf_LastWord(FMS.SwiftSellerName))	-- MixCase will fix O'Brien, McCloud, etc.
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
				inner join #FuzzyMatchedSellers FMS 
							on  FMS.PaymentshieldBusinessCode = PCP.BusinessCode
							and FMS.PaymentshieldSellerName = PCP.SellerName
		where	PCP.CreateDate = @FileID													-- AG 26/06/2013

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '16) Update SellerCode with UID matches. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		---------------------------------------------------------------------------
		-- Update PCP with the non-matched sellers for current month
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '17) Update Forename and Surname with unmatched names', null, 'PaymentShield', 'Openwork'

		update	PCP
			set SellerForename	= dbo.owf_FirstWord(PCP.SellerName),				-- SellerName unchanged from Paymentshield
				SellerSurname	= dbo.owf_MixCase(dbo.owf_LastWord(PCP.SellerName))	-- MixCase will fix O'Brien, McCloud, etc.
		from	owt_PaymentshieldCommissionPayments PCP
				inner join #Months m on m.PeriodMonth = PCP.[Month]
		where	PCP.CreateDate = @FileID											-- AG 26/06/2013
		and		PCP.SellerCode is null		-- non-matched sellers

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '17) Update Forename and Surname with unmatched names. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		-- AG 26/06/2013 End

		----------------------------- PR 30/06/2021 --START PR CHANGE 30/06/2021 (also some code above)
		--STORED UNMATCHED UID'S
		----------------------------
		if @debug = 'Y' exec msp_ProcessLog 'START', '17A) Store unmatched UIDs', null, 'PaymentShield', 'Openwork'

		--select @panelfile='Yes' from owt_PaymentshieldImport where pesn is not null; --if there is a pesn then the last file loaded must be a panel file
	
insert into [dbo].[owt_PaymentshieldImportUnmatched]
(     
	[UniqueRowID] ,
	[Period] ,
	[PolicyReference] ,
	[OWPolicyRef],
	[ClientName] ,
	[StartDate] ,
	[Source] ,
	[Product] ,
	[CommType] ,
	[Status] ,
	[Premium] ,
	[Margin] ,
	[Fee] ,
	[BranchName],
	[BranchNo] ,
	[SellerName] ,
	[OWFirmRef] ,
	[OW_Sellerref] ,
	[PESN] ,
	[comm_id] ,
	[comm_SellerCode],
	[comm_SellerName] ,
	[comm_SellerForename] ,
	[comm_SellerSurname] ,
	[panelfile] ,
	[provider] ,
	[DateLoaded] ,
	[ImportConvertsellerref],
	[sourceid])

--Selects them on the basis they are at the same policy and branch
select 
ii.[UniqueRowID] ,
	ii.[Period] ,
	ii.[PolicyReference] ,
	ii.[OWPolicyRef],
	ii.[ClientName] ,
	ii.[StartDate] ,
	ii.[Source] ,
	ii.[Product] ,
	ii.[CommType] ,
	ii.[Status] ,
	ii.[Premium] ,
	ii.[Margin] ,
	ii.[Fee] ,
	ii.[BranchName],
	ii.[BranchNo] ,
	ii.[SellerName] ,
	ii.[OWFirmRef] ,
	ii.[OW_Sellerref] ,
	ii.[PESN] ,
	owt.id,
	owt.SellerCode,
	owt.SellerName,
	owt.SellerForename,
	owt.SellerSurname,
	@panelfile ,
	owt.provider,
	getdate() ,
	CASE WHEN LEN(dbo.CleanAndTrimString(ii.OW_Sellerref)) =7
             THEN dbo.CleanAndTrimString(ii.OW_Sellerref)
             ELSE ''
        END ,
		owt.sourceid
from owt_PaymentshieldCommissionPayments owt 
inner join #Months m on m.PeriodMonth = owt.[Month]
join owt_PaymentshieldImport ii on ii.UniqueRowID=owt.sourceid
--and ii.margin=owt.MarginCommRate
where ((owt.provider ='payment shield panel' and @panelfile='Yes')  or (owt.provider ='payment shield' and @panelfile='no'))
and owt.sellercode is null 

set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '17A) Insert records unmatched UIDS. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		if @debug = 'Y' exec msp_ProcessLog 'START', '17B) Update sourceids back to null', null, 'PaymentShield', 'Openwork'

		Update owt_PaymentshieldCommissionPayments set sourceid=null where sourceid is not null and provider in ('payment shield panel','payment shield'); --PR 30/06/2021 SET SOURCEID BACK TO NULL - SAFEGUARD UNLESS THIS IS BEING USED

		set @RowCount = @@rowcount

		if @debug = 'Y' 
		begin
			set @Process = '17B) SourceIDs set back to null. RowCount = ' + convert(varchar(20),@Rowcount)
			exec msp_ProcessLog 'END', @Process, null, 'PaymentShield', 'Openwork'
		end

		--END PR CHANGE 30/06/2021
		---------------------------------------------------------------------------
		-- Delete temporary tables
		---------------------------------------------------------------------------

		if @debug = 'Y' exec msp_ProcessLog 'START', '18) Delete temporary tables', null, 'PaymentShield', 'Openwork'

		drop table #currtotals
		drop table #FuzzyMatchedSellers		-- AG 26/06/2013
 
		if @debug = 'Y' exec msp_ProcessLog 'END', '18) Delete temporary tables', null, 'PaymentShield', 'Openwork'

	end
end

drop table #Months;

exec msp_ProcessLog 'END', 'owp_PaymentshieldCommission', null, 'PaymentShield', 'Openwork'

GO
/****** Object:  StoredProcedure [dbo].[owp_PaymentshieldCommissionOwl]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/********************************************************************************

Name		:	owp_PaymentshieldCommissionOwl
Created By	:	A Groves
Created		:	28/10/2015

Description	:	At this point in the process, the Paymentshield Owl Override payments 
				have already been loaded to table "dbo.owt_PaymentshieldOwlOverride".
				This process propagates the Paymentshield Owl data 
				from table: "dbo.owt_PaymentshieldOwlOverride"
				to table:	"dbo.owt_PaymentshieldCommissionPayments"
				
				After this stored proc has completed, the existing stored proc
				"owp_PaymentshieldAdviserListingExtract" is executed to propagate
				the Owl Payments into OpenAccess i.e.
				from table:	"dbo.owt_PaymentshieldCommissionPayments"
				to table:	"dbo.msit_OpenworkAdviserListing" 

				For each case, there are two payments on table "owt_PaymentshieldOwlOverride".
				One payment always has a comm rate of 10% and is Openwork's margin. The 
				other payment maximums at 4% and is the ASM's override payment. Note that the
				rate will be less than 4% where the adviser has sacrificed commission to provide
				his/her client with a better deal.
				
				This proc ignores the 10% record as it does not tell us if any sacrifice
				has occurred. The other record is created twice on table
				"owt_PaymentshieldCommissionPayments" as follows:
				1) Adviser's payment (derived from the ASM's override payment)
				2) ASM's override payment 

				For record (2), the ASM is looked up for the adviser using Insight tables.
	
				Call this stored proc as follows:
				
					exec owp_PaymentshieldCommissionOwl 'Openwork', 'PaymentshieldOwl' 
				
Amendment History
-----------------
Date		Author		Description
----		------		-----------
01/04/2016	A Groves	SR426998. Two fixes:
						1) The DA calculation was incorrect. In agreement with Marcus
							Cossey and Sarah Inglis it was made the same as the APE.
							Note that previously the DA was not apportioned between
							the adviser and the ASM - so over summing occurred.
						2) The Seller Name was propagated to the Original Seller Name	
							on the owt_PaymentshieldCommissionPayments table. This
							was corrected to be the Original Seller Name that was 
							propagated.
19/01/2017	A Groves	SR463747: Changes needed for the new SFTP'd file:- 
						1) The Fee field on table dbo.owt_PaymentshieldOwlOverride
							can be zero on a small number of records. This was causing
							the following to be zero on the ASM record:
							a) PaymentAmount
							b) TotalFeeDue
							c) EnhancedNBI
							d) BaseNBI
							e) Margin
							The fix was to calculate the above values from the premium
							as was already done on the adviser's payment row.
						2) SellerName populated in the same way that SellerForename 
							and SellerSurname are populated. Previously, it was possible
							for the SellerName to be blank with the other two populated
							if the seller's name was not in the data file.
						3) Where an adviser cannot be uniquely identified, then don't
							propagate the payment from table dbo.owt_PaymentshieldOwlOverride
							to table dbo.owt_PaymentshieldCommissionPayments. An example
							of where this occurs is when business for Muhammad Saleem comes
							through without the OWSellerRef, as there are two:
							BUID	UID		Name			Address
							----	---		----			-------
							2002328	4005118	Muhammad Saleem 6 Clements Close, Slough
							2007364	4009549	Muhammad Saleem	33 Mountfield Road,	East Ham, London
24/11/2017	A Groves	SR495162/CH19688. Previously the ASM look-up was failing where the 
							adviser had left. The old code has been replaced with a look-up 
							on table mi_insight_UserHierarchyAllUsers. Also where an
							adviser has been re-linked to a new business, the look-up
							on mstt_Agents was failing to find the adviser's old firm.
							Thus mstt_Agents has been changed to mstt_AgentsHistory.
09/02/2018	A Groves	SR499911/CH20436. Two improvements on the ASM records:
							1) Use the latest record on the mstt_AgentsHistory table
								as older records may have been set up incorrectly and
								subsequently corrected as was the case with "Bijo Kurian"
								whose name was in his UID field on his older records.
							2) Where a seller is also a top-line ASM (i.e. they don't
								themselves have an ASM) then payments for these sellers
								must not generate ASM records (because they don't have 
								an ASM). These unwanted records have been stopped by
								changing three left joins to inner joins on the ASMs.
29/10/2018	A Groves	1) Michal Iwinski's name rather than code exists in column OWSellerRef.
							So the code has been amended to look for this possibility.
						2) Mr Brian Dunajski changed name to Brian Meiklejohn so name
							matching changed from mstt_Agents to mstt_AgentsHistory.
***********************************************************************************/
CREATE procedure [dbo].[owp_PaymentshieldCommissionOwl]
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@Path						varchar(255),
		@DataFileName				varchar(255),
		@sql						varchar(8000),
		@RowCount					int,
		@ErrMsg						nvarchar(4000),
		@ErrMsgBrief				nvarchar(100),
		@ErrNum						int,
		@ErrSev						int,
		@ErrLine					int,
		@ErrState					int,
		@OwlManager2Code			nvarchar(10)	-- AG 29/10/2018

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart			= 'START'
set @PhaseEnd   		= 'END'
set @PhaseLog			= 'LOG'
set @PhaseError			= 'ERROR'
set @Process			= object_name(@@procid)
set @OwlManager2Code	= (select cde.Code from msit_MIWarehouseCodesAndDescriptions cde	-- AG 29/10/2018
								where cde.ColumnName = 'Manager2Code' and cde.Description = 'Owl Financial')

/****************************************************************************

	Log start																
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION

	/******************************************************************************************

	Adviser's Payment

	*******************************************************************************************/

	set @ProcessMessage = 'Adviser''s Payments'
	exec msp_ProcessLog @PhaseStart, @ProcessMessage, null, @Module, @Client

	declare @DACommRate decimal(10,6)
	set @DACommRate = 39.0
	declare @BaseCommRate decimal(10,6)
	set @BaseCommRate = 25.0
	declare @ASMCommRate decimal(10,6)
	set @ASMCommRate = 4.0
	declare @OWCommRate decimal(10,6)
	set @OWCommRate = @DACommRate - @BaseCommRate - @ASMCommRate

	insert into dbo.owt_PaymentshieldCommissionPayments
	(
		BusinessCode,
		BusinessName,
		BusinessECode,
		BusinessRef,
		SellerCode,
		SellerName,
		SellerForename,
		SellerSurname,
		SellerRef,
		Client,
		ClientForename,
		ClientSurname,
		BACSDate,
		Policy,
		ProdType,
		HierarchyProduct,
		StartDate,
		PaymentDate,
		LatestAnniversary,
		Frequency,
		Premium,
		PaymentAmount,
		APEFlag,
		TotalFeeDue,
		CommRate,
		MarginCommRate,
		DACommRate,
		BaseCommRate,
		UpliftRate,
		ICPaidToDate,
		StillToAccrue,
		SalesMoveFlag,
		DA,
		Turnover,
		APE,
		EnhancedNBI,
		BaseNBI,
		Margin,
		CaseCount,
		InitialPeriod,
		PayBasisCode,
		PayBasis,
		AgentSplit,
		FeeType,
		Provider,
		ProviderCode,
		Month,
		Source,
		CreateDate,
		OrigCommtype,
		OrigStatus,
		ELITE_Initial,
		ELITE_Category,
		OrigSellerName,
		SourceID
	)
	select	firm.Code as BusinessCode,
			Rtrim(isnull(firm.TradingName,firm.DESCN)) as BusinessName,
			firm.OscarAgentPrefix + firm.OscarAgentSerial + firm.OscarAgentSuffix as BusinessECode,
			po.BranchNo as BusinessRef,
			--AG 19/01/2017 Start
			case 
				when adv.Code is not null then adv.Code
				else (select top 1 Code from mstt_Agents where Firm = firm.Code)
			end as SellerCode,
			case 
				when adv.Code is not null then adv.Descn
				when adv.Code is null and firm.Code is not null then (select top 1 Descn from mstt_Agents where Firm = firm.Code)
				when MICodes.Code is null then ltrim(rtrim(po.SellerName))	-- No match on person title so title assumed not present
				else ltrim(rtrim(stuff(replace(po.SellerName,'.',''),1,len(MICodes.Code),''))) 
			end as SellerName,	
			case 
				when adv.Code is not null 
				then dbo.owf_FirstWord(adv.Descn)
				else (select top 1 dbo.owf_FirstWord(Descn) from mstt_Agents where Firm = firm.Code)
			end as SellerForename,		
			case when adv.Code is not null 
				then dbo.owf_LastWord(adv.Descn)
				else (select top 1 dbo.owf_LastWord(Descn) from mstt_Agents where Firm = firm.Code)
			end as SellerSurname,
			--AG 19/01/2017 End
			null as SellerRef,			-- Stays NULL
			dbo.owf_CleanText(substring(Rtrim(po.ClientName),1,65)) as Client,
			case when charindex(' ', RTrim(po.ClientName)) = 0 
				then NULL
				else Rtrim(Substring(RTrim(po.ClientName), charindex(' ', RTrim(po.ClientName))+1,1))	-- First initial (after title)
			end as ClientForename,
			case when charindex(' ', RTrim(po.ClientName)) = 0 
				then NULL
				else Rtrim(Right(RTrim(po.ClientName),charindex(' ', Reverse(RTrim(po.ClientName)))-1))	-- Surname
			end as ClientSurname,
			null as BACSDate,
			po.PolicyReference as Policy,
			Left(po.Product,8) as ProdType,
			'PY_' + Left(po.Product,5) as HierarchyProduct,
			po.StartDate as StartDate,
			po.Period as PaymentDate,
			case 
				when po.StartDate >= po.Period then po.StartDate
				when po.StartDate < po.Period and Month(po.StartDate) < Month(po.Period) then 
					case when Day(po.StartDate) = 29 and Month(po.StartDate) = 2 then 
							convert(datetime,'28/02/' +  Cast(Year(po.Period) as varchar(4)),103)
						 else
							convert(datetime,Cast(Day(po.StartDate) as varchar(2)) + '/' +  Cast(Month(po.StartDate) as varchar(2)) + '/' +  Cast(Year(po.Period) as varchar(4)),103)
					end			
				else 
					case when Day(po.StartDate) = 29 and Month(po.StartDate) = 2 then
							convert(datetime,'28/02/' +  Cast(Year(po.Period)-1 as varchar(4)),103)
						 else
							convert(datetime,Cast(Day(po.StartDate) as varchar(2)) + '/' +  Cast(Month(po.StartDate) as varchar(2)) + '/' +  Cast(Year(po.Period)-1 as varchar(4)),103)
					end
			end as LatestAnniversary,
			case when left(po.TermOfContract,6) = 'ANNUAL'
				then 'A'
				else 'M'
			end as Frequency,
			case when left(po.TermOfContract,6) = 'ANNUAL' 
				then 1 
				else 12 
			end * abs(po.Premium) as Premium,
			round(po.Premium * ((@BaseCommRate*(po.Margin/@ASMCommRate))/100),2) as PaymentAmount,
			isnull((select APE_Flag from mstt_ProductHierarchy where ProductType = 'Payshield' and ProductCode = 'PY_' + Left(po.Product,5)),'N') as APEFlag,
			round(po.Premium * ((@BaseCommRate * (po.Margin/@ASMCommRate))/100),2) as TotalFeeDue,
			@BaseCommRate * (po.Margin/@ASMCommRate) as CommRate,
			(@DACommRate * (po.Margin/@ASMCommRate)) - (@BaseCommRate * (po.Margin/@ASMCommRate)) as MarginCommRate,
			@DACommRate * (po.Margin/@ASMCommRate) as DACommRate,
			@BaseCommRate * (po.Margin/@ASMCommRate) as BaseCommRate,
			1.0 as UpliftRate,
			0.0 as ICPaidToDate,	-- These payments are IT (this is an accruals concept)
			0.0 as StillToAccrue,	-- These payments are IT (this is an accruals concept)
			'Y' as SalesMoveFlag,	-- Propagate to OpenAccess
			--AG 01/04/2016 Start
--			round(po.Premium * ((@DACommRate * (po.Margin/@ASMCommRate))/100),2) as DA,
			round(po.Premium * ((((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate)) + @OWCommRate)/100)
					* ((@BaseCommRate * (po.Margin/@ASMCommRate)) / ((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate))),2) as DA,
			--AG 01/04/2016 End
			round(po.Premium * ((((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate)) + @OWCommRate)/100)
					* ((@BaseCommRate * (po.Margin/@ASMCommRate)) / ((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate))),2) as Turnover,
			round(po.Premium * ((((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate)) + @OWCommRate)/100)
					* ((@BaseCommRate * (po.Margin/@ASMCommRate)) / ((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate))),2) as APE,
			round(po.Premium * ((@BaseCommRate * (po.Margin/@ASMCommRate))/100),2) as EnhancedNBI,
			round(po.Premium * ((@BaseCommRate * (po.Margin/@ASMCommRate))/100),2) as BaseNBI,
			round(po.Premium * ((@BaseCommRate * (po.Margin/@ASMCommRate))/100),2) as Margin,
			0 as CaseCount,
			case when po.CommType in ('Double Indemnity','Dind','Dind2') then 24 else 12 end as InitialPeriod,
			case when po.CommType in ('Indemnity','Double Indemnity','Aind','Dind','Dind2') then 'T' else 'F' end as PayBasisCode,
			case when po.CommType in ('Indemnity','Double Indemnity','Aind','Dind','Dind2') then 'IT' else 'Accrual' end as PayBasis,
			100 as AgentSplit,
			case when po.CommType in ('Adjustment','Awaiting Start') or po.Status in ('AWAITING START','MTA') then 'Adj' else 'IC' end as FeeType,
			'Payment Shield Owl' as Provider,
			'PYMTSHLD' as ProviderCode,
			dateadd(mm,1,po.Period) as [Month],
			'Payshield' as Source,
			pic.FileID as CreateDate,	
			po.CommType as OrigCommtype,
			po.Status as OrigStatus,
			0 as ELITE_Initial,			-- Owl don't get ELITE points
			null as ELITE_Category,		-- Owl don't get ELITE points
			ltrim(rtrim(po.OriginalSellerName)) as OrigSellerName,		--AG 01/04/2016
			po.ID as SourceID
	from	dbo.owt_PaymentshieldOwlOverride po
			inner join dbo.owt_PaymentshieldImportControl pic on pic.FileID = po.LoadedDateTime
			--AG 29/10/2018 Start
			left join (select Descn, MAX(IDHISTid_type) as MaxIDHISTid_type from mstt_AgentsHistory where Manager2Code = @OwlManager2Code and AgentType <> 2 group by Descn) agName on agName.Descn = po.SellerName
			left join mstt_AgentsHistory ah on ah.IDHISTid_type = agName.MaxIDHISTid_type
			--left join mstt_Agents adv on adv.Code = po.OWSellerRef and adv.AgentType <> 2 -- Not a firm
			left join mstt_Agents adv 
					on (adv.Code = po.OWSellerRef or adv.Code = ah.Code) 
					and adv.AgentType <> 2 -- Not a firm
			--left join mstt_Agents firm on firm.Code = coalesce(adv.Firm,po.OWSellerRef) 
			left join mstt_Agents firm on firm.Code = adv.Firm
			--AG 29/10/2018 End
			left join dbo.msit_MIWarehouseCodesAndDescriptions MICodes
					on  MICodes.ColumnName = 'PersonTitle' 
					and ltrim(rtrim(replace(po.SellerName,'.',''))) like MICodes.Code + ' %'
	where	po.Margin <> 10	-- Exclude the Openwork margin record as this doesn't tell us if a comm sacrifice has taken place
	and		isnull(po.OWSellerRef,'') <> ''		--AG 19/01/2017
	set @RowCount = @@rowcount

	set @ProcessMessage = @ProcessMessage + '. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @Module, @Client

	/******************************************************************************************

	ASM's Payment

	*******************************************************************************************/

	set @ProcessMessage = 'ASM''s Payments'
	exec msp_ProcessLog @PhaseStart, @ProcessMessage, null, @Module, @Client

	insert into dbo.owt_PaymentshieldCommissionPayments
	(
		BusinessCode,
		BusinessName,
		BusinessECode,
		BusinessRef,
		SellerCode,
		SellerName,
		SellerForename,
		SellerSurname,
		SellerRef,
		Client,
		ClientForename,
		ClientSurname,
		BACSDate,
		Policy,
		ProdType,
		HierarchyProduct,
		StartDate,
		PaymentDate,
		LatestAnniversary,
		Frequency,
		Premium,
		PaymentAmount,
		APEFlag,
		TotalFeeDue,
		CommRate,
		MarginCommRate,
		DACommRate,
		BaseCommRate,
		UpliftRate,
		ICPaidToDate,
		StillToAccrue,
		SalesMoveFlag,
		DA,
		Turnover,
		APE,
		EnhancedNBI,
		BaseNBI,
		Margin,
		CaseCount,
		InitialPeriod,
		PayBasisCode,
		PayBasis,
		AgentSplit,
		FeeType,
		Provider,
		ProviderCode,
		Month,
		Source,
		CreateDate,
		OrigCommtype,
		OrigStatus,
		ELITE_Initial,
		ELITE_Category,
		OrigSellerName,
		SourceID
	)
	select	ASMFirm.Code as BusinessCode,
			Rtrim(isnull(ASMFirm.TradingName,ASMFirm.DESCN)) as BusinessName,
			ASMFirm.OscarAgentPrefix + ASMFirm.OscarAgentSerial + ASMFirm.OscarAgentSuffix as BusinessECode,
			po.BranchNo as BusinessRef,
			--AG 19/01/2017 Start
			case 
				when adv.Code is not null then adv.Code
				else (select top 1 Code from mstt_Agents where Firm = firm.Code)
			end as SellerCode,
			case 
				when adv.Code is not null then adv.Descn
				when adv.Code is null and firm.Code is not null then (select top 1 Descn from mstt_Agents where Firm = firm.Code)
				when MICodes.Code is null then ltrim(rtrim(po.SellerName))	-- No match on person title so title assumed not present
				else ltrim(rtrim(stuff(replace(po.SellerName,'.',''),1,len(MICodes.Code),''))) 
			end as SellerName,	
			case 
				when adv.Code is not null 
				then dbo.owf_FirstWord(adv.Descn)
				else (select top 1 dbo.owf_FirstWord(Descn) from mstt_Agents where Firm = firm.Code)
			end as SellerForename,		
			case when adv.Code is not null 
				then dbo.owf_LastWord(adv.Descn)
				else (select top 1 dbo.owf_LastWord(Descn) from mstt_Agents where Firm = firm.Code)
			end as SellerSurname,
			--AG 19/01/2017 End
			null as SellerRef,			-- Stays NULL
			dbo.owf_CleanText(substring(Rtrim(po.ClientName),1,65)) as Client,
			case when charindex(' ', RTrim(po.ClientName)) = 0 
				then NULL
				else Rtrim(Substring(RTrim(po.ClientName), charindex(' ', RTrim(po.ClientName))+1,1))	-- First initial (after title)
			end as ClientForename,
			case when charindex(' ', RTrim(po.ClientName)) = 0 
				then NULL
				else Rtrim(Right(RTrim(po.ClientName),charindex(' ', Reverse(RTrim(po.ClientName)))-1))	-- Surname
			end as ClientSurname,
			null as BACSDate,
			po.PolicyReference as Policy,
			Left(po.Product,8) as ProdType,
			'PY_' + Left(po.Product,5) as HierarchyProduct,
			po.StartDate as StartDate,
			po.Period as PaymentDate,
			case 
				when po.StartDate >= po.Period then po.StartDate
				when po.StartDate < po.Period and Month(po.StartDate) < Month(po.Period) then 
					case when Day(po.StartDate) = 29 and Month(po.StartDate) = 2 then 
							convert(datetime,'28/02/' +  Cast(Year(po.Period) as varchar(4)),103)
						 else
							convert(datetime,Cast(Day(po.StartDate) as varchar(2)) + '/' +  Cast(Month(po.StartDate) as varchar(2)) + '/' +  Cast(Year(po.Period) as varchar(4)),103)
					end			
				else 
					case when Day(po.StartDate) = 29 and Month(po.StartDate) = 2 then
							convert(datetime,'28/02/' +  Cast(Year(po.Period)-1 as varchar(4)),103)
						 else
							convert(datetime,Cast(Day(po.StartDate) as varchar(2)) + '/' +  Cast(Month(po.StartDate) as varchar(2)) + '/' +  Cast(Year(po.Period)-1 as varchar(4)),103)
					end
			end as LatestAnniversary,
			case when left(po.TermOfContract,6) = 'ANNUAL'
				then 'A'
				else 'M'
			end as Frequency,
			case when left(po.TermOfContract,6) = 'ANNUAL' 
				then 1 
				else 12 
			end * abs(po.Premium) as Premium,
			--AG 19/01/2017 Start
			--po.Fee as PaymentAmount,
			round(po.Premium * ((@ASMCommRate*(po.Margin/@ASMCommRate))/100),2) as PaymentAmount,
			--AG 19/01/2017 End
			isnull((select APE_Flag from mstt_ProductHierarchy where ProductType = 'Payshield' and ProductCode = 'PY_' + Left(po.Product,5)),'N') as APEFlag,
			--AG 19/01/2017 Start
			--po.Fee as TotalFeeDue,
			round(po.Premium * ((@ASMCommRate * (po.Margin/@ASMCommRate))/100),2) as TotalFeeDue,
			--AG 19/01/2017 End
			po.Margin as CommRate,
			@DACommRate * (po.Margin/@ASMCommRate) - po.Margin as MarginCommRate,
			@DACommRate * (po.Margin/@ASMCommRate) as DACommRate,
			po.Margin as BaseCommRate,
			1.0 as UpliftRate,
			0.0 as ICPaidToDate,	-- These payments are IT (this is an accruals concept)
			0.0 as StillToAccrue,	-- These payments are IT (this is an accruals concept)
			case when ASMFirm.Code is not null 
				then 'Y'
				else 'N'			-- If no firm then it can't go to OpenAccess
			end as SalesMoveFlag,	-- Propagate to OpenAccess
			--AG 01/04/2016 Start
--			round(po.Premium * ((@DACommRate * (po.Margin/@ASMCommRate))/100),2) as DA,
			round(po.Premium * ((((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate)) + @OWCommRate)/100)
							* (po.Margin / ((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate))),2) as DA,
			--AG 01/04/2016 End
			round(po.Premium * ((((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate)) + @OWCommRate)/100)
							* (po.Margin / ((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate))),2) as Turnover,
			round(po.Premium * ((((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate)) + @OWCommRate)/100)
							* (po.Margin / ((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate))),2) as APE,
			--AG 19/01/2017 Start
			--po.Fee as EnhancedNBI,
			--po.Fee as BaseNBI,
			--po.Fee as Margin,
			round(po.Premium * ((@ASMCommRate * (po.Margin/@ASMCommRate))/100),2) as EnhancedNBI,
			round(po.Premium * ((@ASMCommRate * (po.Margin/@ASMCommRate))/100),2) as BaseNBI,
			round(po.Premium * ((@ASMCommRate * (po.Margin/@ASMCommRate))/100),2) as Margin,
			--AG 19/01/2017 End
			0 as CaseCount,
			case when po.CommType in ('Double Indemnity','Dind','Dind2') then 24 else 12 end as InitialPeriod,
			case when po.CommType in ('Indemnity','Double Indemnity','Aind','Dind','Dind2') then 'T' else 'F' end as PayBasisCode,
			case when po.CommType in ('Indemnity','Double Indemnity','Aind','Dind','Dind2') then 'IT' else 'Accrual' end as PayBasis,
			100 as AgentSplit,
			case when po.CommType in ('Adjustment','Awaiting Start') or po.Status in ('AWAITING START','MTA') then 'Adj' else 'IC' end as FeeType,
			'Payment Shield Owl ASM' as Provider,
			'PYMTSHLD' as ProviderCode,
			dateadd(mm,1,po.Period) as [Month],
			'Payshield' as Source,
			pic.FileID as CreateDate,	
			po.CommType as OrigCommtype,
			po.Status as OrigStatus,
			0 as ELITE_Initial,			-- Owl don't get ELITE points
			null as ELITE_Category,		-- Owl don't get ELITE points
			ltrim(rtrim(po.OriginalSellerName)) as OrigSellerName,		--AG 01/04/2016
			po.ID as SourceID
	from	dbo.owt_PaymentshieldOwlOverride po
			inner join dbo.owt_PaymentshieldImportControl pic on pic.FileID = po.LoadedDateTime
			--AG 29/10/2018 Start
			left join (select Descn, MAX(IDHISTid_type) as MaxIDHISTid_type from mstt_AgentsHistory where Manager2Code = @OwlManager2Code and AgentType <> 2 group by Descn) agName on agName.Descn = po.SellerName
			left join mstt_AgentsHistory ah on ah.IDHISTid_type = agName.MaxIDHISTid_type
			--left join mstt_Agents adv on adv.Code = po.OWSellerRef and adv.AgentType <> 2 -- Not a firm
			left join mstt_Agents adv 
					on (adv.Code = po.OWSellerRef or adv.Code = ah.Code) 
					and adv.AgentType <> 2 -- Not a firm
			--left join mstt_Agents firm on firm.Code = coalesce(adv.Firm,po.OWSellerRef) 
			left join mstt_Agents firm on firm.Code = adv.Firm
			--AG 29/10/2018 End
			left join dbo.msit_MIWarehouseCodesAndDescriptions MICodes
					on  MICodes.ColumnName = 'PersonTitle' 
					and ltrim(rtrim(replace(po.SellerName,'.',''))) like MICodes.Code + ' %'
			left join sa_insight_UserDetails ud 
					on ud.USR_ExternalID =	case when adv.Code is null 
												--then (select top 1 Code from mstt_Agents where Firm = firm.Code)		  AG 24/11/2017
												then (select top 1 Code from mstt_AgentsHistory where Firm = firm.Code order by ValidFromDate desc)	--AG 24/11/2017 & 09/02/2018
												else adv.Code
											end
			--AG 24/11/2017 Start
			--left join sa_insight_UserPosition up on up.UPS_UserID = ud.USR_ID and up.UPS_DateTo is null and up.UPS_JobTitle = 53 -- OWL Practice Principal
			--left join	(	select	upended.UPS_UserID, max(upended.UPS_DateTo) as Max_UPS_DateTo
			--				from	sa_insight_UserPosition upended
			--				where	upended.UPS_JobTitle = 53 -- OWL Practice Principal
			--				group	by upended.UPS_UserID
			--			)	upended1 on upended1.UPS_UserID = ud.USR_ID  
			--left join sa_insight_UserPosition upended2 on upended2.UPS_UserID = ud.USR_ID and upended2.UPS_DateTo = upended1.Max_UPS_DateTo and upended2.UPS_JobTitle = 53 -- OWL Practice Principal
			---- Use active PP row but if none, then use most recently ended PP row
			--left join sa_insight_HierarchyNodeLink HNL1 on HNL1.HNL_NodeID = coalesce(up.UPS_OrganisationalUnitID,upended2.UPS_OrganisationalUnitID) and HNL1.HNL_DateTo is null and HNL1.HNL_Type = 0 
			--left join sa_insight_UserPosition up1 on up1.UPS_OrganisationalUnitID = HNL1.HNL_ParentID and up1.UPS_DateTo is null and up1.UPS_JobTitle = 54	-- OWL Area Sales Manager
			--left join sa_insight_UserDetails ud1 on ud1.USR_ID = up1.UPS_UserID
			--left join mstt_Agents ASM on ASM.Code = ud1.USR_ExternalID
			inner join mi_insight_UserHierarchyAllUsers uhah			--AG 09/02/2018 changed from left to inner join
						on uhah.UserUID = ud.USR_ExternalID
						and po.StartDate between uhah.EffectiveStartDate and uhah.EffectiveEndDate
			inner join mstt_Agents ASM on ASM.Code = uhah.OwlASMUID1	--AG 09/02/2018 changed from left to inner join
			--AG 24/11/2017 End
			inner join mstt_Agents ASMFirm on ASMFirm.Code = ASM.Firm	--AG 09/02/2018 changed from left to inner join
	where	po.Margin <> 10	-- Exclude the Openwork margin record as this doesn't tell us if a comm sacrifice has taken place
	and		isnull(po.OWSellerRef,'') <> ''		--AG 19/01/2017

	set @RowCount = @@rowcount

	set @ProcessMessage = @ProcessMessage + '. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @Module, @Client

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	COMMIT TRANSACTION      

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE(), @ErrState = XACT_STATE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10))
	
	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION

	-- Error message line 1
	set @ErrMsgBrief = left(@ErrMsg,100)
	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	
	-- Error message line 2 - if any text exists
	set @ErrMsgBrief = substring(@ErrMsg,101,100)
	if len(@ErrMsgBrief) > 0
		exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @ErrSev , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/



GO
/****** Object:  StoredProcedure [dbo].[owp_PaymentshieldCommissionOwl_Backup20180209AG]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/********************************************************************************

Name		:	owp_PaymentshieldCommissionOwl
Created By	:	A Groves
Created		:	28/10/2015

Description	:	At this point in the process, the Paymentshield Owl Override payments 
				have already been loaded to table "dbo.owt_PaymentshieldOwlOverride".
				This process propagates the Paymentshield Owl data 
				from table: "dbo.owt_PaymentshieldOwlOverride"
				to table:	"dbo.owt_PaymentshieldCommissionPayments"
				
				After this stored proc has completed, the existing stored proc
				"owp_PaymentshieldAdviserListingExtract" is executed to propagate
				the Owl Payments into OpenAccess i.e.
				from table:	"dbo.owt_PaymentshieldCommissionPayments"
				to table:	"dbo.msit_OpenworkAdviserListing" 

				For each case, there are two payments on table "owt_PaymentshieldOwlOverride".
				One payment always has a comm rate of 10% and is Openwork's margin. The 
				other payment maximums at 4% and is the ASM's override payment. Note that the
				rate will be less than 4% where the adviser has sacrificed commission to provide
				his/her client with a better deal.
				
				This proc ignores the 10% record as it does not tell us if any sacrifice
				has occurred. The other record is created twice on table
				"owt_PaymentshieldCommissionPayments" as follows:
				1) Adviser's payment (derived from the ASM's override payment)
				2) ASM's override payment 

				For record (2), the ASM is looked up for the adviser using Insight tables.
	
				Call this stored proc as follows:
				
					exec owp_PaymentshieldCommissionOwl 'Openwork', 'PaymentshieldOwl' 
				
Amendment History
-----------------
Date		Author		Description
----		------		-----------
01/04/2016	A Groves	SR426998. Two fixes:
						1) The DA calculation was incorrect. In agreement with Marcus
							Cossey and Sarah Inglis it was made the same as the APE.
							Note that previously the DA was not apportioned between
							the adviser and the ASM - so over summing occurred.
						2) The Seller Name was propagated to the Original Seller Name	
							on the owt_PaymentshieldCommissionPayments table. This
							was corrected to be the Original Seller Name that was 
							propagated.
19/01/2017	A Groves	SR463747: Changes needed for the new SFTP'd file:- 
						1) The Fee field on table dbo.owt_PaymentshieldOwlOverride
							can be zero on a small number of records. This was causing
							the following to be zero on the ASM record:
							a) PaymentAmount
							b) TotalFeeDue
							c) EnhancedNBI
							d) BaseNBI
							e) Margin
							The fix was to calculate the above values from the premium
							as was already done on the adviser's payment row.
						2) SellerName populated in the same way that SellerForename 
							and SellerSurname are populated. Previously, it was possible
							for the SellerName to be blank with the other two populated
							if the seller's name was not in the data file.
						3) Where an adviser cannot be uniquely identified, then don't
							propagate the payment from table dbo.owt_PaymentshieldOwlOverride
							to table dbo.owt_PaymentshieldCommissionPayments. An example
							of where this occurs is when business for Muhammad Saleem comes
							through without the OWSellerRef, as there are two:
							BUID	UID		Name			Address
							----	---		----			-------
							2002328	4005118	Muhammad Saleem 6 Clements Close, Slough
							2007364	4009549	Muhammad Saleem	33 Mountfield Road,	East Ham, London
24/11/2017	A Groves	SR495162/CH19688. Previously the ASM look-up was failing where the 
							adviser had left. The old code has been replaced with a look-up 
							on table mi_insight_UserHierarchyAllUsers. Also where an
							adviser has been re-linked to a new business, the look-up
							on mstt_Agents was failing to find the adviser's old firm.
							Thus mstt_Agents has been changed to mstt_AgentsHistory.
***********************************************************************************/
CREATE procedure [dbo].[owp_PaymentshieldCommissionOwl_Backup20180209AG]
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@Path						varchar(255),
		@DataFileName				varchar(255),
		@sql						varchar(8000),
		@RowCount					int,
		@ErrMsg						nvarchar(4000),
		@ErrMsgBrief				nvarchar(100),
		@ErrNum						int,
		@ErrSev						int,
		@ErrLine					int,
		@ErrState					int

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @PhaseLog		= 'LOG'
set @PhaseError		= 'ERROR'
set @Process		= object_name(@@procid)

/****************************************************************************

	Log start																
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION

	/******************************************************************************************

	Adviser's Payment

	*******************************************************************************************/

	set @ProcessMessage = 'Adviser''s Payments'
	exec msp_ProcessLog @PhaseStart, @ProcessMessage, null, @Module, @Client

	declare @DACommRate decimal(10,6)
	set @DACommRate = 39.0
	declare @BaseCommRate decimal(10,6)
	set @BaseCommRate = 25.0
	declare @ASMCommRate decimal(10,6)
	set @ASMCommRate = 4.0
	declare @OWCommRate decimal(10,6)
	set @OWCommRate = @DACommRate - @BaseCommRate - @ASMCommRate

	insert into dbo.owt_PaymentshieldCommissionPayments
	(
		BusinessCode,
		BusinessName,
		BusinessECode,
		BusinessRef,
		SellerCode,
		SellerName,
		SellerForename,
		SellerSurname,
		SellerRef,
		Client,
		ClientForename,
		ClientSurname,
		BACSDate,
		Policy,
		ProdType,
		HierarchyProduct,
		StartDate,
		PaymentDate,
		LatestAnniversary,
		Frequency,
		Premium,
		PaymentAmount,
		APEFlag,
		TotalFeeDue,
		CommRate,
		MarginCommRate,
		DACommRate,
		BaseCommRate,
		UpliftRate,
		ICPaidToDate,
		StillToAccrue,
		SalesMoveFlag,
		DA,
		Turnover,
		APE,
		EnhancedNBI,
		BaseNBI,
		Margin,
		CaseCount,
		InitialPeriod,
		PayBasisCode,
		PayBasis,
		AgentSplit,
		FeeType,
		Provider,
		ProviderCode,
		Month,
		Source,
		CreateDate,
		OrigCommtype,
		OrigStatus,
		ELITE_Initial,
		ELITE_Category,
		OrigSellerName,
		SourceID
	)
	select	firm.Code as BusinessCode,
			Rtrim(isnull(firm.TradingName,firm.DESCN)) as BusinessName,
			firm.OscarAgentPrefix + firm.OscarAgentSerial + firm.OscarAgentSuffix as BusinessECode,
			po.BranchNo as BusinessRef,
			--AG 19/01/2017 Start
			case 
				when adv.Code is not null then adv.Code
				else (select top 1 Code from mstt_Agents where Firm = firm.Code)
			end as SellerCode,
			case 
				when adv.Code is not null then adv.Descn
				when adv.Code is null and firm.Code is not null then (select top 1 Descn from mstt_Agents where Firm = firm.Code)
				when MICodes.Code is null then ltrim(rtrim(po.SellerName))	-- No match on person title so title assumed not present
				else ltrim(rtrim(stuff(replace(po.SellerName,'.',''),1,len(MICodes.Code),''))) 
			end as SellerName,	
			case 
				when adv.Code is not null 
				then dbo.owf_FirstWord(adv.Descn)
				else (select top 1 dbo.owf_FirstWord(Descn) from mstt_Agents where Firm = firm.Code)
			end as SellerForename,		
			case when adv.Code is not null 
				then dbo.owf_LastWord(adv.Descn)
				else (select top 1 dbo.owf_LastWord(Descn) from mstt_Agents where Firm = firm.Code)
			end as SellerSurname,
			--AG 19/01/2017 End
			null as SellerRef,			-- Stays NULL
			dbo.owf_CleanText(substring(Rtrim(po.ClientName),1,65)) as Client,
			case when charindex(' ', RTrim(po.ClientName)) = 0 
				then NULL
				else Rtrim(Substring(RTrim(po.ClientName), charindex(' ', RTrim(po.ClientName))+1,1))	-- First initial (after title)
			end as ClientForename,
			case when charindex(' ', RTrim(po.ClientName)) = 0 
				then NULL
				else Rtrim(Right(RTrim(po.ClientName),charindex(' ', Reverse(RTrim(po.ClientName)))-1))	-- Surname
			end as ClientSurname,
			null as BACSDate,
			po.PolicyReference as Policy,
			Left(po.Product,8) as ProdType,
			'PY_' + Left(po.Product,5) as HierarchyProduct,
			po.StartDate as StartDate,
			po.Period as PaymentDate,
			case 
				when po.StartDate >= po.Period then po.StartDate
				when po.StartDate < po.Period and Month(po.StartDate) < Month(po.Period) then 
					case when Day(po.StartDate) = 29 and Month(po.StartDate) = 2 then 
							convert(datetime,'28/02/' +  Cast(Year(po.Period) as varchar(4)),103)
						 else
							convert(datetime,Cast(Day(po.StartDate) as varchar(2)) + '/' +  Cast(Month(po.StartDate) as varchar(2)) + '/' +  Cast(Year(po.Period) as varchar(4)),103)
					end			
				else 
					case when Day(po.StartDate) = 29 and Month(po.StartDate) = 2 then
							convert(datetime,'28/02/' +  Cast(Year(po.Period)-1 as varchar(4)),103)
						 else
							convert(datetime,Cast(Day(po.StartDate) as varchar(2)) + '/' +  Cast(Month(po.StartDate) as varchar(2)) + '/' +  Cast(Year(po.Period)-1 as varchar(4)),103)
					end
			end as LatestAnniversary,
			case when left(po.TermOfContract,6) = 'ANNUAL'
				then 'A'
				else 'M'
			end as Frequency,
			case when left(po.TermOfContract,6) = 'ANNUAL' 
				then 1 
				else 12 
			end * abs(po.Premium) as Premium,
			round(po.Premium * ((@BaseCommRate*(po.Margin/@ASMCommRate))/100),2) as PaymentAmount,
			isnull((select APE_Flag from mstt_ProductHierarchy where ProductType = 'Payshield' and ProductCode = 'PY_' + Left(po.Product,5)),'N') as APEFlag,
			round(po.Premium * ((@BaseCommRate * (po.Margin/@ASMCommRate))/100),2) as TotalFeeDue,
			@BaseCommRate * (po.Margin/@ASMCommRate) as CommRate,
			(@DACommRate * (po.Margin/@ASMCommRate)) - (@BaseCommRate * (po.Margin/@ASMCommRate)) as MarginCommRate,
			@DACommRate * (po.Margin/@ASMCommRate) as DACommRate,
			@BaseCommRate * (po.Margin/@ASMCommRate) as BaseCommRate,
			1.0 as UpliftRate,
			0.0 as ICPaidToDate,	-- These payments are IT (this is an accruals concept)
			0.0 as StillToAccrue,	-- These payments are IT (this is an accruals concept)
			'Y' as SalesMoveFlag,	-- Propagate to OpenAccess
			--AG 01/04/2016 Start
--			round(po.Premium * ((@DACommRate * (po.Margin/@ASMCommRate))/100),2) as DA,
			round(po.Premium * ((((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate)) + @OWCommRate)/100)
					* ((@BaseCommRate * (po.Margin/@ASMCommRate)) / ((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate))),2) as DA,
			--AG 01/04/2016 End
			round(po.Premium * ((((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate)) + @OWCommRate)/100)
					* ((@BaseCommRate * (po.Margin/@ASMCommRate)) / ((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate))),2) as Turnover,
			round(po.Premium * ((((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate)) + @OWCommRate)/100)
					* ((@BaseCommRate * (po.Margin/@ASMCommRate)) / ((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate))),2) as APE,
			round(po.Premium * ((@BaseCommRate * (po.Margin/@ASMCommRate))/100),2) as EnhancedNBI,
			round(po.Premium * ((@BaseCommRate * (po.Margin/@ASMCommRate))/100),2) as BaseNBI,
			round(po.Premium * ((@BaseCommRate * (po.Margin/@ASMCommRate))/100),2) as Margin,
			0 as CaseCount,
			case when po.CommType in ('Double Indemnity','Dind','Dind2') then 24 else 12 end as InitialPeriod,
			case when po.CommType in ('Indemnity','Double Indemnity','Aind','Dind','Dind2') then 'T' else 'F' end as PayBasisCode,
			case when po.CommType in ('Indemnity','Double Indemnity','Aind','Dind','Dind2') then 'IT' else 'Accrual' end as PayBasis,
			100 as AgentSplit,
			case when po.CommType in ('Adjustment','Awaiting Start') or po.Status in ('AWAITING START','MTA') then 'Adj' else 'IC' end as FeeType,
			'Payment Shield Owl' as Provider,
			'PYMTSHLD' as ProviderCode,
			dateadd(mm,1,po.Period) as [Month],
			'Payshield' as Source,
			pic.FileID as CreateDate,	
			po.CommType as OrigCommtype,
			po.Status as OrigStatus,
			0 as ELITE_Initial,			-- Owl don't get ELITE points
			null as ELITE_Category,		-- Owl don't get ELITE points
			ltrim(rtrim(po.OriginalSellerName)) as OrigSellerName,		--AG 01/04/2016
			po.ID as SourceID
	from	dbo.owt_PaymentshieldOwlOverride po
			inner join dbo.owt_PaymentshieldImportControl pic on pic.FileID = po.LoadedDateTime
			left join mstt_Agents adv on adv.Code = po.OWSellerRef and adv.AgentType <> 2 -- Not a firm
			left join mstt_Agents firm on firm.Code = coalesce(adv.Firm,po.OWSellerRef) 
			left join dbo.msit_MIWarehouseCodesAndDescriptions MICodes
					on  MICodes.ColumnName = 'PersonTitle' 
					and ltrim(rtrim(replace(po.SellerName,'.',''))) like MICodes.Code + ' %'
	where	po.Margin <> 10	-- Exclude the Openwork margin record as this doesn't tell us if a comm sacrifice has taken place
	and		isnull(po.OWSellerRef,'') <> ''		--AG 19/01/2017
	set @RowCount = @@rowcount

	set @ProcessMessage = @ProcessMessage + '. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @Module, @Client

	/******************************************************************************************

	ASM's Payment

	*******************************************************************************************/

	set @ProcessMessage = 'ASM''s Payments'
	exec msp_ProcessLog @PhaseStart, @ProcessMessage, null, @Module, @Client

	insert into dbo.owt_PaymentshieldCommissionPayments
	(
		BusinessCode,
		BusinessName,
		BusinessECode,
		BusinessRef,
		SellerCode,
		SellerName,
		SellerForename,
		SellerSurname,
		SellerRef,
		Client,
		ClientForename,
		ClientSurname,
		BACSDate,
		Policy,
		ProdType,
		HierarchyProduct,
		StartDate,
		PaymentDate,
		LatestAnniversary,
		Frequency,
		Premium,
		PaymentAmount,
		APEFlag,
		TotalFeeDue,
		CommRate,
		MarginCommRate,
		DACommRate,
		BaseCommRate,
		UpliftRate,
		ICPaidToDate,
		StillToAccrue,
		SalesMoveFlag,
		DA,
		Turnover,
		APE,
		EnhancedNBI,
		BaseNBI,
		Margin,
		CaseCount,
		InitialPeriod,
		PayBasisCode,
		PayBasis,
		AgentSplit,
		FeeType,
		Provider,
		ProviderCode,
		Month,
		Source,
		CreateDate,
		OrigCommtype,
		OrigStatus,
		ELITE_Initial,
		ELITE_Category,
		OrigSellerName,
		SourceID
	)
	select	ASMFirm.Code as BusinessCode,
			Rtrim(isnull(ASMFirm.TradingName,ASMFirm.DESCN)) as BusinessName,
			ASMFirm.OscarAgentPrefix + ASMFirm.OscarAgentSerial + ASMFirm.OscarAgentSuffix as BusinessECode,
			po.BranchNo as BusinessRef,
			--AG 19/01/2017 Start
			case 
				when adv.Code is not null then adv.Code
				else (select top 1 Code from mstt_Agents where Firm = firm.Code)
			end as SellerCode,
			case 
				when adv.Code is not null then adv.Descn
				when adv.Code is null and firm.Code is not null then (select top 1 Descn from mstt_Agents where Firm = firm.Code)
				when MICodes.Code is null then ltrim(rtrim(po.SellerName))	-- No match on person title so title assumed not present
				else ltrim(rtrim(stuff(replace(po.SellerName,'.',''),1,len(MICodes.Code),''))) 
			end as SellerName,	
			case 
				when adv.Code is not null 
				then dbo.owf_FirstWord(adv.Descn)
				else (select top 1 dbo.owf_FirstWord(Descn) from mstt_Agents where Firm = firm.Code)
			end as SellerForename,		
			case when adv.Code is not null 
				then dbo.owf_LastWord(adv.Descn)
				else (select top 1 dbo.owf_LastWord(Descn) from mstt_Agents where Firm = firm.Code)
			end as SellerSurname,
			--AG 19/01/2017 End
			null as SellerRef,			-- Stays NULL
			dbo.owf_CleanText(substring(Rtrim(po.ClientName),1,65)) as Client,
			case when charindex(' ', RTrim(po.ClientName)) = 0 
				then NULL
				else Rtrim(Substring(RTrim(po.ClientName), charindex(' ', RTrim(po.ClientName))+1,1))	-- First initial (after title)
			end as ClientForename,
			case when charindex(' ', RTrim(po.ClientName)) = 0 
				then NULL
				else Rtrim(Right(RTrim(po.ClientName),charindex(' ', Reverse(RTrim(po.ClientName)))-1))	-- Surname
			end as ClientSurname,
			null as BACSDate,
			po.PolicyReference as Policy,
			Left(po.Product,8) as ProdType,
			'PY_' + Left(po.Product,5) as HierarchyProduct,
			po.StartDate as StartDate,
			po.Period as PaymentDate,
			case 
				when po.StartDate >= po.Period then po.StartDate
				when po.StartDate < po.Period and Month(po.StartDate) < Month(po.Period) then 
					case when Day(po.StartDate) = 29 and Month(po.StartDate) = 2 then 
							convert(datetime,'28/02/' +  Cast(Year(po.Period) as varchar(4)),103)
						 else
							convert(datetime,Cast(Day(po.StartDate) as varchar(2)) + '/' +  Cast(Month(po.StartDate) as varchar(2)) + '/' +  Cast(Year(po.Period) as varchar(4)),103)
					end			
				else 
					case when Day(po.StartDate) = 29 and Month(po.StartDate) = 2 then
							convert(datetime,'28/02/' +  Cast(Year(po.Period)-1 as varchar(4)),103)
						 else
							convert(datetime,Cast(Day(po.StartDate) as varchar(2)) + '/' +  Cast(Month(po.StartDate) as varchar(2)) + '/' +  Cast(Year(po.Period)-1 as varchar(4)),103)
					end
			end as LatestAnniversary,
			case when left(po.TermOfContract,6) = 'ANNUAL'
				then 'A'
				else 'M'
			end as Frequency,
			case when left(po.TermOfContract,6) = 'ANNUAL' 
				then 1 
				else 12 
			end * abs(po.Premium) as Premium,
			--AG 19/01/2017 Start
			--po.Fee as PaymentAmount,
			round(po.Premium * ((@ASMCommRate*(po.Margin/@ASMCommRate))/100),2) as PaymentAmount,
			--AG 19/01/2017 End
			isnull((select APE_Flag from mstt_ProductHierarchy where ProductType = 'Payshield' and ProductCode = 'PY_' + Left(po.Product,5)),'N') as APEFlag,
			--AG 19/01/2017 Start
			--po.Fee as TotalFeeDue,
			round(po.Premium * ((@ASMCommRate * (po.Margin/@ASMCommRate))/100),2) as TotalFeeDue,
			--AG 19/01/2017 End
			po.Margin as CommRate,
			@DACommRate * (po.Margin/@ASMCommRate) - po.Margin as MarginCommRate,
			@DACommRate * (po.Margin/@ASMCommRate) as DACommRate,
			po.Margin as BaseCommRate,
			1.0 as UpliftRate,
			0.0 as ICPaidToDate,	-- These payments are IT (this is an accruals concept)
			0.0 as StillToAccrue,	-- These payments are IT (this is an accruals concept)
			case when ASMFirm.Code is not null 
				then 'Y'
				else 'N'			-- If no firm then it can't go to OpenAccess
			end as SalesMoveFlag,	-- Propagate to OpenAccess
			--AG 01/04/2016 Start
--			round(po.Premium * ((@DACommRate * (po.Margin/@ASMCommRate))/100),2) as DA,
			round(po.Premium * ((((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate)) + @OWCommRate)/100)
							* (po.Margin / ((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate))),2) as DA,
			--AG 01/04/2016 End
			round(po.Premium * ((((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate)) + @OWCommRate)/100)
							* (po.Margin / ((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate))),2) as Turnover,
			round(po.Premium * ((((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate)) + @OWCommRate)/100)
							* (po.Margin / ((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate))),2) as APE,
			--AG 19/01/2017 Start
			--po.Fee as EnhancedNBI,
			--po.Fee as BaseNBI,
			--po.Fee as Margin,
			round(po.Premium * ((@ASMCommRate * (po.Margin/@ASMCommRate))/100),2) as EnhancedNBI,
			round(po.Premium * ((@ASMCommRate * (po.Margin/@ASMCommRate))/100),2) as BaseNBI,
			round(po.Premium * ((@ASMCommRate * (po.Margin/@ASMCommRate))/100),2) as Margin,
			--AG 19/01/2017 End
			0 as CaseCount,
			case when po.CommType in ('Double Indemnity','Dind','Dind2') then 24 else 12 end as InitialPeriod,
			case when po.CommType in ('Indemnity','Double Indemnity','Aind','Dind','Dind2') then 'T' else 'F' end as PayBasisCode,
			case when po.CommType in ('Indemnity','Double Indemnity','Aind','Dind','Dind2') then 'IT' else 'Accrual' end as PayBasis,
			100 as AgentSplit,
			case when po.CommType in ('Adjustment','Awaiting Start') or po.Status in ('AWAITING START','MTA') then 'Adj' else 'IC' end as FeeType,
			'Payment Shield Owl ASM' as Provider,
			'PYMTSHLD' as ProviderCode,
			dateadd(mm,1,po.Period) as [Month],
			'Payshield' as Source,
			pic.FileID as CreateDate,	
			po.CommType as OrigCommtype,
			po.Status as OrigStatus,
			0 as ELITE_Initial,			-- Owl don't get ELITE points
			null as ELITE_Category,		-- Owl don't get ELITE points
			ltrim(rtrim(po.OriginalSellerName)) as OrigSellerName,		--AG 01/04/2016
			po.ID as SourceID
	from	dbo.owt_PaymentshieldOwlOverride po
			inner join dbo.owt_PaymentshieldImportControl pic on pic.FileID = po.LoadedDateTime
			left join mstt_Agents adv on adv.Code = po.OWSellerRef and adv.AgentType <> 2 -- Not a firm
			left join mstt_Agents firm on firm.Code = coalesce(adv.Firm,po.OWSellerRef) 
			left join dbo.msit_MIWarehouseCodesAndDescriptions MICodes
					on  MICodes.ColumnName = 'PersonTitle' 
					and ltrim(rtrim(replace(po.SellerName,'.',''))) like MICodes.Code + ' %'
			left join sa_insight_UserDetails ud 
					on ud.USR_ExternalID =	case when adv.Code is null 
												--then (select top 1 Code from mstt_Agents where Firm = firm.Code)		  AG 24/11/2017
												then (select top 1 Code from mstt_AgentsHistory where Firm = firm.Code)	--AG 24/11/2017
												else adv.Code
											end
			--AG 24/11/2017 Start
			--left join sa_insight_UserPosition up on up.UPS_UserID = ud.USR_ID and up.UPS_DateTo is null and up.UPS_JobTitle = 53 -- OWL Practice Principal
			--left join	(	select	upended.UPS_UserID, max(upended.UPS_DateTo) as Max_UPS_DateTo
			--				from	sa_insight_UserPosition upended
			--				where	upended.UPS_JobTitle = 53 -- OWL Practice Principal
			--				group	by upended.UPS_UserID
			--			)	upended1 on upended1.UPS_UserID = ud.USR_ID  
			--left join sa_insight_UserPosition upended2 on upended2.UPS_UserID = ud.USR_ID and upended2.UPS_DateTo = upended1.Max_UPS_DateTo and upended2.UPS_JobTitle = 53 -- OWL Practice Principal
			---- Use active PP row but if none, then use most recently ended PP row
			--left join sa_insight_HierarchyNodeLink HNL1 on HNL1.HNL_NodeID = coalesce(up.UPS_OrganisationalUnitID,upended2.UPS_OrganisationalUnitID) and HNL1.HNL_DateTo is null and HNL1.HNL_Type = 0 
			--left join sa_insight_UserPosition up1 on up1.UPS_OrganisationalUnitID = HNL1.HNL_ParentID and up1.UPS_DateTo is null and up1.UPS_JobTitle = 54	-- OWL Area Sales Manager
			--left join sa_insight_UserDetails ud1 on ud1.USR_ID = up1.UPS_UserID
			--left join mstt_Agents ASM on ASM.Code = ud1.USR_ExternalID
			left join mi_insight_UserHierarchyAllUsers uhah
						on uhah.UserUID = ud.USR_ExternalID
						and po.StartDate between uhah.EffectiveStartDate and uhah.EffectiveEndDate
			left join mstt_Agents ASM on ASM.Code = uhah.OwlASMUID1
			--AG 24/11/2017 End
			left join mstt_Agents ASMFirm on ASMFirm.Code = ASM.Firm
	where	po.Margin <> 10	-- Exclude the Openwork margin record as this doesn't tell us if a comm sacrifice has taken place
	and		isnull(po.OWSellerRef,'') <> ''		--AG 19/01/2017

	set @RowCount = @@rowcount

	set @ProcessMessage = @ProcessMessage + '. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @Module, @Client

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	COMMIT TRANSACTION      

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE(), @ErrState = XACT_STATE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10))
	
	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION

	-- Error message line 1
	set @ErrMsgBrief = left(@ErrMsg,100)
	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	
	-- Error message line 2 - if any text exists
	set @ErrMsgBrief = substring(@ErrMsg,101,100)
	if len(@ErrMsgBrief) > 0
		exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @ErrSev , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/



GO
/****** Object:  StoredProcedure [dbo].[owp_PaymentshieldCommissionOwl_ONEOFF_FULL_LOAD]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/********************************************************************************

Name		:	owp_PaymentshieldCommissionOwl
Created By	:	A Groves
Created		:	28/10/2015

Description	:	At this point in the process, the Paymentshield Owl Override payments 
				have already been loaded to table "dbo.owt_PaymentshieldOwlOverride".
				This process propagates the Paymentshield Owl data 
				from table: "dbo.owt_PaymentshieldOwlOverride"
				to table:	"dbo.owt_PaymentshieldCommissionPayments"
				
				After this stored proc has completed, the existing stored proc
				"owp_PaymentshieldAdviserListingExtract" is executed to propagate
				the Owl Payments into OpenAccess i.e.
				from table:	"dbo.owt_PaymentshieldCommissionPayments"
				to table:	"dbo.msit_OpenworkAdviserListing" 

				For each case, there are two payments on table "owt_PaymentshieldOwlOverride".
				One payment always has a comm rate of 10% and is Openwork's margin. The 
				other payment maximums at 4% and is the ASM's override payment. Note that the
				rate will be less than 4% where the adviser has sacrificed commission to provide
				his/her client with a better deal.
				
				This proc ignores the 10% record as it does not tell us if any sacrifice
				has occurred. The other record is created twice on table
				"owt_PaymentshieldCommissionPayments" as follows:
				1) Adviser's payment (derived from the ASM's override payment)
				2) ASM's override payment 

				For record (2), the ASM is looked up for the adviser using Insight tables.
	
				Call this stored proc as follows:
				
					exec owp_PaymentshieldCommissionOwl 'Openwork', 'PaymentshieldOwl' 
				
Amendment History
-----------------
Date		  Author	  Description
----		  ------      -----------

***********************************************************************************/
CREATE procedure [dbo].[owp_PaymentshieldCommissionOwl_ONEOFF_FULL_LOAD]
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@Path						varchar(255),
		@DataFileName				varchar(255),
		@sql						varchar(8000),
		@RowCount					int,
		@FileID						datetime,
		@ErrMsg						nvarchar(4000),
		@ErrMsgBrief				nvarchar(100),
		@ErrNum						int,
		@ErrSev						int,
		@ErrLine					int,
		@ErrState					int

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @PhaseLog		= 'LOG'
set @PhaseError		= 'ERROR'
set @Process		= object_name(@@procid)

set @FileID			= getdate()	-- DEBUG!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!

/****************************************************************************

	Log start																
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION

	/******************************************************************************************

	Adviser's Payment

	*******************************************************************************************/

	set @ProcessMessage = 'Adviser''s Payments'
	exec msp_ProcessLog @PhaseStart, @ProcessMessage, null, @Module, @Client

	declare @DACommRate decimal(10,6)
	set @DACommRate = 39.0
	declare @BaseCommRate decimal(10,6)
	set @BaseCommRate = 25.0
	declare @ASMCommRate decimal(10,6)
	set @ASMCommRate = 4.0
	declare @OWCommRate decimal(10,6)
	set @OWCommRate = @DACommRate - @BaseCommRate - @ASMCommRate

	insert into dbo.owt_PaymentshieldCommissionPayments
	(
		BusinessCode,
		BusinessName,
		BusinessECode,
		BusinessRef,
		SellerCode,
		SellerName,
		SellerForename,
		SellerSurname,
		SellerRef,
		Client,
		ClientForename,
		ClientSurname,
		BACSDate,
		Policy,
		ProdType,
		HierarchyProduct,
		StartDate,
		PaymentDate,
		LatestAnniversary,
		Frequency,
		Premium,
		PaymentAmount,
		APEFlag,
		TotalFeeDue,
		CommRate,
		MarginCommRate,
		DACommRate,
		BaseCommRate,
		UpliftRate,
		ICPaidToDate,
		StillToAccrue,
		SalesMoveFlag,
		DA,
		Turnover,
		APE,
		EnhancedNBI,
		BaseNBI,
		Margin,
		CaseCount,
		InitialPeriod,
		PayBasisCode,
		PayBasis,
		AgentSplit,
		FeeType,
		Provider,
		ProviderCode,
		Month,
		Source,
		CreateDate,
		OrigCommtype,
		OrigStatus,
		ELITE_Initial,
		ELITE_Category,
		OrigSellerName,
		SourceID
	)
	select	firm.Code as BusinessCode,
			Rtrim(isnull(firm.TradingName,firm.DESCN)) as BusinessName,
			firm.OscarAgentPrefix + firm.OscarAgentSerial + firm.OscarAgentSuffix as BusinessECode,
			po.BranchNo as BusinessRef,
			case when adv.Code is null 
				then (select top 1 Code from mstt_Agents where Firm = firm.Code)
				else adv.Code
			end as SellerCode,
			case when MICodes.Code is null	-- No match on person title so title assumed not present
				then ltrim(rtrim(po.SellerName))
				else ltrim(rtrim(stuff(replace(po.SellerName,'.',''),1,len(MICodes.Code),''))) 
			end as SellerName,	
			case when adv.Code is null 
				then (select top 1 dbo.owf_FirstWord(Descn) from mstt_Agents where Firm = firm.Code)
				else dbo.owf_FirstWord(adv.Descn)
			end as SellerForename,		
			case when adv.Code is null 
				then (select top 1 dbo.owf_LastWord(Descn) from mstt_Agents where Firm = firm.Code)
				else dbo.owf_LastWord(adv.Descn)
			end as SellerSurname,
			null as SellerRef,			-- Stays NULL
			dbo.owf_CleanText(substring(Rtrim(po.ClientName),1,65)) as Client,
			case when charindex(' ', RTrim(po.ClientName)) = 0 
				then NULL
				else Rtrim(Substring(RTrim(po.ClientName), charindex(' ', RTrim(po.ClientName))+1,1))	-- First initial (after title)
			end as ClientForename,
			case when charindex(' ', RTrim(po.ClientName)) = 0 
				then NULL
				else Rtrim(Right(RTrim(po.ClientName),charindex(' ', Reverse(RTrim(po.ClientName)))-1))	-- Surname
			end as ClientSurname,
			null as BACSDate,
			po.PolicyReference as Policy,
			Left(po.Product,8) as ProdType,
			'PY_' + Left(po.Product,5) as HierarchyProduct,
			po.StartDate as StartDate,
			po.Period as PaymentDate,
			case 
				when po.StartDate >= po.Period then po.StartDate
				when po.StartDate < po.Period and Month(po.StartDate) < Month(po.Period) then 
					case when Day(po.StartDate) = 29 and Month(po.StartDate) = 2 then 
							convert(datetime,'28/02/' +  Cast(Year(po.Period) as varchar(4)),103)
						 else
							convert(datetime,Cast(Day(po.StartDate) as varchar(2)) + '/' +  Cast(Month(po.StartDate) as varchar(2)) + '/' +  Cast(Year(po.Period) as varchar(4)),103)
					end			
				else 
					case when Day(po.StartDate) = 29 and Month(po.StartDate) = 2 then
							convert(datetime,'28/02/' +  Cast(Year(po.Period)-1 as varchar(4)),103)
						 else
							convert(datetime,Cast(Day(po.StartDate) as varchar(2)) + '/' +  Cast(Month(po.StartDate) as varchar(2)) + '/' +  Cast(Year(po.Period)-1 as varchar(4)),103)
					end
			end as LatestAnniversary,
			case when left(po.TermOfContract,6) = 'ANNUAL'
				then 'A'
				else 'M'
			end as Frequency,
			case when left(po.TermOfContract,6) = 'ANNUAL' 
				then 1 
				else 12 
			end * abs(po.Premium) as Premium,
			round(po.Premium * ((@BaseCommRate*(po.Margin/@ASMCommRate))/100),2) as PaymentAmount,
			isnull((select APE_Flag from mstt_ProductHierarchy where ProductType = 'Payshield' and ProductCode = 'PY_' + Left(po.Product,5)),'N') as APEFlag,
			round(po.Premium * ((@BaseCommRate * (po.Margin/@ASMCommRate))/100),2) as TotalFeeDue,
			@BaseCommRate * (po.Margin/@ASMCommRate) as CommRate,
			(@DACommRate * (po.Margin/@ASMCommRate)) - (@BaseCommRate * (po.Margin/@ASMCommRate)) as MarginCommRate,
			@DACommRate * (po.Margin/@ASMCommRate) as DACommRate,
			@BaseCommRate * (po.Margin/@ASMCommRate) as BaseCommRate,
			1.0 as UpliftRate,
			0.0 as ICPaidToDate,	-- These payments are IT (this is an accruals concept)
			0.0 as StillToAccrue,	-- These payments are IT (this is an accruals concept)
			'Y' as SalesMoveFlag,	-- Propagate to OpenAccess
			round(po.Premium * ((@DACommRate * (po.Margin/@ASMCommRate))/100),2) as DA,
			round(po.Premium * ((((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate)) + @OWCommRate)/100)
					* ((@BaseCommRate * (po.Margin/@ASMCommRate)) / ((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate))),2) as Turnover,
			round(po.Premium * ((((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate)) + @OWCommRate)/100)
					* ((@BaseCommRate * (po.Margin/@ASMCommRate)) / ((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate))),2) as APE,
			round(po.Premium * ((@BaseCommRate * (po.Margin/@ASMCommRate))/100),2) as EnhancedNBI,
			round(po.Premium * ((@BaseCommRate * (po.Margin/@ASMCommRate))/100),2) as BaseNBI,
			round(po.Premium * ((@BaseCommRate * (po.Margin/@ASMCommRate))/100),2) as Margin,
			0 as CaseCount,
			case when po.CommType in ('Double Indemnity','Dind','Dind2') then 24 else 12 end as InitialPeriod,
			case when po.CommType in ('Indemnity','Double Indemnity','Aind','Dind','Dind2') then 'T' else 'F' end as PayBasisCode,
			case when po.CommType in ('Indemnity','Double Indemnity','Aind','Dind','Dind2') then 'IT' else 'Accrual' end as PayBasis,
			100 as AgentSplit,
			case when po.CommType in ('Adjustment','Awaiting Start') or po.Status in ('AWAITING START','MTA') then 'Adj' else 'IC' end as FeeType,
			'Payment Shield Owl' as Provider,
			'PYMTSHLD' as ProviderCode,
			dateadd(mm,1,po.Period) as [Month],
			'Payshield' as Source,
			/*pic.FileID*/ @FileID as CreateDate,	
			po.CommType as OrigCommtype,
			po.Status as OrigStatus,
			0 as ELITE_Initial,			-- Owl don't get ELITE points
			null as ELITE_Category,		-- Owl don't get ELITE points
			ltrim(rtrim(po.SellerName)) as OrigSellerName,
			po.ID as SourceID
	from	dbo.owt_PaymentshieldOwlOverride po
--			inner join dbo.owt_PaymentshieldImportControl pic on pic.FileID = po.LoadedDateTime
			left join mstt_Agents adv on adv.Code = po.OWSellerRef and adv.AgentType <> 2 -- Not a firm
			left join mstt_Agents firm on firm.Code = coalesce(adv.Firm,po.OWSellerRef) 
			left join dbo.msit_MIWarehouseCodesAndDescriptions MICodes
					on  MICodes.ColumnName = 'PersonTitle' 
					and ltrim(rtrim(replace(po.SellerName,'.',''))) like MICodes.Code + ' %'
	where	po.Margin <> 10	-- Exclude the Openwork margin record as this doesn't tell us if a comm sacrifice has taken place

	set @RowCount = @@rowcount

	set @ProcessMessage = @ProcessMessage + '. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @Module, @Client

	/******************************************************************************************

	ASM's Payment

	*******************************************************************************************/

	set @ProcessMessage = 'ASM''s Payments'
	exec msp_ProcessLog @PhaseStart, @ProcessMessage, null, @Module, @Client

	insert into dbo.owt_PaymentshieldCommissionPayments
	(
		BusinessCode,
		BusinessName,
		BusinessECode,
		BusinessRef,
		SellerCode,
		SellerName,
		SellerForename,
		SellerSurname,
		SellerRef,
		Client,
		ClientForename,
		ClientSurname,
		BACSDate,
		Policy,
		ProdType,
		HierarchyProduct,
		StartDate,
		PaymentDate,
		LatestAnniversary,
		Frequency,
		Premium,
		PaymentAmount,
		APEFlag,
		TotalFeeDue,
		CommRate,
		MarginCommRate,
		DACommRate,
		BaseCommRate,
		UpliftRate,
		ICPaidToDate,
		StillToAccrue,
		SalesMoveFlag,
		DA,
		Turnover,
		APE,
		EnhancedNBI,
		BaseNBI,
		Margin,
		CaseCount,
		InitialPeriod,
		PayBasisCode,
		PayBasis,
		AgentSplit,
		FeeType,
		Provider,
		ProviderCode,
		Month,
		Source,
		CreateDate,
		OrigCommtype,
		OrigStatus,
		ELITE_Initial,
		ELITE_Category,
		OrigSellerName,
		SourceID
	)
	select	ASMFirm.Code as BusinessCode,
			Rtrim(isnull(ASMFirm.TradingName,ASMFirm.DESCN)) as BusinessName,
			ASMFirm.OscarAgentPrefix + ASMFirm.OscarAgentSerial + ASMFirm.OscarAgentSuffix as BusinessECode,
			po.BranchNo as BusinessRef,
			case when adv.Code is null 
				then (select top 1 Code from mstt_Agents where Firm = firm.Code)
				else adv.Code
			end as SellerCode,
			case when MICodes.Code is null	-- No match on person title so title assumed not present
				then ltrim(rtrim(po.SellerName))
				else ltrim(rtrim(stuff(replace(po.SellerName,'.',''),1,len(MICodes.Code),''))) 
			end as SellerName,	
			case when adv.Code is null 
				then (select top 1 dbo.owf_FirstWord(Descn) from mstt_Agents where Firm = firm.Code)
				else dbo.owf_FirstWord(adv.Descn)
			end as SellerForename,		
			case when adv.Code is null 
				then (select top 1 dbo.owf_LastWord(Descn) from mstt_Agents where Firm = firm.Code)
				else dbo.owf_LastWord(adv.Descn)
			end as SellerSurname,
			null as SellerRef,			-- Stays NULL
			dbo.owf_CleanText(substring(Rtrim(po.ClientName),1,65)) as Client,
			case when charindex(' ', RTrim(po.ClientName)) = 0 
				then NULL
				else Rtrim(Substring(RTrim(po.ClientName), charindex(' ', RTrim(po.ClientName))+1,1))	-- First initial (after title)
			end as ClientForename,
			case when charindex(' ', RTrim(po.ClientName)) = 0 
				then NULL
				else Rtrim(Right(RTrim(po.ClientName),charindex(' ', Reverse(RTrim(po.ClientName)))-1))	-- Surname
			end as ClientSurname,
			null as BACSDate,
			po.PolicyReference as Policy,
			Left(po.Product,8) as ProdType,
			'PY_' + Left(po.Product,5) as HierarchyProduct,
			po.StartDate as StartDate,
			po.Period as PaymentDate,
			case 
				when po.StartDate >= po.Period then po.StartDate
				when po.StartDate < po.Period and Month(po.StartDate) < Month(po.Period) then 
					case when Day(po.StartDate) = 29 and Month(po.StartDate) = 2 then 
							convert(datetime,'28/02/' +  Cast(Year(po.Period) as varchar(4)),103)
						 else
							convert(datetime,Cast(Day(po.StartDate) as varchar(2)) + '/' +  Cast(Month(po.StartDate) as varchar(2)) + '/' +  Cast(Year(po.Period) as varchar(4)),103)
					end			
				else 
					case when Day(po.StartDate) = 29 and Month(po.StartDate) = 2 then
							convert(datetime,'28/02/' +  Cast(Year(po.Period)-1 as varchar(4)),103)
						 else
							convert(datetime,Cast(Day(po.StartDate) as varchar(2)) + '/' +  Cast(Month(po.StartDate) as varchar(2)) + '/' +  Cast(Year(po.Period)-1 as varchar(4)),103)
					end
			end as LatestAnniversary,
			case when left(po.TermOfContract,6) = 'ANNUAL'
				then 'A'
				else 'M'
			end as Frequency,
			case when left(po.TermOfContract,6) = 'ANNUAL' 
				then 1 
				else 12 
			end * abs(po.Premium) as Premium,
			po.Fee as PaymentAmount,
			isnull((select APE_Flag from mstt_ProductHierarchy where ProductType = 'Payshield' and ProductCode = 'PY_' + Left(po.Product,5)),'N') as APEFlag,
			po.Fee as TotalFeeDue,
			po.Margin as CommRate,
			@DACommRate * (po.Margin/@ASMCommRate) - po.Margin as MarginCommRate,
			@DACommRate * (po.Margin/@ASMCommRate) as DACommRate,
			po.Margin as BaseCommRate,
			1.0 as UpliftRate,
			0.0 as ICPaidToDate,	-- These payments are IT (this is an accruals concept)
			0.0 as StillToAccrue,	-- These payments are IT (this is an accruals concept)
			case when ASMFirm.Code is not null 
				then 'Y'
				else 'N'			-- If no firm then it can't go to OpenAccess
			end as SalesMoveFlag,	-- Propagate to OpenAccess
			round(po.Premium * ((@DACommRate * (po.Margin/@ASMCommRate))/100),2) as DA,
			round(po.Premium * ((((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate)) + @OWCommRate)/100)
							* (po.Margin / ((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate))),2) as Turnover,
			round(po.Premium * ((((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate)) + @OWCommRate)/100)
							* (po.Margin / ((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate))),2) as APE,
			po.Fee as EnhancedNBI,
			po.Fee as BaseNBI,
			po.Fee as Margin,
			0 as CaseCount,
			case when po.CommType in ('Double Indemnity','Dind','Dind2') then 24 else 12 end as InitialPeriod,
			case when po.CommType in ('Indemnity','Double Indemnity','Aind','Dind','Dind2') then 'T' else 'F' end as PayBasisCode,
			case when po.CommType in ('Indemnity','Double Indemnity','Aind','Dind','Dind2') then 'IT' else 'Accrual' end as PayBasis,
			100 as AgentSplit,
			case when po.CommType in ('Adjustment','Awaiting Start') or po.Status in ('AWAITING START','MTA') then 'Adj' else 'IC' end as FeeType,
			'Payment Shield Owl ASM' as Provider,
			'PYMTSHLD' as ProviderCode,
			dateadd(mm,1,po.Period) as [Month],
			'Payshield' as Source,
			/*pic.FileID*/ @FileID as CreateDate,	
			po.CommType as OrigCommtype,
			po.Status as OrigStatus,
			0 as ELITE_Initial,			-- Owl don't get ELITE points
			null as ELITE_Category,		-- Owl don't get ELITE points
			ltrim(rtrim(po.SellerName)) as OrigSellerName,
			po.ID as SourceID
	from	dbo.owt_PaymentshieldOwlOverride po
--			inner join dbo.owt_PaymentshieldImportControl pic on pic.FileID = po.LoadedDateTime
			left join mstt_Agents adv on adv.Code = po.OWSellerRef and adv.AgentType <> 2 -- Not a firm
			left join mstt_Agents firm on firm.Code = coalesce(adv.Firm,po.OWSellerRef) 
			left join dbo.msit_MIWarehouseCodesAndDescriptions MICodes
					on  MICodes.ColumnName = 'PersonTitle' 
					and ltrim(rtrim(replace(po.SellerName,'.',''))) like MICodes.Code + ' %'
			left join sa_insight_UserDetails ud 
					on ud.USR_ExternalID =	case when adv.Code is null 
												then (select top 1 Code from mstt_Agents where Firm = firm.Code)
												else adv.Code
											end
			left join sa_insight_UserPosition up on up.UPS_UserID = ud.USR_ID and up.UPS_DateTo is null and up.UPS_JobTitle = 53 -- OWL Practice Principal
			left join	(	select	upended.UPS_UserID, max(upended.UPS_DateTo) as Max_UPS_DateTo
							from	sa_insight_UserPosition upended
							where	upended.UPS_JobTitle = 53 -- OWL Practice Principal
							group	by upended.UPS_UserID
						)	upended1 on upended1.UPS_UserID = ud.USR_ID  
			left join sa_insight_UserPosition upended2 on upended2.UPS_UserID = ud.USR_ID and upended2.UPS_DateTo = upended1.Max_UPS_DateTo and upended2.UPS_JobTitle = 53 -- OWL Practice Principal
			-- Use active PP row but if none, then use most recently ended PP row
			left join sa_insight_HierarchyNodeLink HNL1 on HNL1.HNL_NodeID = coalesce(up.UPS_OrganisationalUnitID,upended2.UPS_OrganisationalUnitID) and HNL1.HNL_DateTo is null and HNL1.HNL_Type = 0 
			left join sa_insight_UserPosition up1 on up1.UPS_OrganisationalUnitID = HNL1.HNL_ParentID and up1.UPS_DateTo is null and up1.UPS_JobTitle = 54	-- OWL Area Sales Manager
			left join sa_insight_UserDetails ud1 on ud1.USR_ID = up1.UPS_UserID
			left join mstt_Agents ASM on ASM.Code = ud1.USR_ExternalID
			left join mstt_Agents ASMFirm on ASMFirm.Code = ASM.Firm
	where	po.Margin <> 10	-- Exclude the Openwork margin record as this doesn't tell us if a comm sacrifice has taken place

	set @RowCount = @@rowcount

	set @ProcessMessage = @ProcessMessage + '. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @Module, @Client

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	COMMIT TRANSACTION      

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE(), @ErrState = XACT_STATE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10))
	
	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION

	-- Error message line 1
	set @ErrMsgBrief = left(@ErrMsg,100)
	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	
	-- Error message line 2 - if any text exists
	set @ErrMsgBrief = substring(@ErrMsg,101,100)
	if len(@ErrMsgBrief) > 0
		exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @ErrSev , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/



GO
/****** Object:  StoredProcedure [dbo].[owp_PaymentshieldCommissionOwl_RV]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

/********************************************************************************

Name		:	owp_PaymentshieldCommissionOwl_RV
Created By	:	A Groves
Created		:	28/10/2015

Description	:	At this point in the process, the Paymentshield Owl Override payments 
				have already been loaded to table "dbo.owt_PaymentshieldOwlOverride".
				This process propagates the Paymentshield Owl data 
				from table: "dbo.owt_PaymentshieldOwlOverride"
				to table:	"dbo.owt_PaymentshieldCommissionPayments"
				
				After this stored proc has completed, the existing stored proc
				"owp_PaymentshieldAdviserListingExtract" is executed to propagate
				the Owl Payments into OpenAccess i.e.
				from table:	"dbo.owt_PaymentshieldCommissionPayments"
				to table:	"dbo.msit_OpenworkAdviserListing" 

				For each case, there are two payments on table "owt_PaymentshieldOwlOverride".
				One payment always has a comm rate of 10% and is Openwork's margin. The 
				other payment maximums at 4% and is the ASM's override payment. Note that the
				rate will be less than 4% where the adviser has sacrificed commission to provide
				his/her client with a better deal.
				
				This proc ignores the 10% record as it does not tell us if any sacrifice
				has occurred. The other record is created twice on table
				"owt_PaymentshieldCommissionPayments" as follows:
				1) Adviser's payment (derived from the ASM's override payment)
				2) ASM's override payment 

				For record (2), the ASM is looked up for the adviser using Insight tables.
	
				Call this stored proc as follows:
				
					exec owp_PaymentshieldCommissionOwl 'Openwork', 'PaymentshieldOwl' 
				
Amendment History
-----------------
Date		Author		Description
----		------		-----------
01/04/2016	A Groves	SR426998. Two fixes:
						1) The DA calculation was incorrect. In agreement with Marcus
							Cossey and Sarah Inglis it was made the same as the APE.
							Note that previously the DA was not apportioned between
							the adviser and the ASM - so over summing occurred.
						2) The Seller Name was propagated to the Original Seller Name	
							on the owt_PaymentshieldCommissionPayments table. This
							was corrected to be the Original Seller Name that was 
							propagated.
19/01/2017	A Groves	SR463747: Changes needed for the new SFTP'd file:- 
						1) The Fee field on table dbo.owt_PaymentshieldOwlOverride
							can be zero on a small number of records. This was causing
							the following to be zero on the ASM record:
							a) PaymentAmount
							b) TotalFeeDue
							c) EnhancedNBI
							d) BaseNBI
							e) Margin
							The fix was to calculate the above values from the premium
							as was already done on the adviser's payment row.
						2) SellerName populated in the same way that SellerForename 
							and SellerSurname are populated. Previously, it was possible
							for the SellerName to be blank with the other two populated
							if the seller's name was not in the data file.
						3) Where an adviser cannot be uniquely identified, then don't
							propagate the payment from table dbo.owt_PaymentshieldOwlOverride
							to table dbo.owt_PaymentshieldCommissionPayments. An example
							of where this occurs is when business for Muhammad Saleem comes
							through without the OWSellerRef, as there are two:
							BUID	UID		Name			Address
							----	---		----			-------
							2002328	4005118	Muhammad Saleem 6 Clements Close, Slough
							2007364	4009549	Muhammad Saleem	33 Mountfield Road,	East Ham, London
24/11/2017	A Groves	SR495162/CH19688. Previously the ASM look-up was failing where the 
							adviser had left. The old code has been replaced with a look-up 
							on table mi_insight_UserHierarchyAllUsers. Also where an
							adviser has been re-linked to a new business, the look-up
							on mstt_Agents was failing to find the adviser's old firm.
							Thus mstt_Agents has been changed to mstt_AgentsHistory.
09/02/2018	A Groves	SR499911/CH20436. Two improvements on the ASM records:
							1) Use the latest record on the mstt_AgentsHistory table
								as older records may have been set up incorrectly and
								subsequently corrected as was the case with "Bijo Kurian"
								whose name was in his UID field on his older records.
							2) Where a seller is also a top-line ASM (i.e. they don't
								themselves have an ASM) then payments for these sellers
								must not generate ASM records (because they don't have 
								an ASM). These unwanted records have been stopped by
								changing three left joins to inner joins on the ASMs.
29/10/2018	A Groves	1) Michal Iwinski's name rather than code exists in column OWSellerRef.
							So the code has been amended to look for this possibility.
						2) Mr Brian Dunajski changed name to Brian Meiklejohn so name
							matching changed from mstt_Agents to mstt_AgentsHistory.
13/03/2024	M Fasanya	Replaced mstt_Agents & mstt_AgentsHistory tables with S_AGENTS and fields 
						as part of Tech Debt modification.
***********************************************************************************/
CREATE procedure [dbo].[owp_PaymentshieldCommissionOwl_RV]
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@Path						varchar(255),
		@DataFileName				varchar(255),
		@sql						varchar(8000),
		@RowCount					int,
		@ErrMsg						nvarchar(4000),
		@ErrMsgBrief				nvarchar(100),
		@ErrNum						int,
		@ErrSev						int,
		@ErrLine					int,
		@ErrState					int,
		@OwlManager2Code			nvarchar(10),	-- AG 29/10/2018
		@OscarAgentID				varchar(255),	-- MF 14/03/2024:Tech Debt Source column (Not in S_AGENTS, but in mstt_AgentsHistory)
		@OscarDateStarted			varchar(255),	-- MF 14/03/2024:Tech Debt Source column (Not in S_AGENTS, but in mstt_AgentsHistory)
		@OscarAgentPrefix			int,			-- MF 14/03/2024:Tech Debt Source column (Not in S_AGENTS, but in mstt_AgentsHistory)		
		@OscarAgentSerial			int,			-- MF 14/03/2024:Tech Debt Source column
		@OscarAgentSuffix			int,				-- MF 14/03/2024:Tech Debt Source column
		@DefaultValidFromDate       Varchar(255),				--- MF 14/03/2024: Added to resolve Tech Debt
		@DefaultValidToDate         varchar(255)				--- MF 14/03/2024: Added to resolve Tech Debt

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart			= 'START'
set @PhaseEnd   		= 'END'
set @PhaseLog			= 'LOG'
set @PhaseError			= 'ERROR'
set @Process			= object_name(@@procid)
set @OwlManager2Code	= (select cde.Code from msit_MIWarehouseCodesAndDescriptions cde	-- AG 29/10/2018
								where cde.ColumnName = 'Manager2Code' and cde.Description = 'Owl Financial')
set @OscarDateStarted = ''
set @OscarAgentID     = ''
set	@OscarAgentPrefix = 0
set	@OscarAgentSerial = 0
set	@OscarAgentSuffix = 0
set @DefaultValidFromDate       = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'ValidFromDate')  --- MF 14/03/2024: Added to resolve Tech Debt
set @DefaultValidToDate         = (select DefaultValue from mstt_DefaultCodeValues where CodeColumn = 'ValidToDate')	--- MF 14/03/2024: Added to resolve Tech Debt


/****************************************************************************

	Log start																
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION

	/******************************************************************************************

	Adviser's Payment

	*******************************************************************************************/

	set @ProcessMessage = 'Adviser''s Payments'
	exec msp_ProcessLog @PhaseStart, @ProcessMessage, null, @Module, @Client

	declare @DACommRate decimal(10,6)
	set @DACommRate = 39.0
	declare @BaseCommRate decimal(10,6)
	set @BaseCommRate = 25.0
	declare @ASMCommRate decimal(10,6)
	set @ASMCommRate = 4.0
	declare @OWCommRate decimal(10,6)
	set @OWCommRate = @DACommRate - @BaseCommRate - @ASMCommRate

	insert into dbo.owt_PaymentshieldCommissionPayments
	(
		BusinessCode,
		BusinessName,
		BusinessECode,
		BusinessRef,
		SellerCode,
		SellerName,
		SellerForename,
		SellerSurname,
		SellerRef,
		Client,
		ClientForename,
		ClientSurname,
		BACSDate,
		Policy,
		ProdType,
		HierarchyProduct,
		StartDate,
		PaymentDate,
		LatestAnniversary,
		Frequency,
		Premium,
		PaymentAmount,
		APEFlag,
		TotalFeeDue,
		CommRate,
		MarginCommRate,
		DACommRate,
		BaseCommRate,
		UpliftRate,
		ICPaidToDate,
		StillToAccrue,
		SalesMoveFlag,
		DA,
		Turnover,
		APE,
		EnhancedNBI,
		BaseNBI,
		Margin,
		CaseCount,
		InitialPeriod,
		PayBasisCode,
		PayBasis,
		AgentSplit,
		FeeType,
		Provider,
		ProviderCode,
		Month,
		Source,
		CreateDate,
		OrigCommtype,
		OrigStatus,
		ELITE_Initial,
		ELITE_Category,
		OrigSellerName,
		SourceID
	)
	select	firm.Code as BusinessCode,
			Rtrim(isnull(firm.TradingName,firm.DESCN)) as BusinessName,
			---ASMFirm.OscarAgentPrefix + ASMFirm.OscarAgentSerial + ASMFirm.OscarAgentSuffix as BusinessECode,
			@OscarAgentPrefix + @OscarAgentSerial + @OscarAgentSuffix as BusinessECode,   -- MF 14/03/2024:Tech Debt Source column (Not in S_AGENTS, but in mstt_AgentsHistory)
			po.BranchNo as BusinessRef,
			--AG 19/01/2017 Start
			case 
				when adv.Code is not null then adv.Code
				---else (select top 1 Code from mstt_Agents where Firm = firm.Code)			
				else (select top 1 Code from sa_swift_S_Agents where Firm = firm.Code)								--- MF 13/03/2024 replaced mstt_Agents as Tech Debt source
			end as SellerCode,
			case 
				when adv.Code is not null then adv.Descn
				--when adv.Code is null and firm.Code is not null then (select top 1 Descn from mstt_Agents where Firm = firm.Code)
				when adv.Code is null and firm.Code is not null then (select top 1 Descn from sa_swift_S_Agents where Firm = firm.Code)		--- MF 13/03/2024 replaced mstt_Agents as Tech Debt source
				when MICodes.Code is null then ltrim(rtrim(po.SellerName))	-- No match on person title so title assumed not present
				else ltrim(rtrim(stuff(replace(po.SellerName,'.',''),1,len(MICodes.Code),''))) 
			end as SellerName,	
			case 
				when adv.Code is not null 
				then dbo.owf_FirstWord(adv.Descn)
				---else (select top 1 dbo.owf_FirstWord(Descn) from mstt_Agents where Firm = firm.Code)
				else (select top 1 dbo.owf_FirstWord(Descn) from sa_swift_S_Agents where Firm = firm.Code)		--- MF 13/03/2024 replaced mstt_Agents as Tech Debt source
			end as SellerForename,		
			case when adv.Code is not null 
				then dbo.owf_LastWord(adv.Descn)
				---else (select top 1 dbo.owf_LastWord(Descn) from mstt_Agents where Firm = firm.Code)
				else (select top 1 dbo.owf_LastWord(Descn) from sa_swift_S_Agents where Firm = firm.Code)		--- MF 13/03/2024 replaced mstt_Agents as Tech Debt source
			end as SellerSurname,
			--AG 19/01/2017 End
			null as SellerRef,			-- Stays NULL
			dbo.owf_CleanText(substring(Rtrim(po.ClientName),1,65)) as Client,
			case when charindex(' ', RTrim(po.ClientName)) = 0 
				then NULL
				else Rtrim(Substring(RTrim(po.ClientName), charindex(' ', RTrim(po.ClientName))+1,1))	-- First initial (after title)
			end as ClientForename,
			case when charindex(' ', RTrim(po.ClientName)) = 0 
				then NULL
				else Rtrim(Right(RTrim(po.ClientName),charindex(' ', Reverse(RTrim(po.ClientName)))-1))	-- Surname
			end as ClientSurname,
			null as BACSDate,
			po.PolicyReference as Policy,
			Left(po.Product,8) as ProdType,
			'PY_' + Left(po.Product,5) as HierarchyProduct,
			po.StartDate as StartDate,
			po.Period as PaymentDate,
			case 
				when po.StartDate >= po.Period then po.StartDate
				when po.StartDate < po.Period and Month(po.StartDate) < Month(po.Period) then 
					case when Day(po.StartDate) = 29 and Month(po.StartDate) = 2 then 
							convert(datetime,'28/02/' +  Cast(Year(po.Period) as varchar(4)),103)
						 else
							convert(datetime,Cast(Day(po.StartDate) as varchar(2)) + '/' +  Cast(Month(po.StartDate) as varchar(2)) + '/' +  Cast(Year(po.Period) as varchar(4)),103)
					end			
				else 
					case when Day(po.StartDate) = 29 and Month(po.StartDate) = 2 then
							convert(datetime,'28/02/' +  Cast(Year(po.Period)-1 as varchar(4)),103)
						 else
							convert(datetime,Cast(Day(po.StartDate) as varchar(2)) + '/' +  Cast(Month(po.StartDate) as varchar(2)) + '/' +  Cast(Year(po.Period)-1 as varchar(4)),103)
					end
			end as LatestAnniversary,
			case when left(po.TermOfContract,6) = 'ANNUAL'
				then 'A'
				else 'M'
			end as Frequency,
			case when left(po.TermOfContract,6) = 'ANNUAL' 
				then 1 
				else 12 
			end * abs(po.Premium) as Premium,
			round(po.Premium * ((@BaseCommRate*(po.Margin/@ASMCommRate))/100),2) as PaymentAmount,
			isnull((select APE_Flag from mstt_ProductHierarchy where ProductType = 'Payshield' and ProductCode = 'PY_' + Left(po.Product,5)),'N') as APEFlag,
			round(po.Premium * ((@BaseCommRate * (po.Margin/@ASMCommRate))/100),2) as TotalFeeDue,
			@BaseCommRate * (po.Margin/@ASMCommRate) as CommRate,
			(@DACommRate * (po.Margin/@ASMCommRate)) - (@BaseCommRate * (po.Margin/@ASMCommRate)) as MarginCommRate,
			@DACommRate * (po.Margin/@ASMCommRate) as DACommRate,
			@BaseCommRate * (po.Margin/@ASMCommRate) as BaseCommRate,
			1.0 as UpliftRate,
			0.0 as ICPaidToDate,	-- These payments are IT (this is an accruals concept)
			0.0 as StillToAccrue,	-- These payments are IT (this is an accruals concept)
			'Y' as SalesMoveFlag,	-- Propagate to OpenAccess
			--AG 01/04/2016 Start
--			round(po.Premium * ((@DACommRate * (po.Margin/@ASMCommRate))/100),2) as DA,
			round(po.Premium * ((((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate)) + @OWCommRate)/100)
					* ((@BaseCommRate * (po.Margin/@ASMCommRate)) / ((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate))),2) as DA,
			--AG 01/04/2016 End
			round(po.Premium * ((((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate)) + @OWCommRate)/100)
					* ((@BaseCommRate * (po.Margin/@ASMCommRate)) / ((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate))),2) as Turnover,
			round(po.Premium * ((((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate)) + @OWCommRate)/100)
					* ((@BaseCommRate * (po.Margin/@ASMCommRate)) / ((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate))),2) as APE,
			round(po.Premium * ((@BaseCommRate * (po.Margin/@ASMCommRate))/100),2) as EnhancedNBI,
			round(po.Premium * ((@BaseCommRate * (po.Margin/@ASMCommRate))/100),2) as BaseNBI,
			round(po.Premium * ((@BaseCommRate * (po.Margin/@ASMCommRate))/100),2) as Margin,
			0 as CaseCount,
			case when po.CommType in ('Double Indemnity','Dind','Dind2') then 24 else 12 end as InitialPeriod,
			case when po.CommType in ('Indemnity','Double Indemnity','Aind','Dind','Dind2') then 'T' else 'F' end as PayBasisCode,
			case when po.CommType in ('Indemnity','Double Indemnity','Aind','Dind','Dind2') then 'IT' else 'Accrual' end as PayBasis,
			100 as AgentSplit,
			case when po.CommType in ('Adjustment','Awaiting Start') or po.Status in ('AWAITING START','MTA') then 'Adj' else 'IC' end as FeeType,
			'Payment Shield Owl' as Provider,
			'PYMTSHLD' as ProviderCode,
			dateadd(mm,1,po.Period) as [Month],
			'Payshield' as Source,
			pic.FileID as CreateDate,	
			po.CommType as OrigCommtype,
			po.Status as OrigStatus,
			0 as ELITE_Initial,			-- Owl don't get ELITE points
			null as ELITE_Category,		-- Owl don't get ELITE points
			ltrim(rtrim(po.OriginalSellerName)) as OrigSellerName,		--AG 01/04/2016
			po.ID as SourceID
	from	dbo.owt_PaymentshieldOwlOverride po
			inner join dbo.owt_PaymentshieldImportControl pic on pic.FileID = po.LoadedDateTime
			--AG 29/10/2018 Start
			--left join (select Descn, MAX(IDHISTid_type) as MaxIDHISTid_type from mstt_AgentsHistory where Manager2Code = @OwlManager2Code and AgentType <> 2 group by Descn) agName on agName.Descn = po.SellerName
			left join (select Descn, MAX(ID) as MaxID from sa_swift_S_AGENTS where Manager2Code = @OwlManager2Code and Agt_Type <> 2 group by Descn) agName on agName.Descn = po.SellerName      --- MF 13/03/2024 replaced mstt_Agents as Tech Debt source
			--left join mstt_AgentsHistory ah on ah.IDHISTid_type = agName.MaxIDHISTid_type
			left join sa_swift_S_Agents ah on ah.ID = agName.MaxID						--- MF 13/03/2024 replaced mstt_Agents as Tech Debt source
			--left join mstt_Agents adv on adv.Code = po.OWSellerRef and adv.AgentType <> 2 -- Not a firm
			--left join mstt_Agents adv
			left join sa_swift_S_Agents adv												--- MF 13/03/2024 replaced mstt_Agents as Tech Debt source
					on (adv.Code = po.OWSellerRef or adv.Code = ah.Code) 
					--and adv.AgentType <> 2 -- Not a firm
					and adv.Agt_Type <> 2 -- Not a firm
			--left join mstt_Agents firm on firm.Code = coalesce(adv.Firm,po.OWSellerRef) 
			--left join mstt_Agents firm on firm.Code = adv.Firm					
			left join sa_swift_S_Agents firm on firm.Code = adv.Firm					--- MF 13/03/2024 replaced mstt_Agents as Tech Debt source
			--AG 29/10/2018 End
			left join dbo.msit_MIWarehouseCodesAndDescriptions MICodes
					on  MICodes.ColumnName = 'PersonTitle' 
					and ltrim(rtrim(replace(po.SellerName,'.',''))) like MICodes.Code + ' %'
	where	po.Margin <> 10	-- Exclude the Openwork margin record as this doesn't tell us if a comm sacrifice has taken place
	and		isnull(po.OWSellerRef,'') <> ''		--AG 19/01/2017
	set @RowCount = @@rowcount

	set @ProcessMessage = @ProcessMessage + '. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @Module, @Client

/******************************************************************************************

	Adviser's Payment - OSCAR Update (Reverse Engineered from mstp_AgentsHistory PROC)

*******************************************************************************************/

	 --CR 26 Oscar Agent Data:
    --OscarAgentId, OscarDateStarted, OscarAgentPrefix, OscarAgentSerial, OscarAgentSuffix
    -- PR Oct 2007 use new Oscar Ecode table
  --   update 
  --    #msit_AgentsHistory
  --   set 
  --    OscarAgentId     = O.OscarAgentId,
  --    OscarDateStarted = convert(datetime,O.OscarDateStarted),
  --    OscarAgentPrefix = O.OscarAgentPrefix,
  --    OscarAgentSerial = O.OscarAgentSerial,
  --    OscarAgentSuffix = O.OscarAgentSuffix
  --   from 
  --    msit_OscarSwiftAgents O,
  --    #msit_AgentsHistory A
  --   where
  --    O.SwiftAgentId = A.Code

  ----update #msit_AgentsHistory															-- MF 14/03/2024 (Tech Debt replacement)
  update dbo.owt_PaymentshieldCommissionPayments
      set @OscarDateStarted = x.StartDate,
		  @OscarAgentID   = x.OSCAR_ID,
          @OscarAgentPrefix = x.OSCAR_Prefix,
          @OscarAgentSerial = x.OSCAR_Serial,
          @OscarAgentSuffix = x.OSCAR_Suffix
  ---from  #msit_AgentsHistory ah
  from dbo.owt_PaymentshieldCommissionPayments ah	-- MF 14/03/2024 (Tech Debt replacement)
      inner join Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref x on ah.SellerCode = x.AgentCode		-- MF 14/03/2024 (Tech Debt replacement of Code with Sellercode)
	  left join sa_swift_S_AGENTS a on x.AgentCode = a.code											---  MF 14/03/2024 added to link OSCAR (missing in S_AGENTS) record to paymentshield		
			and a.ID = (select min(ag.id) from sa_swift_S_AGENTS ag -- min(id) matches MIDB001
			where ag.Code = ah.SellerCode 
			and ag.LastModifiedDate between ah.StartDate and isnull(@DefaultValidToDate,ah.PaymentDate))  
  where x.NoEcode is Null 
  and   x.AgentLevel = 'B' 
  and   x.id = (select min(xref.id) from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref xref -- min(id) matches MIDB001
          where xref.AgentLevel = 'B'
          and xref.AgentCode = ah.SellerCode												-- MF 14/03/2024 (Tech Debt replacement of Code with Sellercode)
		  ---and ah.ValidFromDate between xref.StartDate and isnull(xref.EndDate,@DefaultValidToDate)) -- AG 26/06/2009
          and ah.StartDate between xref.StartDate and isnull(xref.EndDate,@DefaultValidToDate)) -- MF 14/03/2024 (Tech Debt replacement of ValidFromDate column with StartDate)
