	/******************************************************************************************

	ASM's Payment

	*******************************************************************************************/

	set @ProcessMessage = 'ASM''s Payments'
	exec msp_ProcessLog @PhaseStart, @ProcessMessage, null, @Module, @Client

	insert into dbo.owt_PaymentshieldCommissionPayments
	(
		BusinessCode,
		BusinessName,
		BusinessECode,
		BusinessRef,
		SellerCode,
		SellerName,
		SellerForename,
		SellerSurname,
		SellerRef,
		Client,
		ClientForename,
		ClientSurname,
		BACSDate,
		Policy,
		ProdType,
		HierarchyProduct,
		StartDate,
		PaymentDate,
		LatestAnniversary,
		Frequency,
		Premium,
		PaymentAmount,
		APEFlag,
		TotalFeeDue,
		CommRate,
		MarginCommRate,
		DACommRate,
		BaseCommRate,
		UpliftRate,
		ICPaidToDate,
		StillToAccrue,
		SalesMoveFlag,
		DA,
		Turnover,
		APE,
		EnhancedNBI,
		BaseNBI,
		Margin,
		CaseCount,
		InitialPeriod,
		PayBasisCode,
		PayBasis,
		AgentSplit,
		FeeType,
		Provider,
		ProviderCode,
		Month,
		Source,
		CreateDate,
		OrigCommtype,
		OrigStatus,
		ELITE_Initial,
		ELITE_Category,
		OrigSellerName,
		SourceID
	)
	select	ASMFirm.Code as BusinessCode,
			Rtrim(isnull(ASMFirm.TradingName,ASMFirm.DESCN)) as BusinessName,
			---ASMFirm.OscarAgentPrefix + ASMFirm.OscarAgentSerial + ASMFirm.OscarAgentSuffix as BusinessECode,
			@OscarAgentPrefix + @OscarAgentSerial + @OscarAgentSuffix as BusinessECode,   -- MF 14/03/2024:Tech Debt Source column (Not in S_AGENTS, but in mstt_AgentsHistory)
			po.BranchNo as BusinessRef,
			--AG 19/01/2017 Start
			case 
				when adv.Code is not null then adv.Code
				--else (select top 1 Code from mstt_Agents where Firm = firm.Code)
				else (select top 1 Code from sa_swift_S_Agents where Firm = firm.Code)						--- MF 13/03/2024 replaced mstt_Agents as Tech Debt source
			end as SellerCode,
			case 
				when adv.Code is not null then adv.Descn
				---when adv.Code is null and firm.Code is not null then (select top 1 Descn from mstt_Agents where Firm = firm.Code)
				when adv.Code is null and firm.Code is not null then (select top 1 Descn from sa_swift_S_Agents where Firm = firm.Code)		--- MF 13/03/2024 replaced mstt_Agents as Tech Debt source
				when MICodes.Code is null then ltrim(rtrim(po.SellerName))	-- No match on person title so title assumed not present
				else ltrim(rtrim(stuff(replace(po.SellerName,'.',''),1,len(MICodes.Code),''))) 
			end as SellerName,	
			case 
				when adv.Code is not null 
				then dbo.owf_FirstWord(adv.Descn)
				--else (select top 1 dbo.owf_FirstWord(Descn) from mstt_Agents where Firm = firm.Code)
				else (select top 1 dbo.owf_FirstWord(Descn) from sa_swift_S_Agents where Firm = firm.Code)		--- MF 13/03/2024 replaced mstt_Agents as Tech Debt source
			end as SellerForename,		
			case when adv.Code is not null 
				then dbo.owf_LastWord(adv.Descn)
				--else (select top 1 dbo.owf_LastWord(Descn) from mstt_Agents where Firm = firm.Code)
				else (select top 1 dbo.owf_LastWord(Descn) from sa_swift_S_Agents where Firm = firm.Code)			--- MF 13/03/2024 replaced mstt_Agents as Tech Debt source
			end as SellerSurname,
			--AG 19/01/2017 End
			null as SellerRef,			-- Stays NULL
			dbo.owf_CleanText(substring(Rtrim(po.ClientName),1,65)) as Client,
			case when charindex(' ', RTrim(po.ClientName)) = 0 
				then NULL
				else Rtrim(Substring(RTrim(po.ClientName), charindex(' ', RTrim(po.ClientName))+1,1))	-- First initial (after title)
			end as ClientForename,
			case when charindex(' ', RTrim(po.ClientName)) = 0 
				then NULL
				else Rtrim(Right(RTrim(po.ClientName),charindex(' ', Reverse(RTrim(po.ClientName)))-1))	-- Surname
			end as ClientSurname,
			null as BACSDate,
			po.PolicyReference as Policy,
			Left(po.Product,8) as ProdType,
			'PY_' + Left(po.Product,5) as HierarchyProduct,
			po.StartDate as StartDate,
			po.Period as PaymentDate,
			case 
				when po.StartDate >= po.Period then po.StartDate
				when po.StartDate < po.Period and Month(po.StartDate) < Month(po.Period) then 
					case when Day(po.StartDate) = 29 and Month(po.StartDate) = 2 then 
							convert(datetime,'28/02/' +  Cast(Year(po.Period) as varchar(4)),103)
						 else
							convert(datetime,Cast(Day(po.StartDate) as varchar(2)) + '/' +  Cast(Month(po.StartDate) as varchar(2)) + '/' +  Cast(Year(po.Period) as varchar(4)),103)
					end			
				else 
					case when Day(po.StartDate) = 29 and Month(po.StartDate) = 2 then
							convert(datetime,'28/02/' +  Cast(Year(po.Period)-1 as varchar(4)),103)
						 else
							convert(datetime,Cast(Day(po.StartDate) as varchar(2)) + '/' +  Cast(Month(po.StartDate) as varchar(2)) + '/' +  Cast(Year(po.Period)-1 as varchar(4)),103)
					end
			end as LatestAnniversary,
			case when left(po.TermOfContract,6) = 'ANNUAL'
				then 'A'
				else 'M'
			end as Frequency,
			case when left(po.TermOfContract,6) = 'ANNUAL' 
				then 1 
				else 12 
			end * abs(po.Premium) as Premium,
			--AG 19/01/2017 Start
			--po.Fee as PaymentAmount,
			round(po.Premium * ((@ASMCommRate*(po.Margin/@ASMCommRate))/100),2) as PaymentAmount,
			--AG 19/01/2017 End
			isnull((select APE_Flag from mstt_ProductHierarchy where ProductType = 'Payshield' and ProductCode = 'PY_' + Left(po.Product,5)),'N') as APEFlag,
			--AG 19/01/2017 Start
			--po.Fee as TotalFeeDue,
			round(po.Premium * ((@ASMCommRate * (po.Margin/@ASMCommRate))/100),2) as TotalFeeDue,
			--AG 19/01/2017 End
			po.Margin as CommRate,
			@DACommRate * (po.Margin/@ASMCommRate) - po.Margin as MarginCommRate,
			@DACommRate * (po.Margin/@ASMCommRate) as DACommRate,
			po.Margin as BaseCommRate,
			1.0 as UpliftRate,
			0.0 as ICPaidToDate,	-- These payments are IT (this is an accruals concept)
			0.0 as StillToAccrue,	-- These payments are IT (this is an accruals concept)
			case when ASMFirm.Code is not null 
				then 'Y'
				else 'N'			-- If no firm then it can't go to OpenAccess
			end as SalesMoveFlag,	-- Propagate to OpenAccess
			--AG 01/04/2016 Start
--			round(po.Premium * ((@DACommRate * (po.Margin/@ASMCommRate))/100),2) as DA,
			round(po.Premium * ((((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate)) + @OWCommRate)/100)
							* (po.Margin / ((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate))),2) as DA,
			--AG 01/04/2016 End
			round(po.Premium * ((((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate)) + @OWCommRate)/100)
							* (po.Margin / ((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate))),2) as Turnover,
			round(po.Premium * ((((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate)) + @OWCommRate)/100)
							* (po.Margin / ((@BaseCommRate + @ASMCommRate) * (po.Margin/@ASMCommRate))),2) as APE,
			--AG 19/01/2017 Start
			--po.Fee as EnhancedNBI,
			--po.Fee as BaseNBI,
			--po.Fee as Margin,
			round(po.Premium * ((@ASMCommRate * (po.Margin/@ASMCommRate))/100),2) as EnhancedNBI,
			round(po.Premium * ((@ASMCommRate * (po.Margin/@ASMCommRate))/100),2) as BaseNBI,
			round(po.Premium * ((@ASMCommRate * (po.Margin/@ASMCommRate))/100),2) as Margin,
			--AG 19/01/2017 End
			0 as CaseCount,
			case when po.CommType in ('Double Indemnity','Dind','Dind2') then 24 else 12 end as InitialPeriod,
			case when po.CommType in ('Indemnity','Double Indemnity','Aind','Dind','Dind2') then 'T' else 'F' end as PayBasisCode,
			case when po.CommType in ('Indemnity','Double Indemnity','Aind','Dind','Dind2') then 'IT' else 'Accrual' end as PayBasis,
			100 as AgentSplit,
			case when po.CommType in ('Adjustment','Awaiting Start') or po.Status in ('AWAITING START','MTA') then 'Adj' else 'IC' end as FeeType,
			'Payment Shield Owl ASM' as Provider,
			'PYMTSHLD' as ProviderCode,
			dateadd(mm,1,po.Period) as [Month],
			'Payshield' as Source,
			pic.FileID as CreateDate,	
			po.CommType as OrigCommtype,
			po.Status as OrigStatus,
			0 as ELITE_Initial,			-- Owl don't get ELITE points
			null as ELITE_Category,		-- Owl don't get ELITE points
			ltrim(rtrim(po.OriginalSellerName)) as OrigSellerName,		--AG 01/04/2016
			po.ID as SourceID
	from	dbo.owt_PaymentshieldOwlOverride po
			inner join dbo.owt_PaymentshieldImportControl pic on pic.FileID = po.LoadedDateTime
			--AG 29/10/2018 Start
			--left join (select Descn, MAX(IDHISTid_type) as MaxIDHISTid_type from mstt_AgentsHistory where Manager2Code = @OwlManager2Code and AgentType <> 2 group by Descn) agName on agName.Descn = po.SellerName
			left join (select Descn, MAX(ID) as MaxID from sa_swift_S_AGENTS where Manager2Code = @OwlManager2Code and Agt_Type <> 2 group by Descn) agName on agName.Descn = po.SellerName	--- MF 13/03/2024 replaced mstt_Agents as Tech Debt source
			---left join mstt_AgentsHistory ah on ah.IDHISTid_type = agName.MaxIDHISTid_type
			left join sa_swift_S_AGENTS ah on ah.ID = agName.MaxID							--- MF 13/03/2024 replaced mstt_Agents as Tech Debt source
			--left join mstt_Agents adv on adv.Code = po.OWSellerRef and adv.AgentType <> 2 -- Not a firm
			--left join mstt_Agents adv 
			left join sa_swift_S_Agents adv							--- MF 13/03/2024 replaced mstt_Agents as Tech Debt source
					on (adv.Code = po.OWSellerRef or adv.Code = ah.Code) 
					---and adv.AgentType <> 2 -- Not a firm
					and adv.Agt_Type <> 2 -- Not a firm				--- MF 13/03/2024 replaced mstt_Agents AgentType column as Tech Debt source
			--left join mstt_Agents firm on firm.Code = coalesce(adv.Firm,po.OWSellerRef) 
			--left join mstt_Agents firm on firm.Code = adv.Firm
			left join sa_swift_S_Agents firm on firm.Code = adv.Firm		--- MF 13/03/2024 replaced mstt_Agents as Tech Debt source
			--AG 29/10/2018 End
			left join dbo.msit_MIWarehouseCodesAndDescriptions MICodes
					on  MICodes.ColumnName = 'PersonTitle' 
					and ltrim(rtrim(replace(po.SellerName,'.',''))) like MICodes.Code + ' %'
			left join sa_insight_UserDetails ud 
					on ud.USR_ExternalID =	case when adv.Code is null 
												--then (select top 1 Code from mstt_Agents where Firm = firm.Code)		  AG 24/11/2017
												--then (select top 1 Code from mstt_AgentsHistory where Firm = firm.Code order by ValidFromDate desc)	--AG 24/11/2017 & 09/02/2018
												then (select top 1 Code from sa_swift_S_Agents where Firm = firm.Code order by LastModifiedDate desc)	--- MF 13/03/2024 replaced mstt_Agents & ValidFromDate as Tech Debt source
												else adv.Code
											end
			--AG 24/11/2017 Start
			--left join sa_insight_UserPosition up on up.UPS_UserID = ud.USR_ID and up.UPS_DateTo is null and up.UPS_JobTitle = 53 -- OWL Practice Principal
			--left join	(	select	upended.UPS_UserID, max(upended.UPS_DateTo) as Max_UPS_DateTo
			--				from	sa_insight_UserPosition upended
			--				where	upended.UPS_JobTitle = 53 -- OWL Practice Principal
			--				group	by upended.UPS_UserID
			--			)	upended1 on upended1.UPS_UserID = ud.USR_ID  
			--left join sa_insight_UserPosition upended2 on upended2.UPS_UserID = ud.USR_ID and upended2.UPS_DateTo = upended1.Max_UPS_DateTo and upended2.UPS_JobTitle = 53 -- OWL Practice Principal
			---- Use active PP row but if none, then use most recently ended PP row
			--left join sa_insight_HierarchyNodeLink HNL1 on HNL1.HNL_NodeID = coalesce(up.UPS_OrganisationalUnitID,upended2.UPS_OrganisationalUnitID) and HNL1.HNL_DateTo is null and HNL1.HNL_Type = 0 
			--left join sa_insight_UserPosition up1 on up1.UPS_OrganisationalUnitID = HNL1.HNL_ParentID and up1.UPS_DateTo is null and up1.UPS_JobTitle = 54	-- OWL Area Sales Manager
			--left join sa_insight_UserDetails ud1 on ud1.USR_ID = up1.UPS_UserID
			--left join mstt_Agents ASM on ASM.Code = ud1.USR_ExternalID
			inner join mi_insight_UserHierarchyAllUsers uhah			--AG 09/02/2018 changed from left to inner join
						on uhah.UserUID = ud.USR_ExternalID
						and po.StartDate between uhah.EffectiveStartDate and uhah.EffectiveEndDate
			----inner join mstt_Agents ASM on ASM.Code = uhah.OwlASMUID1	--AG 09/02/2018 changed from left to inner join
			inner join sa_swift_S_Agents ASM on ASM.Code = uhah.OwlASMUID1	--- MF 13/03/2024 replaced mstt_Agents as Tech Debt source
			--AG 24/11/2017 End
			----inner join mstt_Agents ASMFirm on ASMFirm.Code = ASM.Firm	--AG 09/02/2018 changed from left to inner join
			inner join sa_swift_S_Agents ASMFirm on ASMFirm.Code = ASM.Firm	--- MF 13/03/2024 replaced mstt_Agents as Tech Debt source
	where	po.Margin <> 10	-- Exclude the Openwork margin record as this doesn't tell us if a comm sacrifice has taken place
	and		isnull(po.OWSellerRef,'') <> ''		--AG 19/01/2017

	set @RowCount = @@rowcount

	set @ProcessMessage = @ProcessMessage + '. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @Module, @Client


/******************************************************************************************

	ASM's Payment - OSCAR Update (Reverse Engineered from mstp_AgentsHistory PROC)

*******************************************************************************************/

  ----update #msit_AgentsHistory															-- MF 14/03/2024 (Tech Debt replacement)
  update dbo.owt_PaymentshieldCommissionPayments
      set @OscarDateStarted = x.StartDate,
		  @OscarAgentID   = x.OSCAR_ID,
          @OscarAgentPrefix = x.OSCAR_Prefix,
          @OscarAgentSerial = x.OSCAR_Serial,
          @OscarAgentSuffix = x.OSCAR_Suffix
  ---from  #msit_AgentsHistory ah
  from dbo.owt_PaymentshieldCommissionPayments ah	-- MF 14/03/2024 (Tech Debt replacement)
      inner join Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref x on ah.BusinessCode = x.AgentCode		-- MF 14/03/2024 (Tech Debt replacement of Code with Sellercode)
	  left join sa_swift_S_AGENTS a on x.AgentCode = a.code											---  MF 14/03/2024 added to link OSCAR (missing in S_AGENTS) record to paymentshield		
			and a.ID = (select min(ag.id) from sa_swift_S_AGENTS ag -- min(id) matches MIDB001
			where ag.Code = ah.BusinessCode 
			and ag.LastModifiedDate between ah.StartDate and isnull(@DefaultValidToDate,ah.PaymentDate))  
  where x.NoEcode is Null 
  and   x.AgentLevel = 'B' 
  and   x.id = (select min(xref.id) from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref xref -- min(id) matches MIDB001
          where xref.AgentLevel = 'B'
          and xref.AgentCode = ah.BusinessCode												-- MF 14/03/2024 (Tech Debt replacement of Code with Sellercode)
		  ---and ah.ValidFromDate between xref.StartDate and isnull(xref.EndDate,@DefaultValidToDate)) -- AG 26/06/2009
          and ah.StartDate between xref.StartDate and isnull(xref.EndDate,@DefaultValidToDate)) -- MF 14/03/2024 (Tech Debt replacement of ValidFromDate column with StartDate)
  ---and ah.ValidFromDate between x.StartDate and isnull(x.EndDate,@DefaultValidToDate)            -- AG 26/06/2009
  and   ah.StartDate between x.StartDate and isnull(x.EndDate,@DefaultValidToDate)					-- MF 14/03/2024 (Tech Debt replacement of ValidFromDate column with StartDate)
  ---and   ah.AgentType in (2, 46, 47, 49)	
  and   a.Agt_Type in (2, 46, 47, 49)																--  MF 14/03/2024 (AgentType Column not available in S_Agents) 
  and   a.CompetentStatus in (1,2)																	--- MF 14/03/2024 Tech debt replacement 
---  and   ah.Active = 1																			--- MF 14/03/2024 Tech debt: Column not available in S_Agents


---set @RowCount = @@rowcount

set @ProcessMessage = @ProcessMessage + '. Number of rows = ' + convert(varchar(20),@RowCount)	
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @Module, @Client

  ---update #msit_AgentsHistory
  update dbo.owt_PaymentshieldCommissionPayments											-- MF 14/03/2024 (Tech Debt replacement)
	  set @OscarDateStarted = x.StartDate,
		  @OscarAgentID   = x.OSCAR_ID,
          @OscarAgentPrefix = x.OSCAR_Prefix,
          @OscarAgentSerial = x.OSCAR_Serial,
          @OscarAgentSuffix = x.OSCAR_Suffix
  ---from  #msit_AgentsHistory ah
  from dbo.owt_PaymentshieldCommissionPayments ah											-- MF 14/03/2024 (Tech Debt replacement)
      inner join Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref x on ah.BusinessCode = x.AgentCode
	  left join sa_swift_S_AGENTS a on x.AgentCode = a.code											---  MF 14/03/2024 added to link OSCAR (missing in S_AGENTS) record to paymentshield		
			and a.ID = (select min(ag.id) from sa_swift_S_AGENTS ag -- min(id) matches MIDB001
			where ag.Code = ah.BusinessCode 
			and ag.LastModifiedDate between ah.StartDate and isnull(@DefaultValidToDate,ah.PaymentDate)) 
  where x.NoEcode is Null 
  and   x.AgentLevel= 'M' 
  and   x.id = (select min(xref.id) from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref xref -- min(id) matches MIDB001
          where xref.AgentLevel= 'M' 
          and xref.AgentCode = ah.BusinessCode 
          --and ah.ValidFromDate between xref.StartDate and isnull(xref.EndDate,@DefaultValidToDate)) -- AG 26/06/2009
		  and ah.StartDate between xref.StartDate and isnull(xref.EndDate,@DefaultValidToDate)) -- MF 14/03/2024 (column not available in S_Agents)
  --and   ah.ValidFromDate between x.StartDate and isnull(x.EndDate,@DefaultValidToDate)            -- AG 26/06/2009
  and   ah.StartDate between x.StartDate and isnull(x.EndDate,@DefaultValidToDate)            --  MF 14/03/2024 (column not available in S_Agents)
  --and   ah.AgentType in (52, 53, 54, 55 ) 
  and   a.Agt_Type in (52, 53, 54, 55 )														--  MF 14/03/2024 (AgentType Column not available in S_Agents)
  and   a.CompetentStatus in (1,2,3)														--- MF 14/03/2024 Tech debt replacement 
  --and   a.GivesAdvice = 'Y'																	--- MF 14/03/2024 (AgentType Column not available in S_Agents) 


---set @RowCount = @@rowcount

set @ProcessMessage = @ProcessMessage + '. Number of rows = ' + convert(varchar(20),@RowCount)	
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @Module, @Client

  ---update #msit_AgentsHistory 
  update dbo.owt_PaymentshieldCommissionPayments											-- MF 14/03/2024 (Tech Debt replacement)
      set @OscarDateStarted = x.StartDate,
		  @OscarAgentID   = x.OSCAR_ID,
          @OscarAgentPrefix = x.OSCAR_Prefix,
          @OscarAgentSerial = x.OSCAR_Serial,
          @OscarAgentSuffix = x.OSCAR_Suffix
  ---from  #msit_AgentsHistory ah
  from dbo.owt_PaymentshieldCommissionPayments ah											-- MF 14/03/2024 (Tech Debt replacement)
      inner join Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref x on ah.BusinessCode = x.AgentCode
	  left join sa_swift_S_AGENTS a on x.AgentCode = a.code											---  MF 14/03/2024 added to link OSCAR (missing in S_AGENTS) record to paymentshield		
			and a.ID = (select min(ag.id) from sa_swift_S_AGENTS ag -- min(id) matches MIDB001
			where ag.Code = ah.BusinessCode 
			and ag.LastModifiedDate between ah.StartDate and isnull(@DefaultValidToDate,ah.PaymentDate)) 	
  where x.NoEcode is Null 
  and   x.AgentLevel= 'S' 
  and   x.id = (select min(xref.id) from Head_Office_Systems.dbo.owhot_OSCARSwiftAgentXref xref -- min(id) matches MIDB001
          where xref.AgentLevel= 'S' 
          and xref.AgentCode = ah.BusinessCode 
          --and ah.ValidFromDate between xref.StartDate and isnull(xref.EndDate,@DefaultValidToDate)) -- AG 26/06/2009
		  and ah.StartDate between xref.StartDate and isnull(xref.EndDate,@DefaultValidToDate)) -- MF 14/03/2024 (column not available in S_Agents)
  --and   ah.ValidFromDate between x.StartDate and isnull(x.EndDate,@DefaultValidToDate)            -- AG 26/06/2009
  and   ah.StartDate between x.StartDate and isnull(x.EndDate,@DefaultValidToDate)         --  MF 14/03/2024 (column not available in S_Agents) 
  --and   ah.AgentType in ( 3, 4, 5, 43, 45, 51  ) 
  and   a.Agt_Type in ( 3, 4, 5, 43, 45, 51  )													--  MF 14/03/2024 (AgentType Column not available in S_Agents))
  and   a.CompetentStatus in (1,2,3)															--- MF 14/03/2024 Tech debt replacement
  ---and   a.GivesAdvice = 'Y'																	--- MF 14/03/2024 (AgentType Column not available in S_Agents)
  ---and   ah.Active = 1																		--  MF 14/03/2024 (AgentType Column not available in S_Agents)

---set @RowCount = @@rowcount

set @ProcessMessage = @ProcessMessage + '. Number of rows = ' + convert(varchar(20),@RowCount)	
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @Module, @Client

    -- PR Oct 2007 END new Oscar Ecode table


	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	COMMIT TRANSACTION      

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE(), @ErrState = XACT_STATE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10))
	
	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION

	-- Error message line 1
	set @ErrMsgBrief = left(@ErrMsg,100)
	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	
	-- Error message line 2 - if any text exists
	set @ErrMsgBrief = substring(@ErrMsg,101,100)
	if len(@ErrMsgBrief) > 0
		exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @ErrSev , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/



GO
/****** Object:  StoredProcedure [dbo].[owp_PaymentshieldIssuedValidationAndDestination]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/****************************************************************************
  	 Program:  	owp_PaymentshieldIssuedValidationAndDestination						
	  Author:	A Groves
Date created:	07/04/2014
											
 Description:   This proc will validate the Paymentshield Issued data on the
				staging table and will load rows that are OK and park rows that
				require data fixing.

				Note that the processing of this Issued file is not identical to
				the Business file because they were developed by different people.
				For example, the Issued file doesn't have proper NULLS but the text
				N-U-L-L whereas the Business File doesn't appear to have this problem.
				
				It is called as follows:
				declare @LogID int
				exec owp_PaymentshieldIssuedValidationAndDestination 'Openwork', 'PaymentshieldIssued', @LogID output
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------		
09/04/2014	A Groves	Only update SellerUID and SellerName if either is not populated.
						The above changed as cleaned adviser names are required.	
****************************************************************************/
CREATE PROCEDURE [dbo].[owp_PaymentshieldIssuedValidationAndDestination]
	@Client		varchar(50),
	@Module		varchar(50),
	@LogID		int	output
AS

SET NOCOUNT ON

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@Path						varchar(255),
		@DataFileName				varchar(255),
		@RowCount					int,
		@DestinationRowCount		int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@SQL						varchar(8000),
		@RowsParked					bit,
		@DateTimeRowLoaded			datetime

set @PhaseStart				= 'START'
set @PhaseEnd   			= 'END'
set @PhaseLog				= 'LOG'
set @PhaseError				= 'ERROR'
set @Process				= object_name(@@procid)
set @RowsParked				= 0
set @DestinationRowCount	= 0
set @DateTimeRowLoaded		= GETDATE()

/****************************************************************************

	Log start																
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Start transaction																
																		
****************************************************************************/

BEGIN TRY

	BEGIN TRANSACTION

	/****************************************************************************

		Update Log here with the file dedupe check data rather than in the 
		SSIS script as this step can fall over and we don't want that to happen 
		in the SSIS script as we need to see the data loaded to be able to find 
		the bad data. Also, this must be done before anything else as very soon, 
		some rows may be moved off the staging table and parked which would make 
		the HashTotal invalid. 
		Note: The HashTotal won't be updated below if this proc is re-running to
		attempt to re-process parked data. In this situation, 
		owt_PaymentshieldAutoImportLog.LoadInProgress will be 0 which is what we
		want in this situation.		
															
	****************************************************************************/

	select	@LogID = ID
	from	owt_PaymentshieldAutoImportLog
	where	FileType = 'Issued'
	and		LoadInProgress = 1
	
	update	implog
		set SumOfPremium = (select sum(convert(decimal(12,2),Premium)) from owt_PaymentshieldIssuedStaging),
			SumOfLESN = (select sum(convert(bigint,isnull(replace(LESN,'NULL','0'),0))) from owt_PaymentshieldIssuedStaging),
			SumOfPESN = (select sum(convert(bigint,isnull(replace(PESN,'NULL','0'),0))) from owt_PaymentshieldIssuedStaging)
	from	owt_PaymentshieldAutoImportLog implog
	where	FileType = 'Issued'
	and		LoadInProgress = 1
	
	update	implog
		set HashTotal = (SumOfPremium*100) + SumOfLESN + SumOfPESN
	from	owt_PaymentshieldAutoImportLog implog
	where	FileType = 'Issued'
	and		LoadInProgress = 1

	/****************************************************************************

		Now the HashTotal has been derived, reintroduce the parked data.
		Note that if it still can't be processed then it will be parked
		again later on.
																		
	****************************************************************************/

	insert into owt_PaymentshieldIssuedStaging
		select	*
		from	owt_PaymentshieldIssuedStagingParked

	delete
	from	owt_PaymentshieldIssuedStagingParked
	
	/****************************************************************************

		Fix staging data before any further processing
																		
	****************************************************************************/
	
	-- Strip off the unwanted trailing part of the Branch Number
	update owt_PaymentshieldIssuedStaging
		set BranchNumber = upper(stuff(BranchNumber,patindex('%-%',BranchNumber),60,''))
	where patindex('%-%',BranchNumber) > 0

	update owt_PaymentshieldIssuedStaging	
		set BranchNumber = upper(stuff(BranchNumber,patindex('%[_]%',BranchNumber),60,''))
	where patindex('%[_]%',BranchNumber) > 0

	-- NULL values appear to load as the characters N-U-L-L. So make these real NULLs
	update owt_PaymentshieldIssuedStaging
		set FranchiseUID = null
	where FranchiseUID = 'NULL'
	
	/****************************************************************************

		Get any missing FranchiseUIDs. Any rows for which a FranchiseUID can't be
		found must be moved to the Parked table.
																		
	****************************************************************************/

	-- Since stripping out the _BYO derivatives, there are now dupes in the table. This step removes the dupes.
	select	Xref.*
	into	#owhot_PayshieldSwiftAgentXref
	from	owhot_PaymentshieldSwiftAgentXref Xref
			inner join	(select PayshieldAgent, max(ID) as MaxID
							from owhot_PaymentshieldSwiftAgentXref
							group by PayshieldAgent) as DedupedPayshieldAgent
						on DedupedPayshieldAgent.MaxID = Xref.ID
	-- Insert missing FranchiseUID
	update	s
			set FranchiseUID = x.AgentCode
	from	owt_PaymentshieldIssuedStaging s
			inner join #owhot_PayshieldSwiftAgentXref x on x.PayshieldAgent = s.BranchNumber	
	where	s.FranchiseUID is null

	insert into owt_PaymentshieldIssuedStagingParked
		select	*
		from	owt_PaymentshieldIssuedStaging
		where	FranchiseUID is null

	delete 
	from	owt_PaymentshieldIssuedStaging
	where	FranchiseUID is null

	set @RowCount = @@rowcount
	
	if @RowCount > 0 
	begin
		set @RowsParked = 1
		-- Log and carry on - this shouldn't stop the load.
		update	owt_PaymentshieldAutoImportLog
			set ValidationIssues = case when @RowCount = 1 then 'One row parked' else 'Multiple rows parked' end 
		where	FileType = 'Issued'
		and		LoadInProgress = 1
	end

	/****************************************************************************

		Check the HashTotal to see if we have a duplicate file
																		
	****************************************************************************/

	select	@RowCount = count(*)
	from	owt_PaymentshieldAutoImportLog curr
			inner join owt_PaymentshieldAutoImportLog prev
							on prev.FileType = curr.FileType
							and	prev.LoadInProgress <> curr.LoadInProgress
							and	prev.HashTotal = curr.HashTotal
	where	curr.FileType = 'Issued'
	and		curr.LoadInProgress = 1
	
	if @Rowcount > 0
	begin
		update	owt_PaymentshieldAutoImportLog
				set ValidationIssues = 'Duplicate File - Not Loaded To Destination',
					LoadToDestinationStatus = 'Failed',
					LoadInProgress = 0
		where	FileType = 'Issued'
		and		LoadInProgress = 1

		-- Early exit because the file is a duplicate and not to be loaded. However, 
		-- truncate the staging table because this proc may run again soon due to
		-- scheduling (or run manually) to re-process parked rows. 		
		truncate table owt_PaymentshieldIssuedStaging

		COMMIT TRANSACTION      
		RETURN
	end
	
	/****************************************************************************

		Validation done so now attempt to load the data to the destination
																		
	****************************************************************************/

	insert into owt_PaymentshieldIssued
	select	convert(int,RowID) as SourceRowID,
			convert(datetime,LoadPeriod+'01',112) as LoadPeriod,
			PolicyReference,
			ClientTitle,
			ClientFirstName,
			ClientLastName,
			case when ClientDOB = 'NULL' then null else convert(datetime,ClientDOB,103) end as ClientDOB,
			case when StartDate = 'NULL' then null else convert(datetime,StartDate,103) end as StartDate,
			case when RenewalDate = 'NULL' then null else convert(datetime,RenewalDate,103) end as RenewalDate,
			case when DateWritten = 'NULL' then null else convert(datetime,DateWritten,103) end as DateWritten,
			ProductType,
			BusinessReason,
			CommType,
			[Status],
			Frequency,
			convert(decimal(12,2),Premium) as Premium,
			case when Process = 'NULL' then null else Process end as Process,
			convert(decimal(6,2),CommRate) as CommRate,
			case when CommAmount = 'NULL' then null else convert(decimal(12,2),CommAmount) end as CommAmount,
			convert(decimal(6,2),EnhancedRate) as EnhancedRate,
			convert(decimal(6,2),DARate) as DARate,
			case when DAAmount = 'NULL' then null else convert(decimal(12,2),DAAmount) end as DAAmount,
			BranchNumber,
			FranchiseName,
			case when isnumeric(FranchiseUID)=0 or len(FranchiseUID)>7 then NULL else FranchiseUID end as FranchiseUID,
			case 
				when SellerName = 'NULL' then null 
				when MICodes.Code is null then ltrim(rtrim(SellerName))	-- No match on person title so title assumed not present
				else ltrim(rtrim(stuff(replace(SellerName,'.',''),1,len(MICodes.Code),''))) 
			end as SellerName,
			case when isnumeric(SellerUID)=0 or len(SellerUID)>7 then NULL else SellerUID end as SellerUID,
			UniqueRef,
			Company,
			case when isnumeric(IndemnityMonth) = 0 then null else convert(int,IndemnityMonth) end as IndemnityMonth,
			IntroducedCase,
			case when LESN = 'NULL' then null else convert(int,LESN) end as LESN,
			case when PESN = 'NULL' then null else convert(int,PESN) end as PESN,
			case when SellerName = 'NULL' then null else SellerName end as OriginalSellerName,
			case when isnumeric(SellerUID)=0 or len(SellerUID)>7 then NULL else SellerUID end as OriginalSellerUID,
			NULL as SellerMatchingMethod,
			@DateTimeRowLoaded as DateTimeRowLoaded
	from	owt_PaymentshieldIssuedStaging
			left join dbo.msit_MIWarehouseCodesAndDescriptions MICodes
						on  MICodes.ColumnName = 'PersonTitle' 
						and ltrim(rtrim(replace(SellerName,'.',''))) like MICodes.Code + ' %'

	set @DestinationRowCount = @@rowcount
	
	-- The inserts may have parked some data and loaded the rest to the destination table.
	-- Now truncate the staging table in case this stored proc is run again to load
	-- the parked data. We don't want the staged data to be loaded again creating duplicates.
	
	truncate table owt_PaymentshieldIssuedStaging

	/****************************************************************************

		Fuzzy match the advisers.
																		
	****************************************************************************/

	create table #AdviserSoundex
	(
		[AdviserUID]				varchar(7),
		[EnterpriseUID]				varchar(7),
		[Forenames]					varchar(60),
		[FirstForename]				varchar(60),
		[Surname]					varchar(60),
		[FirstForenameWithSurname]	varchar(121),
		[SoundexForename]			varchar(20),
		[SoundexSurname]			varchar(20)
	)

	insert into #AdviserSoundex
		exec pr_etl_AdviserSoundexEncoding 

	-- Update all rows as it tidies up the Seller Name to just one forename plus surname
	-- so that ultimately if this data ends up in OpenAccess then the drop down Adviser
	-- selection box will have consistent adviser names. However, only update the
	-- SellerMatchingMethod if the data was originally blank. Don't over-reward the process!
	update pshield
		set	SellerUID				= sdx.AdviserUID,
			SellerName				= sdx.FirstForenameWithSurname,
			SellerMatchingMethod	=	case 
											when (pshield.SellerUID is null or pshield.SellerName is null)
											then
												case 
													when isnull(pshield.SellerUID,'') = isnull(sdx.AdviserUID,'') then 'ExactUID' 
													when isnull(pshield.SellerName,'') = isnull(sdx.FirstForenameWithSurname,'') then 'ExactName' 
													else 'Fuzzy' 
												end
											else null
										end
	from	owt_PaymentshieldIssued pshield
			inner join #AdviserSoundex sdx on sdx.EnterpriseUID = pshield.FranchiseUID	
	where	pshield.DateTimeRowLoaded = @DateTimeRowLoaded	
	and		((pshield.SellerName = sdx.FirstForenameWithSurname				-- Whole name matches exactly or
	or		
			(sdx.SoundexSurname = dbo.owf_Soundex(pshield.SellerName,'L')	-- Soundex of surname must match and
			and		(left(sdx.SoundexForename,2) = left(dbo.owf_Soundex(pshield.SellerName,'F'),2)	-- Soundex of first two forename letters match or	
					or dbo.owf_AbbreviatedMatch(sdx.FirstForenameWithSurname,pshield.SellerName) = 1))))	-- The names are abbreviated matches		

	/****************************************************************************

		All good - so commit transaction
																		
	****************************************************************************/

	COMMIT TRANSACTION      

	update	owt_PaymentshieldAutoImportLog
		set LoadInProgress = 0,
			LoadToDestinationStatus = case when @RowsParked = 0 then 'Full' else 'Partial' end, 
			RowsLoadedToDestination = @DestinationRowCount
	where	FileType = 'Issued'
	and		LoadInProgress = 1
	
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = 'Load of PaymentshieldIssued failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)
	  
	update	owt_PaymentshieldAutoImportLog
		set LoadToDestinationStatus = 'Failed',
			LoadInProgress = 0,
			RowsLoadedToDestination = @DestinationRowCount
	where	FileType = 'Issued'
	and		LoadInProgress = 1

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/



GO
/****** Object:  StoredProcedure [dbo].[owp_PaymentshieldOwlImportToOverride]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_PaymentshieldOwlImportToOverride						
	  Author:	A Groves
Date created:	21/09/2015
											
 Description:   This proc will transfer Paymentshield Owl data from the staging
				table to the Override table.
				
				It is called as follows:

				exec owp_PaymentshieldOwlImportToOverride 'Openwork', 'PaymentshieldOwl'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
20/11/2015	A Groves	Table mi_insight_UserHierarchy was previously used
						for looking up the adviser's ASM. However, this was 
						flawed because when advisers leave, their record drops
						out of the table. Thus, this table was replaced with
						a load of Insight table joins to look up the ASM directly.
21/01/2016	A Groves	SR417613: Two rows received for PolicyReference = 'BPNL31333994'
						where SellerName = 'Unknown' and OWSellerRef = ''. This
						caused a load failure to table "owt_PaymentshieldOwlOverrideStatement"
						as the AdviserUID is a "not null" column. A new data fix was added in to 
						match via the PolicyReference to handle the same problem now and into 
						the future.
22/03/2016	A Groves	SR427034. Failure to populate the AdviserUID on table
						owt_PaymentshieldOwlOverrideStatement because the OWSellerRef was empty
						and there were no previous records for the policy. The fix was to look
						up the AdviserUID based on the seller's name. 
						Also, an OWSellerRef was a 6 digit code that did not resemble the real
						UID in any way. A check that every OWSellerRef is a valid UID was 
						introduced. If not valid, then the UID is looked up via the seller name.
						Caution: These name look ups must only occur if absolutely necessary - as 
						we risk invalid matching where multiple advisers have the same name.
17/01/2017	A Groves	SR463747: Changes needed for new SFTP'd file:- 
						1) Change in format of StartDate found, so both old format (dd/mm/yyyy) 
							and new format (yyyy-mm-dd) now handled.
						2) Introduced improved fuzzy matching of seller name to derive the seller
							code when the seller code is not supplied. This will stop the proc 
							from failing when it attempts to INSERT a null AdviserUID on table
							dbo.owt_PaymentshieldOwlOverrideStatement as the AdviserUID should
							be (more) reliably derived going forwards.
23/01/2017	A Groves	Matching to the Seller Log.xls introduced to handle different advisers
							with the same name such as Muhammad Saleem. This is possible because
							the Branch Number is always provided. However, we can only rely on 
							the Seller Log for special cases such as duplicate adviser names 
							because otherwise the Seller Log update burden would be too high.
22/02/2017	A Groves	1) Removal of title removed the title letters throughout the seller name 
							rather than just at the start. Example:
							Mr Mariola Mroz-Iwanska became Mariola oz-Iwanska.
							This is now fixed so the seller becomes Mariola Mroz-Iwanska as required.
						2) Match on Addressee as well as Descn as adviser is set up this way 
							on Swift:
							Descn=Kehinde Akinyele
							Addressee=Kehinde Ojo <- This is the Seller Name in the Paymentshield file
24/11/2017	A Groves	SR495162/CH19688. Previously the ASM look-up was failing where the 
							adviser had left. The old code has been replaced with a look-up 
							on table mi_insight_UserHierarchyAllUsers. Also where an
							adviser has been re-linked to a new business, the look-up
							on mstt_Agents was failing to find the adviser's old firm.
							Thus mstt_Agents has been changed to mstt_AgentsHistory.
************************************************************************************************/

CREATE PROCEDURE [dbo].[owp_PaymentshieldOwlImportToOverride] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@ProcessMessage				varchar(100),
		@Path						varchar(255),
		@DataFileName				varchar(255),
		@sql						varchar(8000),
		@RowCount					int,
		@FileID						datetime,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@OwlManager2Code			nvarchar(10)	-- AG 22/03/2016

/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @PhaseLog		= 'LOG'
set @PhaseError		= 'ERROR'
set @Process		= object_name(@@procid)

set @OwlManager2Code = (select cde.Code from msit_MIWarehouseCodesAndDescriptions cde	-- AG 22/03/2016
			where cde.ColumnName = 'Manager2Code' and cde.Description = 'Owl Financial')

/****************************************************************************

	Log start																
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Processing start
																		
****************************************************************************/

BEGIN TRY

	/****************************************************************************

		Start transaction
																			
	****************************************************************************/

	BEGIN TRANSACTION

	/****************************************************************************

		Track data being loaded
																			
	****************************************************************************/

	select @FileID = max(LoadedDateTime) from owt_PaymentshieldImportOwl

	--Maintain table that controls what to load
	truncate table dbo.owt_PaymentshieldImportControl

	insert into dbo.owt_PaymentshieldImportControl
		Select [FileID] = @FileID
			
	/****************************************************************************

		Transfer the staging data to the override table
																			
	****************************************************************************/

	set @ProcessMessage = 'owt_PaymentshieldOwlOverride'
	exec msp_ProcessLog @PhaseStart, @ProcessMessage, null, @Module, @Client

	insert into owt_PaymentshieldOwlOverride
	(
		TermOfContract,
		Period,
		PolicyReference,
		OWPolicyRef,
		ClientName,
		StartDate,
		Source,
		Product,
		CommType,
		[Status],
		Premium,
		Margin,
		Fee,
		BranchNo,
		BranchName,
		OWFirmRef,
		DataSourceRef,
		IndemnityPeriod,
		SellerName,
		OWSellerRef,
		InsuredPostCode,
		PESN,
		LoadedDateTime,
		OriginalSellerName,		--AG 22/03/2016
		OriginalOWSellerRef		--AG 22/03/2016
	)
		select	TermOfContract,
				dateadd(mm,-1,csp.Month) as Period,
				PolicyReference,
				OWPolicyRef,
				ClientName,
				--AG 17/01/2017 Start
				--convert(datetime,StartDate,103) as StartDate,
				case 
					when patindex('[0-9][0-9][0-9][0-9]-[0-9][0-9]-[0-9][0-9]',StartDate) > 0
						then convert(datetime,StartDate,120)
					when patindex('[0-9][0-9]/[0-9][0-9]/[0-9][0-9][0-9][0-9]',StartDate) > 0
						then convert(datetime,StartDate,103)
					else null
				end as StartDate,
				--AG 17/01/2017 End
				Source,
				Product,
				CommType,
				Status,
				Premium,
				Margin,
				Fee,
				BranchNo,
				BranchName,
				OWFirmRef,
				DataSourceRef,
				IndemnityPeriod,
				--AG 22/02/2017 Start
				--case when MICodes.Code is not null		--AG 22/03/2016 
				--	then ltrim(replace(pio.SellerName,MICodes.Code,''))	  
				--	else pio.SellerName
				--end,				
				case when MICodes.Code is null	-- No match on person title so title assumed not present
						then ltrim(rtrim(pio.SellerName))
						else ltrim(rtrim(stuff(replace(pio.SellerName,'.',''),1,len(MICodes.Code),''))) 
				end,	
				--AG 22/02/2017 End
				OWSellerRef,
				InsuredPostCode,
				PESN,
				LoadedDateTime,
				SellerName,			--AG 22/03/2016
				OWSellerRef			--AG 22/03/2016
		from	owt_PaymentshieldImportOwl pio
				inner join msit_CommissionStatementPeriods csp on csp.MonthName = replace(pio.Period,',','')
				left join dbo.msit_MIWarehouseCodesAndDescriptions MICodes	--AG 22/03/2016
							on  MICodes.ColumnName = 'PersonTitle' 
							and ltrim(rtrim(replace(pio.SellerName,'.',''))) like MICodes.Code + ' %'

	set @RowCount = @@rowcount
	
	set @ProcessMessage = @ProcessMessage + '. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @Module, @Client

	/****************************************************************************

		SR417613: AG 21/01/2016.	Fix where blank OWSellerRef occurs
																			
	****************************************************************************/
	
	set @ProcessMessage = 'Blank OWSellerRef Data Fix 1'
	exec msp_ProcessLog @PhaseStart, @ProcessMessage, null, @Module, @Client

	update	new 
		set new.SellerName = old.SellerName,
			new.OWSellerRef = old.OWSellerRef
	from	owt_PaymentshieldOwlOverride new
			inner join (select PolicyReference, min(ID) as MinID
						from	owt_PaymentshieldOwlOverride
						group	by PolicyReference
						) OnePolRow on OnePolRow.PolicyReference = new.PolicyReference
			inner join owt_PaymentshieldOwlOverride old on old.ID = OnePolRow.MinID
	where	isnull(new.OWSellerRef,'') = ''
	and		isnull(old.PolicyReference,'') <> '' 

	set @RowCount = @@rowcount

	set @ProcessMessage = @ProcessMessage + '. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @Module, @Client

	/****************************************************************************

		SR427034: AG 22/03/2016.	Fix where blank OWSellerRef occurs
		
		Note: two firm checks are required because there was a situation where
		a re-appointment was given a new firm UID but kep his practice principal
		UID. The double firm check ensures that the active firm is prioritised
		over the Left firm.
																			
	****************************************************************************/
	
	set @ProcessMessage = 'Blank OWSellerRef Data Fix 2'
	exec msp_ProcessLog @PhaseStart, @ProcessMessage, null, @Module, @Client

	--SR463747 AG 17/01/2017 Start 

	/****************************************************************************

		The update below didn't catch all seller name
		scenarios:
		1) Dawid Wawrzyniak (David)		--Additional characters
		2) Gbenga  Lawal				--Two spaces between first and second name

		The update has been re-coded for greater matching success.
		
		User Defined Functions are very slow, so they are run once on each 
		base table and populated into temporary tables. The temp tables are 
		then processed and this all happens fast enough without the need for 
		indexes on the temp tables. 
																			
	****************************************************************************/
	
	/*
	update	po 
		set OWSellerRef = coalesce(firmActive.Code,firmLeft.Code,adv.Code)
	from	owt_PaymentshieldOwlOverride po
			left join mstt_Agents ag						--Check it's a valid code as sometimes it can be rubbish
						on  ag.Code = ltrim(rtrim(po.OWSellerRef))
						and	ag.Manager2Code = @OwlManager2Code
			left join mstt_Agents firmActive 
						on  firmActive.Descn = po.SellerName
						and firmActive.Manager2Code = @OwlManager2Code
						and firmActive.AgentType = 2		--Franchise
						and FirmActive.CompetentStatus = 1	--Active
			left join mstt_Agents firmLeft 
						on  firmLeft.Descn = po.SellerName
						and firmLeft.Manager2Code = @OwlManager2Code
						and firmLeft.AgentType = 2			--Franchise
						and FirmLeft.CompetentStatus <> 1	--Not active - probably Left but possibly still pre-contract
			left join (select	Descn, max(Code) as Code
						from	mstt_Agents adv 
						where	adv.Manager2Code = @OwlManager2Code
						and		adv.AgentType <> 2			--Non firm code
						group	by Descn
						) Adv on adv.Descn = po.SellerName
	where	(isnull(po.OWSellerRef,'') = '' or ag.Code is null)
	and		isnull(po.SellerName,'') <> ''
*/

	--AG 23/01/2017. Dedupe the Seller Log.
	--The Seller Log isn't fully relied upon for Owl. It's used for matching exceptions
	--such as for Muhammad Saleem whose name is used by two different advisers.
	select	Xref.*
	into	#owhot_PaymentshieldSwiftAgentXref
	from	owhot_PaymentshieldSwiftAgentXref Xref
			inner join	(select PayshieldAgent, max(ID) as MaxID
							from owhot_PaymentshieldSwiftAgentXref
							group by PayshieldAgent) as DedupedPayshieldAgent
						on DedupedPayshieldAgent.MaxID = Xref.ID
						
	--Clean the master seller and enterprise names
	select	Code,
			replace(dbo.owf_CleanTextForMatching(Descn),'-',' ') as DescnCleaned,
			replace(dbo.owf_CleanTextForMatching(Addressee),'-',' ') as AddresseeCleaned,	--AG 22/02/2017
			AgentType,
			CompetentStatus,
			Name as LastName,
			left(FirstNames,1) as FirstInitial, 
			Title
	into	#Agents
	from	mstt_Agents
	where	Manager2Code = @OwlManager2Code

	--Clean the Paymentshield sourced seller names on the newly loaded rows
	select	po.*,
			replace(dbo.owf_CleanTextForMatching(po.SellerName),'-',' ') as SellerNameCleaned,
			dbo.owf_LastWord(po.SellerName) as LastName,
			LEFT(po.SellerName,1) as FirstInitial,
			MICodes.Code as Title
	into	#PaymentshieldOwlOverride
	from	owt_PaymentshieldOwlOverride po
			inner join dbo.owt_PaymentshieldImportControl pic on pic.FileID = po.LoadedDateTime
			left join dbo.msit_MIWarehouseCodesAndDescriptions MICodes	--AG 22/03/2016
							on  MICodes.ColumnName = 'PersonTitle' 
							and ltrim(rtrim(replace(po.OriginalSellerName,'.',''))) like MICodes.Code + ' %'
							
	--Derive the seller code from the seller name via various fuzzy methods.
	--Soundex is not used as we're not including other elements such as DoB or address 
	--which would be needed to make the matching safe.
	update	po 
		set OWSellerRef = coalesce(firmActive.Code,firmActAddressee.Code,firmLeft.Code,adv.Code,adv2.Code,xref.AgentCode)	--AG 23/01/2017 & AG 22/02/2017
	from	#PaymentshieldOwlOverride po
			left join #Agents ag						--Check it's a valid code as sometimes it can be rubbish
						on  ag.Code = po.OWSellerRef
			left join	(select	DescnCleaned, max(Code) as Code, COUNT(*) as Occurrences
						 from	#Agents 
						 where	AgentType = 2		--Franchise
						 and	CompetentStatus = 1	--Active
						 group	by DescnCleaned
						) firmActive	on	firmActive.Occurrences = 1	--This derivation is only safe if it matches to only one enterprise
										and	(firmActive.DescnCleaned = po.SellerNameCleaned					--The name has matched
										or	CHARINDEX(po.SellerNameCleaned,firmActive.DescnCleaned) > 0		--The name fully exists...
										or	CHARINDEX(firmActive.DescnCleaned,po.SellerNameCleaned) > 0)	--...within the name being checked
			--AG 22/02/2017 Start
			left join	(select	AddresseeCleaned, max(Code) as Code, COUNT(*) as Occurrences
						 from	#Agents 
						 where	AgentType = 2		--Franchise
						 and	CompetentStatus = 1	--Active
						 group	by AddresseeCleaned
						) firmActAddressee	on	firmActAddressee.Occurrences = 1	--This derivation is only safe if it matches to only one enterprise
											and	(firmActAddressee.AddresseeCleaned = po.SellerNameCleaned					--The name has matched
											or	CHARINDEX(po.SellerNameCleaned,firmActAddressee.AddresseeCleaned) > 0		--The name fully exists...
											or	CHARINDEX(firmActAddressee.AddresseeCleaned,po.SellerNameCleaned) > 0)	--...within the name being checked	
			--AG 22/02/2017 End
			left join	(select	DescnCleaned, max(Code) as Code, COUNT(*) as Occurrences
						 from	#Agents
						 where	AgentType = 2			--Franchise
						 and	CompetentStatus <> 1	--Not active - probably Left but possibly still pre-contract
						 group	by DescnCleaned
						) firmLeft		on	firmLeft.Occurrences = 1	--This derivation is only safe if it matches to only one enterprise
										and	(firmLeft.DescnCleaned = po.SellerNameCleaned				--The name has matched
										or	CHARINDEX(po.SellerNameCleaned,firmLeft.DescnCleaned) > 0	--The name fully exists...
										or	CHARINDEX(firmLeft.DescnCleaned,po.SellerNameCleaned) > 0)	--...within the name being checked
			left join (select	DescnCleaned, max(Code) as Code, COUNT(*) as Occurrences
						from	#Agents 
						where	AgentType <> 2			--Non firm code
						group	by DescnCleaned
						) adv	on	Adv.Occurrences = 1	--This derivation is only safe if it matches to only one adviser
								and	(adv.DescnCleaned = po.SellerNameCleaned				--The name has matched
								or	CHARINDEX(po.SellerNameCleaned,adv.DescnCleaned) > 0	--The name fully exists...
								or	CHARINDEX(adv.DescnCleaned,po.SellerNameCleaned) > 0)	--...within the name being checked
			left join (select	LastName, FirstInitial, Title, max(Code) as Code, COUNT(*) as Occurrences
						from	#Agents 
						where	AgentType <> 2			--Non firm code
						group	by LastName, FirstInitial, Title
						) adv2	on	Adv2.Occurrences = 1	--This derivation is only safe if it matches to only one adviser
								and	adv2.LastName = po.LastName				
								and adv2.FirstInitial = po.FirstInitial
								and adv2.Title = po.Title
			left join #owhot_PaymentshieldSwiftAgentXref xref on xref.PayshieldAgent = po.BranchNo	--AG 23/01//2017
	where	(isnull(po.OWSellerRef,'') = '' or ag.Code is null)					--Enterprise code empty or lookup doesn't match
	and		(isnull(po.SellerName,'') <> '' or isnull(po.BranchNo,'') <> '')	--Seller name or branch number exists so lookup is possible	AG 23/01/2017

	--Now transfer the updates from the temp table to the base table
	update po
		set OWSellerRef = tmp.OWSellerRef
	from owt_PaymentshieldOwlOverride po
			inner join #PaymentshieldOwlOverride tmp on tmp.ID = po.ID
	where	isnull(po.OWSellerRef,'') <> isnull(tmp.OWSellerRef,'')
	and		isnull(tmp.OWSellerRef,'') <> ''

	--SR463747 AG 17/01/2017 End

	set @RowCount = @@rowcount

	set @ProcessMessage = @ProcessMessage + '. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @Module, @Client

	/****************************************************************************

		Transfer to the statement table while setting up the quarter dates
																			
	****************************************************************************/

	set @ProcessMessage = 'owt_PaymentshieldOwlOverrideStatement'
	exec msp_ProcessLog @PhaseStart, @ProcessMessage, null, @Module, @Client
	
	insert into dbo.owt_PaymentshieldOwlOverrideStatement
	(
		ID,
		Period,
		QuarterDate,
		QuarterText,
		ASMUID,
		ASMName,
		AdviserUID,
		AdviserName,
		StartDate,
		ClientName,
		Status,
		Premium,
		OverridePct,
		OverrideDue,
		PolicyReference
	)
	select	quarters.ID,
			quarters.Period,
			quarters.QuarterDate,
			case 
				when month(quarters.QuarterDate) = 1 then cast(year(quarters.QuarterDate) as Varchar) + ' Q1'
				when month(quarters.QuarterDate) = 4 then cast(year(quarters.QuarterDate) as Varchar) + ' Q2'
				when month(quarters.QuarterDate) = 7 then cast(year(quarters.QuarterDate) as Varchar) + ' Q3'
				when month(quarters.QuarterDate) = 10 then cast(year(quarters.QuarterDate) as Varchar) + ' Q4'
			end as QuarterText,
			quarters.ASMUID, 
			quarters.ASMName,
			quarters.AdviserUID, 
			quarters.AdviserName,
			quarters.StartDate,
			quarters.ClientName,
			quarters.Status,
			quarters.Premium,
			quarters.OverridePct,
			quarters.OverrideDue,
			quarters.PolicyReference
	from
	(
		select	periods.ID,
				periods.Period,
				case 
					when month(periods.Period) between 1 and 3 then dateadd(mm, (year(periods.Period)-1900)*12, 0)
					when month(periods.Period) between 4 and 6 then dateadd(mm, (year(periods.Period)-1900)*12 + 3, 0)
					when month(periods.Period) between 7 and 9 then dateadd(mm, (year(periods.Period)-1900)*12 + 6, 0)
					when month(periods.Period) between 10 and 12 then dateadd(mm, (year(periods.Period)-1900)*12 + 9, 0)
				end as QuarterDate,
				periods.ASMUID, 
				periods.ASMName,
				periods.AdviserUID, 
				periods.AdviserName,
				periods.StartDate,
				periods.ClientName,
				periods.Status,
				periods.Premium,
				periods.OverridePct,
				periods.OverrideDue,
				periods.PolicyReference
		from
		(
			select	ovr.ID,
					ovr.Period,
					-- AG 20/11/2015 Start		
		--			uh.OwlASMUID1 as ASMUID, 
		--			uh.OwlASMName1 as ASMName,
					ASM.Code as ASMUID, 
					ASM.Descn as ASMName,
		--			adv.Code as AdviserUID, 
		--			adv.DESCN as AdviserName,
					case when adv.Code is null 
						then (select top 1 Code from mstt_Agents where Firm = firm.Code)
						else adv.Code
					end as AdviserUID,
					case when MICodes.Code is null	-- No match on person title so title assumed not present
						then ltrim(rtrim(ovr.SellerName))
						else ltrim(rtrim(stuff(replace(ovr.SellerName,'.',''),1,len(MICodes.Code),''))) 
					end as AdviserName,	
					-- AG 20/11/2015 End
					ovr.StartDate,
					ovr.ClientName,
					ovr.Status,
					ovr.Premium,
					ovr.Margin as OverridePct,
					ovr.Fee as OverrideDue,
					ovr.PolicyReference
			-- AG 20/11/2015 Start		
		--	from	owt_PaymentshieldOwlOverride ovr
		--			inner join dbo.owt_PaymentshieldImportControl pic on pic.FileID = ovr.LoadedDateTime
		--			inner join (select ag.Firm, min(ag.Code) as Code 
		--						from mstt_Agents ag 
		--						where ag.AgentType = 43	-- Principal
		--						group by ag.Firm) a
		--						on a.Firm = ovr.OWSellerRef
		--			inner join mstt_Agents adv on adv.Code = a.code
		--			left join mi_insight_UserHierarchy uh on uh.UserUID = a.Code
		--	where	ovr.Margin <> 10			
			from	owt_PaymentshieldOwlOverride ovr
					inner join dbo.owt_PaymentshieldImportControl pic on pic.FileID = ovr.LoadedDateTime
					left join mstt_Agents adv on adv.Code = ovr.OWSellerRef and adv.AgentType <> 2 -- Not a firm
					left join mstt_Agents firm on firm.Code = coalesce(adv.Firm,ovr.OWSellerRef) 
					left join dbo.msit_MIWarehouseCodesAndDescriptions MICodes
							on  MICodes.ColumnName = 'PersonTitle' 
							and ltrim(rtrim(replace(ovr.SellerName,'.',''))) like MICodes.Code + ' %'
					left join sa_insight_UserDetails ud 
							on ud.USR_ExternalID =	case when adv.Code is null 
														--then (select top 1 Code from mstt_Agents where Firm = firm.Code)		--AG 24/11/2017
														then (select top 1 Code from mstt_AgentsHistory where Firm = firm.Code)	--AG 24/11/2017
														else adv.Code
													end
					--AG 24/11/2017 Start
					--left join sa_insight_UserPosition up on up.UPS_UserID = ud.USR_ID and up.UPS_DateTo is null and up.UPS_JobTitle = 53 -- OWL Practice Principal
					--left join	(	select	upended.UPS_UserID, max(upended.UPS_DateTo) as Max_UPS_DateTo
					--				from	sa_insight_UserPosition upended
					--				where	upended.UPS_JobTitle = 53 -- OWL Practice Principal
					--				group	by upended.UPS_UserID
					--			)	upended1 on upended1.UPS_UserID = ud.USR_ID  
					--left join sa_insight_UserPosition upended2 on upended2.UPS_UserID = ud.USR_ID and upended2.UPS_DateTo = upended1.Max_UPS_DateTo and upended2.UPS_JobTitle = 53 -- OWL Practice Principal
					---- Use active PP row but if none, then use most recently ended PP row
					--left join sa_insight_HierarchyNodeLink HNL1 on HNL1.HNL_NodeID = coalesce(up.UPS_OrganisationalUnitID,upended2.UPS_OrganisationalUnitID) and HNL1.HNL_DateTo is null and HNL1.HNL_Type = 0 
					--left join sa_insight_UserPosition up1 on up1.UPS_OrganisationalUnitID = HNL1.HNL_ParentID and up1.UPS_DateTo is null and up1.UPS_JobTitle = 54	-- OWL Area Sales Manager
					--left join sa_insight_UserDetails ud1 on ud1.USR_ID = up1.UPS_UserID
					--left join mstt_Agents ASM on ASM.Code = ud1.USR_ExternalID
					left join mi_insight_UserHierarchyAllUsers uhah
						on uhah.UserUID = ud.USR_ExternalID
						and ovr.StartDate between uhah.EffectiveStartDate and uhah.EffectiveEndDate
					left join mstt_Agents ASM on ASM.Code = uhah.OwlASMUID1
					--AG 24/11/2017 End
					left join mstt_Agents ASMFirm on ASMFirm.Code = ASM.Firm
			-- AG 20/11/2015 End
			where	ovr.Margin <> 10	-- Exclude the Openwork margin record as this doesn't tell us if a comm sacrifice has taken place
		) periods
	) quarters
	where quarters.AdviserUID is not null			--AG 17/01/2017. If the adviser is unknown, then they can't be propagated.
	order by Period, ASMName, ASMUID, StartDate

	set @RowCount = @@rowcount

	set @ProcessMessage = @ProcessMessage + '. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @Module, @Client

	/****************************************************************************

		Transfer the statement table to Logi
																			
	****************************************************************************/

	set @ProcessMessage = 'logi.OwlASMOverrideStatement'
	exec msp_ProcessLog @PhaseStart, @ProcessMessage, null, @Module, @Client
	
	insert into logi.OwlASMOverrideStatement
	(
		ID,
		Period,
		QuarterDate,
		QuarterText,
		ASMUID,
		ASMName,
		AdviserUID,
		AdviserName,
		StartDate,
		ClientName,
		Status,
		Premium,
		OverridePct,
		OverrideDue,
		PolicyReference
	)
	select	stmt.ID,
			stmt.Period,
			stmt.QuarterDate,
			stmt.QuarterText,
			stmt.ASMUID,
			stmt.ASMName,
			stmt.AdviserUID,
			stmt.AdviserName,
			stmt.StartDate,
			stmt.ClientName,
			stmt.Status,
			stmt.Premium,
			stmt.OverridePct,
			stmt.OverrideDue,
			stmt.PolicyReference
	from	dbo.owt_PaymentshieldOwlOverrideStatement stmt
			inner join dbo.owt_PaymentshieldOwlOverride ovr on ovr.ID = stmt.ID
			inner join dbo.owt_PaymentshieldImportControl pic on pic.FileID = ovr.LoadedDateTime

	set @RowCount = @@rowcount

	set @ProcessMessage = @ProcessMessage + '. Number of rows = ' + convert(varchar(20),@RowCount)	
	exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @Module, @Client

	/****************************************************************************

		Processing end
																		
	****************************************************************************/

	COMMIT TRANSACTION      

	/****************************************************************************

		End transaction
																			
	****************************************************************************/

	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = @Process + ' failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/


GO
/****** Object:  StoredProcedure [dbo].[owp_PaymentshieldPanelFileImport]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/****************************************************************************
  	 Program:  	owp_PaymentshieldPanelFileImport						
	  Author:	A Groves
Date created:	05/04/2013
											
 Description:   This proc will import the Paymentshield Panel Policies from
				the flat file delivered by Paymentshield via Secure Messaging. 

				It is called as follows:

				exec owp_PaymentshieldPanelFileImport 'Openwork', 'PaymentshieldPanel'
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
24/06/2013	A Groves	Replaced OPENROWSET with a SSIS script.
30/06/2021  P REED      Added  OW_SellerRef, and PESN
****************************************************************************/

CREATE PROCEDURE [dbo].[owp_PaymentshieldPanelFileImport] 
	@Client		varchar(50),
	@Module		varchar(50)
as

set nocount on

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@Process					varchar(100),
		@Path						varchar(255),
		@DataFileName				varchar(255),
		@sql						varchar(8000),
		@RowCount					int


/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/


set @PhaseStart		= 'START'
set @PhaseEnd   	= 'END'
set @Process		= object_name(@@procid)

select	@Path			= Path,
		@DataFileName	= DataFileName
from	mst_DataImportConfiguration with (nolock)
where	Client = @Client
and		Module = @Module


/****************************************************************************

	Log start																
																		
****************************************************************************/


exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client


/****************************************************************************

	Import file
																		
****************************************************************************/

/* AG 24/06/2013. We can't make OPRNROWSET work in production for this path:
	\\openwork.local\MIDB\Clientdata\Openwork\ManuallySourced\Paymentshield\Current
	It will only work on C:\Temp. Therefore OPENROWSET replaces with a SSIS script.

exec msp_ProcessLog @PhaseStart, 'Import File', null, @Module, @Client


truncate table owt_PaymentshieldImportPanel


set @sql = 
'insert into owt_PaymentshieldImportPanel
(
	TermOfContract,
	Period,
	PolicyReference,
	OWPolicyRef,
	ClientName,
	StartDate,
	Source,
	Product,
	CommType,
	Status,
	Premium,
	Margin,
	Fee,
	BranchNo,
	BranchName,
	OWFirmRef,
	DataSourceRef,
	IndemnityPeriod,
	SellerName,
	OWSellerRef,
	InsuredPostCode,
	PESN
)
SELECT * 
FROM OPENROWSET(''Microsoft.ACE.OLEDB.12.0'', 
''Text;HDR=YES;FMT=Delimited;Database=' + @Path + ';"'', 
''SELECT * FROM [' + @DataFileName + ']'')'

exec (@sql)

set @RowCount = @@rowcount

set @Process = 'Import File Rows = ' + convert(varchar(20),@RowCount)

exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client
*/

/****************************************************************************

	Transfer to the original Import file for the transformation steps
																		
****************************************************************************/


exec msp_ProcessLog @PhaseStart, 'Transfer Imported Table', null, @Module, @Client

truncate table owt_PaymentshieldImport

set identity_insert owt_PaymentshieldImport on

insert into owt_PaymentshieldImport
(
	Period,
	PolicyReference,
	OWPolicyRef,
	ClientName,
	StartDate,
	Source,
	Product,
	CommType,
	Status,
	Premium,
	Margin,
	Fee,
	BranchName,
	BranchNo,
	SellerName,
	OWFirmRef,
	UniqueRowID,
	OW_SellerRef,
	PESN
)
select	replace(Period,',',''),
		PolicyReference,
		OWPolicyRef,
		ClientName,
		convert(datetime,StartDate,103),
		Source,
		Product,
		CommType,
		Status,
		Premium,
		Margin,
		Fee,
		BranchName,
		case when patindex('%-%',BranchNo) > 0	-- Remove hyphen and everything after 
			then stuff(BranchNo,patindex('%-%',BranchNo),50,'')
			else BranchNo
		end as BranchNo,
		SellerName,
		OWFirmRef,
		UniqueRowID,
		OWSellerRef,
		PESN

from	owt_PaymentshieldImportPanel
	
set identity_insert owt_PaymentshieldImport off

exec msp_ProcessLog @PhaseEnd, 'Transfer Imported Table', null, @Module, @Client


/****************************************************************************

			E N D															

****************************************************************************/


exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client


GO
