/****** Object:  StoredProcedure [dbo].[owp_PaymentshieldSwiftAgentXrefDataClean]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/************************************************************************************************
  	 Program:  	owp_PaymentshieldSwiftAgentXrefDataClean						
	  Author:	A Groves
Date created:	04/09/2017
											
 Description:   This proc comprises the SQL code that existed in DTS script "Payment_Shield_Import_Extract"
				and has now been moved to a stored procedure as part of the DTS to SSIS project.
				DTS script "Payment_Shield_Import_Extract" was used for loading "Seller Log.xls" to
				table dbo.owhot_PaymentshieldSwiftAgentXref.
				
				It is called as follows:
					exec owp_PaymentshieldSwiftAgentXrefDataClean 'Openwork', 'PaymentShield' 
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------	
04/10/2017	A Groves	Code added from the old "Seller Log Repair Report" job which has been 
						replaced by the "Identify Missing UIDs" job. This update was still 
						needed to ensure effective matching between the Seller Log and the 
						staged Paymentshield data.			
************************************************************************************************/
CREATE PROCEDURE [dbo].[owp_PaymentshieldSwiftAgentXrefDataClean] 
	@Client		varchar(50),
	@Module		varchar(50)
AS

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100)
		
		
/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/


set @PhaseStart					= 'START'
set @PhaseEnd   				= 'END'
set @PhaseLog					= 'LOG'
set @PhaseError					= 'ERROR'
set @Process					= object_name(@@procid)

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client


/****************************************************************************

	Main process	
																		
****************************************************************************/


--Delete illegal characters
Delete FROM  owhot_PaymentshieldSwiftAgentXref
Where	PayshieldAgent='needed' 
or		PayshieldAgent is null 
or		PayshieldAgent='tbc' 
or		PayshieldAgent='?' 

exec msp_ProcessLog @PhaseLog, 'Completed - Delete-1', null, @Module, @Client

--Update create date field with today's date
update	owhot_PaymentshieldSwiftAgentXref
	set		CreateDate = getdate(),
			Deleted = 'N',				--Extra added in which used to be mapped with hardcoding in the old DTS script.
			CreatedBy = 'Automatic'		--Extra added in which used to be mapped with hardcoding in the old DTS script.
Where	CreateDate is null

exec msp_ProcessLog @PhaseLog, 'Completed - Update-1', null, @Module, @Client

--Find string containing the character "(" then update table
declare @item varchar(50)
declare @txtData varchar(15)
select	@item = payshieldAgent 
FROM	owhot_PaymentshieldSwiftAgentXref  
WHERE	PayshieldAgent LIKE '%%)'

while (@item <>' ')
Begin
	declare @lent int 
	SELECT @lent = CHARINDEX('(', @item)
	SELECT @txtData =  Left (@item, @lent-1)

	update owhot_PaymentshieldSwiftAgentXref
		set  PayshieldAgent = @txtData
	Where PayshieldAgent = @item

	set @item =''

	select	@item = payshieldAgent 
	FROM	owhot_PaymentshieldSwiftAgentXref  
	WHERE	PayshieldAgent LIKE '%%)'

	if(@@rowcount =0)
	begin
		Break
	end
End 

exec msp_ProcessLog @PhaseLog, 'Completed - While-1', null, @Module, @Client

---Find the character "-" and remove the char and numbers to the right of this character
declare @item0 varchar(50)
declare @txtData0 varchar(15)
select	@item0 = payshieldAgent 
FROM	owhot_PaymentshieldSwiftAgentXref  
WHERE	PayshieldAgent LIKE '%-%'

while (@item0 <>' ')
Begin
	declare @lent0 int 
	SELECT @lent0 = CHARINDEX('-', @item0)
	SELECT @txtData0 =  Left (@item0, @lent0-1)

	update owhot_PaymentshieldSwiftAgentXref
		set  PayshieldAgent = @txtData0
	Where PayshieldAgent = @item0

	set @item0 =''

	select	@item0 = payshieldAgent 
	FROM	owhot_PaymentshieldSwiftAgentXref  
	WHERE	PayshieldAgent LIKE '%-%'

	if(@@rowcount =0)
	begin
		Break
	end
End 

exec msp_ProcessLog @PhaseLog, 'Completed - While-2', null, @Module, @Client

---Find character "." and remove the decimal point char at the end of the string
declare @item01 varchar(50)
declare @txtData01 varchar(15)

select	@item01 = payshieldAgent 
FROM	owhot_PaymentshieldSwiftAgentXref  
WHERE	PayshieldAgent LIKE '%.'

while (@item01 <>' ')
Begin
	declare @lent01 int 
	SELECT @lent01 = CHARINDEX('.', @item01)
	SELECT @txtData01 =  Left (@item01, @lent01-1)

	update owhot_PaymentshieldSwiftAgentXref
		set  PayshieldAgent = @txtData01
	Where PayshieldAgent = @item01

	set @item01 =''

	select	@item01 = payshieldAgent 
	FROM	owhot_PaymentshieldSwiftAgentXref  
	WHERE	PayshieldAgent LIKE '%.'

	if(@@rowcount =0)
	begin
		Break
	end
End 

exec msp_ProcessLog @PhaseLog, 'Completed - While-3', null, @Module, @Client

---Find character "/" and remove the decimal point char at the end of the string
declare @item001 varchar(50)
declare @txtData001 varchar(15)

select	@item001 = payshieldAgent 
FROM	owhot_PaymentshieldSwiftAgentXref  
WHERE	PayshieldAgent LIKE '%/%'

while (@item001 <>' ')
Begin
	declare @lent001 int 
	SELECT @lent001 = CHARINDEX('/', @item001)
	SELECT @txtData001 =  Left (@item001, @lent001-1)

	update owhot_PaymentshieldSwiftAgentXref
		set  PayshieldAgent = @txtData001
	Where PayshieldAgent = @item001

	set @item001 =''

	select	@item001 = payshieldAgent 
	FROM	owhot_PaymentshieldSwiftAgentXref  
	WHERE	PayshieldAgent LIKE '%/%'

	if(@@rowcount =0)
	begin
		Break
	end
End

exec msp_ProcessLog @PhaseLog, 'Completed - While-4', null, @Module, @Client

--- Remove duplicates from table
SELECT	PayshieldAgent, Deleted,AgentCode,CreateDate,CreatedBy,DateUpdated,UpdatedBy,FranchiseName
INTO	#duplicate_table
FROM	owhot_PaymentshieldSwiftAgentXRef
GROUP	BY PayshieldAgent,Deleted,AgentCode,CreateDate,CreatedBy,DateUpdated,UpdatedBy,FranchiseName
HAVING	COUNT(PayshieldAgent) > 1

exec msp_ProcessLog @PhaseLog, 'Completed - Select Into', null, @Module, @Client

DELETE owhot_PaymentshieldSwiftAgentXRef
WHERE PayshieldAgent IN (SELECT PayshieldAgent FROM #duplicate_table)

exec msp_ProcessLog @PhaseLog, 'Completed - Delete-2', null, @Module, @Client

INSERT owhot_PaymentshieldSwiftAgentXRef
	SELECT * FROM #duplicate_table

DROP TABLE #duplicate_table


-- AG 04/10/2017. The code below used to be in the Seller Log Repair Report
-- job as a distinct jobstep. Since that job has been replaced with the 
-- "Identify Missing UIDs" job, then the code has had to be added in somewhere
--.....and this seems the best place for it.

-- AG 19/06/2014. New batch step to remove unwanted characters
-- after either an underscore or a hyphen.

update dbo.owhot_PaymentshieldSwiftAgentXref
	set PayshieldAgent = stuff(PayshieldAgent,patindex('%[-_]%',PayshieldAgent),100,'')
where patindex('%[-_]%',PayshieldAgent) > 0

exec msp_ProcessLog @PhaseLog, 'Completed - Update-2', null, @Module, @Client

/****************************************************************************

			E N D															

****************************************************************************/


exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

GO
/****** Object:  StoredProcedure [dbo].[owp_PaymentshieldWrittenValidationAndDestination]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/****************************************************************************
  	 Program:  	owp_PaymentshieldWrittenValidationAndDestination						
	  Author:	A Groves
Date created:	27/02/2014
											
 Description:   This proc will validate the Paymentshield Written data on the
				staging table and will load rows that are OK and park rows that
				require data fixing.

				It is called as follows:
				declare @LogID int
				exec owp_PaymentshieldWrittenValidationAndDestination 'Openwork', 'PaymentshieldWritten', @LogID output
									
Amendment History								
-----------------								
											
Date		Who			Description				
----		---			-----------			
14/03/2014	A Groves	Quit proc if no data in the file being loaded by checking
						max ROWID is zero as a row of empty commas are possible.
23/03/2014	A Groves	a) The above described quit proc.... has been moved into the
							job for better control.
						b) Truncate staging table to ensure there is no risk of loading
							staged data again if this proc is being used to re-process 
							parked data.
09/04/2014	A Groves	SR301284 Add seller fuzzy matching to improve population and
						to create "clean" adviser details.
****************************************************************************/
CREATE PROCEDURE [dbo].[owp_PaymentshieldWrittenValidationAndDestination]
	@Client		varchar(50),
	@Module		varchar(50),
	@LogID		int	output
AS

SET NOCOUNT ON

declare @PhaseStart					varchar(50),
		@PhaseEnd					varchar(50),
		@PhaseLog					varchar(50),
		@PhaseError					varchar(50),
		@Process					varchar(100),
		@Path						varchar(255),
		@DataFileName				varchar(255),
		@RowCount					int,
		@DestinationRowCount		int,
		@ErrMsg						varchar(400),
		@ErrMsgBrief				varchar(100), 
		@Severity 					int,
		@SQL						varchar(8000),
		@RowsParked					bit,
		@DateTimeRowLoaded			datetime

set @PhaseStart				= 'START'
set @PhaseEnd   			= 'END'
set @PhaseLog				= 'LOG'
set @PhaseError				= 'ERROR'
set @Process				= object_name(@@procid)
set @RowsParked				= 0
set @DestinationRowCount	= 0
set @DateTimeRowLoaded		= GETDATE()

/****************************************************************************

	Log start																
																		
****************************************************************************/

exec msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client

/****************************************************************************

	Start transaction																
																		
****************************************************************************/

BEGIN TRY

	BEGIN TRANSACTION

	/****************************************************************************

		Update Log here with the file dedupe check data rather than in the 
		SSIS script as this step can fall over and we don't want that to happen 
		in the SSIS script as we need to see the data loaded to be able to find 
		the bad data. Also, this must be done before anything else as very soon, 
		some rows may be moved off the staging table and parked which would make 
		the HashTotal invalid. 
		Note: The HashTotal won't be updated below if this proc is re-running to
		attempt to re-process parked data. In this situation, 
		owt_PaymentshieldAutoImportLog.LoadInProgress will be 0 which is what we
		want in this situation.		
															
	****************************************************************************/

	select	@LogID = ID
	from	owt_PaymentshieldAutoImportLog
	where	FileType = 'Written'
	and		LoadInProgress = 1
	
	update	implog
		set SumOfPremium = (select sum(convert(decimal(12,2),Premium)) from owt_PaymentshieldWrittenStaging),
			SumOfLESN = (select sum(convert(bigint,LESN)) from owt_PaymentshieldWrittenStaging),
			SumOfPESN = (select sum(convert(bigint,PESN)) from owt_PaymentshieldWrittenStaging)
	from	owt_PaymentshieldAutoImportLog implog
	where	FileType = 'Written'
	and		LoadInProgress = 1
	
	update	implog
		set HashTotal = (SumOfPremium*100) + SumOfLESN + SumOfPESN
	from	owt_PaymentshieldAutoImportLog implog
	where	FileType = 'Written'
	and		LoadInProgress = 1

	/****************************************************************************

		Now the HashTotal has been derived, reintroduce the parked data.
		Note that if it still can't be processed then it will be parked
		again later on.
																		
	****************************************************************************/

	insert into owt_PaymentshieldWrittenStaging
		select	*
		from	owt_PaymentshieldWrittenStagingParked

	delete
	from	owt_PaymentshieldWrittenStagingParked
	
	/****************************************************************************

		Get any missing FranchiseUIDs. Any rows for which a FranchiseUID can't be
		found must be moved to the Parked table.
																		
	****************************************************************************/

	-- Since stripping out the _BYO derivatives, there are now dupes in the table. This step removes the dupes.
	select	Xref.*
	into	#owhot_PayshieldSwiftAgentXref
	from	owhot_PaymentshieldSwiftAgentXref Xref
			inner join	(select PayshieldAgent, max(ID) as MaxID
							from owhot_PaymentshieldSwiftAgentXref
							group by PayshieldAgent) as DedupedPayshieldAgent
						on DedupedPayshieldAgent.MaxID = Xref.ID

	-- Strip off the unwanted trailing part of the Branch Number
	update owt_PaymentshieldWrittenStaging
		set BranchNumber = stuff(BranchNumber,patindex('%-%',BranchNumber),60,'')
	where patindex('%-%',BranchNumber) > 0

	-- Insert missing FranchiseUID
	update	s
			set FranchiseUID = x.AgentCode
	from	owt_PaymentshieldWrittenStaging s
			inner join #owhot_PayshieldSwiftAgentXref x on x.PayshieldAgent = s.BranchNumber	
	where	s.FranchiseUID is null

	insert into owt_PaymentshieldWrittenStagingParked
		select	*
		from	owt_PaymentshieldWrittenStaging
		where	FranchiseUID is null

	delete 
	from	owt_PaymentshieldWrittenStaging
	where	FranchiseUID is null

	set @RowCount = @@rowcount
	
	if @RowCount > 0 
	begin
		set @RowsParked = 1
		-- Log and carry on - this shouldn't stop the load.
		update	owt_PaymentshieldAutoImportLog
			set ValidationIssues = case when @RowCount = 1 then 'One row parked' else 'Multiple rows parked' end 
		where	FileType = 'Written'
		and		LoadInProgress = 1
	end

	/****************************************************************************

		Check the HashTotal to see if we have a duplicate file
																		
	****************************************************************************/

	select	@RowCount = count(*)
	from	owt_PaymentshieldAutoImportLog curr
			inner join owt_PaymentshieldAutoImportLog prev
							on prev.FileType = curr.FileType
							and	prev.LoadInProgress <> curr.LoadInProgress
							and	prev.HashTotal = curr.HashTotal
	where	curr.FileType = 'Written'
	and		curr.LoadInProgress = 1
	
	if @Rowcount > 0
	begin
		update	owt_PaymentshieldAutoImportLog
				set ValidationIssues = 'Duplicate File - Not Loaded To Destination',
					LoadToDestinationStatus = 'Failed',
					LoadInProgress = 0
		where	FileType = 'Written'
		and		LoadInProgress = 1

		truncate table owt_PaymentshieldWrittenStaging	-- AG 27/03/2014

		COMMIT TRANSACTION      
		RETURN
	end
	
	/****************************************************************************

		Validation done so now attempt to load the data to the destination
																		
	****************************************************************************/

	insert into owt_PaymentshieldWritten
	select	convert(int,RowID) as SourceRowID,
			convert(datetime,FileDate,112) as FileDate,
			PolicyReference,
			ClientTitle,
			ClientFirstName,
			ClientLastName,
			convert(datetime,ClientDOB,112) as ClientDOB,
			convert(datetime,DateWritten,112) as DateWritten,
			ProductType,
			convert(decimal(12,2),Premium) as Premium,
			FranchiseName,
			case when isnumeric(FranchiseUID)=0 or len(FranchiseUID)>7 then NULL else FranchiseUID end as FranchiseUID,
			Frequency,
			case			-- AG 09/04/2014
				when MICodes.Code is null then ltrim(rtrim(SellerName))	-- No match on person title so title assumed not present
				else ltrim(rtrim(stuff(replace(SellerName,'.',''),1,len(MICodes.Code),''))) 
			end as SellerName,			
			case when isnumeric(SellerUID)=0 or len(SellerUID)>7 then NULL else SellerUID end as SellerUID,
			CommType,
			convert(decimal(6,2),CommRate) as CommRate,
			convert(decimal(6,2),EnhancedRate) as EnhancedRate,
			convert(decimal(6,2),DARate) as DARate,
			Company,
			case IntroducedCase	when 'No' then 'N' else 'Y' end as IntroducedCase,
			convert(int,LESN) as LESN,
			convert(int,PESN) as PESN,
			BranchNumber,
			@DateTimeRowLoaded as DateTimeRowLoaded,
			SellerName as OriginalSellerName,
			case when isnumeric(SellerUID)=0 or len(SellerUID)>7 then NULL else SellerUID end as OriginalSellerUID,
			NULL as SellerMatchingMethod
	from	owt_PaymentshieldWrittenStaging
			left join dbo.msit_MIWarehouseCodesAndDescriptions MICodes		-- AG 09/04/2014
						on  MICodes.ColumnName = 'PersonTitle' 
						and ltrim(rtrim(replace(SellerName,'.',''))) like MICodes.Code + ' %'
						
	set @DestinationRowCount = @@rowcount
	
	-- The inserts may have parked some data and loaded the rest to the destination table.
	-- Now truncate the staging table in case this stored proc is run again to load
	-- the parked data. We don't want the staged data to be loaded again creating duplicates.
	
	truncate table owt_PaymentshieldWrittenStaging	-- AG 27/03/2014
	
	/****************************************************************************

		Fuzzy match the advisers.	AG 09/04/2014
																		
	****************************************************************************/

	create table #AdviserSoundex
	(
		[AdviserUID]				varchar(7),
		[EnterpriseUID]				varchar(7),
		[Forenames]					varchar(60),
		[FirstForename]				varchar(60),
		[Surname]					varchar(60),
		[FirstForenameWithSurname]	varchar(121),
		[SoundexForename]			varchar(20),
		[SoundexSurname]			varchar(20)
	)

	insert into #AdviserSoundex
		exec pr_etl_AdviserSoundexEncoding 

	-- Update all rows as it tidies up the Seller Name to just one forename plus surname
	-- so that ultimately if this data ends up in OpenAccess then the drop down Adviser
	-- selection box will have consistent adviser names. However, only update the
	-- SellerMatchingMethod if the data was originally blank. Don't over-reward the process!
	update pshield
		set	SellerUID				= sdx.AdviserUID,
			SellerName				= sdx.FirstForenameWithSurname,
			SellerMatchingMethod	=	case 
											when (pshield.SellerUID is null or pshield.SellerName is null)
											then
												case 
													when isnull(pshield.SellerUID,'') = isnull(sdx.AdviserUID,'') then 'ExactUID' 
													when isnull(pshield.SellerName,'') = isnull(sdx.FirstForenameWithSurname,'') then 'ExactName' 
													else 'Fuzzy' 
												end
											else null
										end
	from	owt_PaymentshieldWritten pshield
			inner join #AdviserSoundex sdx on sdx.EnterpriseUID = pshield.FranchiseUID	
	where	pshield.DateTimeRowLoaded = @DateTimeRowLoaded	
	and		((pshield.SellerName = sdx.FirstForenameWithSurname					-- Whole name matches exactly or
	or		
			(sdx.SoundexSurname = dbo.owf_Soundex(pshield.SellerName,'L')		-- Soundex of surname must match and
			and		(left(sdx.SoundexForename,2) = left(dbo.owf_Soundex(pshield.SellerName,'F'),2)	-- Soundex of first two forename letters match or	
					or dbo.owf_AbbreviatedMatch(sdx.FirstForenameWithSurname,pshield.SellerName) = 1))))			-- The names are abbreviated matches		

	/****************************************************************************

		All good - so commit transaction
																		
	****************************************************************************/

	COMMIT TRANSACTION      

	update	owt_PaymentshieldAutoImportLog
		set LoadInProgress = 0,
			LoadToDestinationStatus = case when @RowsParked = 0 then 'Full' else 'Partial' end, 
			RowsLoadedToDestination = @DestinationRowCount
	where	FileType = 'Written'
	and		LoadInProgress = 1
	
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

END TRY

BEGIN CATCH 

	IF @@TRANCOUNT <> 0
		ROLLBACK TRANSACTION
		
	SET @ErrMsg = 'Load of PaymentshieldWritten failed.' + REPLACE(ERROR_MESSAGE(), '.', '') + ' (error no: ' + CAST(ERROR_NUMBER() AS VARCHAR(10)) + ') on line ' + CAST(ERROR_LINE() AS VARCHAR(10)) + CASE WHEN ERROR_PROCEDURE() IS NOT NULL THEN ' in ' + ERROR_PROCEDURE() ELSE '' END
	SET @Severity = ERROR_SEVERITY()
	set @ErrMsgBrief = left(@ErrMsg,100)
	  
	update	owt_PaymentshieldAutoImportLog
		set LoadToDestinationStatus = 'Failed',
			LoadInProgress = 0,
			RowsLoadedToDestination = @DestinationRowCount
	where	FileType = 'Written'
	and		LoadInProgress = 1

	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	exec msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client

	RAISERROR(@ErrMsg, @Severity , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/





GO
