CREATE PROCEDURE [dbo].[owp_policywithclient_details_wh] AS

set nocount on
SELECT   
p.PolicyRef AS CaseID,p.CONT_NUM AS ProviderRef,p.COMP_CODE AS Provider,
p.ProductCode as Product,p.createdate as CreatedOn,p.start_date as StartDate,
c.refer as ClientRef,c.firstnames as Forename,c.name as Surname
--,*

FROM     msit_S_POLMAI p
inner join msit_s_client c on c.client_num = p.client_num

--where
--p.cont_num in
--(Select cont_num
--from s_polmai
--where cont_num is not null 
--and comp_code = 'SIML'
--group by cont_num 
--having count(*) > 1)
--p.comp_code = 'SIML'
--and p.cont_num is null
--and p.policyref is null


ORDER BY p.PolicyRef,p.pol_num
