		END TRY BEGIN CATCH END CATCH
		BEGIN TRY
			CREATE INDEX [TransAgentSplitHierarchyHistoryID] ON [dbo].[sa_swift_S_AGMFIL] ( [TransAgentSplitHierarchyHistoryID] );
		END TRY BEGIN CATCH END CATCH
		BEGIN TRY
			CREATE INDEX [AGENT_CODE] ON [dbo].[sa_swift_S_AGMPAY] ( [AGENT_CODE] );
		END TRY BEGIN CATCH END CATCH
		BEGIN TRY
