		END TRY BEGIN CATCH END CATCH
		BEGIN TRY
			CREATE INDEX [Active] ON [dbo].[sa_swift_TransAgentSplitHierarchyHistory] ( [Active] );
		END TRY BEGIN CATCH END CATCH
		BEGIN TRY
			CREATE INDEX [AccessAgentCode] ON [dbo].[sa_swift_TransAgentSplitHierarchyHistory] ( [AccessAgentCode] );
		END TRY BEGIN CATCH END CATCH
		BEGIN TRY
			CREATE INDEX [FranchiseAgentCode] ON [dbo].[sa_swift_TransAgentSplitHierarchyHistory] ( [FranchiseAgentCode] );
		END TRY BEGIN CATCH END CATCH
		BEGIN TRY
