		END TRY BEGIN CATCH END CATCH
		BEGIN TRY
			CREATE INDEX [IDX_sa_swift_S_PACC] ON [dbo].[sa_swift_S_PACC] ( [STATEMENT] ) INCLUDE ( [ID], [POL_NUM], [DATE_DUE], [AMOUNT_DUE], [DATE_RECV], [AMOUNT_REC], [TYPE], [STATUS], [ADJUST], [COMP_CODE], [CLIENT_NUM], [NOTES], [Rebate], [StatementCreatedFrom], [VAT], [UnallocatedReasonCode], [RenewalType], [TransactionID], [PMBSerial], [PMBContra], [MatchID], [FutureExpectationID], [Manual], [Authorised], [OriginalAmountReceived], [CreatedBy], [CreatedDate], [AuthorisedBy], [AuthorisedDate], [ParentID] );
		END TRY BEGIN CATCH END CATCH
		BEGIN TRY
			CREATE NONCLUSTERED INDEX [IX_sa_swift_AgentTypeHistory_AgentCode] ON [dbo].[sa_swift_AgentTypeHistory] ( [AgentType] ) INCLUDE ( [AgentCode] );
		END TRY BEGIN CATCH END CATCH
		BEGIN TRY
			CREATE NONCLUSTERED INDEX [IX_sa_swift_AgentUplifts_AgentCode] ON [dbo].[sa_swift_AgentUplifts]	( [AgentCode], [ProductCode], [DateInForce]	);
		END TRY BEGIN CATCH END CATCH
		RETURN;
	END

	IF @SourceSystem = 'insight'
	BEGIN
		BEGIN TRY
			CREATE INDEX [ATT_Name] ON [dbo].[sa_insight_Attribute] ( [ATT_Name] );
		END TRY BEGIN CATCH END CATCH
		BEGIN TRY
			CREATE INDEX [ATTL_ParentID] ON [dbo].[sa_insight_AttributeLink] ( [ATTL_ParentID] );
		END TRY BEGIN CATCH END CATCH
		BEGIN TRY
			CREATE INDEX [ATTL_AttributeID] ON [dbo].[sa_insight_AttributeLink] ( [ATTL_AttributeID] ) INCLUDE ( [ATTL_AttributeValue] );
		END TRY BEGIN CATCH END CATCH
		BEGIN TRY
			CREATE INDEX [BPOL_ParentID] ON [dbo].[sa_insight_BasicPolicy] ( [BPOL_ParentID] );
