/****** Object:  StoredProcedure [dbo].[owp_rdr_get_APEForPrincipalEnterprise]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE PROCEDURE [dbo].[owp_rdr_get_APEForPrincipalEnterprise]
	@SellerUID VARCHAR(20), 
	@EnterpriseUID VARCHAR(20)
AS
BEGIN
	SET NOCOUNT ON;

	SELECT CONVERT(NUMERIC(18,2),SUM(APE)) AS APE, ProductGroup     
	FROM msit_OpenworkAdviserListing AS a
    INNER JOIN msit_CommissionStatementPeriods AS b 
		ON a.[Month] = b.[MONTH] 
    WHERE BusinessCode = @EnterpriseUID AND SellerCode = @SellerUID
            AND b.[Year] = DATEPART(yy,a.[Month])
            AND b.[Year] = DATEPART(yy,getdate()) 
    GROUP BY ProductGroup

END
GO
/****** Object:  StoredProcedure [dbo].[owp_rdr_get_education_by_areamanager_sp]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
CREATE PROCEDURE [dbo].[owp_rdr_get_education_by_areamanager_sp]

	@ISEDUCATED	VARCHAR(1) = NULL

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;


DECLARE @EDUCATIONTABLE TABLE 
	(
	enterprisename	varchar(255) NOT NULL,
	franchisecode		varchar(25) NULL,
	agentname		varchar(255) NULL,
	education			varchar(255)	NULL,
	areamanager		varchar(255)	NULL,
	educationdate	smalldatetime NULL,
	educatedflag		varchar(1) NULL
	)

DECLARE @EDUCATEDEXCEPTION	VARCHAR(150)
SET @EDUCATEDEXCEPTION = 'Not Started'

DECLARE @COMPLIANCECODE VARCHAR(10)
SET @COMPLIANCECODE = 'cob'

DECLARE @GIVESADVICE VARCHAR(1)
SET @GIVESADVICE = 'Y'

/* EDUCATED */
INSERT INTO @EDUCATIONTABLE (enterprisename,franchisecode,agentname,education,areamanager,educationdate,educatedflag)

SELECT 
enterprisename = RTRIM(isnull(b.TradingName,b.DESCN)),
enterpriseid = ISNULL(a.FranchiseCode,a.Firm),
agentname = MAX(RTRIM(a.DESCN)),
education = [stage_1],
areamanager = ad.descn,
educationdate = MAX([education_date]),
educatedflag = 'Y'

FROM mstt_Agents AS A 
INNER JOIN mstt_AgentCompetence AS AC ON A.code = AC.agentcode 
LEFT JOIN dbo.rdr_rdrprincipaldata_tbl AS RDR ON A.CODE = RDR.agent_uid
LEFT JOIN mstt_Agents b ON b.code = a.FIRM
LEFT JOIN mstt_Agents ad on ad.code = a.manager4code
WHERE stage_1 IS NOT NULL  
	AND RTRIM(stage_1) <> ''
	AND stage_1 NOT IN(@EDUCATEDEXCEPTION) 
	AND LOWER(ac.compliancecategorycode) IN(@COMPLIANCECODE)
	AND a.givesadvice IN(@GIVESADVICE)
	AND a.AgentType IN(4,43,51,52,53) 
	AND a.CompetentStatus in (1) --2 = Left
	AND ac.enddate IS NULL

OR RTRIM(stage_1) <> '' 
	AND stage_1 NOT IN(@EDUCATEDEXCEPTION) 
	AND LOWER(ac.compliancecategorycode) IN(@COMPLIANCECODE)
	AND a.givesadvice IN(@GIVESADVICE)
	AND a.AgentType IN(4,43,51,52,53) 
	AND a.CompetentStatus in (1) --2 = Left
	AND ac.enddate IS NULL

OR LEN(RTRIM(stage_1)) > 0 
	AND stage_1 NOT IN(@EDUCATEDEXCEPTION) 
	AND RTRIM(stage_1) <> ''
	AND LOWER(ac.compliancecategorycode) IN(@COMPLIANCECODE)
	AND a.givesadvice IN(@GIVESADVICE)
	AND a.AgentType IN(4,43,51,52,53) 
	AND a.CompetentStatus in (1) --2 = Left
	AND ac.enddate IS NULL

GROUP BY 
	ad.descn,
	RTRIM(isnull(b.TradingName,b.DESCN)),
	ISNULL(a.FranchiseCode,a.Firm),
	[stage_1]

/* Non Educated */
INSERT INTO @EDUCATIONTABLE (enterprisename,franchisecode,agentname,education,areamanager,educationdate,educatedflag)

SELECT
	enterprisename = RTRIM(isnull(b.TradingName,b.DESCN)),
	enterpriseid = ISNULL(a.FranchiseCode,a.Firm),
	agentname = MAX(RTRIM(a.DESCN)),
	education = NULL,
	areamanager = ad.descn,
	educationdate = NULL,
	educatedflag = 'N'
FROM mstt_Agents AS A 
INNER JOIN mstt_AgentCompetence AS AC ON A.code = AC.agentcode 
LEFT JOIN dbo.rdr_rdrprincipaldata_tbl AS RDR ON A.CODE = RDR.agent_uid
LEFT JOIN mstt_Agents b ON b.code = a.FIRM
LEFT JOIN mstt_Agents ad on ad.code = a.manager4code
WHERE stage_1 IS NULL 
	AND ISNULL(a.FranchiseCode,a.Firm) NOT IN(SELECT franchisecode FROM @EDUCATIONTABLE)
	AND LOWER(ac.compliancecategorycode) IN(@COMPLIANCECODE)
	AND a.givesadvice IN(@GIVESADVICE)
	AND a.AgentType IN(4,43,51,52,53) 
	AND a.CompetentStatus in (1) --2 = Left
	AND ac.enddate IS NULL

OR RTRIM(stage_1) = '' 
	AND ISNULL(a.FranchiseCode,a.Firm) NOT IN(SELECT franchisecode FROM @EDUCATIONTABLE)
	AND LOWER(ac.compliancecategorycode) IN(@COMPLIANCECODE)
	AND a.givesadvice IN(@GIVESADVICE)
	AND a.AgentType IN(4,43,51,52,53) 
	AND a.CompetentStatus in (1) --2 = Left
	AND ac.enddate IS NULL

OR LEN(RTRIM(stage_1)) <= 0 
	AND ISNULL(a.FranchiseCode,a.Firm) NOT IN(SELECT franchisecode FROM @EDUCATIONTABLE)
	AND LOWER(ac.compliancecategorycode) IN(@COMPLIANCECODE)
	AND a.givesadvice IN(@GIVESADVICE)
	AND a.AgentType IN(4,43,51,52,53) 
	AND a.CompetentStatus in (1) --2 = Left
	AND ac.enddate IS NULL

GROUP BY 
	ISNULL(a.FranchiseCode,a.Firm),
	RTRIM(isnull(b.TradingName,b.DESCN)), 	
	ad.descn
ORDER BY ad.descn, RTRIM(isnull(b.TradingName,b.DESCN))

IF @ISEDUCATED IS NULL
	BEGIN
		SELECT * FROM @EDUCATIONTABLE 
	END
ELSE
	BEGIN
		SELECT * FROM @EDUCATIONTABLE WHERE educatedflag = @ISEDUCATED
	END

END
GO
/****** Object:  StoredProcedure [dbo].[owp_rdr_get_NBIForPrincipalEnterprise]    Script Date: 7/3/2026 3:44:25 PM ******/
