CREATE PROCEDURE [dbo].[owp_rdr_get_NBIForPrincipalEnterprise]
	@SellerUID VARCHAR(20), 
	@EnterpriseUID VARCHAR(20)
AS
BEGIN
	SET NOCOUNT ON;

	SELECT CONVERT(NUMERIC(18,2),SUM(TotDue_Enhd)) AS NBI, ProductGroup     
	FROM msit_OpenworkAdviserListing AS a
    INNER JOIN msit_CommissionStatementPeriods AS b 
		ON a.[Month] = b.[MONTH] 
    WHERE BusinessCode = @EnterpriseUID AND SellerCode = @SellerUID
            AND b.[Year] = DATEPART(yy,a.[Month])
            AND b.[Year] = DATEPART(yy,getdate()) 
    GROUP BY ProductGroup

END
GO
