CREATE PROCEDURE [dbo].[owp_rdr_get_PrincipalsPaged]    

	@PageSize INT = 10,
	@PageNumber INT = 1,
	@SellerNameFilter VARCHAR(250) = NULL,
	@SellerUIDFilter	 VARCHAR(10) = NULL,
	@EnterpriseNameFilter VARCHAR(250) = NULL,
	@EnterpriseUIDFilter VARCHAR(10) = NULL,
	@ASDFilter VARCHAR(250) = NULL,
	@OrderBySellerNameAsc BIT = 0,
	@OrderBySellerNameDesc BIT = 0,
	@OrderByAgentTypeAsc BIT = 0,
	@OrderByAgentTypeDesc BIT = 0,
	@OrderByEnterpriseNameAsc BIT = 0,
	@OrderByEnterpriseNameDesc BIT = 0,
	@OrderBySellerUIDAsc BIT = 0,
	@OrderBySellerUIDDesc BIT = 0,
	@OrderByEnterpriseUIDAsc BIT = 0,
	@OrderByEnterpriseUIDDesc BIT = 0,
	@OrderByAppointmentDateAsc BIT = 0,
	@OrderByAppointmentDateDesc BIT = 0,
	@OrderByDateOfBirthAsc BIT = 0,
	@OrderByDateOfBirthDesc BIT = 0,
	@OrderByASDAsc BIT = 0,
	@OrderByASDDesc BIT = 0,
	@OrderByLocationAsc BIT = 0,
	@OrderByLocationDesc BIT = 0,
	@OrderByStatusAsc BIT = 0,
	@OrderByStatusDesc BIT = 0,
	@OrderByNumberSellersAsc BIT = 0,
	@OrderByNumberSellersDesc BIT = 0,
	@OrderByDecisionTreeAsc BIT = 0,
	@OrderByDecisionTreeDesc BIT = 0,
	@OrderByPeerGroupAsc BIT = 0,
	@OrderByPeerGroupDesc BIT = 0,
	@OrderByRDRTeamContactAsc BIT = 0,
	@OrderByRDRTeamContactDesc BIT = 0,
	@OrderByRDRTeamVisitAsc BIT = 0,
	@OrderByRDRTeamVisitDesc BIT = 0,
	@OrderBySeminarDateAsc BIT = 0,
	@OrderBySeminarDateDesc BIT = 0,
	@OrderByEducationDateAsc BIT = 0,
	@OrderByEducationDateDesc BIT = 0,
	@OrderByStageAsc BIT = 0,
	@OrderByStageDesc BIT = 0,
	@OrderByWorkshopDateAsc BIT = 0,
	@OrderByWorkshopDateDesc BIT = 0

AS
BEGIN
	SET NOCOUNT ON;
	SET DATEFORMAT dmy

	DECLARE @startRowIndex INT
	SET @startRowIndex = ((@PageNumber - 1) * @PageSize) + 1

	DECLARE @lastRowIndex INT
	SET @lastRowIndex = @startRowIndex + (@PageSize - 1)
	
	/* table variable used as num rows only going to be around 1100 */
	DECLARE @swiftTrackingData TABLE 
	(
		[Seller Name]		VARCHAR(255),
		[Seller UID]		VARCHAR(7),
		[Agent Type]		VARCHAR(150),
		[Enterprise Name]	VARCHAR(255),
		[Enterprise UID]	VARCHAR(7),
		[Date of Birth]		SMALLDATETIME,
		[Appointment Date]	SMALLDATETIME,
		[ASD]				VARCHAR(255),
		[Location]			VARCHAR(255),
		[Trading Style]		VARCHAR(255),
		[Trading Name]		VARCHAR(255),
		[Status]			VARCHAR(100),
		[Contact Email]		VARCHAR(100),	
		[No. of Sellers]	VARCHAR(10),
		[Telephone No.]		VARCHAR(100)
	)

	INSERT INTO @swiftTrackingData EXEC dbo.owp_rdr_get_swift_TrackingData_sp


	SELECT RowNum, [Seller Name], [Agent Type], [Enterprise Name], [Seller UID], [Enterprise UID], 
		[Appointment Date], [Date of Birth], [ASD], [Location], [Status], [No. Of Sellers], 
		[Decision_Tree], [Peer_Group], [RDR_Team_Contact], [RDR_Team_Visit], [Seminar_Date], [Education_Date], [Stage_1],
		[Workshop_Date],
		NumRows /* the total num rows that this searh yields (not the number of rows for a page) */ 
	FROM
	   (SELECT ROW_NUMBER() OVER
		(ORDER BY 
			CASE @OrderBySellerNameAsc WHEN 1 THEN [Seller Name] END,
			CASE @OrderBySellerNameDesc WHEN 1 THEN [Seller Name] END DESC,
			CASE @OrderByAgentTypeAsc WHEN 1 THEN [Agent Type] END,
			CASE @OrderByAgentTypeDesc WHEN 1 THEN [Agent Type] END DESC,
			CASE @OrderByEnterpriseNameAsc WHEN 1 THEN [Enterprise Name] END,
			CASE @OrderByEnterpriseNameDesc WHEN 1 THEN [Enterprise Name] END DESC,
			CASE @OrderBySellerUIDAsc WHEN 1 THEN [Seller UID] END,
			CASE @OrderBySellerUIDDesc WHEN 1 THEN [Seller UID] END DESC,
			CASE @OrderByEnterpriseUIDAsc WHEN 1 THEN [Enterprise UID] END,
			CASE @OrderByEnterpriseUIDDesc WHEN 1 THEN [Enterprise UID] END DESC,
			CASE @OrderByAppointmentDateAsc WHEN 1 THEN CAST ([Appointment Date] AS DATETIME) END,
			CASE @OrderByAppointmentDateDesc WHEN 1 THEN CAST ([Appointment Date] AS DATETIME) END DESC,
			CASE @OrderByDateOfBirthAsc WHEN 1 THEN CAST([Date of Birth] AS DATETIME) END,
			CASE @OrderByDateOfBirthDesc WHEN 1 THEN CAST([Date of Birth] AS DATETIME) END DESC,
			CASE @OrderByASDAsc WHEN 1 THEN ASD END,
			CASE @OrderByASDDesc WHEN 1 THEN ASD END DESC,
			CASE @OrderByLocationAsc WHEN 1 THEN Location END,
			CASE @OrderByLocationDesc WHEN 1 THEN Location END DESC,
			CASE @OrderByStatusAsc WHEN 1 THEN Location END,
			CASE @OrderByStatusDesc WHEN 1 THEN Location END DESC,
			CASE @OrderByNumberSellersAsc WHEN 1 THEN CAST ([No. Of Sellers] AS INT) END,
			CASE @OrderByNumberSellersAsc WHEN 1 THEN CAST ([No. Of Sellers] AS INT) END DESC,
			CASE @OrderByDecisionTreeAsc WHEN 1 THEN [Decision_Tree] END,
			CASE @OrderByDecisionTreeDesc WHEN 1 THEN [Decision_Tree] END DESC,
			CASE @OrderByPeerGroupAsc WHEN 1 THEN [Peer_Group] END,
			CASE @OrderByPeerGroupDesc WHEN 1 THEN [Peer_Group] END DESC,
			CASE @OrderByRDRTeamContactAsc WHEN 1 THEN [RDR_Team_Contact] END,
			CASE @OrderByRDRTeamContactDesc WHEN 1 THEN [RDR_Team_Contact] END DESC,
			CASE @OrderByRDRTeamVisitAsc WHEN 1 THEN [RDR_Team_Visit] END,
			CASE @OrderByRDRTeamVisitDesc WHEN 1 THEN [RDR_Team_Visit] END DESC,
			CASE @OrderBySeminarDateAsc WHEN 1 THEN CAST ([Seminar_Date] AS DATETIME) END,
			CASE @OrderBySeminarDateDesc WHEN 1 THEN CAST ([Seminar_Date] AS DATETIME) END DESC,
			CASE @OrderByEducationDateAsc WHEN 1 THEN CAST ([Education_Date] AS DATETIME) END,
			CASE @OrderByEducationDateDesc WHEN 1 THEN CAST ([Education_Date] AS DATETIME) END DESC,
			CASE @OrderByStageAsc WHEN 1 THEN [Stage_1] END,
			CASE @OrderByStageDesc WHEN 1 THEN [Stage_1] END DESC,
			CASE @OrderByWorkshopDateAsc WHEN 1 THEN CAST ([Workshop_Date] AS DATETIME) END,
			CASE @OrderByWorkshopDateDesc WHEN 1 THEN CAST ([Workshop_Date] AS DATETIME) END DESC
		) 
			AS RowNum, [Seller Name], [Agent Type], [Enterprise Name], [Seller UID], [Enterprise UID], 
			[Appointment Date], [Date of Birth],
			[ASD], [Location], [Status],
			CAST (CASE WHEN ([No. Of Sellers] IS NULL) OR (IsNumeric([No. Of Sellers]) = 0) THEN NULL ELSE [No. Of Sellers] END AS INT) As [No. Of Sellers],
			[Decision_Tree], [Peer_Group], [RDR_Team_Contact], [RDR_Team_Visit], 
			[Seminar_Date], [Education_Date], 
			[Stage_1], [Workshop_Date],
			COUNT(1) OVER() AS NumRows 
		FROM @swiftTrackingData swift
		LEFT JOIN dbo.rdr_rdrprincipaldata_tbl AS principals ON swift.[Seller UID] = principals.agent_uid
	
		WHERE 
			((@SellerNameFilter IS NULL) OR [Seller Name] LIKE '%' + RTRIM(@SellerNameFilter) + '%') AND
			((@SellerUIDFilter IS NULL) OR [Seller UID] LIKE '%' + RTRIM(@SellerUIDFilter) + '%') AND
			((@EnterpriseNameFilter IS NULL) OR [Enterprise Name] LIKE '%' + RTRIM(@EnterpriseNameFilter) + '%') AND
			((@EnterpriseUIDFilter IS NULL) OR [Enterprise UID] LIKE '%' + RTRIM(@EnterpriseUIDFilter) + '%') AND
			((@ASDFilter IS NULL) OR [ASD] LIKE '%' + @ASDFilter + '%')
	   ) as Principals

	 WHERE RowNum BETWEEN @startRowIndex AND @lastRowIndex


END

GO
