/****** Object:  StoredProcedure [dbo].[owp_rdr_get_stats_sp]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

-- =============================================
-- Author:		<Author,,Name>
-- Create date: <Create Date,,>
-- Description:	<Description,,>
-- =============================================
create PROCEDURE [dbo].[owp_rdr_get_stats_sp]

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;


DECLARE @EDUCATED TABLE 
	(
	areamanager			varchar(255)	NULL,
	enterprisename		varchar(255) NOT NULL,
	franchisecode		varchar(25) NULL,
	agentname			varchar(255) NULL,
	education			varchar(255)	NULL,
	educationdate		smalldatetime NULL
	)
DECLARE @NONEDUCATED TABLE 
	(
	areamanager			varchar(255)	NULL,
	enterprisename		varchar(255) NOT NULL,
	franchisecode		varchar(25) NULL,
	agentname			varchar(255) NULL
)
DECLARE @INPROGRESS TABLE 
	(
	areamanager			varchar(255)	NULL,
	enterprisename		varchar(255) NOT NULL,
	franchisecode		varchar(25) NULL,
	agentname			varchar(255) NULL,
	educationdate		smalldatetime NULL
)
DECLARE @COMPLETED TABLE 
	(
	areamanager			varchar(255)	NULL,
	enterprisename		varchar(255) NOT NULL,
	franchisecode		varchar(25) NULL,
	agentname			varchar(255) NULL,
	educationdate		smalldatetime NULL
)

DECLARE @EDUCATEDCOUNT	SMALLINT
DECLARE @NONEDUCATEDCOUNT	SMALLINT
DECLARE @COMPLETEDCOUNT	SMALLINT
DECLARE @INPROGRESSCOUNT	SMALLINT

DECLARE @EDUCATEDEXCEPTION	VARCHAR(150)
SET @EDUCATEDEXCEPTION = 'Not Started'

DECLARE @COMPLIANCECODE VARCHAR(10)
SET @COMPLIANCECODE = 'cob'

DECLARE @GIVESADVICE VARCHAR(1)
SET @GIVESADVICE = 'Y'

/* EDUCATED */
INSERT INTO @EDUCATED (areamanager,enterprisename,franchisecode,agentname,education,educationdate)

SELECT 
areamanager = ad.descn,
enterprisename = RTRIM(isnull(b.TradingName,b.DESCN)),
enterpriseid = ISNULL(a.FranchiseCode,a.Firm),
agentname = MAX(RTRIM(a.DESCN)),
education = [stage_1],
educationdate = MAX([education_date])

FROM mstt_Agents AS A 
INNER JOIN mstt_AgentCompetence AS AC ON A.code = AC.agentcode 
LEFT JOIN dbo.rdr_rdrprincipaldata_tbl AS RDR ON A.CODE = RDR.agent_uid
LEFT JOIN mstt_Agents b ON b.code = a.FIRM
LEFT JOIN mstt_Agents ad on ad.code = a.manager4code
WHERE (stage_1 IS NOT NULL AND RTRIM(stage_1) <> '' AND stage_1 NOT IN(@EDUCATEDEXCEPTION)) 
	AND LOWER(ac.compliancecategorycode) IN(@COMPLIANCECODE)
	AND a.givesadvice IN(@GIVESADVICE)
	AND a.AgentType IN(4,43,51,52,53) 
	AND a.CompetentStatus in (1) --2 = Left
	AND ac.enddate IS NULL

GROUP BY 
	ad.descn,
	RTRIM(isnull(b.TradingName,b.DESCN)),
	ISNULL(a.FranchiseCode,a.Firm),
	[stage_1]

set @EDUCATEDCOUNT = @@ROWCOUNT

-- In Progress
INSERT INTO @INPROGRESS (areamanager,enterprisename,franchisecode,agentname,educationdate)
select areamanager,enterprisename,franchisecode,agentname,educationdate
from @EDUCATED where education = 'In Progress'

set @INPROGRESSCOUNT = @@ROWCOUNT
-- Completed
INSERT INTO @COMPLETED (areamanager,enterprisename,franchisecode,agentname,educationdate)
select areamanager,enterprisename,franchisecode,agentname,educationdate
from @EDUCATED where education = 'Completed'

set @COMPLETEDCOUNT = @@ROWCOUNT

/* Non Educated */
INSERT INTO @NONEDUCATED (areamanager,enterprisename,franchisecode,agentname)

SELECT distinct
	areamanager = ad.descn,
	enterprisename = RTRIM(isnull(b.TradingName,b.DESCN)),
	enterpriseid = ISNULL(a.FranchiseCode,a.Firm),
	agentname = MAX(RTRIM(a.DESCN))
FROM mstt_Agents AS A 
INNER JOIN mstt_AgentCompetence AS AC ON A.code = AC.agentcode 
LEFT JOIN dbo.rdr_rdrprincipaldata_tbl AS RDR ON A.CODE = RDR.agent_uid
LEFT JOIN mstt_Agents b ON b.code = a.FIRM
LEFT JOIN mstt_Agents ad on ad.code = a.manager4code
WHERE (stage_1 IS NULL OR RTRIM(stage_1) = '' OR LEN(RTRIM(stage_1)) <= 0)
	AND ISNULL(a.FranchiseCode,a.Firm) NOT IN(SELECT franchisecode FROM @EDUCATED)
	AND LOWER(ac.compliancecategorycode) IN(@COMPLIANCECODE)
	AND a.givesadvice IN(@GIVESADVICE)
	AND a.AgentType IN(4,43,51,52,53) 
	AND a.CompetentStatus in (1) --2 = Left
	AND ac.enddate IS NULL

GROUP BY 
	ISNULL(a.FranchiseCode,a.Firm),
	RTRIM(isnull(b.TradingName,b.DESCN)), 	
	ad.descn
ORDER BY ad.descn, RTRIM(isnull(b.TradingName,b.DESCN))

set @NONEDUCATEDCOUNT = @@ROWCOUNT


select	@NONEDUCATEDCOUNT + @EDUCATEDCOUNT as 'TotalPopulation',@NONEDUCATEDCOUNT as 'NonEducated', @EDUCATEDCOUNT as 'Educated',
		@INPROGRESSCOUNT as 'Inprogress', @COMPLETEDCOUNT as 'Completed' 

select ne.areamanager, Case 
				when ne.areamanager = 'Steve Baker' then 'London & SE' 
				when ne.areamanager = 'Geoff Denton' then 'North & Central East' 
				when ne.areamanager = 'Paul Rodgers' then 'SW & NI' 
				Else ne.areamanager 
			End, 
		Count(ne.areamanager) as 'NEdCount', 
		(select count(*) from @EDUCATED e where e.areamanager = ne.areamanager) as 'EdCount',
		(select count(*) from @INPROGRESS ip where ip.areamanager = ne.areamanager) as 'ProgCount',
		(select count(*) from @COMPLETED c where c.areamanager = ne.areamanager) as 'CompletedCount'
FROM @NONEDUCATED ne 
group by ne.areamanager 

end

GO
