-- =============================================
-- Author:			Mark Oldridge
-- Create date:	September 2010
-- Description:	Gets data from Swift pertinent to RDR Tracking
-- =============================================
CREATE PROCEDURE [dbo].[owp_rdr_get_swift_TrackingData_new_sp]
	
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

	
	DECLARE @principles TABLE
	(
	[Seller Name]		VARCHAR(255),
	[Seller UID]			VARCHAR(7),
	[Agent Type]			VARCHAR(150),
	[Enterprise Name]	VARCHAR(255),
	[Enterprise UID]		VARCHAR(7),
	[Date of Birth]		SMALLDATETIME,
	[Appointment Date]	SMALLDATETIME,
	[ASD]					VARCHAR(255),
	[BSD]					VARCHAR(255),
	[Location]				VARCHAR(255),
	[Trading Style]		VARCHAR(255),
	[Trading Name]		VARCHAR(255),
	[Status]					VARCHAR(100),
	[Contact Email]		VARCHAR(100),	
	[No. of Sellers]		VARCHAR(10),
	[Telephone No.]		VARCHAR(100)
	)

	INSERT INTO @principles
	SELECT DISTINCT
		   [Seller Name] = RTRIM(a.DESCN),
		   [Seller UID] = RTRIM(a.CODE),
		   [Agent Type] = RTRIM(a.agenttypedescription),
		   [Enterprise Name] = RTRIM(isnull(b.TradingName,b.DESCN)),
		   [Enterprise UID]= RTRIM(a.FIRM),
		   [Date of Birth] = CONVERT(DATETIME,RTRIM(c.BIRTHDATE),113),
		   [Appointment Date] = CONVERT(DATETIME,RTRIM((SELECT MIN(ValidFromDate) FROM mstt_AgentsHistory 
										WHERE CompetentStatus = 1 AND ValidFromDate <> '1900-01-01')),113),
	-- TODO - Greg has advised this field may be decommissioned and we should look to join to f_Insight_GetADsOfAllUsers 
		   [ASD] = ad.descn,--iptiondbo.rdr_GetASDByManager4Code(RTRIM(a.Manager4Code)),
		   [BSD] = bd.descn,
		   [Location] = REPLACE(RTRIM(a.POSTCODE),';',SPACE(1)) + ';' + RTRIM(ISNULL(a.ADDRESS3,'')) + ';' + RTRIM(ISNULL(a.ADDRESS4,'')) + ';' + RTRIM(ISNULL(a.ADDRESS5,'')),
		   [Trading Style] = RTRIM(a.AgentCategoryDescription),
		   [Trading Name] = RTRIM(isnull(b.TradingName,b.DESCN)),
		   [Status] = RTRIM(a.CompetentStatusDescription),
		   [Contact Email] = RTRIM(a.EMAIL),
		   [No. of Sellers] = RTRIM(a.FranchiseSize),
		   [Telephone No.] = RTRIM(a.TELEPHONE)

	FROM mstt_Agents AS A
	INNER JOIN mstt_AgentCompetence AS AC ON A.code = AC.agentcode 
	LEFT JOIN mstt_Agents b ON b.code = a.FIRM
	LEFT JOIN mstt_Clients AS c ON a.CODE = c.REFER AND c.CLIENT_TYP = 4
	LEFT JOIN mstt_Agents ad on ad.code = a.manager4code
	LEFT JOIN mstt_Agents bd on bd.code = a.manager2code

	WHERE 
	LOWER(ac.compliancecategorycode) = 'cob'
	AND a.givesadvice = 'Y'
	AND a.AgentType IN(43,51) 
	AND a.CompetentStatus in (1) --2 = Left
	AND ac.enddate IS NULL

UNION

SELECT DISTINCT
 [Seller Name] = RTRIM(b.DESCN),
                           [Seller UID] = RTRIM(b.CODE),
                           [Agent Type] = RTRIM(b.agenttypedescription),
                           [Enterprise Name] = RTRIM(isnull(ent.TradingName,ent.DESCN)),
                           [Enterprise UID]= RTRIM(b.FIRM),
                           [Date of Birth] = CONVERT(DATETIME,RTRIM(c.BIRTHDATE),113),
                           [Appointment Date] = CONVERT(DATETIME,RTRIM((SELECT MIN(ValidFromDate) FROM mstt_AgentsHistory 
                                                                                                                        WHERE CompetentStatus = 1 AND ValidFromDate <> '1900-01-01')),113),
            -- TODO - Greg has advised this field may be decommissioned and we should look to join to f_Insight_GetADsOfAllUsers 
                           [ASD] = ad.descn,--iptiondbo.rdr_GetASDByManager4Code(RTRIM(a.Manager4Code)),
						   [BSD] = bd.descn,
                           [Location] = REPLACE(RTRIM(b.POSTCODE),';',SPACE(1)) + ';' + RTRIM(ISNULL(b.ADDRESS3,'')) + ';' + RTRIM(ISNULL(b.ADDRESS4,'')) + ';' + RTRIM(ISNULL(b.ADDRESS5,'')),
                           [Trading Style] = RTRIM(b.AgentCategoryDescription),
                           [Trading Name] = RTRIM(isnull(ent.TradingName,b.DESCN)),
                           [Status] = RTRIM(b.CompetentStatusDescription),
                           [Contact Email] = RTRIM(b.EMAIL),
                           [No. of Sellers] = RTRIM(b.FranchiseSize),
                           [Telephone No.] = RTRIM(b.TELEPHONE)           

FROM mstt_Agents AS A
            INNER JOIN mstt_AgentCompetence AS AC ON A.code = AC.agentcode 
            INNER JOIN mstt_Agents b ON b.OfficeCode = a.OfficeCode
            LEFT JOIN mstt_Clients AS c ON b.CODE = c.REFER AND c.CLIENT_TYP = 4
            LEFT JOIN mstt_Agents ad on ad.code = b.manager4code
            LEFT JOIN mstt_Agents ent ON ent.code = a.OfficeCode
			LEFT JOIN mstt_Agents bd on bd.code = a.manager2code

WHERE compliancecategorycode = 'cob'
AND ac.enddate IS NULL
            AND a.CompetentStatus in (1) --2 = Left
            AND a.givesadvice = 'Y'
            AND a.AgentType IN(4)
            AND b.AgentType IN(43)
            AND b.CompetentStatus in (1)

	SELECT * FROM @principles

END
GO
