	AND a.CompetentStatus in (1) --2 = Left
	AND ac.enddate IS NULL

UNION

SELECT DISTINCT
 [Seller Name] = RTRIM(b.DESCN),
                           [Seller UID] = RTRIM(b.CODE),
                           [Agent Type] = RTRIM(b.agenttypedescription),
                           [Enterprise Name] = RTRIM(isnull(ent.TradingName,ent.DESCN)),
