/****** Object:  StoredProcedure [dbo].[owp_rdr_get_swift_TrackingDataForPrincipal]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
-- =============================================
-- Author:	Vincent Holt
-- Create date: 	October 2010
-- Description:	Get the tracking data for a principal
-- =============================================
CREATE PROCEDURE [dbo].[owp_rdr_get_swift_TrackingDataForPrincipal]    
	@PRINCIPALUID	VARCHAR(20)
AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

	SELECT 
		[Seller Name] = RTRIM(a.DESCN),
		[Seller UID] = RTRIM(a.CODE),
		[Agent Type] = RTRIM(a.agenttypedescription),
		[Enterprise Name] = RTRIM(isnull(b.TradingName,b.DESCN)),
		[Enterprise UID]= RTRIM(a.FIRM),
		[Date of Birth] = CONVERT(DATETIME,RTRIM(c.BIRTHDATE),113),
		[Appointment Date] = CONVERT(DATETIME,RTRIM((SELECT MIN(ValidFromDate) FROM mstt_AgentsHistory 
						  WHERE CompetentStatus = 1 AND ValidFromDate <> '1900-01-01')),113),
		[ASD] = dbo.owf_rdr_GetASDByManager4Code(RTRIM(a.Manager4Code)),
		[Location] = REPLACE(RTRIM(a.POSTCODE),';',SPACE(1)) + ';' + RTRIM(ISNULL(a.ADDRESS3,'')) + ';' + RTRIM(ISNULL(a.ADDRESS4,'')) + ';' + RTRIM(ISNULL(a.ADDRESS5,'')),
		[Trading Style] = RTRIM(a.AgentCategoryDescription),
		[Trading Name] = RTRIM(isnull(b.TradingName,b.DESCN)),
		[Status] = RTRIM(a.CompetentStatusDescription),
		[Contact Email] = RTRIM(a.EMAIL),
		[No. of Sellers] = RTRIM(a.FranchiseSize),
		[Telephone No.] = RTRIM(a.TELEPHONE)

	FROM mstt_Agents AS A
	LEFT JOIN mstt_AgentCompetence AS AC ON A.code = AC.agentcode 
	LEFT JOIN mstt_Agents b ON b.code = a.FIRM
	LEFT JOIN mstt_Clients AS c ON a.CODE = c.REFER AND c.CLIENT_TYP IN(4)

	WHERE 
		RTRIM(a.CODE) = RTRIM(@PRINCIPALUID)
END
GO
