-- =============================================
-- Author:		Mark Oldridge
-- Create date: 		September 2010
-- Description:		Updates data in the new RDR tracking table for a principal
-- Amended by:	Paul Robathan on 25th August 2011 
-- =============================================
CREATE PROCEDURE [dbo].[owp_rdr_set_PrincipalTrackingData]    

	@PRINCIPALUID AS VARCHAR(20),
	@APPROXCLIENTS AS INTEGER = 0,
	@CRMUSED AS VARCHAR(150) = NULL,
	@APPROXFUNDSMGMT AS NUMERIC(18,2) = NULL,
	@PAYMENTTERMS AS VARCHAR(150) = NULL,
	@DECISIONTREE AS VARCHAR(150) = NULL,
	@BUSINESSMODEL AS VARCHAR(150) = NULL,
	@PEERGROUP AS VARCHAR(150) = NULL,
	@TEAMCONTACT AS VARCHAR(150) = NULL,
	@TEAMVISIT AS VARCHAR(150) = NULL,
	@PILOTWRAP AS VARCHAR(150) = NULL,
	@PILOTFEES AS VARCHAR(150) = NULL,
	@STAGE1 AS VARCHAR(150) = NULL,
	@SEMINARDATE AS SMALLDATETIME = NULL,
	@EDUCATIONMEETING AS SMALLDATETIME = NULL,
	@STAGE2 AS VARCHAR(150) = NULL,
	@WORKSHOPDATE AS SMALLDATETIME = NULL,
	@STAGE3 AS VARCHAR(150) = NULL,
	@CASHFLOWMODELUSEDDATE AS SMALLDATETIME = NULL,
	@NUMSELLERS AS INT = NULL,
	@QUALIFICATIONLEVEL VARCHAR(255) = NULL,
	@EXAMROUTE VARCHAR(255) = NULL,
	@COMMENTS AS VARCHAR(8000) = NULL,
	@UPDATEDBY AS VARCHAR(150) = NULL,
	@DATELASTSEEN AS SMALLDATETIME = NULL

AS
BEGIN
	
	SET NOCOUNT ON;

	DECLARE @ISUPDATE AS INTEGER

	SET @ISUPDATE = (SELECT COUNT(agent_uid) FROM rdr_rdrprincipaldata_tbl WHERE rtrim(agent_uid) = rtrim(@PRINCIPALUID))

	IF @ISUPDATE >=1
		BEGIN

			--PRINT 'UPDATE VALUES'

			UPDATE rdr_rdrprincipaldata_tbl
			SET approx_no_of_clients = @APPROXCLIENTS,
			crm_used = @CRMUSED,
			approx_funds_under_mgmt = @APPROXFUNDSMGMT,
			payment_terms = @PAYMENTTERMS,
			decision_tree = @DECISIONTREE,
			business_model = @BUSINESSMODEL,
			peer_group = @PEERGROUP,
			rdr_team_contact = @TEAMCONTACT,
			rdr_team_visit = @TEAMVISIT,
			pilot_wrap = @PILOTWRAP,
			pilot_fees = @PILOTFEES,
			stage_1 = @STAGE1,
			seminar_date = @SEMINARDATE,
			education_date = @EDUCATIONMEETING,
			stage_2	= @STAGE2,
			workshop_date = @WORKSHOPDATE,
			stage_3 = @STAGE3,
			cashflow_model_used_date = @CASHFLOWMODELUSEDDATE,
			num_sellers = @NUMSELLERS,
			qualification_level = @QUALIFICATIONLEVEL,
			exam_route = @EXAMROUTE,
			comments = @COMMENTS,
			datelastseen = @DATELASTSEEN, -- Paul R Aug 2011
			updated_by = @UPDATEDBY,
			updated_date = getdate()
			
			WHERE rtrim(agent_uid) = rtrim(@PRINCIPALUID)

		END

	IF @ISUPDATE <=0
		BEGIN

			--PRINT 'INSERT VALUES'
	
			INSERT INTO rdr_rdrprincipaldata_tbl
			(agent_uid, 
			 approx_no_of_clients, 
			 crm_used, 
			 approx_funds_under_mgmt,
			 payment_terms,
			 decision_tree,
			 business_model,
			 peer_group,
			 rdr_team_contact,
			 rdr_team_visit,
			 pilot_wrap,
			 pilot_fees,
			 stage_1,
			 seminar_date,
			 education_date,
			 stage_2,
			 workshop_date,
			 stage_3,
			 cashflow_model_used_date,
			 num_sellers,
			 comments,
			 datelastseen, -- Paul R Aug 2011
			 updated_by,
			 updated_date)
			VALUES(
			@PRINCIPALUID,
			@APPROXCLIENTS,
			@CRMUSED,
			@APPROXFUNDSMGMT,
			@PAYMENTTERMS,
			@DECISIONTREE,
			@BUSINESSMODEL,
			@PEERGROUP,
			@TEAMCONTACT,
			@TEAMVISIT,
			@PILOTWRAP,
			@PILOTFEES,
			@STAGE1,
			@SEMINARDATE,
			@EDUCATIONMEETING,
			@STAGE2,
			@WORKSHOPDATE,
			@STAGE3,
			@CASHFLOWMODELUSEDDATE,
			@NUMSELLERS,
			@COMMENTS,
			@DATELASTSEEN, -- Paul R Aug 2011
			@UPDATEDBY,
			getdate()
			)
		END
   
END

GO
/****** Object:  StoredProcedure [dbo].[owp_rdr_stats_by_areamanager_sp]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
