-- =============================================
-- Author:		Paul Robathan
-- Create date: 26 Jan 2011
-- Description:	Produces stats about which Enterprises have had Education
--              The parm indicates whether we produce records for All
--              ASDs or just a specific one.
-- =============================================
CREATE PROCEDURE [dbo].[owp_rdr_stats_by_areamanager_sp]
	@ASD	varchar(25) = NULL

AS
BEGIN
	-- SET NOCOUNT ON added to prevent extra result sets from
	-- interfering with SELECT statements.
	SET NOCOUNT ON;

--DECLARE @ASD	varchar(25)
--set @ASD = '1000289'
--set @ASD = 'All'

DECLARE @TOTALCOUNT	float

	DECLARE @principals TABLE
	(
	[Enterprise Name]	varchar(255),
	[Enterprise UID]	varchar(7),
	[SellerName]		varchar(255),
	[ASD]				varchar(255),
	[ASDCode]			varchar(25),
	[ASDArea]			varchar(255),
	[BSD]				varchar(255),
	[education]			varchar(255)	NULL,
	[educationdate]		smalldatetime NULL,
	[qual_level]		varchar(255) NULL,
	[exam_route]		varchar(255) NULL,
	[decision_tree]		varchar(255) NULL,
	[rdr_team_contact]  varchar(255) NULL,
	[peer_group]		varchar(255) NULL,
	[rdr_team_visit]	varchar(255) NULL,
	[workshop_date]		smalldatetime NULL,
	[crm_used]			varchar(1000),
	[approx_fum]		numeric(18, 2),
	[business_model]	varchar(255),
	[stage]				varchar(255),
	[cf_used_date]		smalldatetime NULL,
	[num_sellers]		int NULL,
	[approx_num_clients] int NULL
	)
	DECLARE @summary TABLE
	(
	[Order]				smallint,
	[Description]		varchar(100),
	[Area]				varchar(100),
	[Value]				smallint,
	[PercentValue]		decimal(5,2)
	)


	INSERT INTO @principals ([Enterprise Name], [Enterprise UID], [SellerName], [ASD], [ASDCode], [ASDArea],
		[BSD], [education])

  	SELECT DISTINCT
		   RTRIM(isnull(b.TradingName,b.DESCN)),
		   RTRIM(a.FIRM),
		   NULL,
		   ad.descn,
		   a.manager4code,
		   asd.area,
		   bd.descn,
		   'N'

	FROM mstt_Agents AS A
	INNER JOIN mstt_AgentCompetence AS AC ON A.code = AC.agentcode 
	LEFT JOIN mstt_Agents b ON b.code = a.FIRM
	LEFT JOIN mstt_Clients AS c ON a.CODE = c.REFER AND c.CLIENT_TYP = 4
	LEFT JOIN mstt_Agents ad on ad.code = a.manager4code
	LEFT JOIN mstt_Agents bd on bd.code = a.manager2code
	LEFT join rdr_rdrasddata_tbl asd on a.manager4code = asd.Code
	--LEFT outer JOIN rdr_rdrprincipaldata_tbl AS RDR ON A.CODE = RDR.agent_uid

	WHERE LOWER(ac.compliancecategorycode) = 'cob'
		AND a.givesadvice = 'Y'
		AND a.AgentType IN(43,51) 
		AND a.CompetentStatus in (1) --2 = Left
		AND ac.enddate IS NULL
		AND (a.manager4code = @ASD or @ASD = 'All')

--select * from @principals
 
UNION
SELECT DISTINCT
    RTRIM(isnull(ent.TradingName,ent.DESCN)),
	RTRIM(b.FIRM),
	NULL,
    ad.descn,
	b.manager4code,
	asd.area,
	bd.descn,
	'N'

	FROM mstt_Agents AS A
    INNER JOIN mstt_AgentCompetence AS AC ON A.code = AC.agentcode 
    INNER JOIN mstt_Agents b ON b.OfficeCode = a.OfficeCode
    LEFT JOIN mstt_Clients AS c ON b.CODE = c.REFER AND c.CLIENT_TYP = 4
    LEFT JOIN mstt_Agents ad on ad.code = b.manager4code
    LEFT JOIN mstt_Agents bd on bd.code = b.manager2code
    LEFT JOIN mstt_Agents ent ON ent.code = a.OfficeCode
	LEFT join rdr_rdrasddata_tbl asd on b.manager4code = asd.Code
--	LEFT outer JOIN rdr_rdrprincipaldata_tbl AS RDR ON b.CODE = RDR.agent_uid

	WHERE compliancecategorycode = 'cob'
			AND ac.enddate IS NULL
            AND a.CompetentStatus in (1) --2 = Left
            AND a.givesadvice = 'Y'
            AND a.AgentType IN(4)
            AND b.AgentType IN(43)
            AND b.CompetentStatus in (1)
		    AND (b.manager4code = @ASD or @ASD = 'All')
--select * from @principals

set @TOTALCOUNT = @@ROWCOUNT
--select @TOTALCOUNT
	DECLARE @rdrsummary TABLE
	(
	[SellerUID]			VARCHAR(7),
	[SellerName]		VARCHAR(255),
	[EnterpriseUID]		VARCHAR(7),
	[education]			varchar(255)	NULL,
	[educationdate]		smalldatetime NULL,
	[qual_level]		varchar(255) NULL,
	[exam_route]		varchar(255) NULL,
	[decision_tree]		varchar(255) NULL,
	[rdr_team_contact]  varchar(255) NULL,
	[peer_group]		varchar(255) NULL,
	[rdr_team_visit]	varchar(255) NULL,
	[workshop_date]		smalldatetime NULL,
	[crm_used]			varchar(1000),
	[approx_fum]		numeric(18, 2),
	[business_model]	varchar(255),
	[stage]				varchar(255),
	[cf_used_date]		smalldatetime NULL,
	[num_sellers]		int NULL,
	[approx_num_clients] int NULL
	)
	INSERT INTO @rdrsummary 
  	SELECT 
		[SellerUID] = r.agent_uid,
		[SellerName] = a.descn,
		[EnterpriseUID] = isnull(a.FranchiseCode,a.Firm),
		--[education]		=	case when (stage_1 IS NOT NULL AND RTRIM(stage_1) <> '' AND stage_1 <> 'Not Started') then stage_1 else 'N' end,
		[education]		=	stage_1,
		[educationdate]	 =	education_date,
		[qual_level] = qualification_level,
		[exam_route] = exam_route,
		[decision_tree] = decision_tree,
		[rdr_team_contact] = rdr_team_contact,
		[peer_group] = peer_group,
		[rdr_team_visit] = rdr_team_visit,
		[workshop_date] = workshop_date,
		[crm_used] = crm_used,
		[approx_fum] = approx_funds_under_mgmt,
		[business_model] = business_model,
		[stage] = stage_1,
		[cf_used_date] = cashflow_model_used_date,
		[num_sellers] = num_sellers,
		[approx_num_clients] = approx_no_of_clients

	from rdr_rdrprincipaldata_tbl r
	inner join mstt_agents a on a.code = r.agent_uid
	where (stage_1 IS NOT NULL AND RTRIM(stage_1) <> '' AND stage_1 <> 'Not Started')

-- get the latest Education Date for the Enterprise
update @rdrsummary
	set educationdate = (select max(educationdate) from @rdrsummary rs where rs.EnterpriseUID = r.EnterpriseUID)
	from @rdrsummary r

--select * from  @rdrsummary order by EnterpriseUID

--update @principals
--set		sellername = 	(select top 1 rtrim(descn) from mstt_agents a 
--						where ISNULL(a.FranchiseCode,a.Firm) = p.[Enterprise UID]
--						AND a.AgentType IN(43,51) 
--						AND a.CompetentStatus in (1))
--from @principals p

-- this statement updates @principals table with Educated users from @rdrsummary.  All advisers on @rdrsummary are effectively Educated due
-- to the filter when building the table.  The update statement will only pick the first adviser from the @rdrsummary table that is at the
-- matching Enterprise UID.  Do we want to pick the one with the most important Educated status e.g. Completed and then In Progress and then 
-- Attended Education.
update @principals
set		[sellername] = r.sellername,
 		[education] = r.education,
		[educationdate] = r.educationdate,
		[qual_level] = r.qual_level,
		[exam_route] = r.exam_route,
		[decision_tree] = r.decision_tree,
		[rdr_team_contact] = r.rdr_team_contact,
		[peer_group] = r.peer_group,
		[rdr_team_visit] = r.rdr_team_visit,
		[workshop_date] = r.workshop_date,
		[crm_used] = r.[crm_used],
		[approx_fum] = r.approx_fum,
		[business_model] = r.business_model,
		[stage] = r.stage,
		[cf_used_date] = r.cf_used_date,
		[num_sellers] = r.num_sellers,
		[approx_num_clients] = r.approx_num_clients


from @principals p
inner join @rdrsummary r on r.EnterpriseUID = p.[Enterprise UID]

/*
	[stage]				varchar(255),
	[cf_used_date]		smalldatetime NULL,
	[num_sellers]		int NULL,
	[approx_num_clients] int NULL
	*/
---------------
	INSERT INTO @summary 
  	SELECT 
	[Order] = 1,
	[Description]	= 'Total',
	[Area]			= 'All',
	[Value]			= @TOTALCOUNT,
	[PercentValue]	= 100.00

	INSERT INTO @summary 
  	SELECT 
	[Order] = 2,
	[Description]	= 'Non Educated',
	[Area]			= 'All',
	[Value]			= count(*),
	[PercentValue]	= (count(*)/@TOTALCOUNT) * 100
	from @principals where education = 'N' 
	
	INSERT INTO @summary 
  	SELECT 
	[Order] = 3,
	[Description]	= 'Educated',
	[Area]			= 'All',
	[Value]			= count(*),
	[PercentValue]	= (count(*)/@TOTALCOUNT) * 100
	from @principals where education <> 'N' 
	INSERT INTO @summary 
  	SELECT 
	[Order] = 4,
	[Description]	= 'In Progress',
	[Area]			= 'All',
	[Value]			= count(*),
	[PercentValue]	= (count(*)/@TOTALCOUNT) * 100
	from @principals where education = 'In Progress' 

	INSERT INTO @summary 
  	SELECT 
	[Order] = 5,
	[Description]	= 'Completed',
	[Area]			= 'All',
	[Value]			= count(*),
	[PercentValue]	= (count(*)/@TOTALCOUNT) * 100
	from @principals where education = 'Completed' 


	INSERT INTO @summary 
  	SELECT 
	[Order] = 6,
	[Description]	= 'Qualified',
	[Area]			= 'All',
	[Value]			= count(*),
	[PercentValue]	= (count(*)/@TOTALCOUNT) * 100
	from @principals where (qual_level is not null) AND qual_level <> '' AND qual_level <> 'Not Started'

	INSERT INTO @summary 
  	SELECT 
	[Order] = 7,
	[Description]	= 'Non Educated',
	[Area]			= ASDArea,
	[Value]			= count(*),
	[PercentValue]	= (count(*)/@TOTALCOUNT) * 100
	from @principals where education = 'N' group by ASDArea order by ASDArea
	
	INSERT INTO @summary 
  	SELECT 
	[Order] = 7,
	[Description]	= 'Non Educated',
	[Area]			= Area,
	[Value]			= 0,
	[PercentValue]	= 0.00
	from rdr_rdrasddata_tbl where Area not in (select Area from @summary where Description = 'Non Educated')

	INSERT INTO @summary 
  	SELECT 
	[Order] = 8,
	[Description]	= 'Educated',
	[Area]			= ASDArea,
	[Value]			= count(*),
	[PercentValue]	= (count(*)/@TOTALCOUNT) * 100
	from @principals where education <> 'N' group by ASDArea order by ASDArea

	INSERT INTO @summary 
  	SELECT 
	[Order] = 8,
	[Description]	= 'Educated',
	[Area]			= Area,
	[Value]			= 0,
	[PercentValue]	= 0.00
	from rdr_rdrasddata_tbl where Area not in (select Area from @summary where Description = 'Educated')

	INSERT INTO @summary 
  	SELECT 
	[Order] = 9,
	[Description]	= 'In Progress',
	[Area]			= ASDArea,
	[Value]			= count(*),
	[PercentValue]	= (count(*)/@TOTALCOUNT) * 100
	from @principals 
	where education = 'In Progress' group by ASDArea order by ASDArea
	INSERT INTO @summary 
  	SELECT 
	[Order] = 9,
	[Description]	= 'In Progress',
	[Area]			= Area,
	[Value]			= 0,
	[PercentValue]	= 0.00
	from rdr_rdrasddata_tbl where Area not in (select Area from @summary where Description = 'In Progress')
	
INSERT INTO @summary 
  	SELECT 
	[Order] = 10,
	[Description]	= 'Completed',
	[Area]			= ASDArea,
	[Value]			= count(*),
	[PercentValue]	= (count(*)/@TOTALCOUNT) * 100
	from @principals
where education = 'Completed' group by ASDArea order by ASDArea
	INSERT INTO @summary 
  	SELECT 
	[Order] = 10,
	[Description]	= 'Completed',
	[Area]			= Area,
	[Value]			= 0,
	[PercentValue]	= 0.00
	from rdr_rdrasddata_tbl where Area not in (select Area from @summary where Description = 'Completed')

INSERT INTO @summary 
  	SELECT 
	[Order] = 11,
	[Description]	= 'Qualified',
	[Area]			= ASDArea,
	[Value]			= count(*),
	[PercentValue]	= (count(*)/@TOTALCOUNT) * 100
	from @principals
where (qual_level IS NOT NULL) AND qual_level <> '' group by ASDArea order by ASDArea
	INSERT INTO @summary 
  	SELECT 
	[Order] = 11,
	[Description]	= 'Qualified',
	[Area]			= Area,
	[Value]			= 0, -- todo - why are these hard-coded to zero percent??
	[PercentValue]	= 0.00 -- todo - why are these hard-coded to zero percent??
	from rdr_rdrasddata_tbl where Area not in (select Area from @summary where Description = 'Qualified')

select Description, isnull(Area,'Unknown') as [Area Name], [value] as [Population],[PercentValue] as [Percent%] 
 from @summary order by [order],area

---------------

-- Non Educated
select asd as [Area Director], bsd as [BDD], [Enterprise Name], [Enterprise UID] 
from @principals 
where education = 'N' order by ASD,[Enterprise Name]

/*
	[workshop_date]		smalldatetime NULL,
	[crm_used]			varchar(1000),
	[approx_fum]		numeric(18, 2),
	[business_model]	varchar(255),
	[stage]				varchar(255),
	[cf_used_date]		smalldatetime NULL,
	[num_sellers]		int NULL,
	[approx_num_clnts]	int NULL
	*/
-- Educated
select asd as [Area Director], bsd as [BDD], [Enterprise Name], [Enterprise UID], SellerName as Seller,
	education as Status, educationdate as [Status Date], qual_level as [Qualification Level], exam_route as [Exam Route],
	decision_tree as [Decision Tree], rdr_team_contact AS [RDR Team Contact], peer_group AS [Peer Group], rdr_team_visit AS [RDR Team Visist],
	workshop_date as [Workshop Date], crm_used as [CRM Used], approx_fum as [Approx FUM], business_model AS [Business Model],
	stage as Stage, cf_used_date as [Cashflow Used Date], num_sellers as [Num Sellers], approx_num_clients as [Approx Num Clients]

from @principals where education <> 'N' order by ASD,[Enterprise Name]

-- In Progress
select asd as [Area Director], bsd as [BDD], [Enterprise Name], [Enterprise UID], SellerName as Seller,
	education as Status, educationdate as [Status Date], qual_level as [Qualification Level], exam_route as [Exam Route], 
	decision_tree as [Decision Tree], rdr_team_contact AS [RDR Team Contact], peer_group as [Peer Group], rdr_team_visit as [RDR Team Visist],
	workshop_date as [Workshop Date], crm_used as [CRM Used], approx_fum as [Approx FUM], business_model as [Business Model],
	stage as Stage, cf_used_date as [Cashflow Used Date], num_sellers as [Num Sellers], approx_num_clients as [Approx Num Clients]
from @principals where education = 'In Progress' order by ASD,[Enterprise Name]

-- Completed
select asd as [Area Director], bsd as [BDD], [Enterprise Name], [Enterprise UID], SellerName as Seller,
	education as Status, educationdate as [Status Date], qual_level as [Qualification Level], exam_route as [Exam Route], 
	decision_tree as [Decision Tree], rdr_team_contact AS [RDR Team Contact], peer_group AS [Peer Group], rdr_team_visit AS [RDR Team Visist],
	workshop_date as [Workshop Date], crm_used as [CRM Used], approx_fum as [Approx FUM], business_model AS [Business Model],
	stage as Stage, cf_used_date as [Cashflow Used Date], num_sellers as [Num Sellers], approx_num_clients as [Approx Num Clients]
from @principals where education = 'Completed' order by ASD,[Enterprise Name]

-- Qualified - this is at Seller level, not Enterprise level like the rest of the worksheets
select p.asd as [Area Director], p.bsd as [BDD], p.[Enterprise Name], p.[Enterprise UID], r.SellerName as Seller,
	r.education as Status, r.educationdate as [Status Date], r.qual_level as [Qualification Level], r.exam_route as [Exam Route],
	r.decision_tree as [Decision Tree], r.rdr_team_contact AS [RDR Team Contact], r.peer_group AS [Peer Group], r.rdr_team_visit AS [RDR Team Visist],
	r.workshop_date as [Workshop Date], r.crm_used as [CRM Used], r.approx_fum as [Approx FUM], r.business_model AS [Business Model],
	r.stage as Stage, r.cf_used_date as [Cashflow Used Date], r.num_sellers as [Num Sellers], r.approx_num_clients as [Approx Num Clients]
from @rdrsummary r
inner join @principals p 
on p.[Enterprise UID] = r.[EnterpriseUID]

where (r.qual_level is not null) and r.qual_level <> '' and r.qual_level <> 'Not Started' order by p.ASD,p.[Enterprise Name]


end


GO
/****** Object:  StoredProcedure [dbo].[owp_RecognitionGIPaymentshield]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*********************************************************************************************************

Program:		owp_RecognitionGIPaymentshield					
Author:			Alan Groves
Date created:	20/04/2018
											
Description:
===========

This proc populates the new recognition table called "owt_Recognition" with "Value of New Business"
(VNB) points.

This proc handles the GI (Paymentshield) data. 

Note: There is a separate proc that calculates the VNB points for Swift data covering:
WEALTH - COB business i.e. pensions and investments
MORTGAGES
PROTECTION

The approach of this proc is to use the same data-set loaded by the last Paymentshield load
to calculate the VNB points in a temporary table.

The temporary table is then merged with the permanent table to make the calculated (or
re-calculated values) permanent.

Terms
-----
DA	- Distribution Allowance (the total amount paid out by the provider to Openwork)


THE CALCULATION
===============

GI
--
Note: for GI, DA and APE are the same.
= (DA X GI Retention Rate) - (DA X GI FCA Rate) 
GI Points Total = Initial


This proc is called as follows:
	declare @rc int
	exec @rc = dbo.owp_RecognitionGIPaymentshield 'Openwork', 'Recognition'
	select @rc

				
AMENDMENT HISTORY				
=================								

Date		Author		Description
----		------		-----------
03/05/2018	A Groves	Added update of column "msit_OpenworkAdviserListing.VNB_Points".
21/05/2018	A Groves	1) At Marcus Cossey's request, GI payments should only be in scope
							in their first year. Typically, this will include the first payment
							and any clawbacks/adjustments that might occur throughout that first
							year.
						2) In the case of clawbacks/adjustments, the DA is not on the data
							row. Therefore, where the payment is negative, then the "PaymentAmount"
							is used. Where the payment is positive, then the "DA" is used.
23/05/2018	A Groves	Changed value stored in "PaymentReceived" column from "pcp.DA" to
							"pcp.PaymentAmount" as the latter is used for clawbacks and adjustments.
24/05/2018	A Groves	Marcus Cossey asked for the following payments to be excluded from VNB:
						1) Where OrigCommType = 'Renewal'
						2) Where OrigStatus = 'RENEWAL'
						Note: Marcus didn't want to simply include the oldest +ve payment and all
						-ve payments in the first 12 months, as he did not want to miss out any
						MTA (mid term adjustment) credits.
05/06/2018	A Groves	New columns introduced (for the benefit of the wealth calculation):
						1) ReassignedProductGroupCode
						2) ReassignedProductGroupName
13/06/2018	A Groves	Marcus asked for SellerCode and PaymentMatchedDate to be added so he need 
							only use the one table for both the adviser and enterprise leagues. 
							PayBasisCode and PayBasisDesc were also added at the same time as these 
							are used in the calculations.
*************************************************************************************************************/

CREATE PROCEDURE [dbo].[owp_RecognitionGIPaymentshield]
	@Client		varchar(50),
	@Module		Varchar(50)
AS

set nocount on

declare		@PhaseStart				varchar(50),
			@PhaseEnd				varchar(50),
			@PhaseError				varchar(50),
			@PhaseLog				varchar(50),
			@ProcName				varchar(100),
			@ProcessMessage			varchar(100),
			@RowCount				int,
			@OALRowCount			int,
			@ErrMsg					nvarchar(4000),
			@ErrMsgBrief			nvarchar(100),
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@ErrState				int
			
/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @ProcName			= object_name(@@procid)
set @PhaseStart			= 'START'
set @PhaseEnd			= 'END'
set @PhaseError			= 'ERROR'
set @PhaseLog			= 'LOG'
set @ErrNum				= 0	

-- We want this logging irrespective of whether or not there is a rollback
exec msp_ProcessLog @PhaseStart, @ProcName, null, @Module, @Client

/****************************************************************************

	Populate the table																
																		
****************************************************************************/

SET XACT_ABORT ON	-- Needed if XACT_STATE() function is used.

BEGIN TRY

	/****************************************************************************

		Calculate VNB and populate the temporary table with the results
																		
	****************************************************************************/

	select top 0 *
	into #owt_Recognition
	from owt_Recognition

	declare @OwlManager2Code nvarchar(10)
	set @OwlManager2Code = (select cde.Code from msit_MIWarehouseCodesAndDescriptions cde
				where cde.ColumnName = 'Manager2Code' and cde.Description = 'Owl Financial')
	declare @DateLastUpdated datetime = getdate()

	--AG 21/05/2018. Get the oldest payment date for each policy so that the 12 month period can be derived
	select	Policy, MIN(PaymentDate) as MinPaymentDate
	into	#EarliestPolPayments
	from	owt_PaymentshieldCommissionPayments pcp
			inner join mstt_Agents ag on ag.Code = pcp.BusinessCode
	where	ag.Manager2Code <> @OwlManager2Code		--Exclude Owl
	group	by Policy

	insert into #owt_Recognition
	(
		SourceID,
		CaseID,
		TransactionID,
		Policy,
		ProductCode,
		BusinessCode,
		SellerCode,						--AG 13/06/2018
		PointsTotal,
		BSC,
		MBF,
		Initial,
		OngoingTotal,
		OngoingYr01,
		OngoingYr02,
		OngoingYr03,
		OngoingYr04,
		OngoingYr05,
		OngoingYr06,
		OngoingYr07,
		OngoingYr08,
		OngoingYr09,
		OngoingYr10,
		FCARate,
		RetentionRate,
		RetentionRateBroker,
		OngoingServicingRate,
		OngoingServicingSource,
		DA,
		AmountReceived,
		Premium,
		AgentSplit,
		CommissionType,
		CommissionTypeDesc,
		PayBasisCode,					--AG 13/06/2018
		PayBasisDesc,					--AG 13/06/2018
		PaymentMatchedDate,				--AG 13/06/2018
		Month,
		FrequencyCode,
		FrequencyDesc,
		ReassignedProductGroupCode,		--AG 05/06/2018
		ReassignedProductGroupName,		--AG 05/06/2018
		RecognitionType,
		CalculationType,
		Source,
		DateInserted,
		DateLastUpdated
	)
	select	pcp.ID as SourceID,
			null as CaseID,
			null as TransactionID,
			pcp.Policy,
			pcp.HierarchyProduct as ProductCode,
			pcp.BusinessCode,
			pcp.SellerCode,							--AG 13/06/2018
			case when pcp.PaymentAmount < 0.0		--AG 21/05/2018
				then ((pcp.PaymentAmount * GIrate.FACTOR) - (pcp.PaymentAmount * GIfca.FACTOR)) * GIrate.Multiplier 
				else ((pcp.DA * GIrate.FACTOR) - (pcp.DA * GIfca.FACTOR)) * GIrate.Multiplier 
			end as PointsTotal,
			0 as BSC,
			0 as MBF,
			case when pcp.PaymentAmount < 0.0		--AG 21/05/2018
				then ((pcp.PaymentAmount * GIrate.FACTOR) - (pcp.PaymentAmount * GIfca.FACTOR)) * GIrate.Multiplier 
				else ((pcp.DA * GIrate.FACTOR) - (pcp.DA * GIfca.FACTOR)) * GIrate.Multiplier 
			end as Initial,
			0 as OngoingTotal,
			0 as OngoingYr01,
			0 as OngoingYr02,
			0 as OngoingYr03,
			0 as OngoingYr04,
			0 as OngoingYr05,
			0 as OngoingYr06,
			0 as OngoingYr07,
			0 as OngoingYr08,
			0 as OngoingYr09,
			0 as OngoingYr10,
			GIfca.FACTOR*100.0 as FCARate,
			GIrate.FACTOR*100.0 as RetentionRate,
			0 as RetentionRateBroker,
			null as OngoingServicingRate,
			null as OngoingServicingSource,
			pcp.DA,
			pcp.PaymentAmount as AmountReceived,	--AG 23/05/2018
			pcp.Premium,
			100.0 as AgentSplit,
			null as CommissionType,
			pcp.FeeType as CommissionTypeDesc,
			pcp.PayBasisCode,						--AG 13/06/2018
			pcp.PayBasis as PayBasisDesc,			--AG 13/06/2018
			pcp.PaymentDate as PaymentMatchedDate,	--AG 13/06/2018
			pcp.Month,
			null as FrequencyCode,
			pcp.Frequency as FrequencyDesc,
			1 as ReassignedProductGroupCode,		--AG 05/06/2018
			'GI' as ReassignedProductGroupName,		--AG 05/06/2018
			'VNB' as RecognitionType,
			'GI' as CalculationType,
			pcp.Source,
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated
	from	owt_PaymentshieldCommissionPayments pcp
/*			inner join (select max(FileID) as FileID
						from owt_PaymentshieldImportControl) X on pcp.CreateDate = X.FileID
*/			inner join #EarliestPolPayments epp on epp.Policy = pcp.Policy
			inner join mstt_Agents ag on ag.Code = pcp.BusinessCode
			inner join msit_Commissionstatementperiods csp on csp.month = pcp.month
			inner join msit_CommissionStatementPeriods VNBStart on convert(date,pcp.StartDate) between VNBStart.PeriodStartDate and VNBStart.PeriodEndDate
			left join owt_EliteFactors GIfca on GIfca.FeeType = 'VNB' and GIfca.category = 'GI-FCA-RATE' and csp.year between GIfca.StartYear and GIfca.EndYear 
			left join owt_EliteFactors GIrate on GIrate.FeeType = 'VNB' and GIrate.category = 'GI-RETENTION-RATE' and csp.year between GIrate.StartYear and GIrate.EndYear 
	where	ag.Manager2Code <> @OwlManager2Code		--Exclude Owl
	and		pcp.PaymentAmount <> 0 
	and		pcp.SalesMoveFlag <> 'N'				--Although <> 'N' is loaded to OA, only = 'Y' gets DA, etc. calculated.
	and		pcp.OrigCommtype <> 'Renewal'			--AG 24/05/2018
	and		pcp.OrigStatus <> 'RENEWAL'				--AG 24/05/2018
	--IC and Adj must be in 1st year of policy. Add 11 months to 01/05/2017 and you get 01/04/2018 as required.
	and		pcp.PaymentDate <= DATEADD(mm,11,epp.MinPaymentDate)	--AG 21/05/2018	
	and		VNBStart.Year >= 2017					--VNB to start from 2017
	and		csp.Year >= 2017						--Ensure in-scope payments are consistent with VNB start

	select @RowCount = @@rowcount
	set @ProcessMessage = '#owt_Recognition = ' + convert(nvarchar(10), @RowCount)
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client
	
	/****************************************************************************

		Merge the temporary table into the permanent table
																		
	****************************************************************************/

	BEGIN TRANSACTION

	declare @SummaryOfChanges table (Change varchar(20))
	merge	dbo.owt_Recognition as trg
	using	#owt_Recognition as src
	on		trg.SourceID = src.SourceID
	and		trg.Source = src.Source
	when	matched 
--	and		isnull(trg.PointsTotal,0) <> isnull(src.PointsTotal,0)
	then	update 
				set trg.CaseID = src.CaseID,
					trg.TransactionID = src.TransactionID,
					trg.Policy = src.Policy,
					trg.ProductCode = src.ProductCode,
					trg.BusinessCode = src.BusinessCode,
					trg.SellerCode = src.SellerCode,						--AG 13/06/2018
					trg.PointsTotal = src.PointsTotal,
					trg.BSC = src.BSC,
					trg.MBF = src.MBF,
					trg.Initial = src.Initial,
					trg.OngoingTotal = src.OngoingTotal,
					trg.OngoingYr01 = src.OngoingYr01,
					trg.OngoingYr02 = src.OngoingYr02,
					trg.OngoingYr03 = src.OngoingYr03,
					trg.OngoingYr04 = src.OngoingYr04,
					trg.OngoingYr05 = src.OngoingYr05,
					trg.OngoingYr06 = src.OngoingYr06,
					trg.OngoingYr07 = src.OngoingYr07,
					trg.OngoingYr08 = src.OngoingYr08,
					trg.OngoingYr09 = src.OngoingYr09,
					trg.OngoingYr10 = src.OngoingYr10,
					trg.FCARate = src.FCARate,
					trg.RetentionRate = src.RetentionRate,
					trg.RetentionRateBroker = src.RetentionRateBroker,
					trg.OngoingServicingRate = src.OngoingServicingRate,
					trg.OngoingServicingSource = src.OngoingServicingSource,
					trg.DA = src.DA,
					trg.AmountReceived = src.AmountReceived,
					trg.Premium = src.Premium,
					trg.AgentSplit = src.AgentSplit,
					trg.CommissionType = src.CommissionType,
					trg.CommissionTypeDesc = src.CommissionTypeDesc,
					trg.PayBasisCode = trg.PayBasisCode,					--AG 13/06/2018
					trg.PayBasisDesc = trg.PayBasisDesc,					--AG 13/06/2018
					trg.PaymentMatchedDate = trg.PaymentMatchedDate,		--AG 13/06/2018
					trg.Month = src.Month,
					trg.FrequencyCode = src.FrequencyCode,
					trg.FrequencyDesc = src.FrequencyDesc,
					trg.ReassignedProductGroupCode = src.ReassignedProductGroupCode,	--AG 05/06/2018
					trg.ReassignedProductGroupName = src.ReassignedProductGroupCode,	--AG 05/06/2018
					trg.RecognitionType = src.RecognitionType,
					trg.CalculationType = src.CalculationType,
					trg.DateLastUpdated = @DateLastUpdated
	when	not matched by target 
	then	insert
			(
				SourceID,
				CaseID,
				TransactionID,
				Policy,
				ProductCode,
				BusinessCode,
				SellerCode,							--AG 13/06/2018
				PointsTotal,
				BSC,
				MBF,
				Initial,
				OngoingTotal,
				OngoingYr01,
				OngoingYr02,
				OngoingYr03,
				OngoingYr04,
				OngoingYr05,
				OngoingYr06,
				OngoingYr07,
				OngoingYr08,
				OngoingYr09,
				OngoingYr10,
				FCARate,
				RetentionRate,
				RetentionRateBroker,
				OngoingServicingRate,
				OngoingServicingSource,
				DA,
				AmountReceived,
				Premium,
				AgentSplit,
				CommissionType,
				CommissionTypeDesc,
				PayBasisCode,						--AG 13/06/2018
				PayBasisDesc,						--AG 13/06/2018
				PaymentMatchedDate,					--AG 13/06/2018
				Month,
				FrequencyCode,
				FrequencyDesc,
				ReassignedProductGroupCode,			--AG 05/06/2018
				ReassignedProductGroupName,			--AG 05/06/2018
				RecognitionType,
				CalculationType,
				Source,
				DateInserted,
				DateLastUpdated
			)		
			values
			(
				src.SourceID,
				src.CaseID,
				src.TransactionID,
				src.Policy,
				src.ProductCode,
				src.BusinessCode,
				src.SellerCode,						--AG 13/06/2018
				src.PointsTotal,
				src.BSC,
				src.MBF,
				src.Initial,
				src.OngoingTotal,
				src.OngoingYr01,
				src.OngoingYr02,
				src.OngoingYr03,
				src.OngoingYr04,
				src.OngoingYr05,
				src.OngoingYr06,
				src.OngoingYr07,
				src.OngoingYr08,
				src.OngoingYr09,
				src.OngoingYr10,
				src.FCARate,
				src.RetentionRate,
				src.RetentionRateBroker,
				src.OngoingServicingRate,
				src.OngoingServicingSource,
				src.DA,
				src.AmountReceived,
				src.Premium,
				src.AgentSplit,
				src.CommissionType,
				src.CommissionTypeDesc,
				src.PayBasisCode,					--AG 13/06/2018
				src.PayBasisDesc,					--AG 13/06/2018
				src.PaymentMatchedDate,				--AG 13/06/2018
				src.Month,
				src.FrequencyCode,
				src.FrequencyDesc,
				src.ReassignedProductGroupCode,		--AG 05/06/2018
				src.ReassignedProductGroupName,		--AG 05/06/2018
				src.RecognitionType,
				src.CalculationType,
				src.Source,
				src.DateInserted,
				src.DateLastUpdated)				
	output $action into @SummaryOfChanges;			--Merge statements must have a ;

	--00:00:16	27594
	update	oal
		set VNB_Points = r.PointsTotal
	from	owt_PaymentshieldCommissionPayments pcp
			inner join msit_OpenworkAdviserListing oal on oal.SourceID = pcp.ID and oal.Source = 'Payshield'
			inner join owt_Recognition r 
						on  r.SourceID = pcp.ID
						and r.Source = oal.Source		
	where	isnull(oal.VNB_Points,0) <> isnull(r.PointsTotal,0)
	
	select @OALRowCount = @@rowcount

	COMMIT TRANSACTION      

	select	@RowCount = COUNT(*)
	from	@SummaryOfChanges
	where	Change = 'INSERT'

	set @ProcessMessage = 'owt_Recognition (insert) = ' + convert(nvarchar(10), @RowCount)
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

	select	@RowCount = COUNT(*)
	from	@SummaryOfChanges
	where	Change = 'UPDATE'

	set @ProcessMessage = 'owt_Recognition (update) = ' + convert(nvarchar(10), @RowCount)
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

	set @ProcessMessage = 'msit_OpenworkAdviserListing (update) = ' + convert(nvarchar(10), @OALRowCount)
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

	/****************************************************************************

		T H E   E N D
																		
	****************************************************************************/
	
	exec msp_ProcessLog @PhaseEnd, @ProcName, null, @Module, @Client

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE(), @ErrState = XACT_STATE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10))
	
	-- Test XACT_STATE for 0, 1, or -1.
    -- If 1, the transaction is committable.
    -- If -1, the transaction is uncommittable and should be rolled back.
    -- If 0, there is no transaction and a commit or rollback operation would generate an error.

	if @ErrState = -1			-- Transaction is uncommitable
		rollback transaction

	if @ErrState = 1			
		commit transaction

	-- Error message line 1
	set @ErrMsgBrief = left(@ErrMsg,100)
	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	
	-- Error message line 2 - if any text exists
	set @ErrMsgBrief = substring(@ErrMsg,101,100)
	if len(@ErrMsgBrief) > 0
		exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client

	exec msp_ProcessLog @PhaseEnd, @ProcName, null, @Module, @Client

	RAISERROR(@ErrMsg, @ErrSev , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/

return @ErrNum



GO
/****** Object:  StoredProcedure [dbo].[owp_RecognitionGIPaymentshield_Backup20180523AG]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
