*************************************************************************************************************/

CREATE PROCEDURE [dbo].[owp_RecognitionGIPaymentshield_Backup20180523AG]
	@Client		varchar(50),
	@Module		Varchar(50)
AS

set nocount on

declare		@PhaseStart				varchar(50),
			@PhaseEnd				varchar(50),
			@PhaseError				varchar(50),
			@PhaseLog				varchar(50),
			@ProcName				varchar(100),
			@ProcessMessage			varchar(100),
			@RowCount				int,
			@OALRowCount			int,
			@ErrMsg					nvarchar(4000),
			@ErrMsgBrief			nvarchar(100),
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@ErrState				int
			
/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @ProcName			= object_name(@@procid)
set @PhaseStart			= 'START'
set @PhaseEnd			= 'END'
set @PhaseError			= 'ERROR'
set @PhaseLog			= 'LOG'
set @ErrNum				= 0	

-- We want this logging irrespective of whether or not there is a rollback
exec msp_ProcessLog @PhaseStart, @ProcName, null, @Module, @Client

/****************************************************************************

	Populate the table																
																		
****************************************************************************/

SET XACT_ABORT ON	-- Needed if XACT_STATE() function is used.

BEGIN TRY

	/****************************************************************************

		Calculate VNB and populate the temporary table with the results
																		
	****************************************************************************/

	select top 0 *
	into #owt_Recognition
	from owt_Recognition

	declare @OwlManager2Code nvarchar(10)
	set @OwlManager2Code = (select cde.Code from msit_MIWarehouseCodesAndDescriptions cde
				where cde.ColumnName = 'Manager2Code' and cde.Description = 'Owl Financial')
	declare @DateLastUpdated datetime = getdate()

	--AG 21/05/2018. Get the oldest payment date for each policy so that the 12 month period can be derived
	select	Policy, MIN(PaymentDate) as MinPaymentDate
	into	#EarliestPolPayments
	from	owt_PaymentshieldCommissionPayments pcp
			inner join mstt_Agents ag on ag.Code = pcp.BusinessCode
	where	ag.Manager2Code <> @OwlManager2Code		--Exclude Owl
	group	by Policy

	insert into #owt_Recognition
	(
		SourceID,
		CaseID,
		TransactionID,
		Policy,
		ProductCode,
		BusinessCode,
		PointsTotal,
		BSC,
		MBF,
		Initial,
		OngoingTotal,
		OngoingYr01,
		OngoingYr02,
		OngoingYr03,
		OngoingYr04,
		OngoingYr05,
		OngoingYr06,
		OngoingYr07,
		OngoingYr08,
		OngoingYr09,
		OngoingYr10,
		FCARate,
		RetentionRate,
		RetentionRateBroker,
		OngoingServicingRate,
		OngoingServicingSource,
		DA,
		AmountReceived,
		Premium,
		AgentSplit,
		CommissionType,
		CommissionTypeDesc,
		Month,
		FrequencyCode,
		FrequencyDesc,
		RecognitionType,
		CalculationType,
		Source,
		DateInserted,
		DateLastUpdated
	)
	select	pcp.ID as SourceID,
			null as CaseID,
			null as TransactionID,
			pcp.Policy,
			pcp.HierarchyProduct as ProductCode,
			pcp.BusinessCode,
			case when pcp.PaymentAmount < 0.0		--AG 21/05/2018
				then ((pcp.PaymentAmount * GIrate.FACTOR) - (pcp.PaymentAmount * GIfca.FACTOR)) * GIrate.Multiplier 
				else ((pcp.DA * GIrate.FACTOR) - (pcp.DA * GIfca.FACTOR)) * GIrate.Multiplier 
			end as PointsTotal,
			0 as BSC,
			0 as MBF,
			case when pcp.PaymentAmount < 0.0		--AG 21/05/2018
				then ((pcp.PaymentAmount * GIrate.FACTOR) - (pcp.PaymentAmount * GIfca.FACTOR)) * GIrate.Multiplier 
				else ((pcp.DA * GIrate.FACTOR) - (pcp.DA * GIfca.FACTOR)) * GIrate.Multiplier 
			end as Initial,
			0 as OngoingTotal,
			0 as OngoingYr01,
			0 as OngoingYr02,
			0 as OngoingYr03,
			0 as OngoingYr04,
			0 as OngoingYr05,
			0 as OngoingYr06,
			0 as OngoingYr07,
			0 as OngoingYr08,
			0 as OngoingYr09,
			0 as OngoingYr10,
			GIfca.FACTOR*100.0 as FCARate,
			GIrate.FACTOR*100.0 as RetentionRate,
			0 as RetentionRateBroker,
			null as OngoingServicingRate,
			null as OngoingServicingSource,
			pcp.DA,
			pcp.DA as AmountReceived,
			pcp.Premium,
			100.0 as AgentSplit,
			null as CommissionType,
			pcp.FeeType as CommissionTypeDesc,
			pcp.Month,
			null as FrequencyCode,
			pcp.Frequency as FrequencyDesc,
			'VNB' as RecognitionType,
			'GI' as CalculationType,
			pcp.Source,
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated
	from	owt_PaymentshieldCommissionPayments pcp
/*			inner join (select max(FileID) as FileID
						from owt_PaymentshieldImportControl) X on pcp.CreateDate = X.FileID
*/			inner join #EarliestPolPayments epp on epp.Policy = pcp.Policy
			inner join mstt_Agents ag on ag.Code = pcp.BusinessCode
			inner join msit_Commissionstatementperiods csp on csp.month = pcp.month
			inner join msit_CommissionStatementPeriods VNBStart on convert(date,pcp.StartDate) between VNBStart.PeriodStartDate and VNBStart.PeriodEndDate
			left join owt_EliteFactors GIfca on GIfca.FeeType = 'VNB' and GIfca.category = 'GI-FCA-RATE' and csp.year between GIfca.StartYear and GIfca.EndYear 
			left join owt_EliteFactors GIrate on GIrate.FeeType = 'VNB' and GIrate.category = 'GI-RETENTION-RATE' and csp.year between GIrate.StartYear and GIrate.EndYear 
	where	ag.Manager2Code <> @OwlManager2Code		--Exclude Owl
	and		pcp.PaymentAmount <> 0 
	and		pcp.SalesMoveFlag <> 'N'				--Although <> 'N' is loaded to OA, only = 'Y' gets DA, etc. calculated.
	--IC and Adj must be in 1st year of policy. Add 11 months to 01/05/2017 and you get 01/04/2018 as required.
	and		pcp.PaymentDate <= DATEADD(mm,11,epp.MinPaymentDate)	--AG 21/05/2018	
	and		VNBStart.Year >= 2017					--VNB to start from 2017
	and		csp.Year >= 2017						--Ensure in-scope payments are consistent with VNB start

	select @RowCount = @@rowcount
	set @ProcessMessage = '#owt_Recognition = ' + convert(nvarchar(10), @RowCount)
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client
	
	/****************************************************************************

		Merge the temporary table into the permanent table
																		
	****************************************************************************/

	BEGIN TRANSACTION

	declare @SummaryOfChanges table (Change varchar(20))
	merge	dbo.owt_Recognition as trg
	using	#owt_Recognition as src
	on		trg.SourceID = src.SourceID
	and		trg.Source = src.Source
	when	matched 
	and		isnull(trg.PointsTotal,0) <> isnull(src.PointsTotal,0)
	then	update 
				set trg.CaseID = src.CaseID,
					trg.TransactionID = src.TransactionID,
					trg.Policy = src.Policy,
					trg.ProductCode = src.ProductCode,
					trg.BusinessCode = src.BusinessCode,
					trg.PointsTotal = src.PointsTotal,
					trg.BSC = src.BSC,
					trg.MBF = src.MBF,
					trg.Initial = src.Initial,
					trg.OngoingTotal = src.OngoingTotal,
					trg.OngoingYr01 = src.OngoingYr01,
					trg.OngoingYr02 = src.OngoingYr02,
					trg.OngoingYr03 = src.OngoingYr03,
					trg.OngoingYr04 = src.OngoingYr04,
					trg.OngoingYr05 = src.OngoingYr05,
					trg.OngoingYr06 = src.OngoingYr06,
					trg.OngoingYr07 = src.OngoingYr07,
					trg.OngoingYr08 = src.OngoingYr08,
					trg.OngoingYr09 = src.OngoingYr09,
					trg.OngoingYr10 = src.OngoingYr10,
					trg.FCARate = src.FCARate,
					trg.RetentionRate = src.RetentionRate,
					trg.RetentionRateBroker = src.RetentionRateBroker,
					trg.OngoingServicingRate = src.OngoingServicingRate,
					trg.OngoingServicingSource = src.OngoingServicingSource,
					trg.DA = src.DA,
					trg.AmountReceived = src.AmountReceived,
					trg.Premium = src.Premium,
					trg.AgentSplit = src.AgentSplit,
					trg.CommissionType = src.CommissionType,
					trg.CommissionTypeDesc = src.CommissionTypeDesc,
					trg.Month = src.Month,
					trg.FrequencyCode = src.FrequencyCode,
					trg.FrequencyDesc = src.FrequencyDesc,
					trg.RecognitionType = src.RecognitionType,
					trg.CalculationType = src.CalculationType,
					trg.DateLastUpdated = @DateLastUpdated
	when	not matched by target 
	then	insert
			(
				SourceID,
				CaseID,
				TransactionID,
				Policy,
				ProductCode,
				BusinessCode,
				PointsTotal,
				BSC,
				MBF,
				Initial,
				OngoingTotal,
				OngoingYr01,
				OngoingYr02,
				OngoingYr03,
				OngoingYr04,
				OngoingYr05,
				OngoingYr06,
				OngoingYr07,
				OngoingYr08,
				OngoingYr09,
				OngoingYr10,
				FCARate,
				RetentionRate,
				RetentionRateBroker,
				OngoingServicingRate,
				OngoingServicingSource,
				DA,
				AmountReceived,
				Premium,
				AgentSplit,
				CommissionType,
				CommissionTypeDesc,
				Month,
				FrequencyCode,
				FrequencyDesc,
				RecognitionType,
				CalculationType,
				Source,
				DateInserted,
				DateLastUpdated
			)		
			values
			(
				src.SourceID,
				src.CaseID,
				src.TransactionID,
				src.Policy,
				src.ProductCode,
				src.BusinessCode,
				src.PointsTotal,
				src.BSC,
				src.MBF,
				src.Initial,
				src.OngoingTotal,
				src.OngoingYr01,
				src.OngoingYr02,
				src.OngoingYr03,
				src.OngoingYr04,
				src.OngoingYr05,
				src.OngoingYr06,
				src.OngoingYr07,
				src.OngoingYr08,
				src.OngoingYr09,
				src.OngoingYr10,
				src.FCARate,
				src.RetentionRate,
				src.RetentionRateBroker,
				src.OngoingServicingRate,
				src.OngoingServicingSource,
				src.DA,
				src.AmountReceived,
				src.Premium,
				src.AgentSplit,
				src.CommissionType,
				src.CommissionTypeDesc,
				src.Month,
				src.FrequencyCode,
				src.FrequencyDesc,
				src.RecognitionType,
				src.CalculationType,
				src.Source,
				src.DateInserted,
				src.DateLastUpdated)				
	output $action into @SummaryOfChanges;				--Merge statements must have a ;
/*	
	update	oal
		set VNB_Points = r.PointsTotal
	from	owt_PaymentshieldCommissionPayments pcp
			inner join (select max(FileID) as FileID
						from owt_PaymentshieldImportControl) X on pcp.CreateDate = X.FileID
			inner join msit_OpenworkAdviserListing oal on oal.SourceID = pcp.ID and oal.Source = 'Payshield'
			inner join owt_Recognition r 
						on r.RecognitionType = 'VNB'
						and r.SourceID = pcp.ID
						and r.Source = oal.Source		
	where	isnull(oal.VNB_Points,0) <> isnull(r.PointsTotal,0)
	
	select @OALRowCount = @@rowcount
*/
	COMMIT TRANSACTION      

	select	@RowCount = COUNT(*)
	from	@SummaryOfChanges
	where	Change = 'INSERT'

	set @ProcessMessage = 'owt_Recognition (insert) = ' + convert(nvarchar(10), @RowCount)
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

	select	@RowCount = COUNT(*)
	from	@SummaryOfChanges
	where	Change = 'UPDATE'

	set @ProcessMessage = 'owt_Recognition (update) = ' + convert(nvarchar(10), @RowCount)
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client
/*
	set @ProcessMessage = 'msit_OpenworkAdviserListing (update) = ' + convert(nvarchar(10), @OALRowCount)
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client
*/
	/****************************************************************************

		T H E   E N D
																		
	****************************************************************************/
	
	exec msp_ProcessLog @PhaseEnd, @ProcName, null, @Module, @Client

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE(), @ErrState = XACT_STATE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10))
	
	-- Test XACT_STATE for 0, 1, or -1.
    -- If 1, the transaction is committable.
    -- If -1, the transaction is uncommittable and should be rolled back.
    -- If 0, there is no transaction and a commit or rollback operation would generate an error.

	if @ErrState = -1			-- Transaction is uncommitable
		rollback transaction

	if @ErrState = 1			
		commit transaction

	-- Error message line 1
	set @ErrMsgBrief = left(@ErrMsg,100)
	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	
	-- Error message line 2 - if any text exists
	set @ErrMsgBrief = substring(@ErrMsg,101,100)
	if len(@ErrMsgBrief) > 0
		exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client

	exec msp_ProcessLog @PhaseEnd, @ProcName, null, @Module, @Client

	RAISERROR(@ErrMsg, @ErrSev , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/

return @ErrNum



GO
/****** Object:  StoredProcedure [dbo].[owp_RecognitionGIPaymentshield_Backup20180524AG]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*********************************************************************************************************

Program:		owp_RecognitionGIPaymentshield					
Author:			Alan Groves
Date created:	20/04/2018
											
Description:
===========

This proc populates the new recognition table called "owt_Recognition" with "Value of New Business"
(VNB) points.

This proc handles the GI (Paymentshield) data. 

Note: There is a separate proc that calculates the VNB points for Swift data covering:
WEALTH - COB business i.e. pensions and investments
MORTGAGES
PROTECTION

The approach of this proc is to use the same data-set loaded by the last Paymentshield load
to calculate the VNB points in a temporary table.

The temporary table is then merged with the permanent table to make the calculated (or
re-calculated values) permanent.

Terms
-----
DA	- Distribution Allowance (the total amount paid out by the provider to Openwork)


THE CALCULATION
===============

GI
--
Note: for GI, DA and APE are the same.
= (DA X GI Retention Rate) - (DA X GI FCA Rate) 
GI Points Total = Initial


This proc is called as follows:
	declare @rc int
	exec @rc = dbo.owp_RecognitionGIPaymentshield 'Openwork', 'Recognition'
	select @rc

				
AMENDMENT HISTORY				
=================								

Date		Author		Description
----		------		-----------
03/05/2018	A Groves	Added update of column "msit_OpenworkAdviserListing.VNB_Points".
21/05/2018	A Groves	1) At Marcus Cossey's request, GI payments should only be in scope
							in their first year. Typically, this will include the first payment
							and any clawbacks/adjustments that might occur throughout that first
							year.
						2) In the case of clawbacks/adjustments, the DA is not on the data
							row. Therefore, where the payment is negative, then the "PaymentAmount"
							is used. Where the payment is positive, then the "DA" is used.
23/05/2018	A Groves	Changed value stored in "PaymentReceived" column from "pcp.DA" to
							"pcp.PaymentAmount" as the latter is used for clawbacks and adjustments.
*************************************************************************************************************/

CREATE PROCEDURE [dbo].[owp_RecognitionGIPaymentshield_Backup20180524AG]
	@Client		varchar(50),
	@Module		Varchar(50)
AS

set nocount on

declare		@PhaseStart				varchar(50),
			@PhaseEnd				varchar(50),
			@PhaseError				varchar(50),
			@PhaseLog				varchar(50),
			@ProcName				varchar(100),
			@ProcessMessage			varchar(100),
			@RowCount				int,
			@OALRowCount			int,
			@ErrMsg					nvarchar(4000),
			@ErrMsgBrief			nvarchar(100),
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@ErrState				int
			
/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @ProcName			= object_name(@@procid)
set @PhaseStart			= 'START'
set @PhaseEnd			= 'END'
set @PhaseError			= 'ERROR'
set @PhaseLog			= 'LOG'
set @ErrNum				= 0	

-- We want this logging irrespective of whether or not there is a rollback
exec msp_ProcessLog @PhaseStart, @ProcName, null, @Module, @Client

/****************************************************************************

	Populate the table																
																		
****************************************************************************/

SET XACT_ABORT ON	-- Needed if XACT_STATE() function is used.

BEGIN TRY

	/****************************************************************************

		Calculate VNB and populate the temporary table with the results
																		
	****************************************************************************/

	select top 0 *
	into #owt_Recognition
	from owt_Recognition

	declare @OwlManager2Code nvarchar(10)
	set @OwlManager2Code = (select cde.Code from msit_MIWarehouseCodesAndDescriptions cde
				where cde.ColumnName = 'Manager2Code' and cde.Description = 'Owl Financial')
	declare @DateLastUpdated datetime = getdate()

	--AG 21/05/2018. Get the oldest payment date for each policy so that the 12 month period can be derived
	select	Policy, MIN(PaymentDate) as MinPaymentDate
	into	#EarliestPolPayments
	from	owt_PaymentshieldCommissionPayments pcp
			inner join mstt_Agents ag on ag.Code = pcp.BusinessCode
	where	ag.Manager2Code <> @OwlManager2Code		--Exclude Owl
	group	by Policy

	insert into #owt_Recognition
	(
		SourceID,
		CaseID,
		TransactionID,
		Policy,
		ProductCode,
		BusinessCode,
		PointsTotal,
		BSC,
		MBF,
		Initial,
		OngoingTotal,
		OngoingYr01,
		OngoingYr02,
		OngoingYr03,
		OngoingYr04,
		OngoingYr05,
		OngoingYr06,
		OngoingYr07,
		OngoingYr08,
		OngoingYr09,
		OngoingYr10,
		FCARate,
		RetentionRate,
		RetentionRateBroker,
		OngoingServicingRate,
		OngoingServicingSource,
		DA,
		AmountReceived,
		Premium,
		AgentSplit,
		CommissionType,
		CommissionTypeDesc,
		Month,
		FrequencyCode,
		FrequencyDesc,
		RecognitionType,
		CalculationType,
		Source,
		DateInserted,
		DateLastUpdated
	)
	select	pcp.ID as SourceID,
			null as CaseID,
			null as TransactionID,
			pcp.Policy,
			pcp.HierarchyProduct as ProductCode,
			pcp.BusinessCode,
			case when pcp.PaymentAmount < 0.0		--AG 21/05/2018
				then ((pcp.PaymentAmount * GIrate.FACTOR) - (pcp.PaymentAmount * GIfca.FACTOR)) * GIrate.Multiplier 
				else ((pcp.DA * GIrate.FACTOR) - (pcp.DA * GIfca.FACTOR)) * GIrate.Multiplier 
			end as PointsTotal,
			0 as BSC,
			0 as MBF,
			case when pcp.PaymentAmount < 0.0		--AG 21/05/2018
				then ((pcp.PaymentAmount * GIrate.FACTOR) - (pcp.PaymentAmount * GIfca.FACTOR)) * GIrate.Multiplier 
				else ((pcp.DA * GIrate.FACTOR) - (pcp.DA * GIfca.FACTOR)) * GIrate.Multiplier 
			end as Initial,
			0 as OngoingTotal,
			0 as OngoingYr01,
			0 as OngoingYr02,
			0 as OngoingYr03,
			0 as OngoingYr04,
			0 as OngoingYr05,
			0 as OngoingYr06,
			0 as OngoingYr07,
			0 as OngoingYr08,
			0 as OngoingYr09,
			0 as OngoingYr10,
			GIfca.FACTOR*100.0 as FCARate,
			GIrate.FACTOR*100.0 as RetentionRate,
			0 as RetentionRateBroker,
			null as OngoingServicingRate,
			null as OngoingServicingSource,
			pcp.DA,
			pcp.PaymentAmount as AmountReceived,	--AG 23/05/2018
			pcp.Premium,
			100.0 as AgentSplit,
			null as CommissionType,
			pcp.FeeType as CommissionTypeDesc,
			pcp.Month,
			null as FrequencyCode,
			pcp.Frequency as FrequencyDesc,
			'VNB' as RecognitionType,
			'GI' as CalculationType,
			pcp.Source,
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated
	from	owt_PaymentshieldCommissionPayments pcp
/*			inner join (select max(FileID) as FileID
						from owt_PaymentshieldImportControl) X on pcp.CreateDate = X.FileID
*/			inner join #EarliestPolPayments epp on epp.Policy = pcp.Policy
			inner join mstt_Agents ag on ag.Code = pcp.BusinessCode
			inner join msit_Commissionstatementperiods csp on csp.month = pcp.month
			inner join msit_CommissionStatementPeriods VNBStart on convert(date,pcp.StartDate) between VNBStart.PeriodStartDate and VNBStart.PeriodEndDate
			left join owt_EliteFactors GIfca on GIfca.FeeType = 'VNB' and GIfca.category = 'GI-FCA-RATE' and csp.year between GIfca.StartYear and GIfca.EndYear 
			left join owt_EliteFactors GIrate on GIrate.FeeType = 'VNB' and GIrate.category = 'GI-RETENTION-RATE' and csp.year between GIrate.StartYear and GIrate.EndYear 
	where	ag.Manager2Code <> @OwlManager2Code		--Exclude Owl
	and		pcp.PaymentAmount <> 0 
	and		pcp.SalesMoveFlag <> 'N'				--Although <> 'N' is loaded to OA, only = 'Y' gets DA, etc. calculated.
	--IC and Adj must be in 1st year of policy. Add 11 months to 01/05/2017 and you get 01/04/2018 as required.
	and		pcp.PaymentDate <= DATEADD(mm,11,epp.MinPaymentDate)	--AG 21/05/2018	
	and		VNBStart.Year >= 2017					--VNB to start from 2017
	and		csp.Year >= 2017						--Ensure in-scope payments are consistent with VNB start

	select @RowCount = @@rowcount
	set @ProcessMessage = '#owt_Recognition = ' + convert(nvarchar(10), @RowCount)
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client
	
	/****************************************************************************

		Merge the temporary table into the permanent table
																		
	****************************************************************************/

	BEGIN TRANSACTION

	declare @SummaryOfChanges table (Change varchar(20))
	merge	dbo.owt_Recognition as trg
	using	#owt_Recognition as src
	on		trg.SourceID = src.SourceID
	and		trg.Source = src.Source
	when	matched 
	and		isnull(trg.PointsTotal,0) <> isnull(src.PointsTotal,0)
	then	update 
				set trg.CaseID = src.CaseID,
					trg.TransactionID = src.TransactionID,
					trg.Policy = src.Policy,
					trg.ProductCode = src.ProductCode,
					trg.BusinessCode = src.BusinessCode,
					trg.PointsTotal = src.PointsTotal,
					trg.BSC = src.BSC,
					trg.MBF = src.MBF,
					trg.Initial = src.Initial,
					trg.OngoingTotal = src.OngoingTotal,
					trg.OngoingYr01 = src.OngoingYr01,
					trg.OngoingYr02 = src.OngoingYr02,
					trg.OngoingYr03 = src.OngoingYr03,
					trg.OngoingYr04 = src.OngoingYr04,
					trg.OngoingYr05 = src.OngoingYr05,
					trg.OngoingYr06 = src.OngoingYr06,
					trg.OngoingYr07 = src.OngoingYr07,
					trg.OngoingYr08 = src.OngoingYr08,
					trg.OngoingYr09 = src.OngoingYr09,
					trg.OngoingYr10 = src.OngoingYr10,
					trg.FCARate = src.FCARate,
					trg.RetentionRate = src.RetentionRate,
					trg.RetentionRateBroker = src.RetentionRateBroker,
					trg.OngoingServicingRate = src.OngoingServicingRate,
					trg.OngoingServicingSource = src.OngoingServicingSource,
					trg.DA = src.DA,
					trg.AmountReceived = src.AmountReceived,
					trg.Premium = src.Premium,
					trg.AgentSplit = src.AgentSplit,
					trg.CommissionType = src.CommissionType,
					trg.CommissionTypeDesc = src.CommissionTypeDesc,
					trg.Month = src.Month,
					trg.FrequencyCode = src.FrequencyCode,
					trg.FrequencyDesc = src.FrequencyDesc,
					trg.RecognitionType = src.RecognitionType,
					trg.CalculationType = src.CalculationType,
					trg.DateLastUpdated = @DateLastUpdated
	when	not matched by target 
	then	insert
			(
				SourceID,
				CaseID,
				TransactionID,
				Policy,
				ProductCode,
				BusinessCode,
				PointsTotal,
				BSC,
				MBF,
				Initial,
				OngoingTotal,
				OngoingYr01,
				OngoingYr02,
				OngoingYr03,
				OngoingYr04,
				OngoingYr05,
				OngoingYr06,
				OngoingYr07,
				OngoingYr08,
				OngoingYr09,
				OngoingYr10,
				FCARate,
				RetentionRate,
				RetentionRateBroker,
				OngoingServicingRate,
				OngoingServicingSource,
				DA,
				AmountReceived,
				Premium,
				AgentSplit,
				CommissionType,
				CommissionTypeDesc,
				Month,
				FrequencyCode,
				FrequencyDesc,
				RecognitionType,
				CalculationType,
				Source,
				DateInserted,
				DateLastUpdated
			)		
			values
			(
				src.SourceID,
				src.CaseID,
				src.TransactionID,
				src.Policy,
				src.ProductCode,
				src.BusinessCode,
				src.PointsTotal,
				src.BSC,
				src.MBF,
				src.Initial,
				src.OngoingTotal,
				src.OngoingYr01,
				src.OngoingYr02,
				src.OngoingYr03,
				src.OngoingYr04,
				src.OngoingYr05,
				src.OngoingYr06,
				src.OngoingYr07,
				src.OngoingYr08,
				src.OngoingYr09,
				src.OngoingYr10,
				src.FCARate,
				src.RetentionRate,
				src.RetentionRateBroker,
				src.OngoingServicingRate,
				src.OngoingServicingSource,
				src.DA,
				src.AmountReceived,
				src.Premium,
				src.AgentSplit,
				src.CommissionType,
				src.CommissionTypeDesc,
				src.Month,
				src.FrequencyCode,
				src.FrequencyDesc,
				src.RecognitionType,
				src.CalculationType,
				src.Source,
				src.DateInserted,
				src.DateLastUpdated)				
	output $action into @SummaryOfChanges;				--Merge statements must have a ;
/*	
	update	oal
		set VNB_Points = r.PointsTotal
	from	owt_PaymentshieldCommissionPayments pcp
/*			inner join (select max(FileID) as FileID
						from owt_PaymentshieldImportControl) X on pcp.CreateDate = X.FileID
*/			inner join msit_OpenworkAdviserListing oal on oal.SourceID = pcp.ID and oal.Source = 'Payshield'
			inner join owt_Recognition r 
						on r.RecognitionType = 'VNB'
						and r.SourceID = pcp.ID
						and r.Source = oal.Source		
	where	isnull(oal.VNB_Points,0) <> isnull(r.PointsTotal,0)
	
	select @OALRowCount = @@rowcount
*/
	COMMIT TRANSACTION      

	select	@RowCount = COUNT(*)
	from	@SummaryOfChanges
	where	Change = 'INSERT'

	set @ProcessMessage = 'owt_Recognition (insert) = ' + convert(nvarchar(10), @RowCount)
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

	select	@RowCount = COUNT(*)
	from	@SummaryOfChanges
	where	Change = 'UPDATE'

	set @ProcessMessage = 'owt_Recognition (update) = ' + convert(nvarchar(10), @RowCount)
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client
/*
	set @ProcessMessage = 'msit_OpenworkAdviserListing (update) = ' + convert(nvarchar(10), @OALRowCount)
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client
*/
	/****************************************************************************

		T H E   E N D
																		
	****************************************************************************/
	
	exec msp_ProcessLog @PhaseEnd, @ProcName, null, @Module, @Client

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE(), @ErrState = XACT_STATE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10))
	
	-- Test XACT_STATE for 0, 1, or -1.
    -- If 1, the transaction is committable.
    -- If -1, the transaction is uncommittable and should be rolled back.
    -- If 0, there is no transaction and a commit or rollback operation would generate an error.

	if @ErrState = -1			-- Transaction is uncommitable
		rollback transaction

	if @ErrState = 1			
		commit transaction

	-- Error message line 1
	set @ErrMsgBrief = left(@ErrMsg,100)
	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	
	-- Error message line 2 - if any text exists
	set @ErrMsgBrief = substring(@ErrMsg,101,100)
	if len(@ErrMsgBrief) > 0
		exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client

	exec msp_ProcessLog @PhaseEnd, @ProcName, null, @Module, @Client

	RAISERROR(@ErrMsg, @ErrSev , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/

return @ErrNum



GO
/****** Object:  StoredProcedure [dbo].[owp_RecognitionGIPaymentshield_Backup20180606AG]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/*********************************************************************************************************

Program:		owp_RecognitionGIPaymentshield					
Author:			Alan Groves
Date created:	20/04/2018
											
Description:
===========

This proc populates the new recognition table called "owt_Recognition" with "Value of New Business"
(VNB) points.

This proc handles the GI (Paymentshield) data. 

Note: There is a separate proc that calculates the VNB points for Swift data covering:
WEALTH - COB business i.e. pensions and investments
MORTGAGES
PROTECTION

The approach of this proc is to use the same data-set loaded by the last Paymentshield load
to calculate the VNB points in a temporary table.

The temporary table is then merged with the permanent table to make the calculated (or
re-calculated values) permanent.

Terms
-----
DA	- Distribution Allowance (the total amount paid out by the provider to Openwork)


THE CALCULATION
===============

GI
--
Note: for GI, DA and APE are the same.
= (DA X GI Retention Rate) - (DA X GI FCA Rate) 
GI Points Total = Initial


This proc is called as follows:
	declare @rc int
	exec @rc = dbo.owp_RecognitionGIPaymentshield 'Openwork', 'Recognition'
	select @rc

				
AMENDMENT HISTORY				
=================								

Date		Author		Description
----		------		-----------
03/05/2018	A Groves	Added update of column "msit_OpenworkAdviserListing.VNB_Points".
21/05/2018	A Groves	1) At Marcus Cossey's request, GI payments should only be in scope
							in their first year. Typically, this will include the first payment
							and any clawbacks/adjustments that might occur throughout that first
							year.
						2) In the case of clawbacks/adjustments, the DA is not on the data
							row. Therefore, where the payment is negative, then the "PaymentAmount"
							is used. Where the payment is positive, then the "DA" is used.
23/05/2018	A Groves	Changed value stored in "PaymentReceived" column from "pcp.DA" to
							"pcp.PaymentAmount" as the latter is used for clawbacks and adjustments.
24/05/2018	A Groves	Marcus Cossey asked for the following payments to be excluded from VNB:
						1) Where OrigCommType = 'Renewal'
						2) Where OrigStatus = 'RENEWAL'
						Note: Marcus didn't want to simply include the oldest +ve payment and all
						-ve payments in the first 12 months, as he did not want to miss out any
						MTA (mid term adjustment) credits.
*************************************************************************************************************/

CREATE PROCEDURE [dbo].[owp_RecognitionGIPaymentshield_Backup20180606AG]
	@Client		varchar(50),
	@Module		Varchar(50)
AS

set nocount on

declare		@PhaseStart				varchar(50),
			@PhaseEnd				varchar(50),
			@PhaseError				varchar(50),
			@PhaseLog				varchar(50),
			@ProcName				varchar(100),
			@ProcessMessage			varchar(100),
			@RowCount				int,
			@OALRowCount			int,
			@ErrMsg					nvarchar(4000),
			@ErrMsgBrief			nvarchar(100),
			@ErrNum					int,
			@ErrSev					int,
			@ErrLine				int,
			@ErrState				int
			
/****************************************************************************

	Set initial parameters																
																		
****************************************************************************/

set @ProcName			= object_name(@@procid)
set @PhaseStart			= 'START'
set @PhaseEnd			= 'END'
set @PhaseError			= 'ERROR'
set @PhaseLog			= 'LOG'
set @ErrNum				= 0	

-- We want this logging irrespective of whether or not there is a rollback
exec msp_ProcessLog @PhaseStart, @ProcName, null, @Module, @Client

/****************************************************************************

	Populate the table																
																		
****************************************************************************/

SET XACT_ABORT ON	-- Needed if XACT_STATE() function is used.

BEGIN TRY

	/****************************************************************************

		Calculate VNB and populate the temporary table with the results
																		
	****************************************************************************/

	select top 0 *
	into #owt_Recognition
	from owt_Recognition

	declare @OwlManager2Code nvarchar(10)
	set @OwlManager2Code = (select cde.Code from msit_MIWarehouseCodesAndDescriptions cde
				where cde.ColumnName = 'Manager2Code' and cde.Description = 'Owl Financial')
	declare @DateLastUpdated datetime = getdate()

	--AG 21/05/2018. Get the oldest payment date for each policy so that the 12 month period can be derived
	select	Policy, MIN(PaymentDate) as MinPaymentDate
	into	#EarliestPolPayments
	from	owt_PaymentshieldCommissionPayments pcp
			inner join mstt_Agents ag on ag.Code = pcp.BusinessCode
	where	ag.Manager2Code <> @OwlManager2Code		--Exclude Owl
	group	by Policy

	insert into #owt_Recognition
	(
		SourceID,
		CaseID,
		TransactionID,
		Policy,
		ProductCode,
		BusinessCode,
		PointsTotal,
		BSC,
		MBF,
		Initial,
		OngoingTotal,
		OngoingYr01,
		OngoingYr02,
		OngoingYr03,
		OngoingYr04,
		OngoingYr05,
		OngoingYr06,
		OngoingYr07,
		OngoingYr08,
		OngoingYr09,
		OngoingYr10,
		FCARate,
		RetentionRate,
		RetentionRateBroker,
		OngoingServicingRate,
		OngoingServicingSource,
		DA,
		AmountReceived,
		Premium,
		AgentSplit,
		CommissionType,
		CommissionTypeDesc,
		Month,
		FrequencyCode,
		FrequencyDesc,
		RecognitionType,
		CalculationType,
		Source,
		DateInserted,
		DateLastUpdated
	)
	select	pcp.ID as SourceID,
			null as CaseID,
			null as TransactionID,
			pcp.Policy,
			pcp.HierarchyProduct as ProductCode,
			pcp.BusinessCode,
			case when pcp.PaymentAmount < 0.0		--AG 21/05/2018
				then ((pcp.PaymentAmount * GIrate.FACTOR) - (pcp.PaymentAmount * GIfca.FACTOR)) * GIrate.Multiplier 
				else ((pcp.DA * GIrate.FACTOR) - (pcp.DA * GIfca.FACTOR)) * GIrate.Multiplier 
			end as PointsTotal,
			0 as BSC,
			0 as MBF,
			case when pcp.PaymentAmount < 0.0		--AG 21/05/2018
				then ((pcp.PaymentAmount * GIrate.FACTOR) - (pcp.PaymentAmount * GIfca.FACTOR)) * GIrate.Multiplier 
				else ((pcp.DA * GIrate.FACTOR) - (pcp.DA * GIfca.FACTOR)) * GIrate.Multiplier 
			end as Initial,
			0 as OngoingTotal,
			0 as OngoingYr01,
			0 as OngoingYr02,
			0 as OngoingYr03,
			0 as OngoingYr04,
			0 as OngoingYr05,
			0 as OngoingYr06,
			0 as OngoingYr07,
			0 as OngoingYr08,
			0 as OngoingYr09,
			0 as OngoingYr10,
			GIfca.FACTOR*100.0 as FCARate,
			GIrate.FACTOR*100.0 as RetentionRate,
			0 as RetentionRateBroker,
			null as OngoingServicingRate,
			null as OngoingServicingSource,
			pcp.DA,
			pcp.PaymentAmount as AmountReceived,	--AG 23/05/2018
			pcp.Premium,
			100.0 as AgentSplit,
			null as CommissionType,
			pcp.FeeType as CommissionTypeDesc,
			pcp.Month,
			null as FrequencyCode,
			pcp.Frequency as FrequencyDesc,
			'VNB' as RecognitionType,
			'GI' as CalculationType,
			pcp.Source,
			@DateLastUpdated as DateInserted,
			@DateLastUpdated as DateLastUpdated
	from	owt_PaymentshieldCommissionPayments pcp
/*			inner join (select max(FileID) as FileID
						from owt_PaymentshieldImportControl) X on pcp.CreateDate = X.FileID
*/			inner join #EarliestPolPayments epp on epp.Policy = pcp.Policy
			inner join mstt_Agents ag on ag.Code = pcp.BusinessCode
			inner join msit_Commissionstatementperiods csp on csp.month = pcp.month
			inner join msit_CommissionStatementPeriods VNBStart on convert(date,pcp.StartDate) between VNBStart.PeriodStartDate and VNBStart.PeriodEndDate
			left join owt_EliteFactors GIfca on GIfca.FeeType = 'VNB' and GIfca.category = 'GI-FCA-RATE' and csp.year between GIfca.StartYear and GIfca.EndYear 
			left join owt_EliteFactors GIrate on GIrate.FeeType = 'VNB' and GIrate.category = 'GI-RETENTION-RATE' and csp.year between GIrate.StartYear and GIrate.EndYear 
	where	ag.Manager2Code <> @OwlManager2Code		--Exclude Owl
	and		pcp.PaymentAmount <> 0 
	and		pcp.SalesMoveFlag <> 'N'				--Although <> 'N' is loaded to OA, only = 'Y' gets DA, etc. calculated.
	and		pcp.OrigCommtype <> 'Renewal'			--AG 24/05/2018
	and		pcp.OrigStatus <> 'RENEWAL'				--AG 24/05/2018
	--IC and Adj must be in 1st year of policy. Add 11 months to 01/05/2017 and you get 01/04/2018 as required.
	and		pcp.PaymentDate <= DATEADD(mm,11,epp.MinPaymentDate)	--AG 21/05/2018	
	and		VNBStart.Year >= 2017					--VNB to start from 2017
	and		csp.Year >= 2017						--Ensure in-scope payments are consistent with VNB start

	select @RowCount = @@rowcount
	set @ProcessMessage = '#owt_Recognition = ' + convert(nvarchar(10), @RowCount)
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client
	
	/****************************************************************************

		Merge the temporary table into the permanent table
																		
	****************************************************************************/

	BEGIN TRANSACTION

	declare @SummaryOfChanges table (Change varchar(20))
	merge	dbo.owt_Recognition as trg
	using	#owt_Recognition as src
	on		trg.SourceID = src.SourceID
	and		trg.Source = src.Source
	when	matched 
	and		isnull(trg.PointsTotal,0) <> isnull(src.PointsTotal,0)
	then	update 
				set trg.CaseID = src.CaseID,
					trg.TransactionID = src.TransactionID,
					trg.Policy = src.Policy,
					trg.ProductCode = src.ProductCode,
					trg.BusinessCode = src.BusinessCode,
					trg.PointsTotal = src.PointsTotal,
					trg.BSC = src.BSC,
					trg.MBF = src.MBF,
					trg.Initial = src.Initial,
					trg.OngoingTotal = src.OngoingTotal,
					trg.OngoingYr01 = src.OngoingYr01,
					trg.OngoingYr02 = src.OngoingYr02,
					trg.OngoingYr03 = src.OngoingYr03,
					trg.OngoingYr04 = src.OngoingYr04,
					trg.OngoingYr05 = src.OngoingYr05,
					trg.OngoingYr06 = src.OngoingYr06,
					trg.OngoingYr07 = src.OngoingYr07,
					trg.OngoingYr08 = src.OngoingYr08,
					trg.OngoingYr09 = src.OngoingYr09,
					trg.OngoingYr10 = src.OngoingYr10,
					trg.FCARate = src.FCARate,
					trg.RetentionRate = src.RetentionRate,
					trg.RetentionRateBroker = src.RetentionRateBroker,
					trg.OngoingServicingRate = src.OngoingServicingRate,
					trg.OngoingServicingSource = src.OngoingServicingSource,
					trg.DA = src.DA,
					trg.AmountReceived = src.AmountReceived,
					trg.Premium = src.Premium,
					trg.AgentSplit = src.AgentSplit,
					trg.CommissionType = src.CommissionType,
					trg.CommissionTypeDesc = src.CommissionTypeDesc,
					trg.Month = src.Month,
					trg.FrequencyCode = src.FrequencyCode,
					trg.FrequencyDesc = src.FrequencyDesc,
					trg.RecognitionType = src.RecognitionType,
					trg.CalculationType = src.CalculationType,
					trg.DateLastUpdated = @DateLastUpdated
	when	not matched by target 
	then	insert
			(
				SourceID,
				CaseID,
				TransactionID,
				Policy,
				ProductCode,
				BusinessCode,
				PointsTotal,
				BSC,
				MBF,
				Initial,
				OngoingTotal,
				OngoingYr01,
				OngoingYr02,
				OngoingYr03,
				OngoingYr04,
				OngoingYr05,
				OngoingYr06,
				OngoingYr07,
				OngoingYr08,
				OngoingYr09,
				OngoingYr10,
				FCARate,
				RetentionRate,
				RetentionRateBroker,
				OngoingServicingRate,
				OngoingServicingSource,
				DA,
				AmountReceived,
				Premium,
				AgentSplit,
				CommissionType,
				CommissionTypeDesc,
				Month,
				FrequencyCode,
				FrequencyDesc,
				RecognitionType,
				CalculationType,
				Source,
				DateInserted,
				DateLastUpdated
			)		
			values
			(
				src.SourceID,
				src.CaseID,
				src.TransactionID,
				src.Policy,
				src.ProductCode,
				src.BusinessCode,
				src.PointsTotal,
				src.BSC,
				src.MBF,
				src.Initial,
				src.OngoingTotal,
				src.OngoingYr01,
				src.OngoingYr02,
				src.OngoingYr03,
				src.OngoingYr04,
				src.OngoingYr05,
				src.OngoingYr06,
				src.OngoingYr07,
				src.OngoingYr08,
				src.OngoingYr09,
				src.OngoingYr10,
				src.FCARate,
				src.RetentionRate,
				src.RetentionRateBroker,
				src.OngoingServicingRate,
				src.OngoingServicingSource,
				src.DA,
				src.AmountReceived,
				src.Premium,
				src.AgentSplit,
				src.CommissionType,
				src.CommissionTypeDesc,
				src.Month,
				src.FrequencyCode,
				src.FrequencyDesc,
				src.RecognitionType,
				src.CalculationType,
				src.Source,
				src.DateInserted,
				src.DateLastUpdated)				
	output $action into @SummaryOfChanges;				--Merge statements must have a ;
/*	
	update	oal
		set VNB_Points = r.PointsTotal
	from	owt_PaymentshieldCommissionPayments pcp
/*			inner join (select max(FileID) as FileID
						from owt_PaymentshieldImportControl) X on pcp.CreateDate = X.FileID
*/			inner join msit_OpenworkAdviserListing oal on oal.SourceID = pcp.ID and oal.Source = 'Payshield'
			inner join owt_Recognition r 
						on r.RecognitionType = 'VNB'
						and r.SourceID = pcp.ID
						and r.Source = oal.Source		
	where	isnull(oal.VNB_Points,0) <> isnull(r.PointsTotal,0)
	
	select @OALRowCount = @@rowcount
*/
	COMMIT TRANSACTION      

	select	@RowCount = COUNT(*)
	from	@SummaryOfChanges
	where	Change = 'INSERT'

	set @ProcessMessage = 'owt_Recognition (insert) = ' + convert(nvarchar(10), @RowCount)
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client

	select	@RowCount = COUNT(*)
	from	@SummaryOfChanges
	where	Change = 'UPDATE'

	set @ProcessMessage = 'owt_Recognition (update) = ' + convert(nvarchar(10), @RowCount)
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client
/*
	set @ProcessMessage = 'msit_OpenworkAdviserListing (update) = ' + convert(nvarchar(10), @OALRowCount)
	exec msp_ProcessLog @PhaseLog, @ProcessMessage, null, @Module, @Client
*/
	/****************************************************************************

		T H E   E N D
																		
	****************************************************************************/
	
	exec msp_ProcessLog @PhaseEnd, @ProcName, null, @Module, @Client

END TRY

BEGIN CATCH 

	select @ErrNum = ERROR_NUMBER(), @ErrMsg = ERROR_MESSAGE(), @ErrSev = ERROR_SEVERITY(), @ErrLine = ERROR_LINE(), @ErrState = XACT_STATE()
	set @ErrMsg = REPLACE(@ErrMsg, '.', '') + ' (error no: ' + CAST(@ErrNum AS VARCHAR(10)) + ') on line ' + CAST(@ErrLine AS VARCHAR(10))
	
	-- Test XACT_STATE for 0, 1, or -1.
    -- If 1, the transaction is committable.
    -- If -1, the transaction is uncommittable and should be rolled back.
    -- If 0, there is no transaction and a commit or rollback operation would generate an error.

	if @ErrState = -1			-- Transaction is uncommitable
		rollback transaction

	if @ErrState = 1			
		commit transaction

	-- Error message line 1
	set @ErrMsgBrief = left(@ErrMsg,100)
	exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client
	
	-- Error message line 2 - if any text exists
	set @ErrMsgBrief = substring(@ErrMsg,101,100)
	if len(@ErrMsgBrief) > 0
		exec msp_ProcessLog @PhaseError, @ErrMsgBrief, null, @Module, @Client

	exec msp_ProcessLog @PhaseEnd, @ProcName, null, @Module, @Client

	RAISERROR(@ErrMsg, @ErrSev , 1)

END CATCH

/****************************************************************************

			E N D															

****************************************************************************/

return @ErrNum



GO
/****** Object:  StoredProcedure [dbo].[owp_RecognitionGIPaymentshield_Backup20180613AG]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
