CREATE procedure [dbo].[owp_TransformationMovements]
  @Client   varchar(50),            --MPC:21/01/2010
  @Module   varchar(50),            --MPC:21/01/2010
--  @StartDate  varchar(10)           --MPC:21/01/2010		--MPC:08/08/2012
  @StartDate  datetime				--MPC:08/08/2012
as

/*===========================================================================================
    DEFINE RUN PARAMETERS
===========================================================================================*/

declare   @RowCount     int,
      @ProcessMessage   varchar(100),
      @PhaseStart     varchar(50),
      @PhaseEnd     varchar(50),
      @ProgressModule   varchar(50),
      @ProcName     varchar(100)

set @ProcName   = object_name(@@procid)
set @PhaseStart   = 'START'
set @PhaseEnd   = 'END'
set @ProgressModule = 'IDMOVE'

exec msp_ProcessLog @PhaseStart, @ProcName, null, @Module, @Client

declare @MovementStartDate datetime

IF ISDATE(@StartDate) = '0'
BEGIN
  Set @MovementStartDate = DATEADD(day, DATEDIFF(day,0,getdate()) ,0)
END

IF ISDATE(@StartDate) = '1'
BEGIN
  -- AG 09/02/2010 Start
  --set @MovementStartDate = CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)
  set @MovementStartDate = convert(datetime,@StartDate,103)
  -- AG 09/02/2010 End
END

IF @MovementStartDate is NULL
BEGIN
  set @ProcessMessage = 'RunParameter : Date = NULL'    
END

IF ISDATE(@MovementStartDate) = '0'
BEGIN
  set @ProcessMessage = 'RunParameters : Date = INVALID'    
END

IF ISDATE(@MovementStartDate) = '1'
BEGIN
  set @ProcessMessage = 'RunParameters : Date = ' + convert(varchar(10),@MovementStartDate,103)   
END

exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client

/*===========================================================================================
    PROCESSING START
===========================================================================================*/

Select  PKID, DriverTableName, LoadDate, SourceTableName, CommissionSplits, -- AG 09/03/2010
    PendingPayments, CommissionStatement, AdviserListing        -- AG 09/03/2010
INTO  #owt_TransformationMovements
FROM  owt_TransformationMovements
WHERE 1=0

/*===========================================================================================
    IDENTIFY S_AGMFIL Rows to be Processed based on @MovementStartDate
===========================================================================================*/

-- S_AGMFIL Movements.  This query should identify all the inserts/deletes/updates on AGMFIL.
-- All the following queries where DriverTable is 'sa_swift_S_AGMFIL' are designed to find
-- all the non-AGMFIL sourced changes that will cause 1 or more columns to change on
-- msit_CommissionStatement.
 
INSERT INTO #owt_TransformationMovements
Select  Distinct ID as PKID,
    'sa_swift_S_AGMFIL' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_S_AGMFIL' as SourceTable,
    'N' as CommissionSplits,
    'Y' as PendingPayments,
    'Y' as CommissionStatement,
    'Y' as AdviserListing
from  sa_swift_S_AGMFIL_MOVEMENTS
Where MovementDate >= @MovementStartDate

select @RowCount = @@rowcount   --MPC:24/02/2010
set @ProcessMessage = 'S_AGMFIL Movements : Count = ' + convert(varchar(10), @RowCount)          --MPC:24/02/2010
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client

--MPC: 07/06/2012 - SR162104: START
--Add in entries defined in Config if @MovementStartDate between Start & End Dates
INSERT INTO #owt_TransformationMovements
Select  Distinct pp.ID as PKID,
    'sa_swift_S_AGMFIL' as DriverTable,
    getdate() as LoadDate,
    'msit_MIWarehouseCodesAndDescriptions' as SourceTable,
    'N' as CommissionSplits,
    'Y' as PendingPayments,
    'Y' as CommissionStatement,
    'Y' as AdviserListing
from  sa_swift_S_AGMFIL pp
inner join dbo.msit_MIWarehouseCodesAndDescriptions cd on case when isnumeric(cd.CODE) = 1 then cd.CODE end = pp.ID and cd.ColumnName = 'OA_TriggerMovement'
Where @MovementStartDate between 
case when isdate(cd.Description) = 1 then cd.Description else '31 dec 2999' end
and case when isdate(cd.ShortDescription) = 1 then cd.ShortDescription else '31 dec 2999' end

select @RowCount = @@rowcount
set @ProcessMessage = 'CONFIG Movements : Count = ' + convert(varchar(10), @RowCount)
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client
--MPC: 07/06/2012 - SR162104: END

/*
-- AG 11/03/2010.  Removed as superseded by S_PACC movement Check
-- AG 05/03/2010.  Removed because too many rows identified. 
-- AG 09/03/2010.  Restored to ensure TotPaid, LastID and ExpectCount are updated on msit_CommissionStatement
--MPC:24/02/2010 START
--MPC:10/03/2010 START. Join any 1,2,17 CommType to any 1,2,17 CommType to ensure all related
--            transactions are processed and the correct APE is calculated.
--S_AGMFIL Movements (linked to same TransactionID and TYPE as above movements) 
INSERT INTO #owt_TransformationMovements
Select  Distinct P.ID as PKID,
    'sa_swift_S_AGMFIL' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_S_AGMFIL TransId_CommType_Matches' as SourceTable,
    'N' as CommissionSplits,
    'N' as PendingPayments,
    'Y' as CommissionStatement,
    'Y' as AdviserListing
FROM  (Select distinct TransactionID,TYPE,Agent_Code
      from sa_swift_S_AGMFIL_MOVEMENTS
      Where MovementDate >= @MovementStartDate
      AND TransactionId > 0) A
    INNER JOIN PREV_sa_swift_S_AGMFIL P 
      ON P.TransactionId = A.TransactionId 
      and P.agent_code = A.Agent_Code
      and case when P.TYPE in (1,2,17) then 1 end = case when A.TYPE in (1,2,17) then 1 end
    INNER JOIN sa_swift_S_AGENTS Ag
      ON Ag.CODE = P.Agent_Code
Where Ag.AGT_TYPE IN ('2','3','4','5','43','44','45','46','47','49','51','52','53','54','55') --Selection used in msp_CommissionStatement

select @RowCount = @@rowcount   --MPC:24/02/2010
set @ProcessMessage = 'S_AGMFIL Movements (S_AGMFIL Sourced by TransId/TYPE): Count = ' + convert(varchar(10), @RowCount)          --MPC:24/02/2010
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client
--MPC:24/02/2010 END
--MPC:10/03/2010 END
*/

--S_AGMPAY Movements (identify S_AGMFIL rows linked to movements)
INSERT INTO #owt_TransformationMovements
Select  Distinct AGMID as PKID,
    'sa_swift_S_AGMFIL' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_S_AGMPAY' as SourceTable,
    'N' as CommissionSplits,
    'Y' as PendingPayments,
    'Y' as CommissionStatement,
    'Y' as AdviserListing
from  sa_swift_S_AGMPAY_MOVEMENTS
Where MovementDate >= @MovementStartDate

select @RowCount = @@rowcount   --MPC:24/02/2010
set @ProcessMessage = 'S_AGMPAY Movements (S_AGMFIL sourced) : Count = ' + convert(varchar(10), @RowCount)          --MPC:24/02/2010
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client


--S_PACC Movements (identify S_AGMFIL rows linked to movements)
INSERT INTO #owt_TransformationMovements
Select  Distinct PP.ID as PKID,
    'sa_swift_S_AGMFIL' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_S_PACC' as SourceTable,
    'N' as CommissionSplits,
    'Y' as PendingPayments,
    'Y' as CommissionStatement,
    'Y' as AdviserListing
from  sa_swift_S_AGMFIL PP
    inner join sa_swift_S_PACC_MOVEMENTS X on X.PKID = PP.PACC_ID -- AG 05/03/2010
Where X.MovementDate >= @MovementStartDate

select @RowCount = @@rowcount   --MPC:24/02/2010
set @ProcessMessage = 'S_PACC Movements (S_AGMFIL sourced) : Count = ' + convert(varchar(10), @RowCount)          --MPC:24/02/2010
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client


-- MPC 11/03/2010
-- Identifies S_AGMFIL IC payments linked to Transactions where an S_PACC movement detected. 
-- Should fix ExpectCount, LastId, TotPaid and TotDue on msit_CommissionStatement. 
INSERT INTO #owt_TransformationMovements
Select  Distinct PP.ID as PKID,
    'sa_swift_S_AGMFIL' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_S_PACC (IC Trans)' as SourceTable,
    'N' as CommissionSplits,
    'N' as PendingPayments,
    'Y' as CommissionStatement,
    'Y' as AdviserListing
FROM  (Select Distinct X.TransactionId              -- AG 22/06/2010
     From sa_swift_S_PACC_MOVEMENTS X 
        -- Inner Join sa_swift_S_PACC P on P.ID = X.PKID     AG 22/06/2010 Expectation can be deleted and this table not needed anyway
     Where  X.MovementDate >= @MovementStartDate
     and  X.Type in (1,2,17)) A               -- AG 22/06/2010
         Inner Join sa_swift_S_AGMFIL PP on A.TransactionID = PP.TransactionID
     Inner Join sa_swift_S_AGENTS AG on AG.CODE = PP.Agent_Code
Where -- PP.Type in (1,2,17) MPC 16/03/2010 
    AG.Agt_Type in ('2','3','4','5','43','44','45','46','47','49','51','52','53','54','55')
UNION -- MPC 12/03/2010 Start. Include renewal and trail commission types.
Select  Distinct PP.ID as PKID,
    'sa_swift_S_AGMFIL' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_S_PACC (IC Trans)' as SourceTable,
    'N' as CommissionSplits,
    'N' as PendingPayments,
    'Y' as CommissionStatement,
    'Y' as AdviserListing
FROM  (Select Distinct X.TransactionId              -- AG 22/06/2010
     From sa_swift_S_PACC_MOVEMENTS X 
        -- Inner Join sa_swift_S_PACC P on P.ID = X.PKID     AG 22/06/2010 Expectation can be deleted and this table not needed anyway
     Where  X.MovementDate >= @MovementStartDate
     and  X.Type in (4,10,15,16,18,19)) A           -- AG 22/06/2010
    Inner Join sa_swift_S_AGMFIL PP on A.TransactionID = PP.TransactionID
    Inner Join sa_swift_S_AGENTS AG on AG.CODE = PP.Agent_Code
Where PP.Type in (4,10,15,16,18,19) 
and   AG.Agt_Type in ('2','3','4','5','43','44','45','46','47','49','51','52','53','54','55')
-- MPC 12/03/2010 End

select @RowCount = @@rowcount   --MPC:24/02/2010
set @ProcessMessage = 'S_PACC IC Movements (S_AGMFIL sourced) : Count = ' + convert(varchar(10), @RowCount)          --MPC:24/02/2010
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client
-- MPC 11/03/2010 End.


-- AG 29/03/2010 Start.
-- Identify the S_AGMFIL rows linked to the "old" transaction where this is different 
-- to the current transaction on an S_PACC row.
INSERT INTO #owt_TransformationMovements
Select  Distinct PP.ID as PKID,
    'sa_swift_S_AGMFIL' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_S_PACC (Diff Trans)' as SourceTable,
    'N' as CommissionSplits,
    'Y' as PendingPayments,
    'Y' as CommissionStatement,
    'Y' as AdviserListing
from  sa_swift_S_AGMFIL PP
    Inner Join  (Select Distinct P.TransactionId,
                CASE 
                  When P.TYPE in (1,2,17) then 1 
                  When P.Type in (4,15,18) then 4
                  When P.TYPE in (10,16,19) then 10 
                END as TYPE
           FROM sa_swift_S_PACC C 
              inner join sa_swift_S_PACC_MOVEMENTS X on X.PKID = C.ID     
              inner join PREV_sa_swift_S_PACC P on X.PKID = P.ID    
          Where X.MovementDate >= @MovementStartDate
          and   X.Action = 'UPD'
          and   P.TransactionId <> C.TransactionId
          and   isnull(P.TransactionId,0) <> 0) A
      ON A.TransactionID = PP.TransactionId
      and CASE 
          When PP.TYPE in (1,2,17) then 1 
          When PP.Type in (4,15,18) then 4
          When PP.TYPE in (10,16,19) then 10 
      END = A.TYPE

select @RowCount = @@rowcount   
set @ProcessMessage = 'S_PACC Diff Trans Movements (S_AGMFIL sourced) : Count = ' + convert(varchar(10), @RowCount)
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client
-- AG 29/03/2010 End.


--Policy Transaction Movements (identify S_AGMFIL rows linked to movements)
INSERT INTO #owt_TransformationMovements
Select  Distinct PP.ID as PKID,
    'sa_swift_S_AGMFIL' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_PolicyTransactions' as SourceTable,
    'N' as CommissionSplits,
    'Y' as PendingPayments,
    'Y' as CommissionStatement,                   -- AG 18/03/2010
    'Y' as AdviserListing                     -- AG 18/03/2010
from  sa_swift_S_AGMFIL PP
    inner join sa_swift_PolicyTransactions_MOVEMENTS X on X.PKID = PP.TransactionID
    inner join PREV_sa_swift_PolicyTransactions P on P.ID = X.PKID  -- AG 05/03/2010
    inner join sa_swift_PolicyTransactions C on C.ID = X.PKID   -- AG 05/03/2010
Where X.Action <> 'DEL' 
and   X.MovementDate >= @MovementStartDate
and   (isnull(p.TransactionDate,'') <> isnull(c.TransactionDate,'') -- AG 05/03/2010
or    isnull(p.PolicyID,'') <> isnull(c.PolicyID,'')          -- AG 05/03/2010
or    isnull(p.CommProductCode,'') <> isnull(c.CommProductCode,'')  -- AG 05/03/2010
or    isnull(p.CodeCommissionShapeId,'') <> isnull(c.CodeCommissionShapeId,'')  -- MPC 07/04/2010
or    isnull(p.CommCompanyCode,'') <> isnull(c.CommCompanyCode,'')  -- MPC 07/04/2010
or    isnull(p.CommInitialPeriod,'') <> isnull(c.CommInitialPeriod,'')  -- MPC 07/04/2010
or    isnull(p.Frequency,'') <> isnull(c.Frequency,'')        -- MPC 07/04/2010
or    round(round(p.CommBasedonPercent,5),4) <> round(round(c.CommBasedonPercent,5),4)  -- MPC 07/04/2010
or    round(round(p.RenewalRate,5),4) <> round(round(c.RenewalRate,5),4)  -- MPC 07/04/2010
or    round(round(p.CommDeductedatSource,3),2) <> round(round(c.CommDeductedatSource,3),2)  -- MPC 07/04/2010
or    round(round(p.Amount,3),2) <> round(round(c.Amount,3),2)    -- AG 18/03/2010
or    isnull(p.CommType,'') <> isnull(c.CommType,'')          -- AG 24/03/2010
or    isnull(p.ProposalDate,'') <> isnull(c.ProposalDate,'')  -- AG 25/10/2013 SR265296
or    isnull(p.StartDate,'') <> isnull(c.StartDate,''))       -- AG 24/03/2010

select @RowCount = @@rowcount   --MPC:24/02/2010
set @ProcessMessage = 'Policy Transaction Movements (S_AGMFIL sourced) : Count = ' + convert(varchar(10), @RowCount)          --MPC:24/02/2010
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client


