-- AG 15/06/2010 Start
-- Fetch all policy transactions for a newly inserted product code to correct the following:
-- msit_CommissionStatement.ReportingClassDesc
-- msit_CommissionStatement.CommProviderCode
-- msit_CommissionStatement.CommProviderDesc
-- msit_CommissionStatement.EnhancementRate
-- msit_CommissionStatement.ExIssued
-- msit_CommissionStatement.ExAccrued
-- msit_CommissionStatement.providerName
-- msit_CommissionStatement.ProviderCode
-- msit_CommissionStatement.APE
-- msit_CommissionStatement.ABCValue
-- msit_CommissionStatement.ABCRate
-- msit_OpenworkAdviserListing.APE
-- msit_OpenworkAdviserListing.Provider
-- msit_OpenworkAdviserListing.ProviderCode
-- msit_OpenworkAdviserListing.TotDue_Base
-- msit_OpenworkAdviserListing.Accrued_Base
-- msit_OpenworkAdviserListing.ABCValue
-- msit_OpenworkAdviserListing.ABCRate
-- msit_OpenworkAdviserListing.ProductGroup
INSERT  INTO #owt_TransformationMovements
Select  Distinct PP.ID as PKID,
    'sa_swift_S_AGMFIL' as DriverTable,
    getdate() as LoadDate,
    'mstt_ProductHierarchy' as SourceTable,
    'N' as CommissionSplits,
    'N' as PendingPayments,
    'Y' as CommissionStatement,
    'Y' as AdviserListing
From  mstt_ProductHierarchy_MOVEMENTS X
    Inner Join sa_swift_PolicyTransactions PT ON PT.CommProductCode = X.ProductCode 
    Inner Join sa_swift_S_AGMFIL PP ON PP.TransactionID = PT.ID
    left outer join PREV_mstt_ProductHierarchy P on P.ProductCode = X.productCode
    left outer join mstt_ProductHierarchy C on C.ProductCode = X.ProductCode
where X.Action <> 'DEL'   
and   X.MovementDate >= @MovementStartDate
and   (isnull(P.ProductType,'') <> isnull(C.ProductType,'') 
or     isnull(P.ReportingProductCode,'') <> isnull(C.ReportingProductCode,'')
or     isnull(P.ProductSubGroupCode,'') <> isnull(C.ProductSubGroupCode,'')
or     isnull(P.ProductGroupCode,'') <> isnull(C.ProductGroupCode,'')
or     isnull(P.ProductCategoryCode,'') <> isnull(C.ProductCategoryCode,'')
or     isnull(P.ProductProviderCode,'') <> isnull(C.ProductProviderCode,'')
or     isnull(P.ReportingProductProviderCode,'') <> isnull(C.ReportingProductProviderCode,'')
or     isnull(P.CommRepProductProviderCode,'') <> isnull(C.CommRepProductProviderCode,'')
or     isnull(P.ProductName,'') <> isnull(C.ProductName,''))	-- AG 11/03/2015

select @RowCount = @@rowcount
set @ProcessMessage = 'mstt_ProductHierarchy Movements (S_AGMFIL sourced) : Count = ' + convert(varchar(10), @RowCount)          --MPC:24/02/2010
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client
-- AG 15/06/2010 End

-- MPC 12/03/2010 Start
-- This needs to go at the end of the S_AGMFIL section as it is sweeping up 'missing' IC AGMFIL 
-- entries that are needed to calculate "Accrued to Date" and "Still to Accrue" totals correctly.
INSERT INTO #owt_TransformationMovements
Select  Distinct C.ID as PKID,
    'sa_swift_S_AGMFIL' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_S_AGMFIL (IC Accruals)' as SourceTable,
    'N' as CommissionSplits,
    'N' as PendingPayments,
    'Y' as CommissionStatement,
    'Y' as AdviserListing
FROM  (Select DISTINCT C.TransactionID
     from #owt_transformationmovements X
        Inner Join sa_swift_S_AGMFIL C ON C.ID = X.PKID
        INNER JOIN sa_swift_S_AGENTS AG ON AG.CODE = C.Agent_Code
     Where  X.drivertablename = 'sa_swift_S_AGMFIL'
     and  C.TYPE IN (1,2,17)  -- MPC : 12/03/2010
     and  AG.AGT_TYPE IN ('2','3','4','5','43','44','45','46','47','49','51','52','53','54','55') --Selection used in msp_CommissionStatement
    ) A
    Inner Join sa_swift_S_AGMFIL C ON C.TransactionId = A.TransactionId
    Inner Join sa_swift_S_AGENTS AG ON AG.CODE = C.Agent_Code
Where AG.AGT_TYPE IN ('2','3','4','5','43','44','45','46','47','49','51','52','53','54','55') --Selection used in msp_CommissionStatement
-- and    C.TYPE IN (1,2,17)  -- MPC : 12/03/2010 MPC 16/03/2010
and   C.ID not in (Select Distinct PKID 
           from #owt_TransformationMovements 
           where  DriverTableName = 'sa_swift_S_AGMFIL'
           and  CommissionStatement = 'Y')  -- AG 15/03/2010

select @RowCount = @@rowcount  
set @ProcessMessage = 'S_AGMFIL IC Accruals Movements : Count = ' + convert(varchar(10), @RowCount)
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client
-- MPC 12/03/2010 End


-- MPC 28/04/2010 Start
-- S_AGMFIL Movements. This Sweep Up section should run at the end of the S_AGMFIL section.
-- It is needed to address TotPaid differences that arise on msit_CommissionStatement when the
-- only S_AGMFIL row change on a TransactionID/Agent_Code/Type combination is a deletion. This
-- logic selects the associated S_AGMFIL rows with the same TransactionID/Agent_Code/Type as
-- the deleted S_AGMFIL that have not already been selected as a CommissionStatement movement.

INSERT INTO #owt_TransformationMovements
Select  Distinct C.ID as PKID,
    'sa_swift_S_AGMFIL' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_S_AGMFIL (Deletions)' as SourceTable,
    'N' as CommissionSplits,
    'N' as PendingPayments,
    'Y' as CommissionStatement,
    'Y' as AdviserListing
FROM  (Select DISTINCT P.TransactionID, P.TYPE, P.AGENT_CODE
     from sa_swift_S_AGMFIL_MOVEMENTS X
        Inner Join PREV_sa_swift_S_AGMFIL P ON P.ID = X.PKID    -- use PREV table as row deleted     
     Where  X.MovementDate >= @MovementStartDate
     and  X.Action = 'DEL'                    -- Deleted Row
    ) A
    Inner Join sa_swift_S_AGMFIL C 
      ON C.TransactionId = A.TransactionId 
      and C.TYPE = A.TYPE 
      and C.AGENT_CODE = A.AGENT_CODE
Where C.ID not in (Select Distinct PKID 
           from #owt_TransformationMovements 
           where DriverTableName = 'sa_swift_S_AGMFIL'
           and CommissionStatement = 'Y')

select @RowCount = @@rowcount  
set @ProcessMessage = 'S_AGMFIL Deletions Movements : Count = ' + convert(varchar(10), @RowCount)
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client
-- MPC 28/04/2010 End


/*===========================================================================================
    END OF S_AGMFIL SECTION
===========================================================================================*/


/*===========================================================================================
    START OF msit_CommissionStatement SECTION
===========================================================================================*/


-- This section must run after ALL the S_AGMFIL movements have been identified.
-- Log all the IDs that will need to be deleted on msit_OpenworkAdviserListing
-- while we still know what they are, because as soon as msit_CommissionStatement
-- is updated, then this information is lost.  
INSERT INTO #owt_TransformationMovements
Select DISTINCT CS.ID as PKID,
    'msit_CommissionStatement' as DriverTable,
    getdate() as LoadDate,
    'owt_TransformationMovements' as SourceTable,
    'N' as CommissionSplits,  -- All 'N' as this has special meaning in msp_OpenworkAdviserListingSwift
    'N' as PendingPayments,
    'N' as CommissionStatement,
    'Y' as AdviserListing
From  #owt_TransformationMovements T
    inner join msit_CommissionStatement CS on CS.PendingPaymentID = T.PKID
where T.DriverTableName = 'sa_swift_S_AGMFIL'
and   T.AdviserListing = 'Y'  -- AG 15/03/2010

select @RowCount = @@rowcount   --MPC:24/02/2010
set @ProcessMessage = 'msit_CommissionStatement Movements : Count = ' + convert(varchar(10), @RowCount)          --MPC:24/02/2010
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client


/*===========================================================================================
    END OF msit_CommissionStatement SECTION
===========================================================================================*/


/*===========================================================================================
    START OF S_AGTCOM SECTION
===========================================================================================*/

--S_AGTCOM Movements
INSERT INTO #owt_TransformationMovements
Select  Distinct X.PKID,
    'sa_swift_S_AGTCOM' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_S_AGTCOM' as SourceTable,
    'Y' as CommissionSplits,
    'N' as PendingPayments,
    'N' as CommissionStatement,
    'N' as AdviserListing
from  sa_swift_S_AGTCOM_MOVEMENTS X
Where MovementDate >= @MovementStartDate
UNION
--IC Rows in Transaction with at least 1 IC Movement 
Select  Distinct C.ID as PKID,
    'sa_swift_S_AGTCOM' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_S_AGTCOM' as SourceTable,
    'Y' as CommissionSplits,
    'N' as PendingPayments,
    'N' as CommissionStatement,
    'N' as AdviserListing
FROM  (Select Distinct PT.ID as TranID
     from sa_swift_S_AGTCOM_MOVEMENTS X
        Inner Join sa_swift_S_AGTCOM COM ON COM.ID = X.PKID
        Inner Join sa_swift_PolicyTransactions PT ON COM.TransactionID = PT.ID
    Where COM.CommissionType = 1  --IC
    AND   X.MovementDate >= @MovementStartDate) A
    Inner Join sa_swift_S_AGTCOM C ON C.TransactionId = A.TranId
Where C.CommissionType = 1

select @RowCount = @@rowcount   --MPC:24/02/2010
set @ProcessMessage = 'S_AGTCOM Movements : Count = ' + convert(varchar(10), @RowCount)          --MPC:24/02/2010
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client


--TransAgentSplitHierarchyHistory Movements (identify S_AGTCOM rows linked to movements)
INSERT INTO #owt_TransformationMovements
Select  Distinct COM.ID,
    'sa_swift_S_AGTCOM' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_TransAgentSplitHierarchyHistory' as SourceTable,
    'Y' as CommissionSplits,
    'N' as PendingPayments,
    'N' as CommissionStatement,
    'N' as AdviserListing
FROM  sa_swift_TransAgentSplitHierarchyHistory_Movements X
    Inner Join sa_swift_S_AGTCOM COM
      on COM.TransactionID = X.TransactionID 
      and COM.AGENT_CODE = X.AGENTCODE 
      and X.CommissionType = COM.CommissionType
WHERE X.Action <> 'DEL' 
and   X.MovementDate >= @MovementStartDate

select @RowCount = @@rowcount   --MPC:24/02/2010
set @ProcessMessage = 'TransAgentSplitHierarchyHistory Movements (S_AGTCOM sourced) : Count = ' + convert(varchar(10), @RowCount)          --MPC:24/02/2010
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client


--S_POLMAI Movements (identify S_AGTCOM rows linked to movements)
INSERT INTO #owt_TransformationMovements
Select  COM.ID as PKID,
    'sa_swift_S_AGTCOM' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_S_POLMAI' as SourceTable,
    'Y' as CommissionSplits,
    'N' as PendingPayments,
    'N' as CommissionStatement,
    'N' as AdviserListing
FROM  sa_swift_S_POLMAI_MOVEMENTS X
    Inner join sa_swift_S_POLMAI C on X.PKID = C.POL_NUM
    Left Outer join PREV_sa_swift_S_POLMAI P on X.PKID = P.POL_NUM    --MPC: 15/02/2010
    Inner Join mstt_PolicyTransactions PT ON PT.PolicyID = C.POL_NUM  -- AG 19/03/2010
    Inner Join sa_swift_S_AGTCOM COM ON COM.TransactionID = PT.ID
Where (isnull(C.ProductCode,'') <> isnull(P.ProductCode,'') -- AG 08/02/2010 
or    isnull(C.CLIENT_NUM,'') <> isnull(P.CLIENT_NUM,'')    -- AG 08/02/2010
or    isnull(C.JOINT_NUM,'') <> isnull(P.JOINT_NUM,''))   -- AG 08/02/2010
and   X.Action <> 'DEL' 
and   X.MovementDate >= @MovementStartDate

select @RowCount = @@rowcount   --MPC:24/02/2010
set @ProcessMessage = 'S_POLMAI Movements (S_AGTCOM sourced) : Count = ' + convert(varchar(10), @RowCount)          --MPC:24/02/2010
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client


--S_AGENTS Movements (identify S_AGTCOM rows linked to movements)
INSERT INTO #owt_TransformationMovements
Select  DISTINCT COM.ID as PKID,
    'sa_swift_S_AGTCOM' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_S_AGENTS' as SourceTable,
    'Y' as CommissionSplits,
    'N' as PendingPayments,
    'N' as CommissionStatement,
    'N' as AdviserListing
FROM  sa_swift_S_AGENTS_MOVEMENTS X
    Inner join sa_swift_S_AGENTS C on X.PKID = C.ID
    Left Outer join PREV_sa_swift_S_AGENTS P on X.PKID = P.ID   --MPC: 15/02/2010
    Inner Join sa_swift_S_AGTCOM COM on COM.AGENT_CODE = C.CODE
Where (isnull(C.AGT_TYPE,'') <> isnull(P.AGT_TYPE,'')         -- AG 08/02/2010
or    isnull(C.FIRM,'') <> isnull(P.FIRM,'')              -- AG 08/02/2010
or    isnull(C.Manager3Code,'') <> isnull(P.Manager3Code,'')      -- AG 08/02/2010
or    isnull(C.Manager4Code,'') <> isnull(P.Manager4Code,'')      -- AG 08/02/2010
or    isnull(C.PracticeTypeCode,'') <> isnull(P.PracticeTypeCode,'')) -- AG 08/02/2010
and   X.Action <> 'DEL' 
and   X.MovementDate >= @MovementStartDate

union
-- AG 08/03/2010 Start: Additional logic to find changes in mstt_Commissions.FranchiseSize.
select  DISTINCT COM.ID as PKID,
    'sa_swift_S_AGTCOM' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_S_AGENTS' as SourceTable,
    'Y' as CommissionSplits,
    'N' as PendingPayments,
    'N' as CommissionStatement,
    'N' as AdviserListing
from  mstt_AgentsHistory CurrHist 
    Inner Join sa_swift_S_AGTCOM COM on COM.AGENT_CODE = CurrHist.CODE
    Inner Join 
    (
      select Code, max(ValidToDate) as MaxValidToDate
      from mstt_AgentsHistory
      where Active = 0
      group by Code
    ) as PrevHistRow 
        on PrevHistRow.code = CurrHist.code
    inner join mstt_AgentsHistory PrevHist 
        on PrevHist.Code = PrevHistRow.Code 
        and PrevHist.ValidTodate = PrevHistRow.MaxValidToDate
where CurrHist.ValidFromDate >= @MovementStartDate-1    -- AG 09/03/2010
and   CurrHist.Active = 1
and   isnull(CurrHist.FranchiseSize,'') <> isnull(PrevHist.FranchiseSize,'')
-- AG 08/03/2010 End

select @RowCount = @@rowcount   --MPC:24/02/2010
set @ProcessMessage = 'S_AGENTS Movements (S_AGTCOM sourced) : Count = ' + convert(varchar(10), @RowCount)          --MPC:24/02/2010
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client


-- MPC: 04/03/2010 Start
-- Find AGTCOM updates to the Issued Date on older proposals
-- Inner Select finds Transactions where the first match date occurred on or after the day prior 
-- to the MovementDate used by owp_TransformationMovements. We then find Proposals whose 
-- IssuedDate could be impacted by this date and then get their associated S_AGTCOM rows.

INSERT INTO #owt_TransformationMovements
Select  DISTINCT COM.ID as PKID,
    'sa_swift_S_AGTCOM' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_S_PACC (Issued Trans 1)' as SourceTable,
    'Y' as CommissionSplits,
    'N' as PendingPayments,
    'N' as CommissionStatement,
    'N' as AdviserListing
FROM (  Select  PT.ID,PT.PolicyId,PT.Amount,PT.ProposalDate,MIN(C.DATE_RECV) as FirstMatchDate
    FROM  sa_swift_S_PACC_MOVEMENTS X
        Inner Join sa_swift_S_PACC C ON C.ID = X.PKID
        Inner Join sa_swift_PolicyTransactions PT ON PT.ID = C.TransactionId
    Where X.MovementDate >= @MovementStartDate
    Group By PT.ID,PT.PolicyId,PT.Amount,PT.ProposalDate
--    Having      MIN(C.DATE_RECV) >= DATEADD(dd,-1,@MovementStartDate) MPC: 10/03/2010
    ) A
    Inner Join sa_swift_PolicyTransactions PT 
      ON    PT.PolicyId = A.PolicyId 
      AND   PT.TransType = 39
      AND   (PT.Amount = A.Amount OR PT.ProposalDate = A.ProposalDate)
      AND   PT.ID < A.ID
    Inner Join sa_swift_S_AGTCOM COM ON COM.TransactionID = PT.ID

select @RowCount = @@rowcount   
set @ProcessMessage = 'S_PACC Movements (S_AGTCOM Issued Trans 1) : Count = ' + convert(varchar(10), @RowCount)
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client
-- MPC: 04/03/2010 End


-- AG 09/03/2010 Start
-- Find where S_PACC.DATE_RECV has changed to ensure CommissionMonth, IssuedDate and TransactionMonth
-- are updated on mstt_Commissions.
INSERT  INTO #owt_TransformationMovements
Select  DISTINCT COM.ID as PKID,
    'sa_swift_S_AGTCOM' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_S_PACC (Issued Trans 2)' as SourceTable,
    'Y' as CommissionSplits,
    'N' as PendingPayments,
    'N' as CommissionStatement,
    'N' as AdviserListing
FROM  sa_swift_S_PACC_MOVEMENTS X
    Inner Join sa_swift_S_PACC C ON C.ID = X.PKID
    Left Join PREV_sa_swift_S_PACC P ON P.ID = X.PKID
    Inner Join sa_swift_S_AGTCOM COM 
      ON COM.TransactionID = C.TransactionID
      and COM.CommissionType = case 
                    when c.type in (1,2,17) then 1 
                    when c.type in (4,15,18) then 4
                    when c.type in (10,16,19) then 10 
                   end
Where X.MovementDate >= @MovementStartDate
and   isnull(c.DATE_RECV,'') <> isnull(p.DATE_RECV,'')

select @RowCount = @@rowcount   
set @ProcessMessage = 'S_PACC Movements (S_AGTCOM Issued Trans 2) : Count = ' + convert(varchar(10), @RowCount)
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client
-- AG 09/03/2010


-- AG 25/05/2010 Start

-- This processing is to resolve the setting or resetting of mstt_Commissions.PolTranTransactionWrittenDate.
-- The PolTranTransactionWrittenDate can appear because the txn in question has acquired its first S_PACC row.
-- Prior to this it would have been ignored by the mstp_PolicyTransaction processing -  hence, its WrittenDate 
-- on mstt_Commissions would have been null. 

-- Find where transaction exists new on S_PACC today 
INSERT  INTO #owt_TransformationMovements
Select  Distinct COM.ID as PKID,
    'sa_swift_S_AGTCOM' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_S_PACC (New Trans)' as SourceTable,
    'Y' as CommissionSplits,
    'N' as PendingPayments,
    'N' as CommissionStatement,
    'N' as AdviserListing
From  sa_swift_S_PACC_MOVEMENTS X
    inner join sa_swift_S_PACC C ON X.PKID = C.ID
    inner join sa_swift_S_AGTCOM COM ON COM.Transactionid = C.TransactionID
where X.MovementDate >= @MovementStartDate
and   C.Type not in (5,6)
and   C.TransactionId not in (select  TransactionID 
                from  PREV_sa_swift_S_PACC 
                where Type not in (5,6)
                and   TransactionID is not null)
and   C.TransactionId is not null
union -- Find where transaction dropped off S_PACC today
Select  Distinct COM.ID as PKID,
    'sa_swift_S_AGTCOM' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_S_PACC (Deleted Trans)' as SourceTable,
    'Y' as CommissionSplits,
    'N' as PendingPayments,
    'N' as CommissionStatement,
    'N' as AdviserListing
From  sa_swift_S_PACC_MOVEMENTS X
    inner join PREV_sa_swift_S_PACC P ON X.PKID = P.ID
    inner join sa_swift_S_AGTCOM COM ON COM.Transactionid = P.TransactionID
where X.MovementDate >= @MovementStartDate
and   P.Type not in (5,6)
and   P.TransactionId not in (select  TransactionID 
                from  sa_swift_S_PACC 
                where Type not in (5,6)
                and   TransactionID is not null)
and   P.TransactionId is not null

select @RowCount = @@rowcount   
set @ProcessMessage = 'S_PACC New/Del Trans Movements (S_AGTCOM sourced) : Count = ' + convert(varchar(10), @RowCount)
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client

-- AG 25/05/2010 End


-- AG 12/04/2010 Start
-- Find where the S_PACC record has changed transaction.  This query should ensure the following are
-- updated correctly on mstt_Commissions: CommissionMonth and TransactionMonth
INSERT  INTO #owt_TransformationMovements
Select  Distinct COM.ID as PKID,
    'sa_swift_S_AGTCOM' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_S_PACC (Diff Trans)' as SourceTable,
    'Y' as CommissionSplits,
    'N' as PendingPayments,
    'N' as CommissionStatement,
    'N' as AdviserListing
from  sa_swift_S_AGTCOM COM
    Inner Join  (Select Distinct P.TransactionId, P.TYPE, C.TransactionId as NewTransactionId -- AG 19/04/2010
           FROM sa_swift_S_PACC C 
              inner join sa_swift_S_PACC_MOVEMENTS X on X.PKID = C.ID     
              inner join PREV_sa_swift_S_PACC P on X.PKID = P.ID    
           Where  X.MovementDate >= @MovementStartDate
           and  X.Action = 'UPD'
           and  P.TransactionId <> C.TransactionId
           and  isnull(P.TransactionId,0) <> 0) A
        ON (A.TransactionID = COM.TransactionId 
        or A.NewTransactionID = COM.TransactionId)    -- AG 19/04/2010
        and COM.CommissionType = CASE WHEN A.TYPE in (1,2,17) THEN 1
                        WHEN A.TYPE in (4,15,18) THEN 4
                        WHEN A.TYPE in (10,16,19) THEN 10
                     END
                                                                                                                 
select @RowCount = @@rowcount   
set @ProcessMessage = 'S_PACC Diff Trans Movements (S_AGTCOM sourced) : Count = ' + convert(varchar(10), @RowCount)
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client
-- AG 12/04/2010


-- AG 10/03/2010 Start
-- This check to ensure column OriginatingSource and OriginatingSourceDescription on 
-- mstt_Commissions are updated.
INSERT  INTO #owt_TransformationMovements
Select  COM.ID as PKID,
    'sa_swift_S_AGTCOM' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_PolicyQualityCheckB30' as SourceTable,
    'Y' as CommissionSplits,
    'N' as PendingPayments,
    'N' as CommissionStatement,
    'N' as AdviserListing
FROM  sa_swift_PolicyQualityCheckB30_MOVEMENTS X
    Inner join sa_swift_PolicyQualityCheckB30 C on X.PKID = C.PolicyID
    Left Outer join PREV_sa_swift_PolicyQualityCheckB30 P on X.PKID = P.PolicyID  --MPC 08/04/2010
    Inner Join mstt_PolicyTransactions PT ON PT.PolicyID = C.PolicyId     -- AG 19/03/2010
    Inner Join sa_swift_S_AGTCOM COM ON COM.TransactionID = PT.ID
Where isnull(C.OriginatingSourceID,0) <> isnull(P.OriginatingSourceID,0)
and   X.MovementDate >= @MovementStartDate
--order by com.id   --MPC 08/04/2010

select @RowCount = @@rowcount
set @ProcessMessage = 'PolicyQualityCheckB30 Movements (S_AGTCOM sourced) : Count = ' + convert(varchar(10), @RowCount)          --MPC:24/02/2010
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client
-- AG 10/03/2010 End


-- AG 10/03/2010 Start
-- This check to ensure TransType, Frequency, ProposalDate, TransactionDate, CodeCommissionShapeId & CommType
-- changes on mstt_Commissions are picked up.
INSERT  INTO #owt_TransformationMovements
Select  Distinct COM.ID as PKID,
    'sa_swift_S_AGTCOM' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_PolicyTransactions (Changed Transactions)' as SourceTable,
    'Y' as CommissionSplits,
    'N' as PendingPayments,
    'N' as CommissionStatement,
    'N' as AdviserListing
from  sa_swift_S_AGTCOM COM
    inner join sa_swift_PolicyTransactions_MOVEMENTS X on X.PKID = COM.TransactionID
    inner join PREV_sa_swift_PolicyTransactions P on P.ID = X.PKID
    inner join sa_swift_PolicyTransactions C on C.ID = X.PKID
Where X.Action <> 'DEL' 
and   X.MovementDate >= @MovementStartDate
and   (isnull(p.TransType,'') <> isnull(c.TransType,'')
or    isnull(p.Frequency,'') <> isnull(c.Frequency,'')    
or    isnull(p.ProposalDate,'') <> isnull(c.ProposalDate,'')
or    isnull(p.TransactionDate,'') <> isnull(c.TransactionDate,'')
or    isnull(p.CodeCommissionShapeId,-1) <> isnull(c.CodeCommissionShapeId,-1)      -- AG 31/03/2010
or    isnull(p.CommType,'') <> isnull(c.CommType,'')
or    isnull(p.CommProductCode,'') <> isnull(c.CommProductCode,'')            -- AG 14/05/2010
or    isnull(convert(int,p.Authorised),1000) <> isnull(convert(int,c.Authorised),1000)  -- AG 12/04/2010
or    round(round(isnull(p.OutstandingIndemnityLiability,-1),3),2) <> 
    round(round(isnull(c.OutstandingIndemnityLiability,-1),3),2)            -- AG 11/05/2010
or    isnull(p.AdminMethod,'') <> isnull(c.AdminMethod,''))               -- AG 12/03/2010  

select @RowCount = @@rowcount   
set @ProcessMessage = 'Policy Transaction Changes (S_AGTCOM sourced) : Count = ' + convert(varchar(10), @RowCount)          --MPC:24/02/2010
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client
-- AG 10/03/2010 End


-- AG 11/03/2010 Start
-- Identify active transactions for a policy where the earliest proposal 
-- transaction date has changed due to a later proposal with an earlier
-- transaction date.  Affects mstt_Commissions.PolTranTransactionWrittenDate.

INSERT  INTO #owt_TransformationMovements
Select  Distinct COM.ID as PKID,
    'sa_swift_S_AGTCOM' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_PolicyTransactions (New Proposals)' as SourceTable,
    'Y' as CommissionSplits,
    'N' as PendingPayments,
    'N' as CommissionStatement,
    'N' as AdviserListing
FROM  sa_swift_S_AGTCOM COM
    Inner Join sa_swift_policytransactions PT 
            ON PT.ID = COM.TransactionId
Where PT.TransType in (1,17,23,45) 
and   PT.PolicyID IN (
      Select Distinct A.PolicyID
      from  -- Transactions today
        (select C.PolicyId,Min(C.TransactionDate) as TransactionDate
         from sa_swift_policytransactions_movements X
            Inner Join sa_swift_policytransactions C on C.ID = X.PKID
        Where X.MovementDate >= @MovementStartDate
        and   C.TransType = 39
        Group By C.policyid) A
        -- Inner Join -- Transactions Yesterday                   AG 15/04/2010
        left outer join -- Transactions yesterday (may not exist hence outer join)  AG 15/04/2010
        (select P.PolicyId,Min(P.TransactionDate) as TransactionDate
         from sa_swift_policytransactions_movements X
            Inner Join sa_swift_policytransactions C on C.ID = X.PKID
            Inner Join PREV_sa_swift_policytransactions P on P.PolicyID = C.PolicyId
         Where  X.MovementDate >= @MovementStartDate
         and  P.TransType = 39
        Group By P.policyid) B 
        ON A.PolicyID = B.PolicyId
        Where isnull(A.TransactionDate,'') <> isnull(B.TransactionDate,''))

select @RowCount = @@rowcount   
set @ProcessMessage = 'Policy Transaction New Proposals (S_AGTCOM sourced) : Count = ' + convert(varchar(10), @RowCount)          --MPC:24/02/2010
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client
-- AG 11/03/2010 End


-- AG 11/06/2010 Start
-- Fetch all policy transactions for a newly inserted product code to correct the following:
-- mstt_Commissions.APE
-- mstt_Commissions.Turnover
-- mstt_Commissions.ProductType
-- mstt_Commissions.ReportingProductCode
-- mstt_Commissions.ProductSubGroupCode
-- mstt_Commissions.ProductGroupCode
-- mstt_Commissions.productCategoryCode
-- mstt_Commissions.ProductProviderCode
-- mstt_Commissions.ReportingProductProviderCode
-- mstt_Commissions.CommRepProductProviderCode
INSERT  INTO #owt_TransformationMovements
Select  Distinct COM.ID as PKID,
    'sa_swift_S_AGTCOM' as DriverTable,
    getdate() as LoadDate,
    'mstt_ProductHierarchy' as SourceTable,
    'Y' as CommissionSplits,
    'N' as PendingPayments,
    'N' as CommissionStatement,
    'N' as AdviserListing
From  mstt_ProductHierarchy_MOVEMENTS X
    Inner Join sa_swift_PolicyTransactions PT ON PT.CommProductCode = X.ProductCode 
    inner join sa_swift_S_AGTCOM COM ON COM.Transactionid = PT.ID
    left outer join PREV_mstt_ProductHierarchy P on P.ProductCode = X.productCode
    left outer join mstt_ProductHierarchy C on C.ProductCode = X.ProductCode
where X.Action <> 'DEL'   
and   X.MovementDate >= @MovementStartDate
and   (isnull(P.ProductType,'') <> isnull(C.ProductType,'') 
or     isnull(P.ReportingProductCode,'') <> isnull(C.ReportingProductCode,'')
or     isnull(P.ProductSubGroupCode,'') <> isnull(C.ProductSubGroupCode,'')
or     isnull(P.ProductGroupCode,'') <> isnull(C.ProductGroupCode,'')
or     isnull(P.ProductCategoryCode,'') <> isnull(C.ProductCategoryCode,'')
or     isnull(P.ProductProviderCode,'') <> isnull(C.ProductProviderCode,'')
or     isnull(P.ReportingProductProviderCode,'') <> isnull(C.ReportingProductProviderCode,'')
or     isnull(P.CommRepProductProviderCode,'') <> isnull(C.CommRepProductProviderCode,'')
or     isnull(P.ProductName,'') <> isnull(C.ProductName,''))	-- AG 11/03/2015

select @RowCount = @@rowcount
set @ProcessMessage = 'mstt_ProductHierarchy Movements (S_AGTCOM sourced) : Count = ' + convert(varchar(10), @RowCount)          --MPC:24/02/2010
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client
-- AG 11/06/2010 End


-- AG 21/09/2017 Start
-- This trigger was added in to fix the issue where the "Default" tick was - previously - missing 
-- on the Swift AgentHierarchyHistory table for the business UID (ParticipantType=7). This causes 
-- cases on the OpenAccess Pipeline to be linked to the wrong enterprise. When the "Default" box 
-- has been ticked, then this trigger pulls in all the affected rows on the mstt_Commissions table 
-- causing proc mstp_Commissions to re-link the cases to the correct enterprise.
INSERT INTO #owt_TransformationMovements
Select  Distinct C.ID,
    'sa_swift_S_AGTCOM' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_AgentHierarchyHistory' as SourceTable,
    'Y' as CommissionSplits,
    'N' as PendingPayments,
    'N' as CommissionStatement,
    'N' as AdviserListing
from sa_swift_AgentHierarchyHistory_MOVEMENTS X
    Inner join sa_swift_AgentHierarchyHistory ahh on X.PKID = ahh.ID
    Left Outer join PREV_sa_swift_AgentHierarchyHistory Pahh on X.PKID = Pahh.ID
	inner join sa_swift_S_AGTCOM c on c.Agent_Code = ahh.AgentCode 
where ahh.ParticipantType = 7	-- Business
and   X.MovementDate >= @MovementStartDate

select @RowCount = @@rowcount   
set @ProcessMessage = 'AgentHierarchyHistory Movements (S_AGTCOM sourced) : Count = ' + convert(varchar(10), @RowCount)
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client
-- AG 21/09/2017 End


-- MPC 12/03/2010 Start
-- Looking for AGTCOM's linked to Active/Proposal Transactions where Amount or ProposalDate 
-- (used to link Actives to Proposals) has changed which could cause link to be created or 
-- broken.  This affects mstt_Commissions.IssuedDate.
INSERT  INTO #owt_TransformationMovements
Select  Distinct COM.ID as PKID,
    'sa_swift_S_AGTCOM' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_S_AGTCOM (Written/Issued Sweep Up)' as SourceTable,
    'Y' as CommissionSplits,
    'N' as PendingPayments,
    'N' as CommissionStatement,
    'N' as AdviserListing
FROM  (Select DISTINCT X.PolicyID   -- AG 03/06/2010 changed from C.PolicyID
     from sa_swift_PolicyTransactions_MOVEMENTS X
        Left Outer Join sa_swift_PolicyTransactions C ON C.ID = X.PKID  -- AG 03/06/2010 changed from inner join
        Left Outer Join PREV_sa_swift_PolicyTransactions P ON P.ID = X.PKID
     Where  X.MovementDate >= @MovementStartDate
     and  P.TransType in (1,17,23,39,45)
     and  (isnull(C.Amount,0) <> isnull(P.Amount,0)
     or    isnull(C.ProposalDate,'') <> isnull(P.ProposalDate,'')
     or    C.id is null     -- AG 03/06/2010 no row could be present
     or    P.id is null)) A   -- AG 03/06/2010 no row could be present
    Inner Join sa_swift_PolicyTransactions PT ON PT.PolicyID = A.PolicyId
    Inner Join sa_swift_S_AGTCOM COM ON COM.TransactionId = PT.ID
Where PT.TransType in (1,17,23,39,45)
and   COM.ID not in (Select DISTINCT PKID 
            from  #owt_TransformationMovements 
            where DriverTableName = 'sa_swift_S_AGTCOM'
            and   CommissionSplits = 'Y') -- AG 15/03/2010

select @RowCount = @@rowcount   
set @ProcessMessage = 'Policy Transaction Written/Issued Sweep Up (S_AGTCOM sourced) : Count = ' + convert(varchar(10), @RowCount)          --MPC:24/02/2010
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client
-- MPC 12/03/2010 End


--MPC: 05/03/2010 Start
--PolicyTransaction Movements (identify S_AGTCOM rows linked to movements)
--Ensures all entries for TransactionId are extracted - MUST run at end of S_AGTCOM section
--This ensure that DistributionAllowance, Split Margin and Split Sales on mstt_Commissions are
--updated.
INSERT INTO #owt_TransformationMovements
Select  Distinct COM.ID,
    'sa_swift_S_AGTCOM' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_PolicyTransactions (Related Transactions)' as SourceTable,
    'Y' as CommissionSplits,
    'N' as PendingPayments,
    'N' as CommissionStatement,
    'N' as AdviserListing
FROM  sa_swift_PolicyTransactions P
    Inner Join sa_swift_S_AGTCOM COM ON COM.TransactionID = P.ID         
WHERE P.ID in (Select DISTINCT COM.TransactionID 
         From sa_swift_S_AGTCOM COM
            Inner Join #owt_TransformationMovements M on M.PKID = COM.ID
         Where  DriverTableName = 'sa_swift_S_AGTCOM'
         and  CommissionSplits = 'Y') -- AG 15/03/2010

select @RowCount = @@rowcount   
set @ProcessMessage = 'Policy Transactions Related (S_AGTCOM sourced) : Count = ' + convert(varchar(10), @RowCount)          --MPC:24/02/2010
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client
--MPC: 05/03/2010 End


/*===========================================================================================
    END OF S_AGTCOM SECTION
===========================================================================================*/


/*===========================================================================================
    START OF TransAgentSplitHierarchyHistory SECTION
===========================================================================================*/


--TransAgentSplitHierarchyHistory Movements (identify S_AGTCOM rows linked to movements)
INSERT INTO #owt_TransformationMovements
Select  Distinct PKID,
    'sa_swift_TransAgentSplitHierarchyHistory' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_TransAgentSplitHierarchyHistory' as SourceTable,
    'Y' as CommissionSplits,
    'N' as PendingPayments,
    'N' as CommissionStatement,
    'N' as AdviserListing
FROM  sa_swift_TransAgentSplitHierarchyHistory_Movements X
WHERE X.Action <> 'DEL' 
and   X.MovementDate >= @MovementStartDate

select @RowCount = @@rowcount   --MPC:24/02/2010
set @ProcessMessage = 'TransAgentSplitHierarchyHistory Movements  : Count = ' + convert(varchar(10), @RowCount)          --MPC:24/02/2010
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client

--MPC:06/04/2010 START
INSERT INTO #owt_TransformationMovements
Select  Distinct TASH.ID,
    'sa_swift_TransAgentSplitHierarchyHistory' as DriverTable,
    getdate() as LoadDate,
    'TransAgentSplitHierarchyHistory rows linked to S_AGTCOM Movements' as SourceTable,
    'Y' as CommissionSplits,
    'N' as PendingPayments,
    'N' as CommissionStatement,
    'N' as AdviserListing
FROM #owt_TransformationMovements T
 Inner Join sa_swift_S_AGTCOM COM
  ON COM.ID = T.PKID
 Inner Join sa_swift_TransAgentSplitHierarchyHistory TASH
  ON  COM.AGENT_CODE = TASH.AgentCode 
    AND COM.CommissionType = TASH.CommissionType
    AND COM.TransactionID = TASH.TransactionId
    AND TASH.Active = 1
 Left Join #owt_TransformationMovements X --MPC:13/10/2011 Ticket 126044
  ON X.PKID = TASH.ID         --MPC:13/10/2011 Ticket 126044
    AND X.DriverTableName = 'sa_swift_TransAgentSplitHierarchyHistory'        --MPC:13/10/2011 Ticket 126044
    AND X.CommissionSplits = 'Y'          --MPC:13/10/2011 Ticket 126044
WHERE T.DriverTableName = 'sa_swift_S_AGTCOM'
   AND T.CommissionSplits = 'Y'
--   AND TASH.ID NOT IN (SELECT PKID FROM #owt_TransformationMovements        --MPC:13/10/2011 Ticket 126044
--             WHERE DriverTableName = 'sa_swift_TransAgentSplitHierarchyHistory'   --MPC:13/10/2011 Ticket 126044
--             AND CommissionSplits = 'Y')            --MPC:13/10/2011 Ticket 126044
   AND X.PKID is NULL   --MPC:13/10/2011 Ticket 126044

select @RowCount = @@rowcount
set @ProcessMessage = 'TransAgentSplitHierarchyHistory Movements (S_AGTCOM Source) : Count = ' + convert(varchar(10), @RowCount)
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client
--MPC:06/04/2010 END

 --MPC:26/02/2010 START
--TransAgentSplitHierarchyHistory Movements (S_AGMFIL sourced)
INSERT INTO #owt_TransformationMovements
Select  Distinct P.ID as PKID,
    'sa_swift_TransAgentSplitHierarchyHistory' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_S_AGMFIL_ALLMovements' as SourceTable,
    'N' as CommissionSplits,
    'Y' as PendingPayments,
    'N' as CommissionStatement,
    'N' as AdviserListing
FROM (Select Distinct C.TransactionId,C.TYPE 
    FROM #owt_TransformationMovements T
    inner join sa_swift_S_AGMFIL C ON C.ID = T.PKID
    where T.DriverTableName = 'sa_swift_S_AGMFIL') A
inner join sa_swift_TransAgentSplitHierarchyHistory P
  ON A.TransactionId = P.TransactionId AND A.TYPE = P.CommissionType 

select @RowCount = @@rowcount 
set @ProcessMessage = 'TASHH Movements (S_AGMFIL Source)  : Count = ' + convert(varchar(10), @RowCount)      
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client        
--MPC:26/02/2010  END


/*===========================================================================================
    END OF TransAgentSplitHierarchyHistory SECTION
===========================================================================================*/


/*===========================================================================================
    START OF ReportBACSExport SECTION
===========================================================================================*/
 
--ReportBACSExport Movements
INSERT INTO #owt_TransformationMovements
Select  Distinct PKID,
    'sa_swift_ReportBACSExport' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_ReportBACSExport' as SourceTable,
    'N' as CommissionSplits,
    'N' as PendingPayments,
    'Y' as CommissionStatement,
    'N' as AdviserListing
FROM  sa_swift_ReportBACSExport_Movements X
WHERE X.MovementDate >= @MovementStartDate

select @RowCount = @@rowcount   --MPC:24/02/2010
set @ProcessMessage = 'sa_swift_ReportBACSExport Movements  : Count = ' + convert(varchar(10), @RowCount)          --MPC:24/02/2010
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client


--S_AGENTS Movements (identify ReportBACSExport rows linked to movements)
INSERT INTO #owt_TransformationMovements
Select  DISTINCT BAC.ID as PKID,
    'sa_swift_ReportBACSExport' as DriverTable,
    getdate() as LoadDate,
    'sa_swift_S_AGENTS' as SourceTable,
    'N' as CommissionSplits,
    'N' as PendingPayments,
    'Y' as CommissionStatement,
    'N' as AdviserListing
FROM  sa_swift_S_AGENTS_MOVEMENTS X
    Inner join sa_swift_S_AGENTS C on X.PKID = C.ID
    Left Outer join PREV_sa_swift_S_AGENTS P on X.PKID = P.ID   --MPC: 15/02/2010
    Inner Join sa_swift_ReportBACSExport BAC on BAC.AGENTCODE = C.CODE
Where (CAST(isnull(C.DESCN,'') AS varbinary(255)) <> CAST(isnull(P.DESCN,'') AS varbinary(255))       -- AG 22/03/2010
or    CAST(isnull(C.TradingName,'') AS varbinary(255)) <> CAST(isnull(P.TradingName,'') AS varbinary(255))) -- AG 22/03/2010
and   X.Action <> 'DEL' 
and   X.MovementDate >= @MovementStartDate

select @RowCount = @@rowcount   --MPC:24/02/2010
set @ProcessMessage = 'sa_swift_ReportBACSExport Movements (S_AGENTS sourced) : Count = ' + convert(varchar(10), @RowCount)          --MPC:24/02/2010
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client

/*===========================================================================================
    END OF ReportBACSExport SECTION
===========================================================================================*/


/*===========================================================================================
    DATABASE UPDATE - Insert derived Movements into owt_TransformationMovements table
===========================================================================================*/

TRUNCATE TABLE owt_TransformationMovements

INSERT INTO owt_TransformationMovements
Select * FROM #owt_TransformationMovements

