/****** Object:  StoredProcedure [dbo].[owp_UnlicencedSales]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[owp_UnlicencedSales]
  @RptType varchar(1),
  @UserID VARCHAR(255)
, @StartDate VARCHAR(10)
, @EndDate VARCHAR(10)

as

/************************************************************************************************

  AMENDMENT HISTORY

	rh 11 June 2007
	Rewrite of existing cscp_UnlicencedGroupSales  and cscp_UnlicencedEtiSales 
	for performance.

	Both existing stub procs remain but call this proc passing in 'G' or 'E'


	MPC July 2007
	Exclude sales where Business or Seller Agent Category denotes NASP
	Include OTPc cases (originatingsource = 6)


	MPC August 2007
	Minor changes to improve performance.


	MPC September 2007
	SR8 - Relabel OriginatingSource codes to new range of values


	KK October 2007
	Fix for Service Delivery ticket 283 to correct the date used for inclusion
             in the report


	MPC 18 September 2009
	SR10 - Update OriginatingSource logic to cater for new OBP values


	Mike Cawood: 20 January 2010
	New CF30 Check for Pension and Investment COB cases

	Mike Cawood: 8 February 2010
	Include OBP Manual cases (Originating Source 6) as well as automated.
	Use LicenceCheckDate as default in Keep Record check.


	Mike Cawood 9 September 2010
	Remove the following checks as SQST no longer action these errors:
	- "Invalid Competence"  (all types - COB, MCOB, ICOB-GI, ICOB-PP) 
	- "Replacement:No Licence(Cluster)"

	Mike Cawood 11 January 2011
	Ticket 79319 two further fixes:
	a) Use mstt_Policies.Regulation to determine ICOB where SalesProcess 
	   is null (not set on OBP 'skinny' New Business message).
	b) If LicenceCheckDate is future-dated override with Policy Create Date.



****************************************************************************************************/

set nocount on

declare @debug int
select @debug = 0

if @debug=1 select 'Stage 1',getdate()

declare @dteStartDate datetime
declare @dteEndDate datetime

declare @Severity int

select	@dteStartDate = CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME) ,
	      @dteEndDate = CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)

declare @LicCheckEndDate  datetime,     --MPC: 11/01/2011 (b)
        @Yesterday        datetime      --MPC: 11/01/2011 (b)

select @Yesterday = dateadd(dd,-1,datediff(dd,0,getdate()))                    --MPC: 11/01/2011 (b)

select @LicCheckEndDate = case when @dteEndDate > @Yesterday then @dteEndDate else @Yesterday end   --MPC: 11/01/2011 (b)
                           
--MPC: 11/01/2001 (b) - OLD Select Policies for Process: START
/*
if @RptType='E'
begin
select pol_num into #ETiPolsToProcess 
from mstt_policies 
where pol_type <> '205'
and (CASE WHEN isnull(OriginatingSource,0) = 2	                       -- KK: Fix for ticket 283 
	THEN dateadd(dd,0,datediff(dd,0,coalesce(Prop_Date,Start_Date,CreateDate,getdate()) ))
	ELSE CAST(CONVERT(NVARCHAR, coalesce(CreateDate,Prop_Date,Start_Date,getdate()), 112) AS DATETIME)
	END) between @dteStartDate and @dteEndDate
end
else
begin
select distinct pol_num into #GroupPolsToProcess
from mstt_policytransactions pt
inner join mstt_policies on pol_num = policyid
where pol_type = 205 AND pt.AdminMethod = 'A' AND TransType = '39'
and CAST(CONVERT(NVARCHAR, coalesce(TransactionDate,Prop_Date,Start_Date,CreateDate), 112) AS DATETIME) between @dteStartDate and @dteEndDate
end
*/ --MPC: 11/01/2001 (b) - OLD Select Policies for Process: END

--MPC: 11/01/2001 (b) - NEW Select Policies for Process and Derive LicenceCheckDate: START
if @RptType='E'
begin 
select distinct pol_num,
CASE
  WHEN OS.ID is not NULL AND OS.CODE not like '%MAN%' -- not Manual  
       AND dateadd(dd,0,datediff(dd,0,coalesce(Prop_Date,Start_Date,CreateDate,getdate()) )) <= @LicCheckEndDate 
    THEN dateadd(dd,0,datediff(dd,0,coalesce(Prop_Date,Start_Date,CreateDate,getdate()) )) 
  WHEN dateadd(dd,0,datediff(dd,0,coalesce(Start_Date,Prop_Date,CreateDate,getdate()) )) <= @LicCheckEndDate
    THEN dateadd(dd,0,datediff(dd,0,coalesce(Start_Date,Prop_Date,CreateDate,getdate()) ))
  WHEN dateadd(dd,0,datediff(dd,0,CreateDate)) <= @LicCheckEndDate 
    THEN dateadd(dd,0,datediff(dd,0,CreateDate))
  ELSE @LicCheckEndDate
END as LicenceCheckDate
into #ETiPolsToProcess 
from mstt_policies 
LEFT JOIN msit_CodeOriginatingSources OS on OS.ID = OriginatingSource
where pol_type <> '205' and  
CASE
  WHEN OS.ID is not NULL AND OS.CODE not like '%MAN%' -- not Manual  
       AND dateadd(dd,0,datediff(dd,0,coalesce(Prop_Date,Start_Date,CreateDate,getdate()) )) <= @LicCheckEndDate 
    THEN dateadd(dd,0,datediff(dd,0,coalesce(Prop_Date,Start_Date,CreateDate,getdate()) )) 
  WHEN dateadd(dd,0,datediff(dd,0,coalesce(Start_Date,Prop_Date,CreateDate,getdate()) )) <= @LicCheckEndDate
    THEN dateadd(dd,0,datediff(dd,0,coalesce(Start_Date,Prop_Date,CreateDate,getdate()) ))
  WHEN dateadd(dd,0,datediff(dd,0,CreateDate)) <= @LicCheckEndDate 
    THEN dateadd(dd,0,datediff(dd,0,CreateDate))
  ELSE @LicCheckEndDate
END between @dteStartDate and @dteEndDate
end
else
begin
select distinct pol_num,
CASE
  WHEN OS.ID is not NULL AND OS.CODE not like '%MAN%' -- not Manual  
       AND dateadd(dd,0,datediff(dd,0,coalesce(Prop_Date,Start_Date,CreateDate,getdate()) )) <= @LicCheckEndDate 
    THEN dateadd(dd,0,datediff(dd,0,coalesce(Prop_Date,Start_Date,CreateDate,getdate()) )) 
  WHEN dateadd(dd,0,datediff(dd,0,coalesce(Start_Date,Prop_Date,CreateDate,getdate()) )) <= @LicCheckEndDate
    THEN dateadd(dd,0,datediff(dd,0,coalesce(Start_Date,Prop_Date,CreateDate,getdate()) ))
  WHEN dateadd(dd,0,datediff(dd,0,CreateDate)) <= @LicCheckEndDate 
    THEN dateadd(dd,0,datediff(dd,0,CreateDate))
  ELSE @LicCheckEndDate
END as LicenceCheckDate
into #GroupPolsToProcess
from mstt_policytransactions pt
inner join mstt_policies on pol_num = policyid
LEFT JOIN msit_CodeOriginatingSources OS on OS.ID = OriginatingSource
where pol_type = '205' AND pt.AdminMethod = 'A' AND TransType = '39' and  
CASE
  WHEN OS.ID is not NULL AND OS.CODE not like '%MAN%' -- not Manual  
       AND dateadd(dd,0,datediff(dd,0,coalesce(Prop_Date,Start_Date,CreateDate,getdate()) )) <= @LicCheckEndDate 
    THEN dateadd(dd,0,datediff(dd,0,coalesce(Prop_Date,Start_Date,CreateDate,getdate()) )) 
  WHEN dateadd(dd,0,datediff(dd,0,coalesce(Start_Date,Prop_Date,CreateDate,getdate()) )) <= @LicCheckEndDate
    THEN dateadd(dd,0,datediff(dd,0,coalesce(Start_Date,Prop_Date,CreateDate,getdate()) ))
  WHEN dateadd(dd,0,datediff(dd,0,CreateDate)) <= @LicCheckEndDate 
    THEN dateadd(dd,0,datediff(dd,0,CreateDate))
  ELSE @LicCheckEndDate
END between @dteStartDate and @dteEndDate
end
--MPC: 11/01/2001 (b) - NEW Select Policies for Process and Derive LicenceCheckDate: END

