if @debug=1 select 'Stage 1.1',getdate()

	--Flag COB Sales where Seller not assigned CF30 registration
update	#PolDetails
set 	CF30Reason = 'No CF30 registration on COB case',
		CF30Status = 'No CF30 Registration'
from #PolDetails T1
inner join mstt_ProductHierarchy PH on T1.ProductCode = PH.ProductCode
where (T1.CustomerFunctionCode is NULL OR substring(T1.CustomerFunctionCode,1,4) <> 'CF30')
and T1.ComplianceCategory = 'COB'
and PH.ProductCategoryCode in ('1')	--Investment & Pensions

if @debug=1 select 'Stage 1.2',getdate()

	--Flag Sellers with CF30 registration
update	#PolDetails
set 	CF30Status = 'CF30 Registered'
from #PolDetails T1
where	substring(T1.CustomerFunctionCode,1,4) = 'CF30'

--MPC: 20/01/2010 - CF30 Check Added	END

if @debug=1 select 'Stage 2',getdate()

update	#PolDetails
set	BusinessAgentType = Business.AgentType,
	BusinessAgentCategory = Business.AgentCategory
from	#PolDetails Policies
	inner JOIN mstt_Agents Business ON Policies.BusinessCODE = Business.Code 


if @debug=1 select 'Stage 3',getdate()

update	#PolDetails
set	PurchaseTypeID = PolicyMortgage.PurchaseTypeID
from	#PolDetails Policies
	inner JOIN msit_PolicyMortgage PolicyMortgage ON Policies.Pol_Num = PolicyMortgage.PolicyID

/*
	remove the records we're not interested in
*/

if @debug=1 select 'Stage 4',getdate()

select distinct AgentsCode into #AgentCodes 
from #PolDetails 
order by AgentsCode

create table #PreAppAgents(
	CODE		varchar(7) ,
	ValidFromDate	datetime,
	ValidToDate	datetime
	)

create clustered index idxCode on #PreAppAgents(CODE)

insert #PreAppAgents(
	CODE,
	ValidFromDate,
	ValidToDate
	)
SELECT 	CODE ,
	CAST(CONVERT(NVARCHAR, ValidFromDate, 112) AS DATETIME) ,
	CAST(CONVERT(NVARCHAR, ValidToDate, 112) AS DATETIME) 
FROM 	mstt_AgentsHistory AgentsHistory
inner join #AgentCodes t1 on t1.AgentsCode = AgentsHistory.Code
WHERE 	AgentsHistory.CompetentStatus = 5

if @debug=1 select 'Stage 5',getdate()


update	#PolDetails
set	PreAppAgentExists = 1
from	#PolDetails Policies
	inner join #PreAppAgents on Policies.ServicingAgentCode = #PreAppAgents.CODE
where	LicenceCheckDate between #PreAppAgents.ValidFromDate AND #PreAppAgents.ValidToDate

update	#PolDetails
set	PreAppAgentExists = 0
WHERE	PreAppAgentExists is null


if @debug=1 select 'Stage 6',getdate()

if @RptType = 'E'
begin
	update	#PolDetails
	set KeepRecord = 1
	where	
	(
		(BusinessAgentType IS NULL OR BusinessAgentType <> 49)
		and BusinessAgentCategory not like '%NASP%'	-- Exclude NASP Sales
		and AgentCategory not like '%NASP%'		-- Exclude NASP Sales
		AND Pol_Type <> '205'				-- Exclude Group Pensions
		and
		(	OriginatingSource in (2,4,5,6) --1. Originating from ETi or OTPc MPC July 2007 -- MPC: SR8 
											--OBP Automated Cases	MPC: SR10 18/09/2009
											--OBP Manual Cases		MPC: 08/02/2010
		       	OR DualSalesProcess = 'Y'  --2. Can be sold via COB or ICOB (JNP CR587)
		       	OR (OriginatingSource = 3  --3. Residential mortgages originating from CPT (JNP CR863) -- MPC: SR8 
		             AND Pol_Type = '216'
		             AND Plan_Code = 'MRTG'
		             AND (PurchaseTypeID <> '2' OR PurchaseTypeID IS NULL)
			       )
--				OR OrigSourceCode not like '%MAN%'	--OBP Automated Cases	MPC: SR10 18/09/2009	--MPC: 08/02/2010
		)
	
		and       
		(
			--For ETi & mortgage CPT cases, use Proposal date as 'Swift load date'
		--	(OriginatingSource in (2) AND isnull(Prop_Date,LicenceCheckDate) between @dteStartDate and @dteEndDate)		--MPC: 08/02/2010  --MPC: 11/01/2011 (b)
		LicencecheckDate between @dteStartDate and @dteEndDate    --MPC: 11/01/2011 (b)
		--    	OR     --MPC: 11/01/2011 (b)
			--For non-ETi/CPT cases, use Create date as 'Swift load date'
		--	((OriginatingSource not in (2) OR OriginatingSource IS NULL) AND isnull(CreateDate,LicenceCheckDate) between @dteStartDate and @dteEndDate)	--MPC: 08/02/2010  --MPC: 11/01/2011 (b)
		)
		and
		(
			AgentsCompetentStatus  = 1 OR PreAppAgentExists = 1
	         )--Adviser Active/Appointed or Pre-App Recruit chk for common cases
	)
end
else
begin
	update	#PolDetails
	set KeepRecord = 1
	where	
	(
		(BusinessAgentType IS NULL OR BusinessAgentType <> 49)
		and BusinessAgentCategory not like '%NASP%'	-- Exclude NASP Sales
		and AgentCategory not like '%NASP%'		-- Exclude NASP Sales
		and 
		(
			Pol_Type = '205' --4) pension cases belonging to a group scheme
			AND EXISTS (SELECT ID
			               FROM mstt_PolicyTransactions PolicyTransactions 
			               WHERE PolicyTransactions.PolicyID = #PolDetails.Pol_Num
			                 AND PolicyTransactions.AdminMethod = 'A') --4) pension cases belonging to a group scheme	
		)
		and  
		(
			--use Create date as 'Swift load date' for pensions belonging to a group scheme
			--isnull(CreateDate,LicenceCheckDate) between @dteStartDate and @dteEndDate		--MPC: 08/02/2010 --MPC: 11/01/2011 (b)
				LicencecheckDate between @dteStartDate and @dteEndDate    --MPC: 11/01/2011 (b)
		)
		and 
		(
			AgentsCompetentStatus  = 1 OR PreAppAgentExists = 1
	         )--Adviser Active/Appointed or Pre-App Recruit chk for common cases
	)
end

drop index #PolDetails.rt2 
drop index #PolDetails.rt5


delete	#PolDetails
where KeepRecord is null

create index rt1 on #PolDetails(AgentsCode)
create index rt4 on #PolDetails(AgentsID)

if @debug=1 select 'Stage 7',getdate()

select distinct AgentsID into #AgentsID 
from #PolDetails 
order by AgentsID

-- Get list of all licences with all combinations of clusters/sectors as appropriate
create table	#ProdLics(
	CodeLicenceID		int, 
	CodeLicenceCode		varchar(10),
	CodeClusterID		int, 
	CodeClusterSectorID	int, 
	AgentLicenceID		int, 
	AgentID			int, 
	LicenceStartDate	datetime, 
	LicenceEndDate		datetime, 
	LicenceExpiryDate	datetime, 
	AgentClusterID		int, 
	ClusterStartDate	datetime, 
	ClusterEndDate		datetime, 
	AgentSectorID		int, 
	SectorStartDate		datetime, 
	SectorEndDate		datetime
)

insert	#ProdLics(
	CodeLicenceID, 
	CodeLicenceCode,
	CodeClusterID, 
	CodeClusterSectorID, 
	AgentLicenceID, 
	AgentID, 
	LicenceStartDate, 
	LicenceEndDate, 
	LicenceExpiryDate, 
	AgentClusterID, 
	ClusterStartDate, 
	ClusterEndDate, 
	AgentSectorID, 
	SectorStartDate, 
	SectorEndDate
)
SELECT	msit_CodeLicence.ID 								CodeLicenceID, 
	msit_CodeLicence.Code								CodeLicenceCode,
	msit_CodeLicenceCluster.CodeClusterID, 
	msit_CodeCluster.CodeClusterSectorID, 
	mstt_AgentLicence.ID 								AgentLicenceID, 
	mstt_AgentLicence.AgentID, 
	CAST(CONVERT(VARCHAR,mstt_AgentLicence.StartDate,112) AS DATETIME) 		LicenceStartDate, 
	CAST(CONVERT(VARCHAR,mstt_AgentLicence.EndDate,112) AS DATETIME) 		LicenceEndDate, 
	CAST(CONVERT(VARCHAR,mstt_AgentLicence.ExpiryDate,112) AS DATETIME) 		LicenceExpiryDate, 
	mstt_AgentCluster.ID 								AgentClusterID, 
	CAST(CONVERT(VARCHAR,mstt_AgentCluster.StartDate,112) AS DATETIME) 		ClusterStartDate, 
	CAST(CONVERT(VARCHAR,mstt_AgentCluster.EndDate,112) AS DATETIME) 		ClusterEndDate, 
	mstt_AgentSector.ID 								AgentSectorID, 
	CAST(CONVERT(VARCHAR,mstt_AgentSector.StartDate,112) AS DATETIME) 		SectorStartDate, 
	CAST(CONVERT(VARCHAR,mstt_AgentSector.EndDate,112) AS DATETIME) 		SectorEndDate
FROM	mstt_AgentLicence
	INNER Join #AgentsID t1 on t1.AgentsID = mstt_AgentLicence.AgentID
	INNER JOIN msit_CodeLicence ON msit_CodeLicence.ID = mstt_AgentLicence.CodeLicenceID 
	left outer JOIN msit_CodeLicenceCluster ON msit_CodeLicence.ID = msit_CodeLicenceCluster.CodeLicenceID 
	left outer JOIN msit_CodeCluster ON msit_CodeLicenceCluster.CodeClusterID = msit_CodeCluster.ID 
	left outer JOIN msit_CodeClusterSector ON msit_CodeCluster.CodeClusterSectorID = msit_CodeClusterSector.ID 
	left outer JOIN mstt_AgentCluster ON mstt_AgentLicence.AgentCode = mstt_AgentCluster.AgentCode 
					AND msit_CodeLicenceCluster.CodeClusterID = mstt_AgentCluster.CodeClusterID 
	left outer JOIN mstt_AgentSector ON mstt_AgentCluster.AgentCode = mstt_AgentSector.AgentCode 
					AND msit_CodeCluster.CodeClusterSectorID = mstt_AgentSector.CodeClusterSectorID


create clustered index rt1 on #ProdLics(AgentID,CodeLicenceID)


if @debug=1 select 'Stage 8',getdate()


      --========================================
      --Check if adviser has valid CCL licence
      --========================================

	--Valid
	update	#PolDetails
	set 	CCLLicValidID = AgentLicence.ID,
		CCLLicValidStartDate = CAST(CONVERT(VARCHAR,AgentLicence.StartDate,112) AS DATETIME),
		CCLLicValidEndDate = CAST(CONVERT(VARCHAR,AgentLicence.EndDate,112) AS DATETIME),
		CCLLicValidExpiryDate = CAST(CONVERT(VARCHAR,AgentLicence.ExpiryDate,112) AS DATETIME)
	from	#PolDetails Policies
		inner join mstt_AgentLicence AgentLicence on Policies.AgentsID = AgentLicence.AgentID
	where	AgentLicence.CodeLicenceID IN (SELECT CodeLicence.id FROM msit_CodeLicence CodeLicence WHERE CodeLicence.Code = 'QCCL')
		AND CAST(CONVERT(VARCHAR,AgentLicence.StartDate,112) AS DATETIME) <= LicenceCheckDate
		and (AgentLicence.EndDate IS NULL or CAST(CONVERT(VARCHAR,AgentLicence.EndDate,112) AS DATETIME) > LicenceCheckDate)
		AND (AgentLicence.ExpiryDate IS NULL or CAST(CONVERT(VARCHAR,AgentLicence.ExpiryDate,112) AS DATETIME) > LicenceCheckDate)

if @debug=1 select 'Stage 9',getdate()

	--Invalid (expired)
	update	#PolDetails
	set 	CCLLicInvalidID = AgentLicence.ID,
		CCLLicInvalidStartDate = CAST(CONVERT(VARCHAR,AgentLicence.StartDate,112) AS DATETIME),
		CCLLicInvalidEndDate = CAST(CONVERT(VARCHAR,AgentLicence.EndDate,112) AS DATETIME),
		CCLLicInvalidExpiryDate = CAST(CONVERT(VARCHAR,AgentLicence.ExpiryDate,112) AS DATETIME),
		ReasonCCL = 'You do not have the appropriate licences (Ref CCL1)',
		LicCCL = 'CCL:' + CONVERT(VARCHAR, CAST(CONVERT(VARCHAR,AgentLicence.StartDate,112) AS DATETIME), 103) 
			+ '-' + CONVERT(VARCHAR, CAST(CONVERT(VARCHAR,AgentLicence.ExpiryDate,112) AS DATETIME), 103)
	from	#PolDetails Policies
		inner join mstt_AgentLicence AgentLicence on Policies.AgentsID = AgentLicence.AgentID
	where	Policies.CCLLicValidID is null
		and AgentLicence.CodeLicenceID IN (SELECT CodeLicence.id FROM msit_CodeLicence CodeLicence WHERE CodeLicence.Code = 'QCCL')
		AND CAST(CONVERT(VARCHAR,AgentLicence.StartDate,112) AS DATETIME) <= LicenceCheckDate
		and (AgentLicence.EndDate IS NULL or CAST(CONVERT(VARCHAR,AgentLicence.EndDate,112) AS DATETIME) > LicenceCheckDate)
		AND CAST(CONVERT(VARCHAR,AgentLicence.ExpiryDate,112) AS DATETIME) < LicenceCheckDate

if @debug=1 select 'Stage 10',getdate()

	--None at all
	update	#PolDetails
	set 	ReasonCCL = 'You do not have the appropriate licences (Ref CCL1)',
		LicCCL = 'CCL:No Licence'
	where	CCLLicValidID is null
		and CCLLicInvalidID is null

if @debug=1 select 'Stage 11',getdate()

-- Start of DPL and KBUS checks

      --========================================
      --Check if adviser has valid DPL licence
      --========================================

	--Valid
	update	#PolDetails
	set 	DPLLicValidID = AgentLicence.ID,
		DPLLicValidStartDate = CAST(CONVERT(VARCHAR,AgentLicence.StartDate,112) AS DATETIME),
		DPLLicValidEndDate = CAST(CONVERT(VARCHAR,AgentLicence.EndDate,112) AS DATETIME),
		DPLLicValidExpiryDate = CAST(CONVERT(VARCHAR,AgentLicence.ExpiryDate,112) AS DATETIME)
	from	#PolDetails Policies
		inner join mstt_AgentLicence AgentLicence on Policies.AgentsID = AgentLicence.AgentID
	where	AgentLicence.CodeLicenceID IN (SELECT CodeLicence.id FROM msit_CodeLicence CodeLicence WHERE CodeLicence.Code = 'QDPL')
		AND CAST(CONVERT(VARCHAR,AgentLicence.StartDate,112) AS DATETIME) <= LicenceCheckDate
		and (AgentLicence.EndDate IS NULL or CAST(CONVERT(VARCHAR,AgentLicence.EndDate,112) AS DATETIME) > LicenceCheckDate)
		AND (AgentLicence.ExpiryDate IS NULL or CAST(CONVERT(VARCHAR,AgentLicence.ExpiryDate,112) AS DATETIME) > LicenceCheckDate)
		and @RptType = 'E'

if @debug=1 select 'Stage 9a',getdate()

	--Invalid (expired)
	update	#PolDetails
	set 	DPLLicInvalidID = AgentLicence.ID,
		DPLLicInvalidStartDate = CAST(CONVERT(VARCHAR,AgentLicence.StartDate,112) AS DATETIME),
		DPLLicInvalidEndDate = CAST(CONVERT(VARCHAR,AgentLicence.EndDate,112) AS DATETIME),
		DPLLicInvalidExpiryDate = CAST(CONVERT(VARCHAR,AgentLicence.ExpiryDate,112) AS DATETIME),
		ReasonDPL = 'You do not have the appropriate licences (Ref QDPL)',
		LicDPL = 'QDPL:' + CONVERT(VARCHAR, CAST(CONVERT(VARCHAR,AgentLicence.StartDate,112) AS DATETIME), 103) 
			+ '-' + CONVERT(VARCHAR, CAST(CONVERT(VARCHAR,AgentLicence.ExpiryDate,112) AS DATETIME), 103)
	from	#PolDetails Policies
		inner join mstt_AgentLicence AgentLicence on Policies.AgentsID = AgentLicence.AgentID
	where	Policies.DPLLicValidID is null
		and AgentLicence.CodeLicenceID IN (SELECT CodeLicence.id FROM msit_CodeLicence CodeLicence WHERE CodeLicence.Code = 'QDPL')
		AND CAST(CONVERT(VARCHAR,AgentLicence.StartDate,112) AS DATETIME) <= LicenceCheckDate
		and (AgentLicence.EndDate IS NULL or CAST(CONVERT(VARCHAR,AgentLicence.EndDate,112) AS DATETIME) > LicenceCheckDate)
		AND CAST(CONVERT(VARCHAR,AgentLicence.ExpiryDate,112) AS DATETIME) < LicenceCheckDate
		and @RptType = 'E'

if @debug=1 select 'Stage 10a',getdate()

	--None at all
	update	#PolDetails
	set 	ReasonDPL = 'You do not have the appropriate licences (Ref QDPL)',
		LicDPL = 'QDPL:No Licence'
	where	DPLLicValidID is null
		and DPLLicInvalidID is null
		and @RptType = 'E'

if @debug=1 select 'Stage 11a',getdate()

      --================================================================
      --Check if adviser has valid KBUS licence if BAIT or BALOAB policy
      --================================================================

	--Valid
	update	#PolDetails
	set 	KBUSLicValidID = AgentLicence.ID,
		KBUSLicValidStartDate = CAST(CONVERT(VARCHAR,AgentLicence.StartDate,112) AS DATETIME),
		KBUSLicValidEndDate = CAST(CONVERT(VARCHAR,AgentLicence.EndDate,112) AS DATETIME),
		KBUSLicValidExpiryDate = CAST(CONVERT(VARCHAR,AgentLicence.ExpiryDate,112) AS DATETIME)
	from	#PolDetails Policies
		inner join mstt_AgentLicence AgentLicence on Policies.AgentsID = AgentLicence.AgentID
	where	AgentLicence.CodeLicenceID IN (SELECT CodeLicence.id FROM msit_CodeLicence CodeLicence WHERE CodeLicence.Code = 'KBUS')
		AND CAST(CONVERT(VARCHAR,AgentLicence.StartDate,112) AS DATETIME) <= LicenceCheckDate
		and (AgentLicence.EndDate IS NULL or CAST(CONVERT(VARCHAR,AgentLicence.EndDate,112) AS DATETIME) > LicenceCheckDate)
		AND (AgentLicence.ExpiryDate IS NULL or CAST(CONVERT(VARCHAR,AgentLicence.ExpiryDate,112) AS DATETIME) > LicenceCheckDate)
		AND Policies.PolicyCategoryCode in ('BAIT','BALOAB')
		and @RptType = 'E'

if @debug=1 select 'Stage 9b',getdate()

	--Invalid (expired)
	update	#PolDetails
	set 	KBUSLicInvalidID = AgentLicence.ID,
		KBUSLicInvalidStartDate = CAST(CONVERT(VARCHAR,AgentLicence.StartDate,112) AS DATETIME),
		KBUSLicInvalidEndDate = CAST(CONVERT(VARCHAR,AgentLicence.EndDate,112) AS DATETIME),
		KBUSLicInvalidExpiryDate = CAST(CONVERT(VARCHAR,AgentLicence.ExpiryDate,112) AS DATETIME),
		ReasonKBUS = 'You do not have the appropriate licences (Ref KBUS)',
		LicKBUS = 'KBUS:' + CONVERT(VARCHAR, CAST(CONVERT(VARCHAR,AgentLicence.StartDate,112) AS DATETIME), 103) 
			+ '-' + CONVERT(VARCHAR, CAST(CONVERT(VARCHAR,AgentLicence.ExpiryDate,112) AS DATETIME), 103)
	from	#PolDetails Policies
		inner join mstt_AgentLicence AgentLicence on Policies.AgentsID = AgentLicence.AgentID
	where	Policies.KBUSLicValidID is null
		and AgentLicence.CodeLicenceID IN (SELECT CodeLicence.id FROM msit_CodeLicence CodeLicence WHERE CodeLicence.Code = 'KBUS')
		AND CAST(CONVERT(VARCHAR,AgentLicence.StartDate,112) AS DATETIME) <= LicenceCheckDate
		and (AgentLicence.EndDate IS NULL or CAST(CONVERT(VARCHAR,AgentLicence.EndDate,112) AS DATETIME) > LicenceCheckDate)
		AND CAST(CONVERT(VARCHAR,AgentLicence.ExpiryDate,112) AS DATETIME) < LicenceCheckDate
		AND Policies.PolicyCategoryCode in ('BAIT','BALOAB')
		and @RptType = 'E'

if @debug=1 select 'Stage 10b',getdate()

	--None at all
	update	#PolDetails
	set 	ReasonKBUS = 'You do not have the appropriate licences (Ref KBUS)',
		LicKBUS = 'KBUS: No Licence'
	where	KBUSLicValidID is null
		and KBUSLicInvalidID is null
		AND PolicyCategoryCode in ('BAIT','BALOAB')
		and @RptType = 'E'

if @debug=1 select 'Stage 11b',getdate()

-- End of DPL and KBUS checks

     --==================================================================================================
      --Adviser has a valid CCL, DPL and KBUS Licence. Now Check for other licences.
      --Find out if the adviser has a valid competence in the relevant compliance category for the plan
      --==================================================================================================
/*	update	#PolDetails
	set 	CompetencyCode = AgentCompetence.AgentControlFunctionCode
	from	#PolDetails Policies
		inner join mstt_AgentCompetence AgentCompetence on Policies.AgentsID = AgentCompetence.AgentID 
			and AgentCompetence.ComplianceCategoryCode = Policies.ComplianceCategory
	where	
      		(CAST(CONVERT(VARCHAR,AgentCompetence.AchievedDate,112) AS DATETIME) <= Policies.LicenceCheckDate)
      		AND (AgentCompetence.EndDate IS NULL OR CAST(CONVERT(VARCHAR,AgentCompetence.EndDate,112) AS DATETIME) > Policies.LicenceCheckDate)
*/

	update	#PolDetails
	set 	Competent = 1
	from	#PolDetails Policies
		inner join mstt_AgentCompetence AgentCompetence on Policies.AgentsID = AgentCompetence.AgentID 
			and AgentCompetence.ComplianceCategoryCode = Policies.ComplianceCategory
	where	-- not 
		(
			(AgentCompetence.AgentControlFunctionCode IS NOT NULL) 
			AND 
			(
				(
					(AgentCompetence.AgentControlFunctionCode = 'S1' Or AgentCompetence.AgentControlFunctionCode = 'IC' Or AgentCompetence.AgentControlFunctionCode = 'FC') 
					And 
					(Policies.ComplianceCategory = 'COB' Or Policies.ComplianceCategory = 'MCOB')
				)
			Or 
				(
					(AgentCompetence.AgentControlFunctionCode = 'IC' Or AgentCompetence.AgentControlFunctionCode = 'FC') 
					And 
					(Policies.ComplianceCategory = 'ICOB-PP' Or Policies.ComplianceCategory = 'ICOB-GI')
				)
			)
		)
      		and (CAST(CONVERT(VARCHAR,AgentCompetence.AchievedDate,112) AS DATETIME) <= Policies.LicenceCheckDate)
      		AND (AgentCompetence.EndDate IS NULL OR CAST(CONVERT(VARCHAR,AgentCompetence.EndDate,112) AS DATETIME) > Policies.LicenceCheckDate)

