  t1.LicenceCheckDate,   --MPC: 11/01/2011 (b)
--	  CASE        --MPC: 11/01/2011 (b)
--		  WHEN OS.ID is not NULL AND OS.CODE not like '%MAN%' -- Valid Source excl Manual MPC: SR10 18/09/2009    --MPC: 11/01/2011 (b)
--        THEN CAST(CONVERT(NVARCHAR, coalesce(Policies.Prop_Date,Policies.Start_Date,Policies.CreateDate,getdate()), 112) AS DATETIME) --Proposal date (this is 'licence check date' for non-ETi cases)	-- MPC: SR10 18/09/2009
--	    WHEN Policies.OriginatingSource = 2 
--			  THEN CAST(CONVERT(NVARCHAR, coalesce(Policies.Prop_Date,Policies.Start_Date,Policies.CreateDate,getdate()), 112) AS DATETIME) --Proposal date (this is 'licence check date' for ETi cases)
--	    WHEN Policies.OriginatingSource = 3		-- MPC: SR8 
--        THEN CAST(CONVERT(NVARCHAR, coalesce(Policies.Prop_Date,Policies.Start_Date,Policies.CreateDate,getdate()), 112) AS DATETIME) --Proposal date (this is 'licence check date' for CPT mortgage cases) - JNP CR863
--	    WHEN Policies.OriginatingSource = 4 		-- MPC: SR8 
--        THEN CAST(CONVERT(NVARCHAR, coalesce(Policies.Prop_Date,Policies.Start_Date,Policies.CreateDate,getdate()), 112) AS DATETIME) --Proposal date (this is 'licence check date' for OTPc cases)	MPC July 2007
--	    ELSE CAST(CONVERT(NVARCHAR, coalesce(Policies.Start_Date,Policies.Prop_Date,Policies.CreateDate,getdate()), 112) AS DATETIME) --Start date (this is 'licence check date' for non-ETi/CPT cases)     --MPC: 11/01/2011 (b)
--	  END,        --MPC: 11/01/2011 (b)
	Policies.SalesProcess				,
	case
		when Policies.Plan_Code = 'MRTG' then 'MCOB' --Mortgage
		when Policies.Plan_Code in ('B&C','ASU') then 'ICOB-GI' --General Insurance
		when Policies.SalesProcess = 1 then 'ICOB-PP' --Simplified Sales process (JNP CR587)
    when Policies.Regulation is not null then Policies.Regulation --MPC: 11/01/2011 default to value assigned from Product Hierarchy
	  else 'COB'
	END, -- ComplianceCategory
	null, -- CompetencyCode
	Agents.ID					,
	Agents.Code					,
	Agents.SpanSupervisorCode			,
	Agents.Firm					,
	Agents.CompetentStatus				,
	Agents.AgentCategory				,
	null,--CodeBIProducts.DualSalesProcess		,
	null, --PurchaseTypeID				,
	null, --BusinessAgentType			,
	null, --BusinessAgentCategory 			,
	null, -- PreAppAgentExists			,
	Policies.Replacement				,
	Policies.COMP_CODE				,
	'', -- LicenceStatus
	'2' -- RecordSource for debugging
	,CASE										--OrigSourceCode MPC: SR10 18/09/2009 
		WHEN OS.ID is not NULL THEN OS.CODE		--OrigSourceCode MPC: SR10 18/09/2009 
		ELSE 'Unknown'							--OrigSourceCode MPC: SR10 18/09/2009 
	END											--OrigSourceCode MPC: SR10 18/09/2009 

   FROM mstt_Policies Policies 
       inner join #Etipolstoprocess t1 on t1.pol_num = Policies.Pol_num
       INNER JOIN mstt_Agents Agents ON Policies.ServicingAgentCode = Agents.CODE
       LEFT OUTER JOIN mstt_Agents Supvisr ON Agents.SpanSupervisorCode = Supvisr.CODE --SpanSupervisorCode
       LEFT JOIN mstt_Agents AS Business ON Agents.Firm = Business.Code
	   LEFT JOIN msit_CodeOriginatingSources OS on OS.ID = Policies.OriginatingSource --MPC: SR10 18/09/2009 
 
  WHERE EXISTS(SELECT CODE FROM mstt_AgentsHistory AgentsHistory
                 WHERE AgentsHistory.CompetentStatus = 5
		 AND AgentsHistory.CODE = Policies.ServicingAgentCode
		 AND t1.LicenceCheckDate between CAST(CONVERT(NVARCHAR, AgentsHistory.ValidFromDate, 112) AS DATETIME) and CAST(CONVERT(NVARCHAR, AgentsHistory.ValidToDate, 112) AS DATETIME)  --MPC: 11/01/2011 (b)
--                 AND (OS.ID is not NULL AND OS.CODE not like '%MAN%' -- All non-Manual cases, use Proposal date as 'licence check date' -- MPC: SR10 18/09/2009   --MPC: 11/01/2011 (b)
--                 AND (Policies.OriginatingSource IN (2,3,4) --For ETi, OTPc & Mortgage CPT cases, use Proposal date as 'licence check date' -- MPC: SR8 --MPC: SR10 18/09/2009
--                      AND CAST(CONVERT(NVARCHAR, Policies.Prop_Date, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, AgentsHistory.ValidFromDate, 112) AS DATETIME)   --MPC: 11/01/2011 (b)
--                      AND CAST(CONVERT(NVARCHAR, Policies.Prop_Date, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, AgentsHistory.ValidToDate, 112) AS DATETIME)     --MPC: 11/01/2011 (b)
--                  OR (OS.ID is NULL OR OS.CODE like '%MAN%') -- For Manual cases, use Start date as 'licence check date' -- MPC: SR10 18/09/2009    --MPC: 11/01/2011 (b)
--                  OR (Policies.OriginatingSource NOT IN (2,3,4) OR Policies.OriginatingSource IS NULL) --For non-ETi/OTPc/CPT cases, use Start date as 'licence check date' -- MPC: SR10 18/09/2009
--                      AND CAST(CONVERT(NVARCHAR, Policies.Start_Date, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, AgentsHistory.ValidFromDate, 112) AS DATETIME)  --MPC: 11/01/2011 (b)
--                      AND CAST(CONVERT(NVARCHAR, Policies.Start_Date, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, AgentsHistory.ValidToDate, 112) AS DATETIME))   --MPC: 11/01/2011 (b)
               ) --Adviser is Pre-App 
--   AND (Policies.OriginatingSource IN (2) --For ETi & Mortgage CPT cases, use Proposal date as 'Swift load date'                        --MPC: 11/01/2011 (b)
--        AND CAST(CONVERT(NVARCHAR, Policies.Prop_Date, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)        --MPC: 11/01/2011 (b)
--        AND CAST(CONVERT(NVARCHAR, Policies.Prop_Date, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)          --MPC: 11/01/2011 (b)
--    OR (Policies.OriginatingSource NOT IN (2) OR Policies.OriginatingSource IS NULL) --For non-ETi/CPT cases, use Create date as 'Swift load date'    --MPC: 11/01/2011 (b)
--        AND CAST(CONVERT(NVARCHAR, Policies.CreateDate, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME)       --MPC: 11/01/2011 (b)
--        AND CAST(CONVERT(NVARCHAR, Policies.CreateDate, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME))        --MPC: 11/01/2011 (b)
   AND Policies.POL_NUM NOT IN (SELECT POL_NUM from #PolDetails) --Exclude Pre-App ETi/CPT sales records
   AND (Business.AgentType IS NULL OR Business.AgentType <> 49) -- exclude directly authorised
   AND Business.AgentCategory not like '%NASP%'			-- Exclude NASP Sales
   AND Agents.AgentCategory not like '%NASP%'			-- Exclude NASP Sales
end


if @debug=1 select 'Stage 30',getdate()


	-- get some extra bits of info

	update	#PolDetails
	set	ProviderName = isnull(ProductProviders.ProductProviderName,'')
	from	#PolDetails
		left outer join mstt_ProductProviders ProductProviders ON #PolDetails.ProviderCode = ProductProviders.ProductProviderCode

	-- agents and supervisors name
	update	#PolDetails
	set	AgentName = ISNULL(RTRIM(SUBSTRING(Agents.Firstnames, 1, PATINDEX('%[^ ] %', Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name), '')
	from	#PolDetails
		left outer join mstt_Agents Agents ON #PolDetails.AgentsCODE = Agents.CODE

	update	#PolDetails
	set	AgentSupervisor = ISNULL(RTRIM(SUBSTRING(Supvisr.Firstnames, 1, PATINDEX('%[^ ] %', Supvisr.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Supvisr.Name), '')
	from	#PolDetails
		left outer join mstt_Agents Supvisr ON #PolDetails.SupvisrCODE = Supvisr.CODE 

	-- agent status
	update	#PolDetails
	set	AgentStatus = 'Pre-App Recruit'
	from	#PolDetails
		inner join #PreAppAgents on #PolDetails.ServicingAgentCode = #PreAppAgents.CODE
					and #PolDetails.LicenceCheckDate between #PreAppAgents.ValidFromDate AND #PreAppAgents.ValidToDate

	update	#PolDetails
	set	AgentStatus = 'Appointed'
	where	AgentStatus is null

if @debug=1 select 'Stage 31',getdate()


	-- competencies

	   UPDATE #PolDetails
	   SET  COBCompetency = (SELECT TOP 1 COBCompetence.AgentControlFunctionDescn
	                         FROM mstt_AgentCompetence COBCompetence
	                         WHERE PolDetails.AgentsCODE = COBCompetence.AgentCode
	                           AND COBCompetence.ComplianceCategoryCode = 'COB'
	                           AND COBCompetence.EndDate IS NULL
	                         ORDER BY COBCompetence.DateAppointed DESC) -- the latest null-end-dated COB record
	      , ICOBPPCompetency = (SELECT TOP 1 ICOBPPCompetence.AgentControlFunctionDescn
	                         FROM mstt_AgentCompetence ICOBPPCompetence
	                         WHERE PolDetails.AgentsCODE = ICOBPPCompetence.AgentCode
	                           AND ICOBPPCompetence.ComplianceCategoryCode = 'ICOB-PP'
	                           AND ICOBPPCompetence.EndDate IS NULL
	                         ORDER BY ICOBPPCompetence.DateAppointed DESC) -- the latest null-end-dated ICOB-PP record
	   FROM #PolDetails PolDetails

if @debug=1 select 'Stage 32',getdate()


	-- last one is split sales
	create table #SplitSales(
		POL_NUM		int,
		AgentCode	varchar(7),
		AgentName	varchar(700)
		)
	CREATE CLUSTERED INDEX RT1 ON #SplitSales(POL_NUM)

	insert	#SplitSales(
		POL_NUM,
		AgentCode,
		AgentName)
	select	distinct
		Commissions.PolicyId,
		Agents.CODE,
		ISNULL(RTRIM(SUBSTRING(Agents.Firstnames, 1, PATINDEX('%[^ ] %', Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name), '')
	from	#PolDetails
		inner join mstt_Commissions Commissions on #PolDetails.POL_NUM = Commissions.PolicyId
		inner join mstt_Agents Agents ON Commissions.AGENT_CODE = Agents.CODE
	where	Commissions.AGENT_CODE <> #PolDetails.AgentsCode	--Exclude the selling agent himself
		and Commissions.AGENT_CODE <> '10002'			--Exclude all Openwork Margins
		and Commissions.CommissionType = 1			--Exclude RC/Trail Splits
		
if @debug=1 select 'Stage 33',getdate()


	while exists (select * from #SplitSales)
	begin
		UPDATE	#PolDetails
		set	SplitSale = coalesce(SplitSale,'') + ' - ' + (CASE WHEN (#SplitSales.AgentName = '') THEN 'Unknown' ELSE #SplitSales.AgentName END)
	                           + '(' + ISNULL(#SplitSales.AgentCode,'') + ')'
		from 	#PolDetails PolDetails
			inner join #SplitSales on PolDetails.POL_NUM = #SplitSales.POL_NUM
			inner join 
			(
			select	POL_NUM,
				min(AgentCode) MinAgentCode
			FROM 	#SplitSales
			group by POL_NUM
			) FirstAgent on #SplitSales.POL_NUM = FirstAgent.POL_NUM and #SplitSales.AgentCode = FirstAgent.MinAgentCode
		
		-- delete earliest AgentCode for each POL_NUM as its been used
		delete	#SplitSales
		from 	#SplitSales 
			inner join 
			(
			select	POL_NUM,
				min(AgentCode) MinAgentCode
			FROM 	#SplitSales
			group by POL_NUM
			) FirstAgent on #SplitSales.POL_NUM = FirstAgent.POL_NUM and #SplitSales.AgentCode = FirstAgent.MinAgentCode
		
	end

if @debug=1 select 'Stage 34',getdate()

	update	#PolDetails
	set	SplitSale = case when SplitSale is null then 'N' else 'Y ' + SplitSale end


if @debug=1 select 'Stage 35',getdate()

	-- just copying ineffectual error handling from earlier version
   SELECT @Severity = @@ERROR

   SELECT 
        AgentName 
      , AgentsCode AgentCode 
      , AgentSupervisor 
      , ProductCode PlanType 
      , AgentStatus 
      , CONVERT(VARCHAR, LicenceCheckDate, 103) AS [LicenceCheckDate]
      , PolicyRef CaseID 
--      , CASE OriginatingSource					--MPC: SR10 18/09/2009
--           WHEN 0 THEN 'Manual'	-- MPC: SR8		--MPC: SR10 18/09/2009
--	   When 1 then 'Manual'	-- MPC: SR8				--MPC: SR10 18/09/2009
--	   WHEN 2 THEN 'ETi'							--MPC: SR10 18/09/2009
--	   When 3 then 'OTPm'	-- MPC: SR8				--MPC: SR10 18/09/2009
--	   When 4 then 'OTPc'	-- MPC: SR8				--MPC: SR10 18/09/2009
--	   WHEN 2 THEN 'ETr'	-- MPC: SR8 
--           WHEN 3 THEN 'MBL'	-- MPC: SR8 
--           WHEN 4 THEN 'Trigold' -- MPC: SR8 
--           WHEN 5 THEN 'CPT' 	-- JNP CR863 -- MPC: SR8 
--	   WHEN 6 THEN 'OTPc' 	-- MPC July 2007
--           ELSE 'Unknown'							--MPC: SR10 18/09/2009
--        END AS [Source]							--MPC: SR10 18/09/2009
	  , OrigSourceCode as [Source]					--MPC: SR10 18/09/2009
      , SplitSale 
      , LicenseStatus 
      , ProviderName ProductProvider 
      , COBCompetency
      , ICOBPPCompetency
      , NULL AS Error
   FROM #PolDetails
 --  WHERE CAST(CONVERT(NVARCHAR, LicenceCheckDate, 112) AS DATETIME) between @dteStartDate and @dteEndDate       -- KK: Fix for ticket 283
   ORDER BY AgentName, AgentsCode, PolicyRef

if @debug=1 select 'Stage 36',getdate()


   RETURN @Severity;
GO
/****** Object:  StoredProcedure [dbo].[owp_UnlicencedSales_New]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO





-- exec cscp_UnlicencedETiSales null, '2006-01-01','2007-01-01'

CREATE procedure [dbo].[owp_UnlicencedSales_New]
   @RptType varchar(1),
  @UserID VARCHAR(255)
, @StartDate VARCHAR(10)
, @EndDate VARCHAR(10)

as

/*
  rh 11 June 2007
  Rewrite of existing cscp_UnlicencedGroupSales  and cscp_UnlicencedEtiSales 
  for performance.

  Both existing stub procs remain but call this proc passing in 'G' or 'E'

*/

/*
  MPC July 2007
  Exclude sales where Business or Seller Agent Category denotes NASP
  Include OTPc cases (originatingsource = 6)
*/


set nocount on

declare @debug int
select @debug = 0

if @debug=1 select 'Stage 1',getdate()

declare @dteStartDate datetime
declare @dteEndDate datetime

declare @Severity int

select  @dteStartDate = CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME) ,
  @dteEndDate = CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)


if @RptType='E'
begin
select pol_num into #ETiPolsToProcess 
from mstt_policies 
where pol_type <> '205'
and (CASE WHEN OriginatingSource in (1,5,6)
  THEN CAST(CONVERT(NVARCHAR, coalesce(Prop_Date,Start_Date,CreateDate,getdate()), 112) AS DATETIME)
  ELSE CAST(CONVERT(NVARCHAR, coalesce(Start_Date,Prop_Date,CreateDate,getdate()), 112) AS DATETIME)
  END) between @dteStartDate and @dteEndDate
end
else
begin
select distinct pol_num into #GroupPolsToProcess
from mstt_policytransactions pt
inner join mstt_policies on pol_num = policyid
where pol_type = 205 AND pt.AdminMethod = 'A' AND TransType = '39'
and CAST(CONVERT(NVARCHAR, coalesce(TransactionDate,Prop_Date,Start_Date,CreateDate), 112) AS DATETIME) between @dteStartDate and @dteEndDate
end

create table #PolDetails 
  (
      POL_NUM     int,
  KeepRecord    int,
  Competent   int,
      ProductCode   varchar(8) collate LATIN1_GENERAL_CI_AS,
      PolicyRef     int,
      OriginatingSource   int,
      Pol_Type      tinyint,
      Plan_Code     varchar(10),
      PolicyCategoryCode  varchar(10),
      ServicingAgentCode  varchar(7) collate LATIN1_GENERAL_CI_AS,
      Prop_Date     datetime,
      Start_Date    datetime,
      CreateDate    datetime,
  LicenceCheckDate  datetime,
  SalesProcess    int,
  ComplianceCategory  varchar(10) collate LATIN1_GENERAL_CI_AS,
  CompetencyCode    varchar(8) collate LATIN1_GENERAL_CI_AS,
  AgentsID    int,
      AgentsCODE    varchar(7) collate LATIN1_GENERAL_CI_AS,
      SupvisrCODE   varchar(7) collate LATIN1_GENERAL_CI_AS,
      BusinessCODE    varchar(7) collate LATIN1_GENERAL_CI_AS,
      DualSalesProcess    varchar(255),
      PurchaseTypeID    int,
      BusinessAgentType   tinyint,
      BusinessAgentCategory     varchar(8),
      AgentsCompetentStatus tinyint,
      AgentCategory       varchar(8),
  PreAppAgentExists int,
  Replacement   int,
  ProviderCode    varchar(10)  collate LATIN1_GENERAL_CI_AS,
  ProviderName    varchar(100),
  AgentName   varchar(155),
  AgentSupervisor   varchar(155),
  AgentStatus   varchar(20),
  COBCompetency   varchar(255),
  ICOBPPCompetency  varchar(255),
  SplitSale   varchar(2000),
  RecordSource    varchar(1)

      , LicCCL                          VARCHAR(80) 
      , LicDPL                          VARCHAR(80) 
      , LicKBUS                         VARCHAR(80) 
      , LicProd                         VARCHAR(80)
      , LicIHT                          VARCHAR(80)
      , LicReplace                      VARCHAR(80)
      , LicCompetent                    VARCHAR(80)

      , ReasonCCL                       VARCHAR(80)
      , ReasonDPL                       VARCHAR(80)
      , ReasonKBUS                      VARCHAR(80)
      , ReasonProd                      VARCHAR(80)
      , ReasonIHT                       VARCHAR(80)
      , ReasonReplace                   VARCHAR(80)
      , ReasonCompetent                 VARCHAR(80)

  , LicenseStatus     VARCHAR(2000)
  ,Reason       varchar(500)

  , CCLLicValidID     int
  , CCLLicValidStartDate    datetime
  , CCLLicValidEndDate    datetime
  , CCLLicValidExpiryDate   datetime
  , CCLLicInvalidID   int
  , CCLLicInvalidStartDate  datetime
  , CCLLicInvalidEndDate    datetime
  , CCLLicInvalidExpiryDate datetime

  , DPLLicValidID     int
  , DPLLicValidStartDate    datetime
  , DPLLicValidEndDate    datetime
  , DPLLicValidExpiryDate   datetime
  , DPLLicInvalidID   int
  , DPLLicInvalidStartDate  datetime
  , DPLLicInvalidEndDate    datetime
  , DPLLicInvalidExpiryDate datetime

  , KBUSLicValidID    int
  , KBUSLicValidStartDate   datetime
  , KBUSLicValidEndDate   datetime
  , KBUSLicValidExpiryDate  datetime
  , KBUSLicInvalidID    int
  , KBUSLicInvalidStartDate datetime
  , KBUSLicInvalidEndDate   datetime
  , KBUSLicInvalidExpiryDate  datetime

  , LicProdOld      int
  , LicProdHasClusters    int

  , ProdLicValidID    int
  , ProdLicValidStartDate   datetime
  , ProdLicValidEndDate   datetime
  , ProdLicValidExpiryDate  datetime

  , ProdLicInvalidID    int
  , ProdLicInvalidStartDate datetime
  , ProdLicInvalidEndDate   datetime
  , ProdLicInvalidExpiryDate  datetime

  , ProdLicClusterValidID     int
  , ProdLicClusterValidStartDate    datetime
  , ProdLicClusterValidEndDate    datetime

  , ProdLicSectorValidID      int
  , ProdLicSectorValidStartDate   datetime
  , ProdLicSectorValidEndDate   datetime

  , ReplLicValidID      int
  , ReplLicValidStartDate     datetime
  , ReplLicValidEndDate     datetime
  , ReplLicValidExpiryDate    datetime

  , ReplLicInvalidID      int
  , ReplLicInvalidStartDate   datetime
  , ReplLicInvalidEndDate     datetime
  , ReplLicInvalidExpiryDate    datetime

  , ReplLicClusterValidID     int
  , ReplLicClusterValidStartDate    datetime
  , ReplLicClusterValidEndDate    datetime

  , ReplLicSectorValidID      int
  , ReplLicSectorValidStartDate   datetime

  , ReplLicSectorValidEndDate   datetime

  )

create clustered index idxPol_Num on #PolDetails(POL_NUM)


if @RptType='E'
begin
  insert #PolDetails(
    POL_NUM     ,
    ProductCode   ,
    PolicyRef   ,
    OriginatingSource ,
    Pol_Type    ,
    Plan_Code   ,
          PolicyCategoryCode  ,
    ServicingAgentCode  ,
    Prop_Date   ,
    Start_Date    ,
    CreateDate    ,
    LicenceCheckDate  ,
    SalesProcess    ,
    ComplianceCategory  ,
    CompetencyCode    ,
    AgentsID    ,
    AgentsCODE    ,
    SupvisrCODE   ,
    BusinessCODE    ,
    AgentsCompetentStatus ,
    AgentCategory   ,
    DualSalesProcess  ,
    PurchaseTypeID    ,
    BusinessAgentType ,
    BusinessAgentCategory ,
    PreAppAgentExists ,
    Replacement   ,
    ProviderCode    ,
    RecordSource
  )
  select  
    Policies.POL_NUM        ,
    Policies.ProductCode        ,
    Policies.PolicyRef        ,
    Policies.OriginatingSource      ,
    Policies.Pol_Type       ,
    Policies.Plan_Code        ,
    msit_S_POLMAI.PolicyCategoryCode    ,
    Policies.ServicingAgentCode     ,
    CAST(CONVERT(NVARCHAR, Policies.Prop_Date, 112) AS DATETIME)    ,
    CAST(CONVERT(NVARCHAR, Policies.Start_Date, 112) AS DATETIME)   ,
    CAST(CONVERT(NVARCHAR, Policies.CreateDate, 112) AS DATETIME)   ,
          CASE
             WHEN Policies.OriginatingSource = 1 
         THEN CAST(CONVERT(NVARCHAR, coalesce(Policies.Prop_Date,Policies.Start_Date,Policies.CreateDate,getdate()), 112) AS DATETIME) --Proposal date (this is 'licence check date' for ETi cases)
             WHEN Policies.OriginatingSource = 5 
                     THEN CAST(CONVERT(NVARCHAR, coalesce(Policies.Prop_Date,Policies.Start_Date,Policies.CreateDate,getdate()), 112) AS DATETIME) --Proposal date (this is 'licence check date' for CPT mortgage cases) - JNP CR863
             WHEN Policies.OriginatingSource = 6 
                     THEN CAST(CONVERT(NVARCHAR, coalesce(Policies.Prop_Date,Policies.Start_Date,Policies.CreateDate,getdate()), 112) AS DATETIME) --Proposal date (this is 'licence check date' for OTPc cases)  MPC July 2007
             ELSE CAST(CONVERT(NVARCHAR, coalesce(Policies.Start_Date,Policies.Prop_Date,Policies.CreateDate,getdate()), 112) AS DATETIME) --Start date (this is 'licence check date' for non-ETi/CPT cases)
          END,
    Policies.SalesProcess       ,
    case
      when Policies.Plan_Code = 'MRTG' then 'MCOB' --Mortgage
      when Policies.Plan_Code in ('B&C','ASU') then 'ICOB-GI' --General Insurance
      when Policies.SalesProcess = 1 then 'ICOB-PP' --Simplified Sales process (JNP CR587)
                  else 'COB'
    END, -- ComplianceCategory
    null, -- CompetencyCode
    Agents.ID         ,
    Agents.Code         ,
    Agents.SpanSupervisorCode     ,
    Agents.Firm         ,
    Agents.CompetentStatus        ,
    Agents.AgentCategory        ,
    CodeBIProducts.DualSalesProcess     ,
    null, --PurchaseTypeID        ,
    null, --BusinessAgentType     ,
    null, --BusinessAgentCategory     ,
    null, -- PreAppAgentExists
    Policies.Replacement        ,
    Policies.COMP_CODE        ,
    '1'
  from  mstt_Policies Policies
    inner join #Etipolstoprocess t1 on t1.pol_num = Policies.Pol_num
    inner join msit_S_POLMAI on msit_S_POLMAI.POL_NUM = Policies.POL_NUM
    inner join mstt_Agents Agents ON Policies.ServicingAgentCode = Agents.CODE
          INNER JOIN mstt_CodeBIProducts CodeBIProducts ON CodeBIProducts.ProductCode = Policies.ProductCode --JNP CR587
    where Policies.Pol_Type <> '205'  -- Exclude Group Pensions
end
else
begin
  -- 'G' group report
  insert #PolDetails(
    POL_NUM     ,
    ProductCode   ,
    PolicyRef   ,
    OriginatingSource ,
    Pol_Type    ,
    Plan_Code   ,
          PolicyCategoryCode  ,
    ServicingAgentCode  ,
    Prop_Date   ,
    Start_Date    ,
    CreateDate    ,
    LicenceCheckDate  ,
    SalesProcess    ,
    ComplianceCategory  ,
    CompetencyCode    ,
    AgentsID    ,
    AgentsCODE    ,
    SupvisrCODE   ,
    BusinessCODE    ,
    AgentsCompetentStatus ,
    AgentCategory   ,
    DualSalesProcess  ,
    PurchaseTypeID    ,
    BusinessAgentType ,
    BusinessAgentCategory ,
    PreAppAgentExists ,
    Replacement   ,
    ProviderCode    ,
    RecordSource
  )
  select  
    Policies.POL_NUM        ,
    Policies.ProductCode        ,
    Policies.PolicyRef        ,
    Policies.OriginatingSource      ,
    Policies.Pol_Type       ,
    Policies.Plan_Code        ,
    NULL            ,
    Policies.ServicingAgentCode     ,
    CAST(CONVERT(NVARCHAR, Policies.Prop_Date, 112) AS DATETIME)    ,
    CAST(CONVERT(NVARCHAR, Policies.Start_Date, 112) AS DATETIME)   ,
    CAST(CONVERT(NVARCHAR, Policies.CreateDate, 112) AS DATETIME)   ,
    CAST(CONVERT(NVARCHAR, coalesce(LatestPolTrans39.TransactionDate,Policies.Prop_Date,Policies.Start_Date,Policies.CreateDate), 112) AS DATETIME) ,
    Policies.SalesProcess       ,
    case
      when Policies.Plan_Code = 'MRTG' then 'MCOB' --Mortgage
      when Policies.Plan_Code in ('B&C','ASU') then 'ICOB-GI' --General Insurance
      when Policies.SalesProcess = 1 then 'ICOB-PP' --Simplified Sales process (JNP CR587)
                  else 'COB'
    END, -- ComplianceCategory
    null, -- CompetencyCode
    Agents.ID         ,
    Agents.Code         ,
    Agents.SpanSupervisorCode     ,
    Agents.Firm         ,
    Agents.CompetentStatus        ,
    Agents.AgentCategory        ,
    CodeBIProducts.DualSalesProcess     ,
    null, --PurchaseTypeID        ,
    null, --BusinessAgentType     ,
    null, --BusinessAgentCategory     ,
    null, -- PreAppAgentExists
    Policies.Replacement        ,
    Policies.COMP_CODE        ,
    '1'
  from  mstt_Policies Policies
    inner join #Grouppolstoprocess t1 on t1.pol_num = Policies.Pol_num
          LEFT JOIN mstt_PolicyTransactions LatestPolTrans39 ON LatestPolTrans39.PolicyID = Policies.Pol_Num
                         AND LatestPolTrans39.AdminMethod = 'A'
                         AND LatestPolTrans39.TransType = '39'
                         AND NOT EXISTS (SELECT ID
                                         FROM mstt_PolicyTransactions EarlierPolTrans
                                         WHERE EarlierPolTrans.PolicyID = LatestPolTrans39.PolicyID
                                           AND EarlierPolTrans.TransType = '39'
                                           AND EarlierPolTrans.TransactionNumber > LatestPolTrans39.TransactionNumber)
          LEFT JOIN mstt_Agents Agents ON LatestPolTrans39.AgentCode = Agents.CODE
          INNER JOIN mstt_CodeBIProducts CodeBIProducts ON CodeBIProducts.ProductCode = Policies.ProductCode --JNP CR587
    where Policies.Pol_Type = '205' -- Include Group Pensions only
end


