if @debug=1 select 'Stage 11b',getdate()

-- End of DPL and KBUS checks

     --==================================================================================================
      --Adviser has a valid CCL, DPL and KBUS Licence. Now Check for other licences.
      --Find out if the adviser has a valid competence in the relevant compliance category for the plan
      --==================================================================================================
/*  update  #PolDetails
  set   CompetencyCode = AgentCompetence.AgentControlFunctionCode
  from  #PolDetails Policies
    inner join mstt_AgentCompetence AgentCompetence on Policies.AgentsID = AgentCompetence.AgentID 
      and AgentCompetence.ComplianceCategoryCode = Policies.ComplianceCategory
  where 
          (CAST(CONVERT(VARCHAR,AgentCompetence.AchievedDate,112) AS DATETIME) <= Policies.LicenceCheckDate)
          AND (AgentCompetence.EndDate IS NULL OR CAST(CONVERT(VARCHAR,AgentCompetence.EndDate,112) AS DATETIME) > Policies.LicenceCheckDate)
*/

  update  #PolDetails
  set   Competent = 1
  from  #PolDetails Policies
    inner join mstt_AgentCompetence AgentCompetence on Policies.AgentsID = AgentCompetence.AgentID 
      and AgentCompetence.ComplianceCategoryCode = Policies.ComplianceCategory
  where -- not 
    (
      (AgentCompetence.AgentControlFunctionCode IS NOT NULL) 
      AND 
      (
        (
          (AgentCompetence.AgentControlFunctionCode = 'S1' Or AgentCompetence.AgentControlFunctionCode = 'IC' Or AgentCompetence.AgentControlFunctionCode = 'FC') 
          And 
          (Policies.ComplianceCategory = 'COB' Or Policies.ComplianceCategory = 'MCOB')
        )
      Or 
        (
          (AgentCompetence.AgentControlFunctionCode = 'IC' Or AgentCompetence.AgentControlFunctionCode = 'FC') 
          And 
          (Policies.ComplianceCategory = 'ICOB-PP' Or Policies.ComplianceCategory = 'ICOB-GI')
        )
      )
    )
          and (CAST(CONVERT(VARCHAR,AgentCompetence.AchievedDate,112) AS DATETIME) <= Policies.LicenceCheckDate)
          AND (AgentCompetence.EndDate IS NULL OR CAST(CONVERT(VARCHAR,AgentCompetence.EndDate,112) AS DATETIME) > Policies.LicenceCheckDate)

if @debug=1 select 'Stage 12',getdate()


  update  #PolDetails
  set ReasonCompetent = 'Adviser does not have a valid competency',
    LicCompetent = ComplianceCategory + ':Invalid Competence'
  where   Competent is null

if @debug=1 select 'Stage 13',getdate()


      --=========================================================
      --Adviser is competent in the relevant compliance category
      --Find out if this product has a licence
      --=========================================================

          --No licence exists for this product so we assume that it's an old product and the
          --licence was never loaded onto Swift and therefore passes the licence check
          --This record is not displayed
  update  #PolDetails
  set LicProdOld = 1
  where not exists (select * from msit_CodeProductLicence where CodeProductsCode = #PolDetails.ProductCode)


if @debug=1 select 'Stage 14',getdate()

      --========================================
      --Check if adviser has valid Prod licence
      --========================================

  -- product licences that have clusters
  update  #PolDetails
  set   LicProdHasClusters = 1  
  from  #PolDetails
    inner join msit_CodeProductLicence CodeProductLicence on #PolDetails.ProductCode = CodeProductLicence.CodeProductsCode
    inner join msit_CodeLicenceCluster CodeLicenceCluster on CodeProductLicence.CodeLicenceID = CodeLicenceCluster.CodeLicenceID

if @debug=1 select 'Stage 15',getdate()


  -- Valid Licence no clusters needed
  update  #PolDetails
  set   ProdLicValidID = #ProdLics.AgentLicenceID,
    ProdLicValidStartDate = #ProdLics.LicenceStartDate,
    ProdLicValidEndDate = #ProdLics.LicenceEndDate,
    ProdLicValidExpiryDate = #ProdLics.LicenceExpiryDate
  from  #PolDetails Policies
    inner join msit_CodeProductLicence CodeProductLicence on Policies.ProductCode = CodeProductLicence.CodeProductsCode
    inner join #ProdLics on Policies.AgentsID = #ProdLics.AgentID
          and #ProdLics.CodeLicenceID = CodeProductLicence.CodeLicenceID
  where Policies.LicProdOld IS NULL
    and LicProdHasClusters is null
    AND #ProdLics.LicenceStartDate <= LicenceCheckDate
    and (#ProdLics.LicenceEndDate IS NULL or #ProdLics.LicenceEndDate > LicenceCheckDate)
    AND (#ProdLics.LicenceExpiryDate IS NULL or #ProdLics.LicenceExpiryDate > LicenceCheckDate)

if @debug=1 select 'Stage 16',getdate()

  -- Expired Licence no clusters needed
  update  #PolDetails
  set   ProdLicInvalidID = #ProdLics.AgentLicenceID,
    ProdLicInvalidStartDate = #ProdLics.LicenceStartDate,
    ProdLicInvalidEndDate = #ProdLics.LicenceEndDate,
    ProdLicInvalidExpiryDate = #ProdLics.LicenceExpiryDate,
    ReasonProd = 'You do not have the appropriate licences (Ref Prod1)',
    LicProd = ProductCode + ':' + CONVERT(VARCHAR, #ProdLics.LicenceStartDate, 103) 
      + '-' + CONVERT(VARCHAR, #ProdLics.LicenceExpiryDate, 103)
  from  #PolDetails Policies
    inner join msit_CodeProductLicence CodeProductLicence on Policies.ProductCode = CodeProductLicence.CodeProductsCode
    inner join #ProdLics on Policies.AgentsID = #ProdLics.AgentID
          and #ProdLics.CodeLicenceID = CodeProductLicence.CodeLicenceID
  where Policies.LicProdOld IS NULL
    and Policies.LicProdHasClusters is null
    and Policies.ProdLicValidID is null
    AND #ProdLics.LicenceStartDate <= LicenceCheckDate
    and (#ProdLics.LicenceEndDate IS NULL or #ProdLics.LicenceEndDate > LicenceCheckDate)
    AND (#ProdLics.LicenceExpiryDate IS NULL or #ProdLics.LicenceExpiryDate < LicenceCheckDate)

if @debug=1 select 'Stage 17',getdate()

  -- No licence no clusters needed
  update  #PolDetails
  set   ReasonProd = 'You do not have the appropriate licences (Ref Prod1)',
    LicProd = ProductCode +':No Licence'
  where LicProdOld is null
    and LicProdHasClusters is null
    and ProdLicValidID is null
    and ProdLicInvalidID is null

if @debug=1 select 'Stage 18',getdate()

  -- Valid Licence and cluster and sector
  update  #PolDetails
  set   ProdLicValidID = #ProdLics.AgentLicenceID,
    ProdLicValidStartDate = #ProdLics.LicenceStartDate,
    ProdLicValidEndDate = #ProdLics.LicenceEndDate,
    ProdLicValidExpiryDate = #ProdLics.LicenceExpiryDate,
    ProdLicClusterValidID = #ProdLics.AgentClusterID,
    ProdLicClusterValidStartDate = #ProdLics.ClusterStartDate,
    ProdLicClusterValidEndDate = #ProdLics.ClusterEndDate,
    ProdLicSectorValidID = #ProdLics.AgentSectorID,
    ProdLicSectorValidStartDate = #ProdLics.SectorStartDate,
    ProdLicSectorValidEndDate = #ProdLics.SectorEndDate
  from  #PolDetails Policies
    inner join msit_CodeProductLicence CodeProductLicence on Policies.ProductCode = CodeProductLicence.CodeProductsCode
    inner join #ProdLics on Policies.AgentsID = #ProdLics.AgentID
          and #ProdLics.CodeLicenceID = CodeProductLicence.CodeLicenceID
  where Policies.LicProdOld IS NULL
    and LicProdHasClusters = 1
    AND #ProdLics.LicenceStartDate <= LicenceCheckDate
    and (#ProdLics.LicenceEndDate IS NULL or #ProdLics.LicenceEndDate > LicenceCheckDate)
    AND (#ProdLics.LicenceExpiryDate IS NULL or #ProdLics.LicenceExpiryDate > LicenceCheckDate)
    AND #ProdLics.ClusterStartDate <= LicenceCheckDate
    and (#ProdLics.ClusterEndDate IS NULL or #ProdLics.ClusterEndDate > LicenceCheckDate)
    AND #ProdLics.SectorStartDate <= LicenceCheckDate
    and (#ProdLics.SectorEndDate IS NULL or #ProdLics.SectorEndDate > LicenceCheckDate)

if @debug=1 select 'Stage 19',getdate()

  -- Valid Licence and cluster NO sector
  update  #PolDetails
  set   ProdLicValidID = #ProdLics.AgentLicenceID,
    ProdLicValidStartDate = #ProdLics.LicenceStartDate,
    ProdLicValidEndDate = #ProdLics.LicenceEndDate,
    ProdLicValidExpiryDate = #ProdLics.LicenceExpiryDate,
    ProdLicClusterValidID = #ProdLics.AgentClusterID,
    ProdLicClusterValidStartDate = #ProdLics.ClusterStartDate,
    ProdLicClusterValidEndDate = #ProdLics.ClusterEndDate,
    ReasonProd = 'You do not have the appropriate licences (Ref Prod3)',
    LicProd = Policies.ProductCode +':No Licence (Sector)'
  from  #PolDetails Policies
    inner join msit_CodeProductLicence CodeProductLicence on Policies.ProductCode = CodeProductLicence.CodeProductsCode
    inner join #ProdLics on Policies.AgentsID = #ProdLics.AgentID
          and #ProdLics.CodeLicenceID = CodeProductLicence.CodeLicenceID
  where Policies.LicProdOld IS NULL
    and Policies.ProdLicValidID is null
    and Policies.LicProdHasClusters = 1
    AND #ProdLics.LicenceStartDate <= LicenceCheckDate
    and (#ProdLics.LicenceEndDate IS NULL or #ProdLics.LicenceEndDate > LicenceCheckDate)
    AND (#ProdLics.LicenceExpiryDate IS NULL or #ProdLics.LicenceExpiryDate > LicenceCheckDate)
    AND #ProdLics.ClusterStartDate <= LicenceCheckDate
    and (#ProdLics.ClusterEndDate IS NULL or #ProdLics.ClusterEndDate > LicenceCheckDate)

if @debug=1 select 'Stage 20',getdate()

  -- Valid Licence NO cluster NO sector
  update  #PolDetails
  set   ProdLicValidID = #ProdLics.AgentLicenceID,
    ProdLicValidStartDate = #ProdLics.LicenceStartDate,
    ProdLicValidEndDate = #ProdLics.LicenceEndDate,
    ProdLicValidExpiryDate = #ProdLics.LicenceExpiryDate,
    ReasonProd = 'You do not have the appropriate licences (Ref Prod2)',
    LicProd = Policies.ProductCode +':No Licence (Cluster)'
  from  #PolDetails Policies
    inner join msit_CodeProductLicence CodeProductLicence on Policies.ProductCode = CodeProductLicence.CodeProductsCode
    inner join #ProdLics on Policies.AgentsID = #ProdLics.AgentID
          and #ProdLics.CodeLicenceID = CodeProductLicence.CodeLicenceID
  where Policies.LicProdOld IS NULL
    and Policies.ProdLicValidID is null
    and Policies.LicProdHasClusters = 1
    AND #ProdLics.LicenceStartDate <= LicenceCheckDate
    and (#ProdLics.LicenceEndDate IS NULL or #ProdLics.LicenceEndDate > LicenceCheckDate)
    AND (#ProdLics.LicenceExpiryDate IS NULL or #ProdLics.LicenceExpiryDate > LicenceCheckDate)

if @debug=1 select 'Stage 21',getdate()

  -- Expired Licence
  update  #PolDetails
  set   ProdLicInvalidID = #ProdLics.AgentLicenceID,
    ProdLicInvalidStartDate = #ProdLics.LicenceStartDate,
    ProdLicInvalidEndDate = #ProdLics.LicenceEndDate,
    ProdLicInvalidExpiryDate = #ProdLics.LicenceExpiryDate,
    ReasonProd = 'You do not have the appropriate licences (Ref Prod1)',
    LicProd = Policies.ProductCode + ':' + CONVERT(VARCHAR, #ProdLics.LicenceStartDate, 103) 
      + '-' + CONVERT(VARCHAR, #ProdLics.LicenceExpiryDate, 103)
  from  #PolDetails Policies
    inner join msit_CodeProductLicence CodeProductLicence on Policies.ProductCode = CodeProductLicence.CodeProductsCode
    inner join #ProdLics on Policies.AgentsID = #ProdLics.AgentID
          and #ProdLics.CodeLicenceID = CodeProductLicence.CodeLicenceID
  where Policies.LicProdOld IS NULL
    and Policies.ProdLicValidID is null
    and Policies.LicProdHasClusters = 1
    AND #ProdLics.LicenceStartDate <= LicenceCheckDate
    and (#ProdLics.LicenceEndDate IS NULL or #ProdLics.LicenceEndDate > LicenceCheckDate)
    AND (#ProdLics.LicenceExpiryDate IS NULL or #ProdLics.LicenceExpiryDate < LicenceCheckDate)

if @debug=1 select 'Stage 22',getdate()

  -- no licence at all
  update  #PolDetails
  set   ReasonProd = 'You do not have the appropriate licences (Ref Prod1)',
    LicProd = ProductCode +':No Licence'
  where LicProdOld is null
    and LicProdHasClusters = 1
    and ProdLicValidID is null
    and ProdLicInvalidID is null

if @debug=1 select 'Stage 23',getdate()


         --======================================================================================
         --Replacement - only interested in type 'B' and 'C'(which are 2 and  3 respectively!)
         --======================================================================================


  --Valid licence and cluster and sector
  update  #PolDetails
  set   ReplLicValidID = #ProdLics.AgentLicenceID,
    ReplLicValidStartDate = #ProdLics.LicenceStartDate,
    ReplLicValidEndDate = #ProdLics.LicenceEndDate,
    ReplLicValidExpiryDate = #ProdLics.LicenceExpiryDate,
    ReplLicClusterValidID = #ProdLics.AgentClusterID,
    ReplLicClusterValidStartDate = #ProdLics.ClusterStartDate,
    ReplLicClusterValidEndDate = #ProdLics.ClusterEndDate,
    ReplLicSectorValidID = #ProdLics.AgentSectorID,
    ReplLicSectorValidStartDate = #ProdLics.SectorStartDate,
    ReplLicSectorValidEndDate = #ProdLics.SectorEndDate
  from  #PolDetails Policies
    inner join #ProdLics on Policies.AgentsID = #ProdLics.AgentID
          and (#ProdLics.CodeLicenceCode = 'ERIN' OR (#ProdLics.CodeLicenceCode = 'ERPR' and Policies.Plan_Code<>'INV' ))
  where isnull(Policies.Replacement,0) in (2,3)
    and Policies.Plan_Code in ('LIFE' ,'TERM' ,'CRITILL' ,'IPP' ,'DMC' ,'INV')
    and Policies.LicProdOld IS NULL
    AND #ProdLics.LicenceStartDate <= LicenceCheckDate
    and (#ProdLics.LicenceEndDate IS NULL or #ProdLics.LicenceEndDate > LicenceCheckDate)
    AND (#ProdLics.LicenceExpiryDate IS NULL or #ProdLics.LicenceExpiryDate > LicenceCheckDate)
    AND #ProdLics.ClusterStartDate <= LicenceCheckDate
    and (#ProdLics.ClusterEndDate IS NULL or #ProdLics.ClusterEndDate > LicenceCheckDate)
    AND #ProdLics.SectorStartDate <= LicenceCheckDate
    and (#ProdLics.SectorEndDate IS NULL or #ProdLics.SectorEndDate > LicenceCheckDate)

if @debug=1 select 'Stage 24',getdate()

  --Valid licence and cluster NO sector
  update  #PolDetails
  set   ReplLicValidID = #ProdLics.AgentLicenceID,
    ReplLicValidStartDate = #ProdLics.LicenceStartDate,
    ReplLicValidEndDate = #ProdLics.LicenceEndDate,
    ReplLicValidExpiryDate = #ProdLics.LicenceExpiryDate,
    ReplLicClusterValidID = #ProdLics.AgentClusterID,
    ReplLicClusterValidStartDate = #ProdLics.ClusterStartDate,
    ReplLicClusterValidEndDate = #ProdLics.ClusterEndDate,
    ReasonReplace = 'You do not have the appropriate licences (Ref REP3)',
    LicReplace = 'Replacement:No Licence (Sector)'
  from  #PolDetails Policies
    inner join #ProdLics on Policies.AgentsID = #ProdLics.AgentID
          and (#ProdLics.CodeLicenceCode = 'ERIN' OR (#ProdLics.CodeLicenceCode = 'ERPR' and Policies.Plan_Code<>'INV' ))
  where isnull(Policies.Replacement,0) in (2,3)
    and Policies.Plan_Code in ('LIFE' ,'TERM' ,'CRITILL' ,'IPP' ,'DMC' ,'INV')
    and Policies.LicProdOld IS NULL
    and ReplLicValidID is null
    AND #ProdLics.LicenceStartDate <= LicenceCheckDate
    and (#ProdLics.LicenceEndDate IS NULL or #ProdLics.LicenceEndDate > LicenceCheckDate)
    AND (#ProdLics.LicenceExpiryDate IS NULL or #ProdLics.LicenceExpiryDate > LicenceCheckDate)
    AND #ProdLics.ClusterStartDate <= LicenceCheckDate
    and (#ProdLics.ClusterEndDate IS NULL or #ProdLics.ClusterEndDate > LicenceCheckDate)

if @debug=1 select 'Stage 25',getdate()

  --Valid licence NO cluster NO sector
  update  #PolDetails
  set   ReplLicValidID = #ProdLics.AgentLicenceID,
    ReplLicValidStartDate = #ProdLics.LicenceStartDate,
    ReplLicValidEndDate = #ProdLics.LicenceEndDate,
    ReplLicValidExpiryDate = #ProdLics.LicenceExpiryDate,
    ReasonReplace = 'You do not have the appropriate licences (Ref REP2)',
    LicReplace = 'Replacement:No Licence (Cluster)'
  from  #PolDetails Policies
    inner join #ProdLics on Policies.AgentsID = #ProdLics.AgentID
          and (#ProdLics.CodeLicenceCode = 'ERIN' OR (#ProdLics.CodeLicenceCode = 'ERPR' and Policies.Plan_Code<>'INV' ))
  where isnull(Policies.Replacement,0) in (2,3)
    and Policies.Plan_Code in ('LIFE' ,'TERM' ,'CRITILL' ,'IPP' ,'DMC' ,'INV')
    and Policies.LicProdOld IS NULL
    and ReplLicValidID is null
    AND #ProdLics.LicenceStartDate <= LicenceCheckDate
    and (#ProdLics.LicenceEndDate IS NULL or #ProdLics.LicenceEndDate > LicenceCheckDate)
    AND (#ProdLics.LicenceExpiryDate IS NULL or #ProdLics.LicenceExpiryDate > LicenceCheckDate)

if @debug=1 select 'Stage 26',getdate()

  --Expired licence
  update  #PolDetails
  set   ReplLicInvalidID = #ProdLics.AgentLicenceID,
    ReplLicInvalidStartDate = #ProdLics.LicenceStartDate,
    ReplLicInvalidEndDate = #ProdLics.LicenceEndDate,
    ReplLicInvalidExpiryDate = #ProdLics.LicenceExpiryDate,
    ReasonReplace = 'You do not have the appropriate licences (Ref REP1)',
    LicReplace = 'Replacement:' + CONVERT(VARCHAR, #ProdLics.LicenceStartDate, 103) 
      + '-' + CONVERT(VARCHAR, #ProdLics.LicenceExpiryDate, 103)
  from  #PolDetails Policies
    inner join #ProdLics on Policies.AgentsID = #ProdLics.AgentID
          and (#ProdLics.CodeLicenceCode = 'ERIN' OR (#ProdLics.CodeLicenceCode = 'ERPR' and Policies.Plan_Code<>'INV' ))
  where isnull(Policies.Replacement,0) in (2,3)
    and Policies.Plan_Code in ('LIFE' ,'TERM' ,'CRITILL' ,'IPP' ,'DMC' ,'INV')
    and Policies.LicProdOld IS NULL
    and ReplLicValidID is null
    AND #ProdLics.LicenceStartDate <= LicenceCheckDate

    and (#ProdLics.LicenceEndDate IS NULL or #ProdLics.LicenceEndDate > LicenceCheckDate)
    AND (#ProdLics.LicenceExpiryDate IS NULL or #ProdLics.LicenceExpiryDate < LicenceCheckDate)

if @debug=1 select 'Stage 27',getdate()

  --None at all
  update  #PolDetails
  set   ReasonReplace = 'You do not have the appropriate licences (Ref REP1)',
    LicReplace = 'Replacement:No Licence'
  where LicProdOld is null
    and isnull(Replacement,0) in (2,3)
    and Plan_Code in ('LIFE' ,'TERM' ,'CRITILL' ,'IPP' ,'DMC' ,'INV')
    and ReplLicValidID is null
    and ReplLicInvalidID is null



if @debug=1 select 'Stage 28',getdate()

UPDATE  #PolDetails
SET     LicenseStatus = ISNULL(LicCCL + '. ', '')
      + ISNULL(LicDPL + '. ', '') 
      + ISNULL(LicKBUS + '. ', '')
      + ISNULL(LicCompetent + '. ', '') 
      + ISNULL(LicProd + '. ', '') 
      + ISNULL(LicIHT + '. ', '') 
      + ISNULL(LicReplace + '.', '')
    , Reason = ISNULL(ReasonCCL + '. ', '') 
       + ISNULL(ReasonDPL + '. ', '')
       + ISNULL(ReasonKBUS + '. ', '')
       + ISNULL(ReasonCompetent + '. ', '') 
       + ISNULL(ReasonProd + '. ', '') 
       + ISNULL(ReasonIHT + '. ', '') 
       + ISNULL(ReasonReplace + '.', '')

DELETE FROM #PolDetails WHERE ISNULL(RTRIM(LicenseStatus), '') = ''

if @debug=1 select 'Stage 29',getdate()


   --========================================================================
   --Policies from a PreAppointed Adviser (excluding Pre-App ETi/CPT Sales )
   --insert them into temp table 
   --========================================================================

-- only if it's the Eti report
if @RptType = 'E'
begin
insert #PolDetails(
  POL_NUM     ,
  ProductCode   ,
  PolicyRef   ,
  OriginatingSource ,
  Pol_Type    ,
  Plan_Code   ,
  ServicingAgentCode  ,
  Prop_Date   ,
  Start_Date    ,
  CreateDate    ,
  LicenceCheckDate  ,
  SalesProcess    ,
  ComplianceCategory  ,
  CompetencyCode    ,
  AgentsID    ,
  AgentsCODE    ,
  SupvisrCODE   ,
  BusinessCODE    ,
  AgentsCompetentStatus ,
  AgentCategory   ,
  DualSalesProcess  ,
  PurchaseTypeID    ,
  BusinessAgentType ,
  BusinessAgentCategory   ,
  PreAppAgentExists ,
  Replacement   ,
  ProviderCode    ,
  LicenseStatus   ,
  RecordSource
)
select  
  Policies.POL_NUM        ,
  Policies.ProductCode        ,
  Policies.PolicyRef        ,
  Policies.OriginatingSource      ,
  Policies.Pol_Type       ,
  Policies.Plan_Code        ,
  Policies.ServicingAgentCode     ,
  CAST(CONVERT(NVARCHAR, Policies.Prop_Date, 112) AS DATETIME)    ,
  CAST(CONVERT(NVARCHAR, Policies.Start_Date, 112) AS DATETIME)   ,
  CAST(CONVERT(NVARCHAR, Policies.CreateDate, 112) AS DATETIME)   ,
        CASE
           WHEN Policies.OriginatingSource = 1 
       THEN CAST(CONVERT(NVARCHAR, coalesce(Policies.Prop_Date,Policies.Start_Date,Policies.CreateDate,getdate()), 112) AS DATETIME) --Proposal date (this is 'licence check date' for ETi cases)
           WHEN Policies.OriginatingSource = 5 
             THEN CAST(CONVERT(NVARCHAR, coalesce(Policies.Prop_Date,Policies.Start_Date,Policies.CreateDate,getdate()), 112) AS DATETIME) --Proposal date (this is 'licence check date' for CPT mortgage cases) - JNP CR863
           WHEN Policies.OriginatingSource = 6 
             THEN CAST(CONVERT(NVARCHAR, coalesce(Policies.Prop_Date,Policies.Start_Date,Policies.CreateDate,getdate()), 112) AS DATETIME) --Proposal date (this is 'licence check date' for OTPc cases)  MPC July 2007
           ELSE CAST(CONVERT(NVARCHAR, coalesce(Policies.Start_Date,Policies.Prop_Date,Policies.CreateDate,getdate()), 112) AS DATETIME) --Start date (this is 'licence check date' for non-ETi/CPT cases)
        END,
  Policies.SalesProcess       ,
  case
    when Policies.Plan_Code = 'MRTG' then 'MCOB' --Mortgage
    when Policies.Plan_Code in ('B&C','ASU') then 'ICOB-GI' --General Insurance
    when Policies.SalesProcess = 1 then 'ICOB-PP' --Simplified Sales process (JNP CR587)
                else 'COB'
  END, -- ComplianceCategory
  null, -- CompetencyCode
  Agents.ID         ,
  Agents.Code         ,
  Agents.SpanSupervisorCode     ,
  Agents.Firm         ,
  Agents.CompetentStatus        ,
  Agents.AgentCategory        ,
  null,--CodeBIProducts.DualSalesProcess    ,
  null, --PurchaseTypeID        ,
  null, --BusinessAgentType     ,
  null, --BusinessAgentCategory       ,
  null, -- PreAppAgentExists
  Policies.Replacement        ,
  Policies.COMP_CODE        ,
  '', -- LicenceStatus
  '2' -- RecordSource for debugging

   FROM mstt_Policies Policies 
       inner join #Etipolstoprocess t1 on t1.pol_num = Policies.Pol_num
       INNER JOIN mstt_Agents Agents ON Policies.ServicingAgentCode = Agents.CODE
       LEFT OUTER JOIN mstt_Agents Supvisr ON Agents.SpanSupervisorCode = Supvisr.CODE --SpanSupervisorCode
       LEFT JOIN mstt_Agents AS Business ON Agents.Firm = Business.Code
 
  WHERE EXISTS(SELECT CODE FROM mstt_AgentsHistory AgentsHistory
                 WHERE AgentsHistory.CompetentStatus = 5
                 AND AgentsHistory.CODE = Policies.ServicingAgentCode
                 AND (Policies.OriginatingSource IN (1,5,6) --For ETi, OTPc & Mortgage CPT cases, use Proposal date as 'licence check date'
                      AND CAST(CONVERT(NVARCHAR, Policies.Prop_Date, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, AgentsHistory.ValidFromDate, 112) AS DATETIME) 
                      AND CAST(CONVERT(NVARCHAR, Policies.Prop_Date, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, AgentsHistory.ValidToDate, 112) AS DATETIME) 
                  OR (Policies.OriginatingSource NOT IN (1,5,6) OR Policies.OriginatingSource IS NULL) --For non-ETi/OTPc/CPT cases, use Start date as 'licence check date'
                      AND CAST(CONVERT(NVARCHAR, Policies.Start_Date, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, AgentsHistory.ValidFromDate, 112) AS DATETIME) 
                      AND CAST(CONVERT(NVARCHAR, Policies.Start_Date, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, AgentsHistory.ValidToDate, 112) AS DATETIME))
               ) --Adviser is Pre-App 
   AND (Policies.OriginatingSource IN (1) --For ETi & Mortgage CPT cases, use Proposal date as 'Swift load date'
        AND CAST(CONVERT(NVARCHAR, Policies.Prop_Date, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME) 
        AND CAST(CONVERT(NVARCHAR, Policies.Prop_Date, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME) 
    OR (Policies.OriginatingSource NOT IN (1) OR Policies.OriginatingSource IS NULL) --For non-ETi/CPT cases, use Create date as 'Swift load date'
        AND CAST(CONVERT(NVARCHAR, Policies.CreateDate, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME) 
        AND CAST(CONVERT(NVARCHAR, Policies.CreateDate, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME))
   AND Policies.POL_NUM NOT IN (SELECT POL_NUM from #PolDetails) --Exclude Pre-App ETi/CPT sales records
   AND (Business.AgentType IS NULL OR Business.AgentType <> 49) -- exclude directly authorised
   AND Business.AgentCategory not like '%NASP%'     -- Exclude NASP Sales
   AND Agents.AgentCategory not like '%NASP%'     -- Exclude NASP Sales
end


if @debug=1 select 'Stage 30',getdate()


  -- get some extra bits of info

  update  #PolDetails
  set ProviderName = isnull(ProductProviders.ProductProviderName,'')
  from  #PolDetails
    left outer join mstt_ProductProviders ProductProviders ON #PolDetails.ProviderCode = ProductProviders.ProductProviderCode

  -- agents and supervisors name
  update  #PolDetails
  set AgentName = ISNULL(RTRIM(SUBSTRING(Agents.Firstnames, 1, PATINDEX('%[^ ] %', Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name), '')
  from  #PolDetails
    left outer join mstt_Agents Agents ON #PolDetails.AgentsCODE = Agents.CODE

  update  #PolDetails
  set AgentSupervisor = ISNULL(RTRIM(SUBSTRING(Supvisr.Firstnames, 1, PATINDEX('%[^ ] %', Supvisr.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Supvisr.Name), '')
  from  #PolDetails
    left outer join mstt_Agents Supvisr ON #PolDetails.SupvisrCODE = Supvisr.CODE 

  -- agent status
  update  #PolDetails
  set AgentStatus = 'Pre-App Recruit'
  from  #PolDetails
    inner join #PreAppAgents on #PolDetails.ServicingAgentCode = #PreAppAgents.CODE
          and #PolDetails.LicenceCheckDate between #PreAppAgents.ValidFromDate AND #PreAppAgents.ValidToDate

  update  #PolDetails
  set AgentStatus = 'Appointed'
  where AgentStatus is null

if @debug=1 select 'Stage 31',getdate()


  -- competencies

     UPDATE #PolDetails
     SET  COBCompetency = (SELECT TOP 1 COBCompetence.AgentControlFunctionDescn
                           FROM mstt_AgentCompetence COBCompetence
                           WHERE PolDetails.AgentsCODE = COBCompetence.AgentCode
                             AND COBCompetence.ComplianceCategoryCode = 'COB'
                             AND COBCompetence.EndDate IS NULL
                           ORDER BY COBCompetence.DateAppointed DESC) -- the latest null-end-dated COB record
        , ICOBPPCompetency = (SELECT TOP 1 ICOBPPCompetence.AgentControlFunctionDescn
                           FROM mstt_AgentCompetence ICOBPPCompetence
                           WHERE PolDetails.AgentsCODE = ICOBPPCompetence.AgentCode
                             AND ICOBPPCompetence.ComplianceCategoryCode = 'ICOB-PP'
                             AND ICOBPPCompetence.EndDate IS NULL
                           ORDER BY ICOBPPCompetence.DateAppointed DESC) -- the latest null-end-dated ICOB-PP record
     FROM #PolDetails PolDetails

if @debug=1 select 'Stage 32',getdate()


  -- last one is split sales
  create table #SplitSales(
    POL_NUM   int,
    AgentCode varchar(7),
    AgentName varchar(700)
    )
  CREATE CLUSTERED INDEX RT1 ON #SplitSales(POL_NUM)

  insert  #SplitSales(
    POL_NUM,
    AgentCode,
    AgentName)
  select  distinct
    Commissions.PolicyId,
    Agents.CODE,
    ISNULL(RTRIM(SUBSTRING(Agents.Firstnames, 1, PATINDEX('%[^ ] %', Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name), '')
  from  #PolDetails
    inner join mstt_Commissions Commissions on #PolDetails.POL_NUM = Commissions.PolicyId
    inner join mstt_Agents Agents ON Commissions.AGENT_CODE = Agents.CODE
  where Commissions.AGENT_CODE <> #PolDetails.AgentsCode  --Exclude the selling agent himself
    and Commissions.AGENT_CODE <> '10002'     --Exclude all Openwork Margins
    and Commissions.CommissionType = 1      --Exclude RC/Trail Splits
    
if @debug=1 select 'Stage 33',getdate()


  while exists (select * from #SplitSales)
  begin
    UPDATE  #PolDetails
    set SplitSale = coalesce(SplitSale,'') + ' - ' + (CASE WHEN (#SplitSales.AgentName = '') THEN 'Unknown' ELSE #SplitSales.AgentName END)
                             + '(' + ISNULL(#SplitSales.AgentCode,'') + ')'
    from  #PolDetails PolDetails
      inner join #SplitSales on PolDetails.POL_NUM = #SplitSales.POL_NUM
      inner join 
      (
      select  POL_NUM,
        min(AgentCode) MinAgentCode
      FROM  #SplitSales
      group by POL_NUM
      ) FirstAgent on #SplitSales.POL_NUM = FirstAgent.POL_NUM and #SplitSales.AgentCode = FirstAgent.MinAgentCode
    
    -- delete earliest AgentCode for each POL_NUM as its been used
    delete  #SplitSales
    from  #SplitSales 
      inner join 
      (
      select  POL_NUM,
        min(AgentCode) MinAgentCode
      FROM  #SplitSales
      group by POL_NUM
      ) FirstAgent on #SplitSales.POL_NUM = FirstAgent.POL_NUM and #SplitSales.AgentCode = FirstAgent.MinAgentCode
    
  end

if @debug=1 select 'Stage 34',getdate()

  update  #PolDetails
  set SplitSale = case when SplitSale is null then 'N' else 'Y ' + SplitSale end


if @debug=1 select 'Stage 35',getdate()

  -- just copying ineffectual error handling from earlier version
   SELECT @Severity = @@ERROR

   SELECT 
        AgentName 
      , AgentsCode AgentCode 
      , AgentSupervisor 
      , ProductCode PlanType 
      , AgentStatus 
      , CONVERT(VARCHAR, LicenceCheckDate, 103) AS [LicenceCheckDate]
      , PolicyRef CaseID 
      , CASE OriginatingSource
           WHEN 0 THEN 'Manual'
           WHEN 1 THEN 'ETi'
           WHEN 2 THEN 'ETr'
           WHEN 3 THEN 'MBL'
           WHEN 4 THEN 'Trigold'
           WHEN 5 THEN 'CPT'  -- JNP CR863
     WHEN 6 THEN 'OTPc'   -- MPC July 2007
           ELSE 'Unknown'
        END AS [Source]
      , SplitSale 
      , LicenseStatus 
      , ProviderName ProductProvider 
      , COBCompetency
      , ICOBPPCompetency
      , NULL AS Error
   FROM #PolDetails
   WHERE CAST(CONVERT(NVARCHAR, LicenceCheckDate, 112) AS DATETIME) between @dteStartDate and @dteEndDate
   ORDER BY AgentName, AgentsCode, PolicyRef

if @debug=1 select 'Stage 36',getdate()


   RETURN @Severity



GO
/****** Object:  StoredProcedure [dbo].[owp_UnlicencedSales_old]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO





-- exec cscp_UnlicencedETiSales null, '2006-01-01','2007-01-01'

CREATE procedure [dbo].[owp_UnlicencedSales_old]
   @RptType varchar(1),
  @UserID VARCHAR(255)
, @StartDate VARCHAR(10)
, @EndDate VARCHAR(10)

as

/*
  rh 11 June 2007
  Rewrite of existing cscp_UnlicencedGroupSales  and cscp_UnlicencedEtiSales 
  for performance.

  Both existing stub procs remain but call this proc passing in 'G' or 'E'

*/

/*
  MPC July 2007
  Exclude sales where Business or Seller Agent Category denotes NASP
  Include OTPc cases (originatingsource = 6)
*/

/*
  MPC August 2007
  Minor changes to improve performance.
*/

/*
  MPC September 2007
  SR8 - Relabel OriginatingSource codes to new range of values
*/


set nocount on

declare @debug int
select @debug = 0

if @debug=1 select 'Stage 1',getdate()

declare @dteStartDate datetime
declare @dteEndDate datetime

declare @Severity int

select  @dteStartDate = CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME) ,
  @dteEndDate = CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME)


if @RptType='E'
begin
select pol_num into #ETiPolsToProcess 
from mstt_policies 
where pol_type <> '205'
and (CASE WHEN OriginatingSource in (2,3,4) -- MPC: SR8 
  THEN CAST(CONVERT(NVARCHAR, coalesce(Prop_Date,Start_Date,CreateDate,getdate()), 112) AS DATETIME)
  ELSE CAST(CONVERT(NVARCHAR, coalesce(Start_Date,Prop_Date,CreateDate,getdate()), 112) AS DATETIME)
  END) between @dteStartDate and @dteEndDate
end
else
begin
select distinct pol_num into #GroupPolsToProcess
from mstt_policytransactions pt
inner join mstt_policies on pol_num = policyid
where pol_type = 205 AND pt.AdminMethod = 'A' AND TransType = '39'
and CAST(CONVERT(NVARCHAR, coalesce(TransactionDate,Prop_Date,Start_Date,CreateDate), 112) AS DATETIME) between @dteStartDate and @dteEndDate
end

create table #PolDetails 
  (
      POL_NUM     int,
  KeepRecord    int,
  Competent   int,
      ProductCode   varchar(8) collate LATIN1_GENERAL_CI_AS,
      PolicyRef     int,
      OriginatingSource   int,
      Pol_Type      tinyint,
      Plan_Code     varchar(10),
      PolicyCategoryCode  varchar(10),
      ServicingAgentCode  varchar(7) collate LATIN1_GENERAL_CI_AS,
      Prop_Date     datetime,
      Start_Date    datetime,
      CreateDate    datetime,
  LicenceCheckDate  datetime,
  SalesProcess    int,
  ComplianceCategory  varchar(10) collate LATIN1_GENERAL_CI_AS,
  CompetencyCode    varchar(8) collate LATIN1_GENERAL_CI_AS,
  AgentsID    int,
      AgentsCODE    varchar(7) collate LATIN1_GENERAL_CI_AS,
      SupvisrCODE   varchar(7) collate LATIN1_GENERAL_CI_AS,
      BusinessCODE    varchar(7) collate LATIN1_GENERAL_CI_AS,
      DualSalesProcess    varchar(255),
      PurchaseTypeID    int,
      BusinessAgentType   tinyint,
      BusinessAgentCategory     varchar(8),
      AgentsCompetentStatus tinyint,
      AgentCategory       varchar(8),
  PreAppAgentExists int,
  Replacement   int,
  ProviderCode    varchar(10)  collate LATIN1_GENERAL_CI_AS,
  ProviderName    varchar(100),
  AgentName   varchar(155),
  AgentSupervisor   varchar(155),
  AgentStatus   varchar(20),
  COBCompetency   varchar(255),
  ICOBPPCompetency  varchar(255),
  SplitSale   varchar(2000),
  RecordSource    varchar(1)

      , LicCCL                          VARCHAR(80) 
      , LicDPL                          VARCHAR(80) 
      , LicKBUS                         VARCHAR(80) 
      , LicProd                         VARCHAR(80)
      , LicIHT                          VARCHAR(80)
      , LicReplace                      VARCHAR(80)
      , LicCompetent                    VARCHAR(80)

      , ReasonCCL                       VARCHAR(80)
      , ReasonDPL                       VARCHAR(80)
      , ReasonKBUS                      VARCHAR(80)
      , ReasonProd                      VARCHAR(80)
      , ReasonIHT                       VARCHAR(80)
      , ReasonReplace                   VARCHAR(80)
      , ReasonCompetent                 VARCHAR(80)

  , LicenseStatus     VARCHAR(2000)
  ,Reason       varchar(500)

  , CCLLicValidID     int
  , CCLLicValidStartDate    datetime
  , CCLLicValidEndDate    datetime
  , CCLLicValidExpiryDate   datetime
  , CCLLicInvalidID   int
  , CCLLicInvalidStartDate  datetime
  , CCLLicInvalidEndDate    datetime
  , CCLLicInvalidExpiryDate datetime

  , DPLLicValidID     int
  , DPLLicValidStartDate    datetime
  , DPLLicValidEndDate    datetime
  , DPLLicValidExpiryDate   datetime
  , DPLLicInvalidID   int
  , DPLLicInvalidStartDate  datetime
  , DPLLicInvalidEndDate    datetime
  , DPLLicInvalidExpiryDate datetime

  , KBUSLicValidID    int
  , KBUSLicValidStartDate   datetime
  , KBUSLicValidEndDate   datetime
  , KBUSLicValidExpiryDate  datetime
  , KBUSLicInvalidID    int
  , KBUSLicInvalidStartDate datetime
  , KBUSLicInvalidEndDate   datetime
  , KBUSLicInvalidExpiryDate  datetime

  , LicProdOld      int
  , LicProdHasClusters    int

  , ProdLicValidID    int
  , ProdLicValidStartDate   datetime
  , ProdLicValidEndDate   datetime
  , ProdLicValidExpiryDate  datetime

  , ProdLicInvalidID    int
  , ProdLicInvalidStartDate datetime
  , ProdLicInvalidEndDate   datetime
  , ProdLicInvalidExpiryDate  datetime

  , ProdLicClusterValidID     int
  , ProdLicClusterValidStartDate    datetime
  , ProdLicClusterValidEndDate    datetime

  , ProdLicSectorValidID      int
  , ProdLicSectorValidStartDate   datetime
  , ProdLicSectorValidEndDate   datetime

  , ReplLicValidID      int
  , ReplLicValidStartDate     datetime
  , ReplLicValidEndDate     datetime
  , ReplLicValidExpiryDate    datetime

  , ReplLicInvalidID      int
  , ReplLicInvalidStartDate   datetime
  , ReplLicInvalidEndDate     datetime
  , ReplLicInvalidExpiryDate    datetime

  , ReplLicClusterValidID     int
  , ReplLicClusterValidStartDate    datetime
  , ReplLicClusterValidEndDate    datetime

  , ReplLicSectorValidID      int
  , ReplLicSectorValidStartDate   datetime

  , ReplLicSectorValidEndDate   datetime

  )

create clustered index idxPol_Num on #PolDetails(POL_NUM)


if @RptType='E'
begin
  insert #PolDetails(
    POL_NUM     ,
    ProductCode   ,
    PolicyRef   ,
    OriginatingSource ,
    Pol_Type    ,
    Plan_Code   ,
          PolicyCategoryCode  ,
    ServicingAgentCode  ,
    Prop_Date   ,
    Start_Date    ,
    CreateDate    ,
    LicenceCheckDate  ,
    SalesProcess    ,
    ComplianceCategory  ,
    CompetencyCode    ,
    AgentsID    ,
    AgentsCODE    ,
    SupvisrCODE   ,
    BusinessCODE    ,
    AgentsCompetentStatus ,
    AgentCategory   ,
    DualSalesProcess  ,
    PurchaseTypeID    ,
    BusinessAgentType ,
    BusinessAgentCategory ,
    PreAppAgentExists ,
    Replacement   ,
    ProviderCode    ,
    RecordSource
  )
  select  
    Policies.POL_NUM        ,
    Policies.ProductCode        ,
    Policies.PolicyRef        ,
    Policies.OriginatingSource      ,
    Policies.Pol_Type       ,
    Policies.Plan_Code        ,
    msit_S_POLMAI.PolicyCategoryCode    ,
    Policies.ServicingAgentCode     ,
    CAST(CONVERT(NVARCHAR, Policies.Prop_Date, 112) AS DATETIME)    ,
    CAST(CONVERT(NVARCHAR, Policies.Start_Date, 112) AS DATETIME)   ,
    CAST(CONVERT(NVARCHAR, Policies.CreateDate, 112) AS DATETIME)   ,
          CASE
             WHEN Policies.OriginatingSource = 2 
         THEN CAST(CONVERT(NVARCHAR, coalesce(Policies.Prop_Date,Policies.Start_Date,Policies.CreateDate,getdate()), 112) AS DATETIME) --Proposal date (this is 'licence check date' for ETi cases)
             WHEN Policies.OriginatingSource = 3    -- MPC: SR8 
                     THEN CAST(CONVERT(NVARCHAR, coalesce(Policies.Prop_Date,Policies.Start_Date,Policies.CreateDate,getdate()), 112) AS DATETIME) --Proposal date (this is 'licence check date' for CPT mortgage cases) - JNP CR863
             WHEN Policies.OriginatingSource = 4    -- MPC: SR8 
                     THEN CAST(CONVERT(NVARCHAR, coalesce(Policies.Prop_Date,Policies.Start_Date,Policies.CreateDate,getdate()), 112) AS DATETIME) --Proposal date (this is 'licence check date' for OTPc cases)  MPC July 2007
             ELSE CAST(CONVERT(NVARCHAR, coalesce(Policies.Start_Date,Policies.Prop_Date,Policies.CreateDate,getdate()), 112) AS DATETIME) --Start date (this is 'licence check date' for non-ETi/CPT cases)
          END,
    Policies.SalesProcess       ,
    case
      when Policies.Plan_Code = 'MRTG' then 'MCOB' --Mortgage
      when Policies.Plan_Code in ('B&C','ASU') then 'ICOB-GI' --General Insurance
      when Policies.SalesProcess = 1 then 'ICOB-PP' --Simplified Sales process (JNP CR587)
                  else 'COB'
    END, -- ComplianceCategory
    null, -- CompetencyCode
    Agents.ID         ,
    Agents.Code         ,
    Agents.SpanSupervisorCode     ,
    Agents.Firm         ,
    Agents.CompetentStatus        ,
    Agents.AgentCategory        ,
    CodeBIProducts.DualSalesProcess     ,
    null, --PurchaseTypeID        ,
    null, --BusinessAgentType     ,
    null, --BusinessAgentCategory     ,
    null, -- PreAppAgentExists
    Policies.Replacement        ,
    Policies.COMP_CODE        ,
    '1'
  from  mstt_Policies Policies
    inner join #Etipolstoprocess t1 on t1.pol_num = Policies.Pol_num
    inner join msit_S_POLMAI on msit_S_POLMAI.POL_NUM = Policies.POL_NUM
    inner join mstt_Agents Agents ON Policies.ServicingAgentCode = Agents.CODE
          INNER JOIN mstt_CodeBIProducts CodeBIProducts ON CodeBIProducts.ProductCode = Policies.ProductCode --JNP CR587
    where Policies.Pol_Type <> '205'  -- Exclude Group Pensions
end
else
begin
  -- 'G' group report
  insert #PolDetails(
    POL_NUM     ,
    ProductCode   ,
    PolicyRef   ,
    OriginatingSource ,
    Pol_Type    ,
    Plan_Code   ,
          PolicyCategoryCode  ,
    ServicingAgentCode  ,
    Prop_Date   ,
    Start_Date    ,
    CreateDate    ,
    LicenceCheckDate  ,
    SalesProcess    ,
    ComplianceCategory  ,
    CompetencyCode    ,
    AgentsID    ,
    AgentsCODE    ,
    SupvisrCODE   ,
    BusinessCODE    ,
    AgentsCompetentStatus ,
    AgentCategory   ,
    DualSalesProcess  ,
    PurchaseTypeID    ,
    BusinessAgentType ,
    BusinessAgentCategory ,
    PreAppAgentExists ,
    Replacement   ,
    ProviderCode    ,
    RecordSource
  )
  select  
    Policies.POL_NUM        ,
    Policies.ProductCode        ,
    Policies.PolicyRef        ,
    Policies.OriginatingSource      ,
    Policies.Pol_Type       ,
    Policies.Plan_Code        ,
    NULL            ,
    Policies.ServicingAgentCode     ,
    CAST(CONVERT(NVARCHAR, Policies.Prop_Date, 112) AS DATETIME)    ,
    CAST(CONVERT(NVARCHAR, Policies.Start_Date, 112) AS DATETIME)   ,
    CAST(CONVERT(NVARCHAR, Policies.CreateDate, 112) AS DATETIME)   ,
    CAST(CONVERT(NVARCHAR, coalesce(LatestPolTrans39.TransactionDate,Policies.Prop_Date,Policies.Start_Date,Policies.CreateDate), 112) AS DATETIME) ,
    Policies.SalesProcess       ,
    case
      when Policies.Plan_Code = 'MRTG' then 'MCOB' --Mortgage
      when Policies.Plan_Code in ('B&C','ASU') then 'ICOB-GI' --General Insurance
      when Policies.SalesProcess = 1 then 'ICOB-PP' --Simplified Sales process (JNP CR587)
                  else 'COB'
    END, -- ComplianceCategory
    null, -- CompetencyCode
    Agents.ID         ,
    Agents.Code         ,
    Agents.SpanSupervisorCode     ,
    Agents.Firm         ,
    Agents.CompetentStatus        ,
    Agents.AgentCategory        ,
    CodeBIProducts.DualSalesProcess     ,
    null, --PurchaseTypeID        ,
    null, --BusinessAgentType     ,
    null, --BusinessAgentCategory     ,
    null, -- PreAppAgentExists
    Policies.Replacement        ,
    Policies.COMP_CODE        ,
    '1'
  from  mstt_Policies Policies
    inner join #Grouppolstoprocess t1 on t1.pol_num = Policies.Pol_num
          LEFT JOIN mstt_PolicyTransactions LatestPolTrans39 ON LatestPolTrans39.PolicyID = Policies.Pol_Num
                         AND LatestPolTrans39.AdminMethod = 'A'
                         AND LatestPolTrans39.TransType = '39'
                         AND NOT EXISTS (SELECT ID
                                         FROM mstt_PolicyTransactions EarlierPolTrans
                                         WHERE EarlierPolTrans.PolicyID = LatestPolTrans39.PolicyID
                                           AND EarlierPolTrans.TransType = '39'
                                           AND EarlierPolTrans.TransactionNumber > LatestPolTrans39.TransactionNumber)
          LEFT JOIN mstt_Agents Agents ON LatestPolTrans39.AgentCode = Agents.CODE
          INNER JOIN mstt_CodeBIProducts CodeBIProducts ON CodeBIProducts.ProductCode = Policies.ProductCode --JNP CR587
    where Policies.Pol_Type = '205' -- Include Group Pensions only
end


create index rt2 on #PolDetails(BusinessCODE)
create index rt5 on #PolDetails(ServicingAgentCode)


if @debug=1 select 'Stage 2',getdate()


update  #PolDetails
set BusinessAgentType = Business.AgentType,
  BusinessAgentCategory = Business.AgentCategory
from  #PolDetails Policies
  inner JOIN mstt_Agents Business ON Policies.BusinessCODE = Business.Code 


if @debug=1 select 'Stage 3',getdate()

update  #PolDetails
set PurchaseTypeID = PolicyMortgage.PurchaseTypeID
from  #PolDetails Policies
  inner JOIN msit_PolicyMortgage PolicyMortgage ON Policies.Pol_Num = PolicyMortgage.PolicyID

/*
  remove the records we're not interested in
*/

if @debug=1 select 'Stage 4',getdate()

select distinct AgentsCode into #AgentCodes 
from #PolDetails 
order by AgentsCode

create table #PreAppAgents(
  CODE    varchar(7) collate LATIN1_GENERAL_CI_AS,
  ValidFromDate datetime,
  ValidToDate datetime
  )

create clustered index idxCode on #PreAppAgents(CODE)

insert #PreAppAgents(
  CODE,
  ValidFromDate,
  ValidToDate
  )
SELECT  CODE ,
  CAST(CONVERT(NVARCHAR, ValidFromDate, 112) AS DATETIME) ,
  CAST(CONVERT(NVARCHAR, ValidToDate, 112) AS DATETIME) 
FROM  mstt_AgentsHistory AgentsHistory
inner join #AgentCodes t1 on t1.AgentsCode = AgentsHistory.Code
WHERE   AgentsHistory.CompetentStatus = 5

if @debug=1 select 'Stage 5',getdate()


update  #PolDetails
set PreAppAgentExists = 1
from  #PolDetails Policies
  inner join #PreAppAgents on Policies.ServicingAgentCode = #PreAppAgents.CODE
where LicenceCheckDate between #PreAppAgents.ValidFromDate AND #PreAppAgents.ValidToDate

update  #PolDetails
set PreAppAgentExists = 0
WHERE PreAppAgentExists is null


if @debug=1 select 'Stage 6',getdate()

if @RptType = 'E'
begin
  update  #PolDetails
  set KeepRecord = 1
  where 
  (
    (BusinessAgentType IS NULL OR BusinessAgentType <> 49)
    and BusinessAgentCategory not like '%NASP%' -- Exclude NASP Sales
    and AgentCategory not like '%NASP%'   -- Exclude NASP Sales
    AND Pol_Type <> '205'       -- Exclude Group Pensions
    and
    ( OriginatingSource in (2,4) --1. Originating from ETi or OTPc MPC July 2007 -- MPC: SR8 
            OR DualSalesProcess = 'Y'  --2. Can be sold via COB or ICOB (JNP CR587)
            OR (OriginatingSource = 3  --3. Residential mortgages originating from CPT (JNP CR863) -- MPC: SR8 
               AND Pol_Type = '216'
               AND Plan_Code = 'MRTG'
               AND (PurchaseTypeID <> '2' OR PurchaseTypeID IS NULL)
         )
    )
  
    and
    (
      --For ETi & mortgage CPT cases, use Proposal date as 'Swift load date'
      (OriginatingSource in (2) AND Prop_Date between @dteStartDate and @dteEndDate)
          OR 
      --For non-ETi/CPT cases, use Create date as 'Swift load date'
      ((OriginatingSource not in (2) OR OriginatingSource IS NULL) AND CreateDate between @dteStartDate and @dteEndDate)
    )
    and
    (
      AgentsCompetentStatus  = 1 OR PreAppAgentExists = 1
           )--Adviser Active/Appointed or Pre-App Recruit chk for common cases
  )
end
else
begin
  update  #PolDetails
  set KeepRecord = 1
  where 
  (
    (BusinessAgentType IS NULL OR BusinessAgentType <> 49)
    and BusinessAgentCategory not like '%NASP%' -- Exclude NASP Sales
    and AgentCategory not like '%NASP%'   -- Exclude NASP Sales
    and 
    (
      Pol_Type = '205' --4) pension cases belonging to a group scheme
      AND EXISTS (SELECT ID
                     FROM mstt_PolicyTransactions PolicyTransactions 
                     WHERE PolicyTransactions.PolicyID = #PolDetails.Pol_Num
                       AND PolicyTransactions.AdminMethod = 'A') --4) pension cases belonging to a group scheme 
    )
    and 
    (
      --use Create date as 'Swift load date' for pensions belonging to a group scheme
      CreateDate between @dteStartDate and @dteEndDate
    )
    and 
    (
      AgentsCompetentStatus  = 1 OR PreAppAgentExists = 1
           )--Adviser Active/Appointed or Pre-App Recruit chk for common cases
  )
end

drop index #PolDetails.rt2 
drop index #PolDetails.rt5


delete  #PolDetails
where KeepRecord is null

create index rt1 on #PolDetails(AgentsCode)
create index rt4 on #PolDetails(AgentsID)

if @debug=1 select 'Stage 7',getdate()

select distinct AgentsID into #AgentsID 
from #PolDetails 
order by AgentsID

-- Get list of all licences with all combinations of clusters/sectors as appropriate
create table  #ProdLics(
  CodeLicenceID   int, 
  CodeLicenceCode   varchar(10),
  CodeClusterID   int, 
  CodeClusterSectorID int, 
  AgentLicenceID    int, 
  AgentID     int, 
  LicenceStartDate  datetime, 
  LicenceEndDate    datetime, 
  LicenceExpiryDate datetime, 
  AgentClusterID    int, 
  ClusterStartDate  datetime, 
  ClusterEndDate    datetime, 
  AgentSectorID   int, 
  SectorStartDate   datetime, 
  SectorEndDate   datetime
)

insert  #ProdLics(
  CodeLicenceID, 
  CodeLicenceCode,
  CodeClusterID, 
  CodeClusterSectorID, 
  AgentLicenceID, 
  AgentID, 
  LicenceStartDate, 
  LicenceEndDate, 
  LicenceExpiryDate, 
  AgentClusterID, 
  ClusterStartDate, 
  ClusterEndDate, 
  AgentSectorID, 
  SectorStartDate, 
  SectorEndDate
)
SELECT  msit_CodeLicence.ID                 CodeLicenceID, 
  msit_CodeLicence.Code               CodeLicenceCode,
  msit_CodeLicenceCluster.CodeClusterID, 
  msit_CodeCluster.CodeClusterSectorID, 
  mstt_AgentLicence.ID                AgentLicenceID, 
  mstt_AgentLicence.AgentID, 
  CAST(CONVERT(VARCHAR,mstt_AgentLicence.StartDate,112) AS DATETIME)    LicenceStartDate, 
  CAST(CONVERT(VARCHAR,mstt_AgentLicence.EndDate,112) AS DATETIME)    LicenceEndDate, 
  CAST(CONVERT(VARCHAR,mstt_AgentLicence.ExpiryDate,112) AS DATETIME)     LicenceExpiryDate, 
  mstt_AgentCluster.ID                AgentClusterID, 
  CAST(CONVERT(VARCHAR,mstt_AgentCluster.StartDate,112) AS DATETIME)    ClusterStartDate, 
  CAST(CONVERT(VARCHAR,mstt_AgentCluster.EndDate,112) AS DATETIME)    ClusterEndDate, 
  mstt_AgentSector.ID                 AgentSectorID, 
  CAST(CONVERT(VARCHAR,mstt_AgentSector.StartDate,112) AS DATETIME)     SectorStartDate, 
  CAST(CONVERT(VARCHAR,mstt_AgentSector.EndDate,112) AS DATETIME)     SectorEndDate
FROM  mstt_AgentLicence
  INNER Join #AgentsID t1 on t1.AgentsID = mstt_AgentLicence.AgentID
  INNER JOIN msit_CodeLicence ON msit_CodeLicence.ID = mstt_AgentLicence.CodeLicenceID 
  left outer JOIN msit_CodeLicenceCluster ON msit_CodeLicence.ID = msit_CodeLicenceCluster.CodeLicenceID 
  left outer JOIN msit_CodeCluster ON msit_CodeLicenceCluster.CodeClusterID = msit_CodeCluster.ID 
  left outer JOIN msit_CodeClusterSector ON msit_CodeCluster.CodeClusterSectorID = msit_CodeClusterSector.ID 
  left outer JOIN mstt_AgentCluster ON mstt_AgentLicence.AgentCode = mstt_AgentCluster.AgentCode 
          AND msit_CodeLicenceCluster.CodeClusterID = mstt_AgentCluster.CodeClusterID 
  left outer JOIN mstt_AgentSector ON mstt_AgentCluster.AgentCode = mstt_AgentSector.AgentCode 
          AND msit_CodeCluster.CodeClusterSectorID = mstt_AgentSector.CodeClusterSectorID


create clustered index rt1 on #ProdLics(AgentID,CodeLicenceID)


if @debug=1 select 'Stage 8',getdate()


      --========================================
      --Check if adviser has valid CCL licence
      --========================================

  --Valid
  update  #PolDetails
  set   CCLLicValidID = AgentLicence.ID,
    CCLLicValidStartDate = CAST(CONVERT(VARCHAR,AgentLicence.StartDate,112) AS DATETIME),
    CCLLicValidEndDate = CAST(CONVERT(VARCHAR,AgentLicence.EndDate,112) AS DATETIME),
    CCLLicValidExpiryDate = CAST(CONVERT(VARCHAR,AgentLicence.ExpiryDate,112) AS DATETIME)
  from  #PolDetails Policies
    inner join mstt_AgentLicence AgentLicence on Policies.AgentsID = AgentLicence.AgentID
  where AgentLicence.CodeLicenceID IN (SELECT CodeLicence.id FROM msit_CodeLicence CodeLicence WHERE CodeLicence.Code = 'QCCL')
    AND CAST(CONVERT(VARCHAR,AgentLicence.StartDate,112) AS DATETIME) <= LicenceCheckDate
    and (AgentLicence.EndDate IS NULL or CAST(CONVERT(VARCHAR,AgentLicence.EndDate,112) AS DATETIME) > LicenceCheckDate)
    AND (AgentLicence.ExpiryDate IS NULL or CAST(CONVERT(VARCHAR,AgentLicence.ExpiryDate,112) AS DATETIME) > LicenceCheckDate)

if @debug=1 select 'Stage 9',getdate()

  --Invalid (expired)
  update  #PolDetails
  set   CCLLicInvalidID = AgentLicence.ID,
    CCLLicInvalidStartDate = CAST(CONVERT(VARCHAR,AgentLicence.StartDate,112) AS DATETIME),
    CCLLicInvalidEndDate = CAST(CONVERT(VARCHAR,AgentLicence.EndDate,112) AS DATETIME),
    CCLLicInvalidExpiryDate = CAST(CONVERT(VARCHAR,AgentLicence.ExpiryDate,112) AS DATETIME),
    ReasonCCL = 'You do not have the appropriate licences (Ref CCL1)',
    LicCCL = 'CCL:' + CONVERT(VARCHAR, CAST(CONVERT(VARCHAR,AgentLicence.StartDate,112) AS DATETIME), 103) 
      + '-' + CONVERT(VARCHAR, CAST(CONVERT(VARCHAR,AgentLicence.ExpiryDate,112) AS DATETIME), 103)
  from  #PolDetails Policies
    inner join mstt_AgentLicence AgentLicence on Policies.AgentsID = AgentLicence.AgentID
  where Policies.CCLLicValidID is null
    and AgentLicence.CodeLicenceID IN (SELECT CodeLicence.id FROM msit_CodeLicence CodeLicence WHERE CodeLicence.Code = 'QCCL')
    AND CAST(CONVERT(VARCHAR,AgentLicence.StartDate,112) AS DATETIME) <= LicenceCheckDate
    and (AgentLicence.EndDate IS NULL or CAST(CONVERT(VARCHAR,AgentLicence.EndDate,112) AS DATETIME) > LicenceCheckDate)
    AND CAST(CONVERT(VARCHAR,AgentLicence.ExpiryDate,112) AS DATETIME) < LicenceCheckDate

if @debug=1 select 'Stage 10',getdate()

  --None at all
  update  #PolDetails
  set   ReasonCCL = 'You do not have the appropriate licences (Ref CCL1)',
    LicCCL = 'CCL:No Licence'
  where CCLLicValidID is null
    and CCLLicInvalidID is null

if @debug=1 select 'Stage 11',getdate()

-- Start of DPL and KBUS checks

      --========================================
      --Check if adviser has valid DPL licence
      --========================================

  --Valid
  update  #PolDetails
  set   DPLLicValidID = AgentLicence.ID,
    DPLLicValidStartDate = CAST(CONVERT(VARCHAR,AgentLicence.StartDate,112) AS DATETIME),
    DPLLicValidEndDate = CAST(CONVERT(VARCHAR,AgentLicence.EndDate,112) AS DATETIME),
    DPLLicValidExpiryDate = CAST(CONVERT(VARCHAR,AgentLicence.ExpiryDate,112) AS DATETIME)
  from  #PolDetails Policies
    inner join mstt_AgentLicence AgentLicence on Policies.AgentsID = AgentLicence.AgentID
  where AgentLicence.CodeLicenceID IN (SELECT CodeLicence.id FROM msit_CodeLicence CodeLicence WHERE CodeLicence.Code = 'QDPL')
    AND CAST(CONVERT(VARCHAR,AgentLicence.StartDate,112) AS DATETIME) <= LicenceCheckDate
    and (AgentLicence.EndDate IS NULL or CAST(CONVERT(VARCHAR,AgentLicence.EndDate,112) AS DATETIME) > LicenceCheckDate)
    AND (AgentLicence.ExpiryDate IS NULL or CAST(CONVERT(VARCHAR,AgentLicence.ExpiryDate,112) AS DATETIME) > LicenceCheckDate)
    and @RptType = 'E'

if @debug=1 select 'Stage 9a',getdate()

  --Invalid (expired)
  update  #PolDetails
  set   DPLLicInvalidID = AgentLicence.ID,
    DPLLicInvalidStartDate = CAST(CONVERT(VARCHAR,AgentLicence.StartDate,112) AS DATETIME),
    DPLLicInvalidEndDate = CAST(CONVERT(VARCHAR,AgentLicence.EndDate,112) AS DATETIME),
    DPLLicInvalidExpiryDate = CAST(CONVERT(VARCHAR,AgentLicence.ExpiryDate,112) AS DATETIME),
    ReasonDPL = 'You do not have the appropriate licences (Ref QDPL)',
    LicDPL = 'QDPL:' + CONVERT(VARCHAR, CAST(CONVERT(VARCHAR,AgentLicence.StartDate,112) AS DATETIME), 103) 
      + '-' + CONVERT(VARCHAR, CAST(CONVERT(VARCHAR,AgentLicence.ExpiryDate,112) AS DATETIME), 103)
  from  #PolDetails Policies
    inner join mstt_AgentLicence AgentLicence on Policies.AgentsID = AgentLicence.AgentID
  where Policies.DPLLicValidID is null
    and AgentLicence.CodeLicenceID IN (SELECT CodeLicence.id FROM msit_CodeLicence CodeLicence WHERE CodeLicence.Code = 'QDPL')
    AND CAST(CONVERT(VARCHAR,AgentLicence.StartDate,112) AS DATETIME) <= LicenceCheckDate
    and (AgentLicence.EndDate IS NULL or CAST(CONVERT(VARCHAR,AgentLicence.EndDate,112) AS DATETIME) > LicenceCheckDate)
    AND CAST(CONVERT(VARCHAR,AgentLicence.ExpiryDate,112) AS DATETIME) < LicenceCheckDate
    and @RptType = 'E'

if @debug=1 select 'Stage 10a',getdate()

  --None at all
  update  #PolDetails
  set   ReasonDPL = 'You do not have the appropriate licences (Ref QDPL)',
    LicDPL = 'QDPL:No Licence'
  where DPLLicValidID is null
    and DPLLicInvalidID is null
    and @RptType = 'E'

if @debug=1 select 'Stage 11a',getdate()

      --================================================================
      --Check if adviser has valid KBUS licence if BAIT or BALOAB policy
      --================================================================

  --Valid
  update  #PolDetails
  set   KBUSLicValidID = AgentLicence.ID,
    KBUSLicValidStartDate = CAST(CONVERT(VARCHAR,AgentLicence.StartDate,112) AS DATETIME),
    KBUSLicValidEndDate = CAST(CONVERT(VARCHAR,AgentLicence.EndDate,112) AS DATETIME),
    KBUSLicValidExpiryDate = CAST(CONVERT(VARCHAR,AgentLicence.ExpiryDate,112) AS DATETIME)
  from  #PolDetails Policies
    inner join mstt_AgentLicence AgentLicence on Policies.AgentsID = AgentLicence.AgentID
  where AgentLicence.CodeLicenceID IN (SELECT CodeLicence.id FROM msit_CodeLicence CodeLicence WHERE CodeLicence.Code = 'KBUS')
    AND CAST(CONVERT(VARCHAR,AgentLicence.StartDate,112) AS DATETIME) <= LicenceCheckDate
    and (AgentLicence.EndDate IS NULL or CAST(CONVERT(VARCHAR,AgentLicence.EndDate,112) AS DATETIME) > LicenceCheckDate)
    AND (AgentLicence.ExpiryDate IS NULL or CAST(CONVERT(VARCHAR,AgentLicence.ExpiryDate,112) AS DATETIME) > LicenceCheckDate)
    AND Policies.PolicyCategoryCode in ('BAIT','BALOAB')
    and @RptType = 'E'

if @debug=1 select 'Stage 9b',getdate()

  --Invalid (expired)
  update  #PolDetails
  set   KBUSLicInvalidID = AgentLicence.ID,
    KBUSLicInvalidStartDate = CAST(CONVERT(VARCHAR,AgentLicence.StartDate,112) AS DATETIME),
    KBUSLicInvalidEndDate = CAST(CONVERT(VARCHAR,AgentLicence.EndDate,112) AS DATETIME),
    KBUSLicInvalidExpiryDate = CAST(CONVERT(VARCHAR,AgentLicence.ExpiryDate,112) AS DATETIME),
    ReasonKBUS = 'You do not have the appropriate licences (Ref KBUS)',
    LicKBUS = 'KBUS:' + CONVERT(VARCHAR, CAST(CONVERT(VARCHAR,AgentLicence.StartDate,112) AS DATETIME), 103) 
      + '-' + CONVERT(VARCHAR, CAST(CONVERT(VARCHAR,AgentLicence.ExpiryDate,112) AS DATETIME), 103)
  from  #PolDetails Policies
    inner join mstt_AgentLicence AgentLicence on Policies.AgentsID = AgentLicence.AgentID
  where Policies.KBUSLicValidID is null
    and AgentLicence.CodeLicenceID IN (SELECT CodeLicence.id FROM msit_CodeLicence CodeLicence WHERE CodeLicence.Code = 'KBUS')
    AND CAST(CONVERT(VARCHAR,AgentLicence.StartDate,112) AS DATETIME) <= LicenceCheckDate
    and (AgentLicence.EndDate IS NULL or CAST(CONVERT(VARCHAR,AgentLicence.EndDate,112) AS DATETIME) > LicenceCheckDate)
    AND CAST(CONVERT(VARCHAR,AgentLicence.ExpiryDate,112) AS DATETIME) < LicenceCheckDate
    AND Policies.PolicyCategoryCode in ('BAIT','BALOAB')
    and @RptType = 'E'

if @debug=1 select 'Stage 10b',getdate()

  --None at all
  update  #PolDetails
  set   ReasonKBUS = 'You do not have the appropriate licences (Ref KBUS)',
    LicKBUS = 'KBUS: No Licence'
  where KBUSLicValidID is null
    and KBUSLicInvalidID is null
    AND PolicyCategoryCode in ('BAIT','BALOAB')
    and @RptType = 'E'

if @debug=1 select 'Stage 11b',getdate()

-- End of DPL and KBUS checks

     --==================================================================================================
      --Adviser has a valid CCL, DPL and KBUS Licence. Now Check for other licences.
      --Find out if the adviser has a valid competence in the relevant compliance category for the plan
      --==================================================================================================
/*  update  #PolDetails
  set   CompetencyCode = AgentCompetence.AgentControlFunctionCode
  from  #PolDetails Policies
    inner join mstt_AgentCompetence AgentCompetence on Policies.AgentsID = AgentCompetence.AgentID 
      and AgentCompetence.ComplianceCategoryCode = Policies.ComplianceCategory
  where 
          (CAST(CONVERT(VARCHAR,AgentCompetence.AchievedDate,112) AS DATETIME) <= Policies.LicenceCheckDate)
          AND (AgentCompetence.EndDate IS NULL OR CAST(CONVERT(VARCHAR,AgentCompetence.EndDate,112) AS DATETIME) > Policies.LicenceCheckDate)
*/

  update  #PolDetails
  set   Competent = 1
  from  #PolDetails Policies
    inner join mstt_AgentCompetence AgentCompetence on Policies.AgentsID = AgentCompetence.AgentID 
      and AgentCompetence.ComplianceCategoryCode = Policies.ComplianceCategory
  where -- not 
    (
      (AgentCompetence.AgentControlFunctionCode IS NOT NULL) 
      AND 
      (
        (
          (AgentCompetence.AgentControlFunctionCode = 'S1' Or AgentCompetence.AgentControlFunctionCode = 'IC' Or AgentCompetence.AgentControlFunctionCode = 'FC') 
          And 
          (Policies.ComplianceCategory = 'COB' Or Policies.ComplianceCategory = 'MCOB')
        )
      Or 
        (
          (AgentCompetence.AgentControlFunctionCode = 'IC' Or AgentCompetence.AgentControlFunctionCode = 'FC') 
          And 
          (Policies.ComplianceCategory = 'ICOB-PP' Or Policies.ComplianceCategory = 'ICOB-GI')
        )
      )
    )
          and (CAST(CONVERT(VARCHAR,AgentCompetence.AchievedDate,112) AS DATETIME) <= Policies.LicenceCheckDate)
          AND (AgentCompetence.EndDate IS NULL OR CAST(CONVERT(VARCHAR,AgentCompetence.EndDate,112) AS DATETIME) > Policies.LicenceCheckDate)

if @debug=1 select 'Stage 12',getdate()


  update  #PolDetails
  set ReasonCompetent = 'Adviser does not have a valid competency',
    LicCompetent = ComplianceCategory + ':Invalid Competence'
  where   Competent is null

if @debug=1 select 'Stage 13',getdate()


      --=========================================================
      --Adviser is competent in the relevant compliance category
      --Find out if this product has a licence
      --=========================================================

          --No licence exists for this product so we assume that it's an old product and the
          --licence was never loaded onto Swift and therefore passes the licence check
          --This record is not displayed
  update  #PolDetails
  set LicProdOld = 1
  where not exists (select * from msit_CodeProductLicence where CodeProductsCode = #PolDetails.ProductCode)


