      + ISNULL(LicProd + '. ', '') 
      + ISNULL(LicIHT + '. ', '') 
      + ISNULL(LicReplace + '.', '')
    , Reason = ISNULL(ReasonCCL + '. ', '') 
       + ISNULL(ReasonDPL + '. ', '')
       + ISNULL(ReasonKBUS + '. ', '')
