if @debug=1 select 'Stage 29',getdate()


   --========================================================================
   --Policies from a PreAppointed Adviser (excluding Pre-App ETi/CPT Sales )
   --insert them into temp table 
   --========================================================================

-- only if it's the Eti report
if @RptType = 'E'
begin
insert #PolDetails(
  POL_NUM     ,
  ProductCode   ,
  PolicyRef   ,
  OriginatingSource ,
  Pol_Type    ,
  Plan_Code   ,
  ServicingAgentCode  ,
  Prop_Date   ,
  Start_Date    ,
  CreateDate    ,
  LicenceCheckDate  ,
  SalesProcess    ,
  ComplianceCategory  ,
  CompetencyCode    ,
  AgentsID    ,
  AgentsCODE    ,
  SupvisrCODE   ,
  BusinessCODE    ,
  AgentsCompetentStatus ,
  AgentCategory   ,
  DualSalesProcess  ,
  PurchaseTypeID    ,
  BusinessAgentType ,
  BusinessAgentCategory   ,
  PreAppAgentExists ,
  Replacement   ,
  ProviderCode    ,
  LicenseStatus   ,
  RecordSource
)
select  
  Policies.POL_NUM        ,
  Policies.ProductCode        ,
  Policies.PolicyRef        ,
  Policies.OriginatingSource      ,
  Policies.Pol_Type       ,
  Policies.Plan_Code        ,
  Policies.ServicingAgentCode     ,
  CAST(CONVERT(NVARCHAR, Policies.Prop_Date, 112) AS DATETIME)    ,
  CAST(CONVERT(NVARCHAR, Policies.Start_Date, 112) AS DATETIME)   ,
  CAST(CONVERT(NVARCHAR, Policies.CreateDate, 112) AS DATETIME)   ,
        CASE
           WHEN Policies.OriginatingSource = 2 
       THEN CAST(CONVERT(NVARCHAR, coalesce(Policies.Prop_Date,Policies.Start_Date,Policies.CreateDate,getdate()), 112) AS DATETIME) --Proposal date (this is 'licence check date' for ETi cases)
           WHEN Policies.OriginatingSource = 3  -- MPC: SR8  
             THEN CAST(CONVERT(NVARCHAR, coalesce(Policies.Prop_Date,Policies.Start_Date,Policies.CreateDate,getdate()), 112) AS DATETIME) --Proposal date (this is 'licence check date' for CPT mortgage cases) - JNP CR863
           WHEN Policies.OriginatingSource = 4  -- MPC: SR8  
             THEN CAST(CONVERT(NVARCHAR, coalesce(Policies.Prop_Date,Policies.Start_Date,Policies.CreateDate,getdate()), 112) AS DATETIME) --Proposal date (this is 'licence check date' for OTPc cases)  MPC July 2007
           ELSE CAST(CONVERT(NVARCHAR, coalesce(Policies.Start_Date,Policies.Prop_Date,Policies.CreateDate,getdate()), 112) AS DATETIME) --Start date (this is 'licence check date' for non-ETi/CPT cases)
        END,
  Policies.SalesProcess       ,
  case
    when Policies.Plan_Code = 'MRTG' then 'MCOB' --Mortgage
    when Policies.Plan_Code in ('B&C','ASU') then 'ICOB-GI' --General Insurance
    when Policies.SalesProcess = 1 then 'ICOB-PP' --Simplified Sales process (JNP CR587)
                else 'COB'
  END, -- ComplianceCategory
  null, -- CompetencyCode
  Agents.ID         ,
  Agents.Code         ,
  Agents.SpanSupervisorCode     ,
  Agents.Firm         ,
  Agents.CompetentStatus        ,
  Agents.AgentCategory        ,
  null,--CodeBIProducts.DualSalesProcess    ,
  null, --PurchaseTypeID        ,
  null, --BusinessAgentType     ,
  null, --BusinessAgentCategory       ,
  null, -- PreAppAgentExists
  Policies.Replacement        ,
  Policies.COMP_CODE        ,
  '', -- LicenceStatus
  '2' -- RecordSource for debugging

   FROM mstt_Policies Policies 
       inner join #Etipolstoprocess t1 on t1.pol_num = Policies.Pol_num
       INNER JOIN mstt_Agents Agents ON Policies.ServicingAgentCode = Agents.CODE
       LEFT OUTER JOIN mstt_Agents Supvisr ON Agents.SpanSupervisorCode = Supvisr.CODE --SpanSupervisorCode
       LEFT JOIN mstt_Agents AS Business ON Agents.Firm = Business.Code
 
  WHERE EXISTS(SELECT CODE FROM mstt_AgentsHistory AgentsHistory
                 WHERE AgentsHistory.CompetentStatus = 5
                 AND AgentsHistory.CODE = Policies.ServicingAgentCode
                 AND (Policies.OriginatingSource IN (2,3,4) --For ETi, OTPc & Mortgage CPT cases, use Proposal date as 'licence check date' -- MPC: SR8 
                      AND CAST(CONVERT(NVARCHAR, Policies.Prop_Date, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, AgentsHistory.ValidFromDate, 112) AS DATETIME) 
                      AND CAST(CONVERT(NVARCHAR, Policies.Prop_Date, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, AgentsHistory.ValidToDate, 112) AS DATETIME) 
                  OR (Policies.OriginatingSource NOT IN (2,3,4) OR Policies.OriginatingSource IS NULL) --For non-ETi/OTPc/CPT cases, use Start date as 'licence check date' -- MPC: SR8 
                      AND CAST(CONVERT(NVARCHAR, Policies.Start_Date, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, AgentsHistory.ValidFromDate, 112) AS DATETIME) 
                      AND CAST(CONVERT(NVARCHAR, Policies.Start_Date, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, AgentsHistory.ValidToDate, 112) AS DATETIME))
               ) --Adviser is Pre-App 
   AND (Policies.OriginatingSource IN (2) --For ETi & Mortgage CPT cases, use Proposal date as 'Swift load date'
        AND CAST(CONVERT(NVARCHAR, Policies.Prop_Date, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME) 
        AND CAST(CONVERT(NVARCHAR, Policies.Prop_Date, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME) 
    OR (Policies.OriginatingSource NOT IN (2) OR Policies.OriginatingSource IS NULL) --For non-ETi/CPT cases, use Create date as 'Swift load date'
        AND CAST(CONVERT(NVARCHAR, Policies.CreateDate, 112) AS DATETIME) >= CAST(CONVERT(NVARCHAR, @StartDate, 112) AS DATETIME) 
        AND CAST(CONVERT(NVARCHAR, Policies.CreateDate, 112) AS DATETIME) <= CAST(CONVERT(NVARCHAR, @EndDate, 112) AS DATETIME))
   AND Policies.POL_NUM NOT IN (SELECT POL_NUM from #PolDetails) --Exclude Pre-App ETi/CPT sales records
   AND (Business.AgentType IS NULL OR Business.AgentType <> 49) -- exclude directly authorised
   AND Business.AgentCategory not like '%NASP%'     -- Exclude NASP Sales
   AND Agents.AgentCategory not like '%NASP%'     -- Exclude NASP Sales
end


if @debug=1 select 'Stage 30',getdate()


  -- get some extra bits of info

  update  #PolDetails
  set ProviderName = isnull(ProductProviders.ProductProviderName,'')
  from  #PolDetails
    left outer join mstt_ProductProviders ProductProviders ON #PolDetails.ProviderCode = ProductProviders.ProductProviderCode

  -- agents and supervisors name
  update  #PolDetails
  set AgentName = ISNULL(RTRIM(SUBSTRING(Agents.Firstnames, 1, PATINDEX('%[^ ] %', Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name), '')
  from  #PolDetails
    left outer join mstt_Agents Agents ON #PolDetails.AgentsCODE = Agents.CODE

  update  #PolDetails
  set AgentSupervisor = ISNULL(RTRIM(SUBSTRING(Supvisr.Firstnames, 1, PATINDEX('%[^ ] %', Supvisr.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Supvisr.Name), '')
  from  #PolDetails
    left outer join mstt_Agents Supvisr ON #PolDetails.SupvisrCODE = Supvisr.CODE 

  -- agent status
  update  #PolDetails
  set AgentStatus = 'Pre-App Recruit'
  from  #PolDetails
    inner join #PreAppAgents on #PolDetails.ServicingAgentCode = #PreAppAgents.CODE
          and #PolDetails.LicenceCheckDate between #PreAppAgents.ValidFromDate AND #PreAppAgents.ValidToDate

  update  #PolDetails
  set AgentStatus = 'Appointed'
  where AgentStatus is null

if @debug=1 select 'Stage 31',getdate()


  -- competencies

     UPDATE #PolDetails
     SET  COBCompetency = (SELECT TOP 1 COBCompetence.AgentControlFunctionDescn
                           FROM mstt_AgentCompetence COBCompetence
                           WHERE PolDetails.AgentsCODE = COBCompetence.AgentCode
                             AND COBCompetence.ComplianceCategoryCode = 'COB'
                             AND COBCompetence.EndDate IS NULL
                           ORDER BY COBCompetence.DateAppointed DESC) -- the latest null-end-dated COB record
        , ICOBPPCompetency = (SELECT TOP 1 ICOBPPCompetence.AgentControlFunctionDescn
                           FROM mstt_AgentCompetence ICOBPPCompetence
                           WHERE PolDetails.AgentsCODE = ICOBPPCompetence.AgentCode
                             AND ICOBPPCompetence.ComplianceCategoryCode = 'ICOB-PP'
                             AND ICOBPPCompetence.EndDate IS NULL
                           ORDER BY ICOBPPCompetence.DateAppointed DESC) -- the latest null-end-dated ICOB-PP record
     FROM #PolDetails PolDetails

if @debug=1 select 'Stage 32',getdate()


  -- last one is split sales
  create table #SplitSales(
    POL_NUM   int,
    AgentCode varchar(7),
    AgentName varchar(700)
    )
  CREATE CLUSTERED INDEX RT1 ON #SplitSales(POL_NUM)

  insert  #SplitSales(
    POL_NUM,
    AgentCode,
    AgentName)
  select  distinct
    Commissions.PolicyId,
    Agents.CODE,
    ISNULL(RTRIM(SUBSTRING(Agents.Firstnames, 1, PATINDEX('%[^ ] %', Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name), '')
  from  #PolDetails
    inner join mstt_Commissions Commissions on #PolDetails.POL_NUM = Commissions.PolicyId
    inner join mstt_Agents Agents ON Commissions.AGENT_CODE = Agents.CODE
  where Commissions.AGENT_CODE <> #PolDetails.AgentsCode  --Exclude the selling agent himself
    and Commissions.AGENT_CODE <> '10002'     --Exclude all Openwork Margins
    and Commissions.CommissionType = 1      --Exclude RC/Trail Splits
    
if @debug=1 select 'Stage 33',getdate()


  while exists (select * from #SplitSales)
  begin
    UPDATE  #PolDetails
    set SplitSale = coalesce(SplitSale,'') + ' - ' + (CASE WHEN (#SplitSales.AgentName = '') THEN 'Unknown' ELSE #SplitSales.AgentName END)
                             + '(' + ISNULL(#SplitSales.AgentCode,'') + ')'
    from  #PolDetails PolDetails
      inner join #SplitSales on PolDetails.POL_NUM = #SplitSales.POL_NUM
      inner join 
      (
      select  POL_NUM,
        min(AgentCode) MinAgentCode
      FROM  #SplitSales
      group by POL_NUM
      ) FirstAgent on #SplitSales.POL_NUM = FirstAgent.POL_NUM and #SplitSales.AgentCode = FirstAgent.MinAgentCode
    
    -- delete earliest AgentCode for each POL_NUM as its been used
    delete  #SplitSales
    from  #SplitSales 
      inner join 
      (
      select  POL_NUM,
        min(AgentCode) MinAgentCode
      FROM  #SplitSales
      group by POL_NUM
      ) FirstAgent on #SplitSales.POL_NUM = FirstAgent.POL_NUM and #SplitSales.AgentCode = FirstAgent.MinAgentCode
    
  end

if @debug=1 select 'Stage 34',getdate()

  update  #PolDetails
  set SplitSale = case when SplitSale is null then 'N' else 'Y ' + SplitSale end


if @debug=1 select 'Stage 35',getdate()

  -- just copying ineffectual error handling from earlier version
   SELECT @Severity = @@ERROR

   SELECT 
        AgentName 
      , AgentsCode AgentCode 
      , AgentSupervisor 
      , ProductCode PlanType 
      , AgentStatus 
      , CONVERT(VARCHAR, LicenceCheckDate, 103) AS [LicenceCheckDate]
      , PolicyRef CaseID 
      , CASE OriginatingSource   
--           WHEN 0 THEN 'Manual' -- MPC: SR8 
     When 1 then 'Manual' -- MPC: SR8 
     WHEN 2 THEN 'ETi' 
     When 3 then 'OTPm' -- MPC: SR8 
     When 4 then 'OTPc' -- MPC: SR8 
--     WHEN 2 THEN 'ETr'  -- MPC: SR8 
--           WHEN 3 THEN 'MBL'  -- MPC: SR8 
--           WHEN 4 THEN 'Trigold' -- MPC: SR8 
--           WHEN 5 THEN 'CPT'  -- JNP CR863 -- MPC: SR8 
--     WHEN 6 THEN 'OTPc'   -- MPC July 2007
           ELSE 'Unknown'
        END AS [Source]
      , SplitSale 
      , LicenseStatus 
      , ProviderName ProductProvider 
      , COBCompetency
      , ICOBPPCompetency
      , NULL AS Error
   FROM #PolDetails
   WHERE CAST(CONVERT(NVARCHAR, LicenceCheckDate, 112) AS DATETIME) between @dteStartDate and @dteEndDate
   ORDER BY AgentName, AgentsCode, PolicyRef

if @debug=1 select 'Stage 36',getdate()


   RETURN @Severity



GO
/****** Object:  StoredProcedure [dbo].[owp_UnlicencedSwitchSales]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO


CREATE procedure [dbo].[owp_UnlicencedSwitchSales]
as

/*
  KK January 2008
  One-off scan to identify all Switches sold without a license
*/

set nocount on

declare @debug int
select @debug = 0

if @debug=1 select 'Stage 1',getdate()

select pol_num into #SwitchPolsToProcess 
from mstt_policies 
where ppswitch = -1 and (productcode = 'FPP' or productcode = 'INDPP' or productcode = 'INDSTK' or productcode = 'LPRP' or productcode = 'PPXFR')

create table #PolDetails 
  (
        POL_NUM     int,
        KeepRecord    int,
        ProductCode   varchar(8) collate LATIN1_GENERAL_CI_AS,
        PolicyRef   int,
        ServicingAgentCode  varchar(7) collate LATIN1_GENERAL_CI_AS,
        Prop_Date   datetime,
        Start_Date    datetime,
        CreateDate    datetime,
  LicenceCheckDate  datetime,
  ComplianceCategory  varchar(10) collate LATIN1_GENERAL_CI_AS,
  CompetencyCode    varchar(8) collate LATIN1_GENERAL_CI_AS,
  AgentsID    int,
  AgentsCODE    varchar(7) collate LATIN1_GENERAL_CI_AS,
  SupvisrCODE   varchar(7) collate LATIN1_GENERAL_CI_AS,
  BusinessCODE    varchar(7) collate LATIN1_GENERAL_CI_AS,
  BusinessAgentType tinyint,
  BusinessAgentCategory   varchar(8),
  AgentCategory       varchar(8),
  ProviderCode    varchar(10)  collate LATIN1_GENERAL_CI_AS,
  ProviderName    varchar(100),
  AgentName   varchar(155),
  AgentSupervisor   varchar(155),
  SplitSale   varchar(2000),
  RecordSource    varchar(1)

  , ProdLicValidID    int
  , ProdLicValidStartDate   datetime
  , ProdLicValidEndDate   datetime
  , ProdLicValidExpiryDate  datetime

  )

create clustered index idxPol_Num on #PolDetails(POL_NUM)


  insert #PolDetails(
    POL_NUM     ,
    ProductCode   ,
    PolicyRef   ,
    ServicingAgentCode  ,
    Prop_Date   ,
    Start_Date    ,
    CreateDate    ,
    LicenceCheckDate  ,
    ComplianceCategory  ,
    AgentsID    ,
    AgentsCODE    ,
    SupvisrCODE   ,
    BusinessCODE    ,
    AgentCategory   ,
    BusinessAgentType ,
    BusinessAgentCategory ,
    ProviderCode    ,
    RecordSource
  )
  select  
    Policies.POL_NUM        ,
    Policies.ProductCode        ,
    Policies.PolicyRef        ,
    Policies.ServicingAgentCode     ,
    CAST(CONVERT(NVARCHAR, Policies.Prop_Date, 112) AS DATETIME)    ,
    CAST(CONVERT(NVARCHAR, Policies.Start_Date, 112) AS DATETIME)   ,
    CAST(CONVERT(NVARCHAR, Policies.CreateDate, 112) AS DATETIME)   ,
          CASE
             WHEN Policies.OriginatingSource = 2 
         THEN CAST(CONVERT(NVARCHAR, coalesce(Policies.Prop_Date,Policies.Start_Date,Policies.CreateDate,getdate()), 112) AS DATETIME) --Proposal date (this is 'licence check date' for ETi cases)
             WHEN Policies.OriginatingSource = 3    -- MPC: SR8 
                     THEN CAST(CONVERT(NVARCHAR, coalesce(Policies.Prop_Date,Policies.Start_Date,Policies.CreateDate,getdate()), 112) AS DATETIME) --Proposal date (this is 'licence check date' for CPT mortgage cases) - JNP CR863
             WHEN Policies.OriginatingSource = 4    -- MPC: SR8 
                     THEN CAST(CONVERT(NVARCHAR, coalesce(Policies.Prop_Date,Policies.Start_Date,Policies.CreateDate,getdate()), 112) AS DATETIME) --Proposal date (this is 'licence check date' for OTPc cases)  MPC July 2007
             ELSE CAST(CONVERT(NVARCHAR, coalesce(Policies.Start_Date,Policies.Prop_Date,Policies.CreateDate,getdate()), 112) AS DATETIME) --Start date (this is 'licence check date' for non-ETi/CPT cases)
          END,
    case
      when Policies.Plan_Code = 'MRTG' then 'MCOB' --Mortgage
      when Policies.Plan_Code in ('B&C','ASU') then 'ICOB-GI' --General Insurance
      when Policies.SalesProcess = 1 then 'ICOB-PP' --Simplified Sales process (JNP CR587)
                  else 'COB'
    END, -- ComplianceCategory
    Agents.ID         ,
    Agents.Code         ,
    Agents.SpanSupervisorCode     ,
    Agents.Firm         ,
    Agents.AgentCategory        ,
    null, --BusinessAgentType     ,
    null, --BusinessAgentCategory     ,
    Policies.COMP_CODE        ,
    '1'
  from  mstt_Policies Policies
    inner join #Switchpolstoprocess t1 on t1.pol_num = Policies.Pol_num
    inner join msit_S_POLMAI on msit_S_POLMAI.POL_NUM = Policies.POL_NUM
    inner join mstt_Agents Agents ON Policies.ServicingAgentCode = Agents.CODE
    where Policies.Pol_Type <> '205'  -- Exclude Group Pensions


create index rt2 on #PolDetails(BusinessCODE)
create index rt5 on #PolDetails(ServicingAgentCode)


if @debug=1 select 'Stage 2',getdate()


update  #PolDetails
set BusinessAgentType = Business.AgentType,
  BusinessAgentCategory = Business.AgentCategory
from  #PolDetails Policies
  inner JOIN mstt_Agents Business ON Policies.BusinessCODE = Business.Code 


if @debug=1 select 'Stage 3',getdate()

  update  #PolDetails
  set KeepRecord = 1
  where 
  (
    (BusinessAgentType IS NULL OR BusinessAgentType <> 49)
    and BusinessAgentCategory not like '%NASP%' -- Exclude NASP Sales
    and AgentCategory not like '%NASP%'   -- Exclude NASP Sales
  )

drop index #PolDetails.rt2 
drop index #PolDetails.rt5


delete  #PolDetails
where KeepRecord is null

create index rt1 on #PolDetails(AgentsCode)
create index rt4 on #PolDetails(AgentsID)

if @debug=1 select 'Stage 4',getdate()

select distinct AgentsID into #AgentsID 
from #PolDetails 
order by AgentsID

-- Get list of all licences with all combinations of clusters/sectors as appropriate
create table  #ProdLics(
  CodeLicenceID   int, 
  CodeLicenceCode   varchar(10),
  AgentLicenceID    int, 
  AgentID     int, 
  LicenceStartDate  datetime, 
  LicenceEndDate    datetime, 
  LicenceExpiryDate datetime 
)

insert  #ProdLics(
  CodeLicenceID, 
  CodeLicenceCode,
  AgentLicenceID, 
  AgentID, 
  LicenceStartDate, 
  LicenceEndDate, 
  LicenceExpiryDate 
)
SELECT  msit_CodeLicence.ID                 CodeLicenceID, 
  msit_CodeLicence.Code               CodeLicenceCode,
  mstt_AgentLicence.ID                AgentLicenceID, 
  mstt_AgentLicence.AgentID, 
  CAST(CONVERT(VARCHAR,mstt_AgentLicence.StartDate,112) AS DATETIME)    LicenceStartDate, 
  CAST(CONVERT(VARCHAR,mstt_AgentLicence.EndDate,112) AS DATETIME)    LicenceEndDate, 
  CAST(CONVERT(VARCHAR,mstt_AgentLicence.ExpiryDate,112) AS DATETIME)     LicenceExpiryDate 
FROM  mstt_AgentLicence
  INNER Join #AgentsID t1 on t1.AgentsID = mstt_AgentLicence.AgentID
  INNER JOIN msit_CodeLicence ON msit_CodeLicence.ID = mstt_AgentLicence.CodeLicenceID
WHERE   msit_CodeLicence.Code = 'ESTH' 


create clustered index rt1 on #ProdLics(AgentID,CodeLicenceID)


if @debug=1 select 'Stage 5',getdate()

  -- Valid Licence no clusters needed
  update  #PolDetails
  set   ProdLicValidID = #ProdLics.AgentLicenceID,
    ProdLicValidStartDate = #ProdLics.LicenceStartDate,
    ProdLicValidEndDate = #ProdLics.LicenceEndDate,
    ProdLicValidExpiryDate = #ProdLics.LicenceExpiryDate
  from  #PolDetails Policies
    inner join #ProdLics on Policies.AgentsID = #ProdLics.AgentID


if @debug=1 select 'Stage 6',getdate()

  delete  #PolDetails
  where ProdLicValidID is not null


if @debug=1 select 'Stage 7',getdate()

  -- agents and supervisors name
  update  #PolDetails
  set AgentName = ISNULL(RTRIM(SUBSTRING(Agents.Firstnames, 1, PATINDEX('%[^ ] %', Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name), '')
  from  #PolDetails
    left outer join mstt_Agents Agents ON #PolDetails.AgentsCODE = Agents.CODE

  update  #PolDetails
  set AgentSupervisor = ISNULL(RTRIM(SUBSTRING(Supvisr.Firstnames, 1, PATINDEX('%[^ ] %', Supvisr.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Supvisr.Name), '')
  from  #PolDetails
    left outer join mstt_Agents Supvisr ON #PolDetails.SupvisrCODE = Supvisr.CODE 

if @debug=1 select 'Stage 8',getdate()


  -- last one is split sales
  create table #SplitSales(
    POL_NUM   int,
    AgentCode varchar(7),
    AgentName varchar(700)
    )
  CREATE CLUSTERED INDEX RT1 ON #SplitSales(POL_NUM)

  insert  #SplitSales(
    POL_NUM,
    AgentCode,
    AgentName)
  select  distinct
    Commissions.PolicyId,
    Agents.CODE,
    ISNULL(RTRIM(SUBSTRING(Agents.Firstnames, 1, PATINDEX('%[^ ] %', Agents.Firstnames + ' '))) + ' ', '') + ISNULL(RTRIM(Agents.Name), '')
  from  #PolDetails
    inner join mstt_Commissions Commissions on #PolDetails.POL_NUM = Commissions.PolicyId
    inner join mstt_Agents Agents ON Commissions.AGENT_CODE = Agents.CODE
  where Commissions.AGENT_CODE <> #PolDetails.AgentsCode  --Exclude the selling agent himself
    and Commissions.AGENT_CODE <> '10002'     --Exclude all Openwork Margins
    and Commissions.CommissionType = 1      --Exclude RC/Trail Splits
    
if @debug=1 select 'Stage 9',getdate()


  while exists (select * from #SplitSales)
  begin
    UPDATE  #PolDetails
    set SplitSale = coalesce(SplitSale,'') + ' - ' + (CASE WHEN (#SplitSales.AgentName = '') THEN 'Unknown' ELSE #SplitSales.AgentName END)
                             + '(' + ISNULL(#SplitSales.AgentCode,'') + ')'
    from  #PolDetails PolDetails
      inner join #SplitSales on PolDetails.POL_NUM = #SplitSales.POL_NUM
      inner join 
      (
      select  POL_NUM,
        min(AgentCode) MinAgentCode
      FROM  #SplitSales
      group by POL_NUM
      ) FirstAgent on #SplitSales.POL_NUM = FirstAgent.POL_NUM and #SplitSales.AgentCode = FirstAgent.MinAgentCode
    
    -- delete earliest AgentCode for each POL_NUM as its been used
    delete  #SplitSales
    from  #SplitSales 
      inner join 
      (
      select  POL_NUM,
        min(AgentCode) MinAgentCode
      FROM  #SplitSales
      group by POL_NUM
      ) FirstAgent on #SplitSales.POL_NUM = FirstAgent.POL_NUM and #SplitSales.AgentCode = FirstAgent.MinAgentCode
    
  end

if @debug=1 select 'Stage 10',getdate()

  update  #PolDetails
  set SplitSale = case when SplitSale is null then 'N' else 'Y ' + SplitSale end

if @debug=1 select 'Stage 11',getdate()

   SELECT 
        AgentName 
      , AgentsCode AgentCode 
      , AgentSupervisor 
      , PolicyRef CaseID 
      , ProductCode PlanType 
      , CONVERT(VARCHAR, LicenceCheckDate, 103) AS [StartDate]
      , SplitSale
   FROM #PolDetails
   WHERE  ProdLicValidID is null
   ORDER BY AgentName, AgentsCode, PolicyRef


drop table #SwitchPolsToProcess
drop table #PolDetails
drop table #ProdLics
drop table #AgentsID
drop table #SplitSales
GO
/****** Object:  StoredProcedure [dbo].[OWUtil_AgentJobRunStatus]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE PROCEDURE [dbo].[OWUtil_AgentJobRunStatus]
 @jobName VARCHAR(100)
,@ServerName VARCHAR(100)
AS
/******************************************************************************

Date      Amended By  Change Details
========  ==========  ==============
06/09/19  C Mellors   Created SP

*******************************************************************************/
BEGIN
	SET NOCOUNT ON;
  
	DECLARE
		 @sql		NVARCHAR(MAX)
		,@result	INT = -1
		; 

	IF (@jobName IS NOT NULL AND @ServerName IS NOT NULL)
	BEGIN
		SET @sql = 
			N'
			IF EXISTS
			(
				SELECT	 *
				FROM	['+ @ServerName + '].msdb.dbo.sysjobs j
				WHERE	j.name = ''' + @JobName + '''
			)
			BEGIN
				IF EXISTS
				(
					SELECT	 *
					FROM		['+@ServerName+'].msdb.dbo.sysjobs j
					INNER JOIN	['+@ServerName+'].msdb.dbo.sysjobactivity ja	 ON ja.job_id = j.job_id
																				AND	ja.run_Requested_date IS NOT NULL
																				AND	ja.stop_execution_date IS NULL
					INNER JOIN	(
									SELECT	MAX( session_id ) AS max_session_id
									FROM	['+@ServerName+'].msdb.dbo.syssessions
								) s ON s.max_session_id = ja.session_id
					WHERE	j.name = N'''+@jobName+'''
				)
				BEGIN
					SET @result = 1;
				END
				ELSE
				BEGIN
					SET @result = 0;
				END
			END
			ELSE
			BEGIN
				SET @result = -1;
			END
			';

		EXEC sys.sp_executesql
			 @query = @sql
			,@params = N'@result INT OUTPUT'
			,@result = @result OUTPUT
			;
	END

	RETURN @result
END
GO
/****** Object:  StoredProcedure [dbo].[owyo_ODPSellerExtract]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

CREATE procedure [dbo].[owyo_ODPSellerExtract]
AS
/************************************************************************************************************

 Object  : procedure
 Desc    : Derive list of sellers for ODP Documents tool
 Owner   : MPC
 Created : 20/09/2007


	This proc is called as follows:

		exec owyo_ODPSellerExtract


 Amendment History

Date    Author    Description
====    ======    ===========
12/05/08  A Groves  1)  Amended to give permission to leavers for all HO staff.
            2)  Made generic to remove server name hardcoding.
            3)  Moved as much processing as possible onto BI server
              to make module more robust as it is prone to hanging.  
13/10/08  A Groves  Added a RAISERROR to ensure batch fails if Yoda/BI counts don't 
            reconcile.  
28/10/08  P Robathan  Add processing to include new Agents that aren't on the 
            msct_advisersinqualityspan table.  This table is only updated once 
            a month just after month end so new agents added after this don't 
            get picked up. Added a union to most of the selects to pick up these 
            new advisors from the mstt_agents whose datestarted > than the date 
            that drives the creation of msct_advisersinqualityspan. 
26/01/2009  A Groves  Added ANSI_NULLS on and ANSI_WARNINGS on as required by execution error.
18/03/2009  A Groves  SDE ticket 42582: Link SQST to any code even if not a ptl code. 
07/07/2009  A Groves  Hardcoded 7 members of the Complaints Team to access the documents of leavers.
07/09/2009  A Groves  Update of the production Yoda server failing since migration of the warehouse
              to prod-midb-003.  Logic recoded to run stored procedures on the Yoda server.
08/09/2009  A Groves  Added two returned parameters that will be used to send an email if they differ.
12/02/2010  A Groves  Added Christina Batten to Complaints Team hardcoded list for leavers.
15/03/2010  A Groves  Added Debbie Burchell, ptl90796, PSD & Suzanna Leka, ptl90891, PSD
              as requested by Nick Wilson via email to AG dated 15/03/2010.
26/04/2010  A Groves  Added Becky Sprawson as requested by Nick Wilson via email to AG dated 26/04/2010.
              Added Mark Hicks as requested by himself to AG.
28/02/2012  A Harrison	Added Katrina Raddon (Complaints Team), SR138492 refers.
18/02/2013  A Groves		Replace Katrina Raddon (who has left) with Sally Ball (Complaints Team). SR 208170
11/10/2013  A Groves	Added Kim Martinez (Complaints Team?), SR259450 refers.
22/10/2013  A Groves	Introduced AD Group GLS_YODA_TERMINATIONS_ACCESS via sp
						owp_HeadOfficeUsersForYodaTerminatedAdvisers to link SQST staff
						to the documents of advisers who have left.
07/05/2026  C Mellors	Updated to run locally. The result will be pushed to Yoda outside of this process.
                        Removed output parameters from the SP, as these are not used.
************************************************************************************************************/
BEGIN
	SET NOCOUNT ON;

    declare 
        @PhaseStart     varchar(50) = 'START',
        @PhaseEnd       varchar(50) = 'END',
        @Client         varchar(50) = 'Openwork',
        @Module         varchar(50) = 'Document Archive Permissions',
        @Process        varchar(100) = 'owyo_ODPSellerExtract',
        @Msg            varchar(100),
        @RecordCount    int,
        @OrphansCount   int;

    exec dbo.msp_ProcessLog @PhaseStart, @Process, null, @Module, @Client;

    --############################################################################################################
    -- Create temp table
    --############################################################################################################

    exec dbo.msp_ProcessLog @PhaseStart, '01) Create table #tmp', null, @Module, @Client;

	create table #tmp 
	(login varchar(50)
	,xcode varchar(25)
	,type int
	,usecode varchar(25)
	,descn varchar(50)
	);

    --############################################################################################################
    -- inserts all head office users into temp table
    --############################################################################################################

    exec dbo.msp_ProcessLog @PhaseStart, '02) Get Head Office Users', null, @Module, @Client;

	insert into #tmp
	select right(ltrim(rtrim(domainlogin)),len(domainlogin)-charindex('\',domainlogin)),'HOUSER',99,'HOUSER','HOUSER'
	from dbo.msct_headofficeusers;

    --############################################################################################################
    -- inserts all other users, by using users from Swift user table that have an agent code
    --############################################################################################################

    exec dbo.msp_ProcessLog @PhaseStart, '03) Get All Other Users', null, @Module, @Client;

	insert into #tmp
	select name,associatedAgent,0,associatedAgent,''
	from dbo.msit_intusers iu
	full outer join dbo.msct_headofficeusers ho on name = right(domainlogin,len(domainlogin)-charindex('\',domainlogin))
	where associatedAgent <> ''
	  and domainlogin is null;

    --############################################################################################################
    -- sets the type of user for non-head office staff e.g. BQM
    --############################################################################################################

    exec dbo.msp_ProcessLog @PhaseStart, '04) Update Type', null, @Module, @Client;

	update #tmp 
	set type = case   when agentcategory  like '%AQM%'  then 3  -- aqm / corporate aqm
		  when agenttype    = 55    then 4  -- asd
		  when agentcategory  not like '%AQM%'
		   and agenttype    = 52    then 2  -- bqm
		  when agenttype    not in (52,53,54,55)  
		   and cansupervise   = 1     then 1  -- practice supervisor
		  else 0
	  end
	,descn = 'non HO User'
	from dbo.mstt_agents a
	where a.code = xcode
	  and type <> 99;

    --############################################################################################################
    -- updates usecode to blank for AQMs
    --############################################################################################################

    exec dbo.msp_ProcessLog @PhaseStart, '05) Update usecode for AQMs', null, @Module, @Client;

	update #tmp 
	  set usecode = ''
	  where type = 3;

    --############################################################################################################
    -- for delegates of AQMs resets use code to the AQM they are a delegate of
    --############################################################################################################

    exec dbo.msp_ProcessLog @PhaseStart, '06) Update usecode for AQM delegates', null, @Module, @Client;

	update #tmp
	  set usecode = iu.associatedAgent
	 from dbo.msct_qualityDelegates qd 
	inner join dbo.msit_intusers iu on iu.name =  COALESCE( right(delegateof,len(delegateof)-charindex('\',delegateof)),'n/a')
	where type = 3 
	and domainlogin = 'OPENWORK\' + #tmp.login;

    --############################################################################################################
    -- updates type for AQMs to make them an ASD
    --############################################################################################################

    exec dbo.msp_ProcessLog @PhaseStart, '07) Update AQMs to ASDs', null, @Module, @Client;

	update #tmp 
	  set type = 4
	  where type = 3;

    --############################################################################################################
    -- create empty table to start determining who can see who
    --############################################################################################################

    exec dbo.msp_ProcessLog @PhaseStart, '08) Create table #SELLERSList', null, @Module, @Client;

	create table #SELLERSlist 
	(
	  login varchar(20),
	  VALUE varchar(20)
	);

    --############################################################################################################
    -- determine the cutoff point for the last monthly agent quality hierarchy 
    -- any agents joined after this date need to be included as well  NEW
    --############################################################################################################

    exec dbo.msp_ProcessLog @PhaseStart, '09) Determine the cutoff point', null, @Module, @Client;

	declare @ReportMonth datetime
    set @ReportMonth = dateadd(mm, 1, (Select max(ReportMonth) 
                      from dbo.mstt_AgentQualityAggregation
                      where KPILevel = 'ADVISERKPI')) - 1;

    --############################################################################################################
    -- add HO users in.  Basically HO users can see docs for all advisers
    --############################################################################################################

    exec dbo.msp_ProcessLog @PhaseStart, '10) Add HO users to #SELLERSList', null, @Module, @Client;

	insert into #SELLERSlist 
	(login,VALUE)
	select  distinct #tmp.login, agentCode
	from  dbo.msct_advisersinqualityspan
		full outer join #tmp on 1=1
	where hierarchytypecode = 'CURRENT'
	and   agentCode is not null
	and   #tmp.type = 99
  
    --############################################################################################################
    -- for HO users add in advisers who have joined since last monthly quality update. NEW
    --############################################################################################################

    union

	select  distinct #tmp.login, agentCode
	from  dbo.mstt_AgentQualityHierarchy b
		full outer join #tmp on 1=1
		inner join dbo.mstt_agents a on a.code = b.agentCode
	where agenthierarchystartdate > @ReportMonth
	and   agentCode is not null
	and   IsCurrent = '1'
	and   a.datestarted > @ReportMonth
	and   #tmp.type = 99;

    --############################################################################################################
    -- add AQM/ASD users in.  Quality hierarchy table dictates which advisers they can see
    --############################################################################################################

    exec dbo.msp_ProcessLog @PhaseStart, '11) Add AQM/ASD users to #SELLERSList', null, @Module, @Client;

    -- get list of all sellers
	insert into #SELLERSlist 
	(login,VALUE)
	select  distinct #tmp.login, agentCode
	from  dbo.msct_advisersinqualityspan
		inner join #tmp on salesqualityASDlevelcode =#tmp.usecode
	where hierarchytypecode = 'CURRENT'
	and   agentCode is not null
	and   #tmp.type = 4 
 
    --############################################################################################################
    -- for AQM/ASD users add in advisers who have joined since last monthly quality update. NEW
    --############################################################################################################

    union

	select  distinct #tmp.login, agentCode
	from  dbo.mstt_AgentQualityHierarchy b
		inner join #tmp on salesqualityasdlevelCode= #tmp.usecode
		inner join dbo.mstt_agents a on a.code = b.agentCode
	where agenthierarchystartdate > @ReportMonth
	and   IsCurrent = '1'
	and   a.datestarted > @ReportMonth
	and   agentCode is not null
	and   #tmp.type = 4;


    --############################################################################################################
    -- add BQM users in.  Quality hierarchy table dictates which advisers they can see
    --############################################################################################################

    exec dbo.msp_ProcessLog @PhaseStart, '12) Add BQM users to #SELLERSList', null, @Module, @Client;

	insert into #SELLERSlist 
	(login,VALUE)
	select  distinct #tmp.login, agentCode
	from  dbo.msct_advisersinqualityspan
		inner join #tmp on salesqualitySQMlevelcode =#tmp.usecode
	where hierarchytypecode = 'CURRENT'
	and   agentCode is not null
	and   #tmp.type = 2

    --############################################################################################################
    -- for BQM users add in advisers who have joined since last monthly quality update. NEW
    --############################################################################################################

    union

	select  distinct #tmp.login,agentCode
	from  dbo.mstt_AgentQualityHierarchy b
		inner join #tmp on salesqualitysqmlevelCode =#tmp.usecode
		inner join dbo.mstt_agents a on a.code = b.agentCode
	where agenthierarchystartdate > @ReportMonth
	and   IsCurrent = '1'
	and   a.datestarted > @ReportMonth
	and   agentCode is not null
	and   #tmp.type = 2;

    --############################################################################################################
    -- add Practice Supervisors users in.  Quality hierarchy table dictates which advisers they can see. Often 
    -- the salesqualityPSlevelcode field will be null so nothing to add in
    --############################################################################################################

    exec dbo.msp_ProcessLog @PhaseStart, '13) Add Practice Supervisors to #SELLERSList', null, @Module, @Client;

	insert into #SELLERSlist 
	(login,VALUE)
	select  distinct #tmp.login,agentCode
	from  dbo.msct_advisersinqualityspan
		inner join #tmp on salesqualityPSlevelcode =#tmp.usecode
	where hierarchytypecode = 'CURRENT'
	and   agentCode is not null
	and   #tmp.type = 1
  
    --############################################################################################################
    -- for Practice Supervisors users add in advisers who have joined since last monthly quality update. Often 
    -- the salesqualityPSlevelCode field will be null so nothing to add in   NEW
    --############################################################################################################
  
    union

	select distinct #tmp.login, agentCode
	from  dbo.mstt_AgentQualityHierarchy b
		inner join #tmp on salesqualityPSlevelCode =#tmp.usecode
		inner join dbo.mstt_agents a on a.code = b.agentCode
	where agenthierarchystartdate > @ReportMonth
	and   IsCurrent = '1'
	and   a.datestarted > @ReportMonth
	and   agentCode is not null
	and   #tmp.type = 1;

    --############################################################################################################
    -- Now everyone should be able to see themselves so add a row in for everyone to reflect this
    --############################################################################################################

    exec dbo.msp_ProcessLog @PhaseStart, '14) Add each person to self-see in #SELLERSList', null, @Module, @Client;

	insert into #SELLERSlist 
	(login , VALUE)
	select  distinct #tmp.login,#tmp.xcode
	from  #tmp;
  
    --############################################################################################################
    -- clear the permissions_staging table 
    --############################################################################################################

	truncate table dbo.owyo_PermissionsStaging;

    --############################################################################################################
    -- Load the empty Staging table
    --############################################################################################################

    exec dbo.msp_ProcessLog @PhaseStart, '15) Load Permissions Staging Table - Main Population', null, @Module, @Client;

	insert into dbo.owyo_PermissionsStaging
	( 
	  LoggedInUserFK,
	  PTLCode,
	  ModifyCommand,
	  DateRowLoaded
	)
	select  distinct sl.login, iu.domainLogin, null, getdate()
	from  dbo.msct_advisersinqualityspan iu
		inner join #SELLERSlist sl 
		  on iu.Agentcode  = sl.value 
		  and iu.useragentcode  = sl.value
	where hierarchytypecode='current'

	union             --Now add in the recent agents

	select  distinct login, portallogon, null, getdate()
	from  dbo.mstt_Agents iu
		inner join #SELLERSlist sl on iu.Code  = sl.value 
	where iu.portallogon is not null 
	and   iu.portallogon <> ''
	and   iu.datestarted > @ReportMonth;

    set @RecordCount = @@rowcount;

    set @Msg = '16) owyo_PermissionsStaging @RecordCount = ' + convert(varchar(15),@recordCount)

    exec dbo.msp_ProcessLog @PhaseStart, @Msg, null, @Module, @Client;

	if @@error <> 0 begin
	  return 100;
	end

    --############################################################################################################
    -- The Orphans table contains any agent who has archived documents but no Permissions set up to access them.
    -- This table mostly contains leavers though it is possible some agents have become disconnected for other reasons.
    -- This stage is not part of the previous UNION as we need to do this after the Staging table as a form of
    -- mopping up.  Otherwise there would be no mechanism for removing these permissions once they have gone on.
    --############################################################################################################

    exec dbo.msp_ProcessLog @PhaseStart, '17) Load #Orphans Table', null, @Module, @Client;

	create table #Orphans 
	(
	  PTLCode varchar(20)
	);

    Insert into #Orphans
      select d.PTLCode
      from dbo.owyo_DocumentPTLs d
        where not exists (select 1 from dbo.owyo_PermissionsStaging p where p.PTLCode = d.PTLCode);

    select @OrphansCount = count(*) 
    from #Orphans; 

    set @Msg = '18) #Orphans @OrphansCount = ' + convert(varchar(15),@OrphansCount);

    exec dbo.msp_ProcessLog @PhaseStart, @Msg, null, @Module, @Client;

    --############################################################################################################
    -- Now add in the leavers for access by HO SQST staff only
    -- No need to check that the orphan portal code is not already in the Staging table as this is achieved by the 
    -- previous step. 
    --############################################################################################################

    exec dbo.msp_ProcessLog @PhaseStart, '19) Load Permissions Staging Table - Leavers', null, @Module, @Client;

    insert into dbo.owyo_HeadOfficePTLs
    (
	    LoggedInUserFK	
    )
    select	Ag.PortalLogon
    from	dbo.mstt_Agents Ag
    where   Ag.AgentCategory like 'SQST%'				-- SQST
    and		Ag.CompetentStatusDescription = 'Active'    -- Current SQST
    and		isnull(Ag.PortalLogon,'') <> ''
    and		not exists (select 1 from dbo.owyo_HeadOfficePTLs where LoggedInUserFK = Ag.PortalLogon);

    insert into dbo.owyo_PermissionsStaging
    ( 
      LoggedInUserFK,
      PTLCode,
      ModifyCommand,
      DateRowLoaded
    )
    select  scs.LoggedInUserFK, Orphans.PTLCode, null, getdate()
    from	    dbo.owyo_HeadOfficePTLs scs	-- Support Centre staff requiring access to left adviser documents
	cross join  #Orphans Orphans;           -- Left advisers (cartesian join)

    set @OrphansCount = @@rowcount;

    set @Msg = '20) owyo_PermissionsStaging @OrphansCount = ' + convert(varchar(15),@OrphansCount);

    exec dbo.msp_ProcessLog @PhaseStart, @Msg, null, @Module, @Client;

    --############################################################################################################
    -- Staging loaded, now add to Staging any agents not on Staging but on owyo_Permissions and mark them for deletion.
    --############################################################################################################

    exec dbo.msp_ProcessLog @PhaseStart, '21) Flag Deletes', null, @Module, @Client;

    -- Populate Staging and set ModifyCommand flag to identify deletes

    insert into owyo_PermissionsStaging
    ( 
      LoggedInUserFK,
      PTLCode,
      ModifyCommand,
      DateRowLoaded
    )
    select  p.LoggedInUserFK, p.PTLCode, 'D', getdate()
    from    owyo_Permissions p 
        LEFT OUTER JOIN owyo_PermissionsStaging ps 
                on  P.loggedInUserFK = ps.loggedInUserFK 
                AND p.PTLCode = ps.PTLCode 
    where   ps.loggedInUserFK is null
    and   ps.PTLCode is null

    --############################################################################################################
    -- Staging loaded, now update Staging for agents on Staging but not on owyo_Permissions and mark them for addition.
    --############################################################################################################

    exec dbo.msp_ProcessLog @PhaseStart, '22) Flag Inserts', null, @Module, @Client;

    update  owyo_PermissionsStaging
          set ModifyCommand = 'I'
    from  owyo_Permissions p
        RIGHT OUTER JOIN owyo_PermissionsStaging ps 
                ON  p.loggedInUserFK = ps.loggedInUserFK 
                AND p.PTLCode = ps.PTLCode 
    where p.loggedInUserFK is null
    and   p.PTLCode is null

    --############################################################################################################
    -- Now delete permissions to remove on the BI server
    --############################################################################################################

    exec dbo.msp_ProcessLog @PhaseStart, '23) Delete BI Permissions', null, @Module, @Client;

    delete  p
    from  dbo.owyo_permissions p
        inner join dbo.owyo_PermissionsStaging ps 
              on p.loggedInUserFK = ps.LoggedInUserFK
              and p.PTLCode = ps.PTLCode
    where ps.ModifyCommand = 'D';

    --############################################################################################################
    -- Now insert permissions to add on the BI server
    --############################################################################################################

    exec dbo.msp_ProcessLog @PhaseStart, '24) Insert BI Permissions', null, @Module, @Client;

	insert dbo.owyo_Permissions
	(
		loggedInUserFK,
		PTLCode
	)
    select  ps.LoggedInUserFK, ps.PTLCode
    from  dbo.owyo_PermissionsStaging ps
    where ps.ModifyCommand = 'I';

    --############################################################################################################
    -- It's all over so tidy up
    --############################################################################################################

    drop table #Orphans;
    drop table #tmp;
    drop table #SELLERSlist;

    exec dbo.msp_ProcessLog @PhaseEnd, @Process, null, @Module, @Client;
END
GO
/****** Object:  StoredProcedure [dbo].[PARALLEL_msp_CommissionStatement]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[PARALLEL_msp_CommissionStatement]
	@Client		varchar(50),						--MPC:21/01/2010
	@Module		varchar(50),						--MPC:21/01/2010
	@Mode		varchar(4)		--'FULL' or 'MOVE'	--MPC:21/01/2010

as
--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : PARALLEL_msp_CommissionStatement.sql
-- Owner   : CTT
-- Created : 26/10/2005
--
-- Call as 
--	PARALLEL_msp_CommissionStatement 'Openwork', 'Open Access','MOVE'
-- OR
--	PARALLEL_msp_CommissionStatement 'Openwork', 'Open Access','FULL'
--
--########################################################################

/*
	RH [openwork] 24 jan 2007
	CR 226 - Exclude Declined Authorisations
	CR 229 - Mortgage Early Payments
*/

/*
	MC [openwork] 06 Feb 2007
	CR 236 - Ensure BusinessCode set to UID with AgentType 2, 46 or 49
*/

/*
	MC [openwork] 09 Feb 2007
	CR 239 - Repost BACS entries dated 12/02/2007 to January 2007 period (dated 01/02/2007)
*/

/*
	WI260 Mike Cawood 23/03/2007
	Amendment to derivation of CreateDate and INIssued
	Amendment to zeroise Still to Accrue on earlier payments in same Month
*/

/*
	Mike Cawood 08/06/2007
	Ticket 140 Remove Create Dates override introduced in WI260
	Ticket 143 Assign Mortgage Overrides based on Product code not Provider
*/

/*
	Mike Cawood 11 July 2007
	Repost BACS entries dated 11/07/2007 to June 2007 period (dated 01/07/2007)
*/

/*
	Mike Cawood 18 July 2007
	Open Access - Treat Type 17 Adjustments as APE/NBI movements for IT and SP Accrual cases

	Mike Cawood 25 July 2007 
	Ticket 205 - Fix missing Still to Accrue issue for split commission cases.

	Mike Cawood 14 August 2007
	OW239 - Warehouse cleanup - Revised APE processing so that only set when NBI changes significantly

	Richard Highes - September 2007
	Performance Improvements 
	Perform all processing on internal tables and then table inserts at end of procedure.

	Mike Cawood - 21 September 2007
	Ticket 108 - Default Basis to Accrual if CommType is NULL on mstt_policytransactions
	Fix indeterminate CommissionsID issue - sort entries to ensure consistent ID applied

	Mike Cawood - 13 December 2007
	Post entries created after BACS run on 12:45 on 12 Dec'07 to December period
	Period end date originally 11 Dec'07 but moved due to Swift processing delays

	Mike Cawood - 20 December 2007
	Amend processing to derive correct BusinessCode where TASHH missing or invalid.
	Use DefaultValue = 1 entries only and find owner using Transaction Proposal Date
	or (if manual payment) using Payment Create Date.

	Alan Groves - 23 January 2008
	Performance improvement:
	1)  Drop indexes after TRUNCATE and re-create them after INSERT to make INSERT faster.
	2)  Introduce index IX_AgentCode to make proc msp_OpenworkAdviserListingSwift faster.

	Alan Groves - 30 January 2008
	Performance improvement:
	1)  Drop non-clustered indexes before the clustered index to avoid unnecessary update
		to the non-clustered indexes immediately prior to them being dropped.

	Mike Cawood 19 February 2008 Ref 08/06785
	Include Manager Payments to ensure that payments linked to Seller who has subsequently become a Manager 
	are not dropped. Also include Company Secretary (44) as Seller type.

	Mike Cawood 29 February 2008 
	1)  Move TOTDUE calculation closer to Swift logic as used in CommCalculateCurrentInitialCommission.
            BI Ignores Negative Movements as attempting to show Original Amount due.
	1)B Ensure TOTDUE Ignores IC Payments linked to Adjustment (type 17) with same DATE_DUE to avoid double
	    counting
	2)  For cases where product uses Gross Fee for Turnover (defined on Product Hierarchy) use Actual DA 
	    received to derive APE (applying AgentSplit).
	3)  Add ExpectationID to NBI Table.
	4)  Ensure NBI sign is aligned with Payment Amount.
	5)  Amend ReportingClassCode derivation to cater for new Comm Types or Standing Order codes

	Paul Robathan - 13th May 2008
	Add processing to calculate the ABC Value for a transaction

	Alan Groves - 10th June 2008
	Drop and re-create index IX_OAStatus

	Alan Groves - 11th June 2008
	Permanent data fix to change the BACS date from 11/06/08 to 10/06/08.

	Paul Robathan - 13th Sept 2008
	1. Amend TotDue calc changed above to exclude certain types of txns 
	2. Set Base Amount to positive if Amount is positive

	Alan Groves - 4th Nov 2008
	Pre-emptive fix on 04/11/08 by AG in case monthly pay run on 11/11/08
	runs past midnight and falls into the next period.

	Paul Robathan - 3rd Dec 2008
	Amend NBI calcs for Regular Premium ISAs
	
	Paul Robathan - 4th Mar 2009
	As per part 1 of 13th Sep 2008 fix but exclude type 5 and 6

	Paul Robathan - 16th Mar 2009
	Add Scheme num onto the record

	Mike Cawood - 7 July 2009
	Replace =* and *= ANSI JOINS as these not allowed in SQL Server 2005

	Mike Cawood - 12 January 2010
	1) Fix to avoid duplicate rows in initial select (use DISTINCT)
	2) Output Process Messages at intermediate stages
	3) Add BACSExportID (new column) - populated with ReportBACSExport.ID
	4) Order Load by ReportingClassCode,PaymentPendingID (S_AGMFIL.ID),
	   AgentPaymentsID (S_AGMPAY.ID),BACSExportID (ReportBACSExport.Id).

	Mike Cawood - 20 January 2010
	Performance Improvements - processing overview: 

	a)  Two new parameters added: @Mode and @MovementsStartDate. @Mode has two run
		settings:
 
			'FULL': This triggers the full refresh of the msit_CommissionStatement
					table. The table is truncated and its indexes are dropped and 
					recreated after the insert. @MovementStartDate is not used here.

			'MOVE': In this mode only those S_AGMFIL and ReportBACSExport rows that 
					are linked to daily movements are processed. The primary keys of
					these movements are held on the owt_TransformationMovements table.
					The rows processed are deleted from the msit_CommissionStatement 
					table and then inserted from the new data generated by the procedure. 
					Indexes	are not dropped/created in this mode.

	b)	The procedure works upon a list of Staging Table ID's identified according to
		the @Mode specified. For a 'FULL' run this list will comprise every ID on the
		S_AGMFIL and ReportBACSExport staging tables. Results are stored on a temporary
		table #msit_CommissionStatement.

	c)  The data on the #msit_CommissionStatement table is then applied to the 
		msit_CommissionStatement table as per the @Mode (see above).

	Two further amendments have been made:
		(1) Add BACSExportID (new column) - populated with ReportBACSExport.ID - to
			enable the 'MOVE' mode of processing to be performed.
		(2) Generate ProcessLog entries at key parts of the process. Where relevant,	
			counts are included on the ProcessLog entry.

	Mike Cawood - 10 February 2010
	Fix for ReportBACSExport Movements.

	Alan Groves - 24 February 2010
	Changed all references of mstt_PaymentsPending to PARALLEL_mstt_PaymentsPending.

	Mike Cawood - 22 March 2010
	(1)	Tighten up CommSacrificePct calculation.
	(2) Remove CHECKSUM column from Table

	Paul Robathan - 24th Mar 2010
	1) Move the processing that sets Month to after the processing introduced
       on 4th Nov 2008, which will stop Month being set to the previous month when there
       has been a BACs overrun.
    2) Code added 12/01/2010 is now uncommented out just above the fix in 1) 

	Paul Robathan - 25th Mar 2010
	1) Amend the BACS overrun fix added 11/08 to cater for all ReportingClasses not just
       ReportingClassCode = 4

	Alan Groves - 30 March 2010
	1) Added use of flag owt_TransformationMovements.CommissionStatement to reduce num 
		of rows to process.
	2) Removed some redundant ORDER BYs 

	Alan Groves - 16 April 2010
	1) Made index CREATEs and DROPs conditional to improve robustness.

	Alan Groves - 18 May 2010
	1) Restrict "TotPaid" to Initial Commission or IC Clawback or IC Adjustment only

	PARALLEL_PROD RUN VERSION
*/

declare		@RowCount			int,
			@ProcessMessage		varchar(100)

--MPC:21/01/2010 New ProcessLog Start
declare		@PhaseStart				varchar(50),
			@PhaseEnd				varchar(50),
			@ProcName				varchar(100),
			@ProgressModule			varchar(50)

set @ProcName		= object_name(@@procid) + ' - ' + @Mode
set @PhaseStart		= 'START'
set @PhaseEnd		= 'END'
set @ProgressModule = 'CSTMT'

exec msp_ProcessLog @PhaseStart, @ProcName, null, @Module, @Client
--MPC:21/01/2010 New ProcessLog End

/*===========================================================================================
    IDENTIFY S_AGMFIL Rows to be Processed based on @Mode and @MovementStartDate
===========================================================================================*/

--MPC 21/01/2010 Start of Identify Payment Movements processing

CREATE TABLE #AGMFILChanges (ID int)
CREATE INDEX #X ON #AGMFILCHANGES (ID)

IF @Mode = 'FULL'	--FULL Reload of Table
BEGIN

	Insert INTO #AGMFILCHANGES
	Select Distinct ID 
	from sa_swift_S_AGMFIL 

	select @RowCount = @@rowcount
	set @ProcessMessage = 'FULL - IdentifyPaymentMovements : Count = ' + convert(varchar(10), @RowCount)		
	exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client

END	--@Mode = 'FULL'

IF @Mode = 'MOVE'	--Process Movements only
BEGIN

	Insert	INTO #AGMFILCHANGES
	Select	DISTINCT PKID 
	FROM	owt_TransformationMovements
	Where	DriverTableName = 'sa_swift_S_AGMFIL'
	and		CommissionStatement = 'Y'				-- AG 30/03/2010

	select @RowCount = @@rowcount
	set @ProcessMessage = 'MOVE - IdentifyPaymentMovements : Count = ' + convert(varchar(10), @RowCount)		
	exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client

END		--@Mode = 'MOVE'

--MPC 21/01/2010 End of Identify Payment Movements processing

/*===========================================================================================
    PROCESS S_AGMFIL Rows selected based on @Mode and @MovementStartDate
===========================================================================================*/

--All columns except ID selected onto #msit_CommissionStatement as Primary Key defined on Insert

select
[AgentCode], [PaymentType], [StandingOrderCode], [StandingOrderDesc], [StandingOrderText], 
[CommissionType], [JournalEntryCode], [JournalEntryDesc], [ReportingClassCode], 
[ReportingClassDesc], [BusinessCode], [SellerName], [FranchiseName], [CommProviderCode], 
[CommProviderDesc], [PaymentDate], [BACSDate], [PaymentStatus], [Amount], [DebitCredit], 
[ExtPolicyNumber], [ClientSurname], [ClientForenames], [ProductCode], [StartDate], 
[FrequencyCode], [FrequencyDesc], [Premium], [CommissionRate], [InitialPeriod], 
[FranchiseUpliftRate], [PayBasisCode], [PayBasisDesc], [CommSacrificeAmt], 
[CommSacrificePct], [AgentSplit], [FranchiseSplit], [CommFeeCode], [CommFeeType], 
[CommReason], [TotDue], [FirstID], [LastID], [ExpectCount], [TotPaid], [AccruedToDate], 
[BaseAmount], [UpliftAmount], [EnhancementRate], [INIssued], [INAccrued], 
[INStilltoAccrue], [INIndemnity], [EXIssued], [EXAccrued], [EXStilltoAccrue], 
[EXIndemnity], [DistributorRef], [DueDate], [AuthDate], [PaidListDate], [AgentPaymentsID], 
[PendingPaymentID], [ExpectationID], [TransactionID], [PolicyID], [ClientID], 
[CommissionsID], [AgtStandingOrderID], [CaseID], [APE], [CreateDate], [Month], -- [ID], 
[ProviderName], [ProviderCode], [SuspendComm], [CommShapeID], [LastAccrualinMonth], [OAStatus],		--MPC:16/04/08 SR9 
[ABCValue],[ABCRate],[SchemeNum],[BACSExportId] 	--MPC: 21/01/2010		--PR:16/3/09 and 13/05/08 ABC
into	#msit_CommissionStatement
from	PARALLEL_msit_CommissionStatement		--MPC:21/01/2010
where	1=0
------------------------- 
 
-- insert details from sa_swift_AgentPayments, mstt_PaymentsPending & mstt_Agents 
 
insert into 
 #msit_CommissionStatement
select DISTINCT						--MPC 21/01/2010
 PP.Agent_Code [AgentCode], 
 AP.PaymentType [PaymentType], 
 PP.StandingOrderCode * 1 [StandingOrderCode], 
 PP.Notes [StandingOrderDesc], 
 '' [StandingOrderText], 
 PP.CommissionType [CommissionType], 
 PP.JournalEntryCode [JournalEntryCode], 
 PP.JournalEntryCodeDesc [JournalEntryDesc], 
 '' [ReportingClassCode], 
 '' [ReportingClassDesc], 
/* 
--MPC: 16/04/08 SR9 - Default to FIRM from mstt_PaymentsPending
case
 when AG.AgentType in ('3','4','5','43','44','45','51') then 			--MPC:19/02/2008	
 coalesce(PP.StrategicAllianceAgentCode, 
 PP.FranchiseAgentCode, 
 PP.AccessAgentCode, 
 PP.DirectlyAuthorisedAgentCode)
 else PP.Agent_Code  end 
*/
PP.FIRM [BusinessCode], 
 rtrim(AG.Descn) [SellerName], 
 '' [FranchiseName], 
 '' [CommProviderCode], 
 '' [CommProviderDesc], 
 convert(datetime,coalesce(AP.PaymentDate,PP.CreateDateTime,'1901-01-01'),103) [PaymentDate],
 -- PR 25/03/2010 - leave hour/minutes/seconds on BACs date so it can be tested later when checking
-- for a BACs overrun.  Previous code commented out below
--convert(datetime,isnull(convert(varchar(10),AP.Export_Date,103),'01/01/1901'),103) [BACSDate],
 convert(datetime,isnull(AP.Export_Date,'01/01/1901'),103) [BACSDate],
 case 
 when AP.Export_Date is null then 'Pending' 
 else 'Paid' end [PaymentStatus], 
 isnull(AP.Amount, PP.Amount) [Amount], 
 case 
 when PP.Amount < '0' then 'D' 
 else 'C' end [DebitCredit], 
 CASE WHEN AP.ID is not NULL THEN AP.CONT_NUM ELSE '' END [ExtPolicyNumber],	--MPC 21/01/2010
 '' [ClientSurname], 
 '' [ClientForenames], 
 '' [ProductCode], 
 '' [StartDate], 
 '' [FrequencyCode], 
 '' [FrequencyDesc], 
 '' [Premium], 
 '' [CommissionRate], 
 '' [InitialPeriod], 
 [FranchiseUpliftRate] = case
                          when PP.CommissionType in ('4','10','15','16','18','19') then '100'
                          else isnull(PP.FranchiseUpliftPercent, 0.0)
                         end,
 '' [PayBasisCode], 
 '' [PayBasisDesc], 
 0  [CommSacrificeAmt],			--MPC: 22/03/2010 
 0  [CommSacrificePct],			--MPC: 22/03/2010
 [AgentSplit] = isnull(PP.AGENT_PERC, 0.0),
 '' [FranchiseSplit], 
 PP.CommissionType [CommFeeCode], 
 case
 when PP.CommissionType in ('1','2','17') then 'IC' 
 when PP.CommissionType = '3' then 'Adv' 
 when PP.CommissionType in ('4','15','18') then 'RC' 
 when PP.CommissionType in ('10','16','19') then 'Trail' 
 when PP.CommissionType in ('11','12') then 'Adj' 
 when PP.CommissionType = '13' then 'Fee' 
 when PP.CommissionType in ('15','16') then 'Claw' 
 else 'Oth' end [CommFeeType], 
 case 
 when PP.CommissionType in ('1','4','10','13') then 'New' 
 when PP.CommissionType in ('2','15','16') then 'Claw' 
 else 'Adj' end [CommReason], 
 '' [TotDue], 
 '' [FirstID], 
 '' [LastID], 
 '' [ExpectCount], 
 '' [TotPaid], 
 '' [AccruedToDate], 
 [BaseAmount] = case
                 when PP.Amount < 0 and PP.BaseAmount > 0 then PP.BaseAmount * -1
                 when PP.Amount > 0 and PP.BaseAmount < 0 then PP.BaseAmount * -1			-- PR 13/9/08
                 when PP.BaseAmount is NULL and PP.CommissionType in ('1', '2', '17') and case -- FranchiseUpliftRate
                                                                                           when PP.CommissionType in ('4','10','15','16','18','19') then '100'
                                                                                           else isnull(PP.FranchiseUpliftPercent, 0.0)
                                                                                          end > 100 then round(PP.Amount / (0.01 * case -- FranchiseUpliftRate
                                                                                                                                    when PP.CommissionType in ('4','10','15','16','18','19') then '100'
                                                                                                                                    else isnull(PP.FranchiseUpliftPercent, 0.0)
                                                                                                                                   end),2)
                 when PP.BaseAmount is NULL and PP.CommissionType in ('1', '2', '17') and case -- FranchiseUpliftRate
                                                                                           when PP.CommissionType in ('4','10','15','16','18','19') then '100'
                                                                                           else isnull(PP.FranchiseUpliftPercent, 0.0)
                                                                                          end <= 100 then PP.Amount
                 else PP.BaseAmount
                end,
 [UpliftAmount] = case
                   when PP.Amount < 0 and PP.UpliftAmount > 0 then PP.UpliftAmount * -1
                   when PP.UpliftAmount is NULL and PP.CommissionType in ('1', '2', '17') and case -- FranchiseUpliftRate
                                                                                               when PP.CommissionType in ('4','10','15','16','18','19') then '100'
                                                                                               else isnull(PP.FranchiseUpliftPercent, 0.0)
                                                                                              end > 100 then PP.Amount - case -- BaseAmount
                                                                                                                          when PP.Amount < 0 and PP.BaseAmount > 0 then PP.BaseAmount * -1
                                                                                                                          when PP.Amount > 0 and PP.BaseAmount < 0 then PP.BaseAmount * -1    --  PR 13/9/08
                                                                                                                          when PP.BaseAmount is NULL and PP.CommissionType in ('1', '2', '17') and case -- FranchiseUpliftRate
                                                                                                                                                                                                    when PP.CommissionType in ('4','10','15','16','18','19') then '100'
                                                                                                                                                                                                    else isnull(PP.FranchiseUpliftPercent, 0.0)
                                                                                                                                                                                                   end > 100 then round(PP.Amount / (0.01 * case -- FranchiseUpliftRate
                                                                                                                                                                                                                                             when PP.CommissionType in ('4','10','15','16','18','19') then '100'
                                                                                                                                                                                                                                             else isnull(PP.FranchiseUpliftPercent, 0.0)
                                                                                                                                                                                                                                            end),2)
                                                                                                                          when PP.BaseAmount is NULL and PP.CommissionType in ('1', '2', '17') and case -- FranchiseUpliftRate
                                                                                                                                                                                                    when PP.CommissionType in ('4','10','15','16','18','19') then '100'
                                                                                                                                                                                                    else isnull(PP.FranchiseUpliftPercent, 0.0)
                                                                                                                                                                                                   end <= 100 then PP.Amount
                                                                                                                          else PP.BaseAmount
                                                                                                                         end
                   else PP.UpliftAmount
                  end,
 '' [EnhancementRate], 
 '' [INIssued], 
 '' [INAccrued], 
 '' [INStilltoAccrue], 
 '' [INIndemnity], 
 '' [EXIssued], 
 '' [EXAccrued], 
 '' [EXStilltoAccrue], 
 '' [EXIndemnity], 
 '' [DistributorRef], 
 case
 when PP.Due_Date < '2006-01-01' then PP.PaymentDueDate
 else PP.Due_Date end [DueDate], 
 PP.AuthorisedDate [AuthDate], 
 AP.PaymentDate [PaidListDate], 
 AP.ID [AgentPaymentsID], 
 PP.ID [PendingPaymentID], 
 PP.PACC_ID [ExpectationID], 
 PP.TransactionID [TransactionID], 
 '' [PolicyID], 
 '' [ClientID], 
 '' [CommissionsID], 
 PP.StandingOrderId [AgtStandingOrderID], 
 '' [CaseID],
 '' [APE],
	case 
		when 	PP.CommissionType = 21	-- RH CR229 mortgage early payment test added			and PP.Amount < 0
			and PP.PaymentDueDate is not null 
		then	convert(datetime,convert(varchar,PP.PaymentDueDate,106)) -- RH convert to whole date (not sure if needed but CreateDateTime below had similar treatment
										 -- Use 106 as totally unambiguous ie "10 Jan 2007" and not 1/10, ... 10/1 etc
		else	convert(datetime,convert(varchar,PP.CreateDateTime,106)) -- RH tidied up existing ungainly processing to convert to whole date
	end 
	[CreateDate],
 '' [Month],
 '' [ProviderName],
 '' [ProviderCode],
 '' [SuspendComm] ,
 '' [CommShapeID] ,		-- WI260
 '' [LastAccrualinMonth],	-- WI260
 case when PP.FIRM is null then 'No FIRM' else 'Valid' end [OAStatus], 	--MPC:16/04/08 SR9
 '' [ABCValue], 			-- PR:13/05/08
 '' [ABCRate], 			-- PR:13/05/08
Null [SchemeNum] 		-- PR:16/03/09
,NULL [BACSExportId]	--MPC: 21/01/2010
from 
 PARALLEL_mstt_PaymentsPending PP					-- AG 24/02/2010
 Inner Join #AGMFILChanges X ON X.ID = PP.ID		--MPC 21/01/2010 Select Daily Movements only
 inner join mstt_Agents AG on PP.AGENT_CODE = AG.Code 
-- left outer join mstt_AgentPayments AP on PP.id = AP.agmid	--MPC 21/01/2010
 left outer join sa_swift_S_AGMPAY AP on PP.id = AP.agmid		--MPC 21/01/2010
where 
	-- RH CR226 include Authorised test and rephrased "where" clause to match spec
	AG.AgentType in ('2','3','4','5','43','44','45','46','47','49','51','52','53','54','55') 	--MPC:19/02/2008
	and isnull(PP.Due_Date,'1901-01-01') < getdate() -- MWA 03/09/2006 Change Requested by MC
	and not (
			PP.CommissionType in ('0','7','14','20','21') 
			and (
				isnull(PP.AuthorisedDate,'1901-01-01') = '1901-01-01'
				or PP.Authorised<>0
			)
			and ap.id is null
		)


/*
	AG.AgentType in ('2','3','4','5','43','46','47','49','51') 
	and isnull(PP.Due_Date,'1901-01-01') < getdate() -- MWA 03/09/2006 Change Requested by MC
	and (
		PP.CommissionType not in ('0','7','14','20','21') 
		or (
			PP.CommissionType in ('0','7','14','20','21') 
			and ap.id is not null 
			and isnull(PP.AuthorisedDate,'1901-01-01') = '1901-01-01'
		)
		or (
			PP.CommissionType in ('0','7','14','20','21') 
			and isnull(PP.AuthorisedDate,'1901-01-01') <> '1901-01-01'
		)
	 )
*/
select @RowCount = @@rowcount
set @ProcessMessage = 'InitialSelect: Count = ' + convert(varchar(10), @RowCount)	--MPC:21/01/2010
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client		--MPC:21/01/2010

