/*
--MPC:16/04/2008 - REMOVED IN SR9 - Default to FIRM from mstt_PaymentsPending 
-- Update BusinessCode where missing or set to non-Business UID

-- First find latest valid Agent Hierarchy row earlier than Transaction Proposal Date
-- If no Transaction use Create Date of Payment (manual payments)

select
 CS.PendingPaymentID as ID,
 CS.TransactionId,
 CS.AgentCode,
 coalesce(PT.ProposalDate,CS.CreateDate) as Date,
 max(AH.startdate) as StartDate
into
 #LastBusiness
from
 #msit_CommissionStatement CS 
 inner join msit_AgentHierarchyHistory AH on AH.agentcode = CS.agentcode
 left outer join mstt_policytransactions pt on pt.id = CS.transactionid
 left outer join mstt_agents ag on ag.code = cs.businesscode
where
 AH.ParticipantType in (6,7,8,9) and
 AH.Startdate <= coalesce(PT.ProposalDate,CS.CreateDate) and
 AH.DefaultValue = 1 	and
 (ag.agenttype not in (2,46,49) or len(CS.BusinessCode) = '0' or CS.BusinessCode is null)
group by
 CS.PendingPaymentID,
 CS.transactionid,
 CS.agentcode,
 coalesce(PT.ProposalDate,CS.CreateDate)
order by
 CS.PendingPaymentID

select t1.*,ah.Detailagentcode as Firm
into #LastBusinessCode
from msit_AgentHierarchyHistory AH
inner join #Lastbusiness t1 
on t1.agentcode = AH.agentcode and t1.startdate = AH.startdate and AH.participanttype in (6,7,8,9)
where AH.DefaultValue = 1

update
 #msit_CommissionStatement
set
 BusinessCode = t1.Firm
from
 #msit_CommissionStatement CS 
 inner join #Lastbusinesscode t1 on CS.PendingPaymentID = t1.ID
 left outer join mstt_agents ag on ag.code = cs.businesscode
where 
 (ag.agenttype not in (2,46,49) or len(CS.BusinessCode) = '0' or CS.BusinessCode is null) 

drop table #lastbusiness
drop table #lastbusinesscode

-- If any payments still missing correct Business code then apply Business using earliest
-- Agent Hierarchy after Transaction Proposal Date or Create Date (manual payment)

select
 CS.PendingPaymentID as ID,
 CS.TransactionId,
 CS.AgentCode,
 coalesce(PT.ProposalDate,CS.CreateDate) as Date,
 max(AH.startdate) as StartDate
into
 #FirstBusiness
from
 #msit_CommissionStatement CS 
 inner join msit_AgentHierarchyHistory AH on AH.agentcode = CS.agentcode
 left outer join mstt_policytransactions pt on pt.id = CS.transactionid
 left outer join mstt_agents ag on ag.code = cs.businesscode
where
 AH.ParticipantType in (6,7,8,9) and
 AH.Startdate >= coalesce(PT.ProposalDate,CS.CreateDate) and
 AH.DefaultValue = 1 	and
 (ag.agenttype not in (2,46,49) or len(CS.BusinessCode) = '0' or CS.BusinessCode is null)
group by
 CS.PendingPaymentID,
 CS.transactionid,
 CS.agentcode,
 coalesce(PT.ProposalDate,CS.CreateDate)
order by
 CS.PendingPaymentID

select t1.*,ah.Detailagentcode as Firm
into #FirstBusinessCode
from msit_AgentHierarchyHistory AH
inner join #Firstbusiness t1 
on t1.agentcode = AH.agentcode and t1.startdate = AH.startdate and AH.participanttype in (6,7,8,9)
where AH.DefaultValue = 1

update
 #msit_CommissionStatement
set
 BusinessCode = t1.Firm
from
 #msit_CommissionStatement CS 
 inner join #Firstbusinesscode t1 on CS.PendingPaymentID = t1.ID
 left outer join mstt_agents ag on ag.code = cs.businesscode
where 
 (ag.agenttype not in (2,46,49) or len(CS.BusinessCode) = '0' or CS.BusinessCode is null) 

drop table #firstbusiness
drop table #firstbusinesscode
 
-- If no code yet allocated then default to current Firm from Agents table

update
 #msit_CommissionStatement
set
 BusinessCode = AG.Firm
from
 mstt_Agents AG
where
 (len(#msit_CommissionStatement.BusinessCode) = '0' or
 #msit_CommissionStatement.BusinessCode is null) and
 #msit_CommissionStatement.AgentCode = AG.Code
-- CR236 MC 06/02/2007
-- Set Business Code to Firm for entries where a Seller Code has been found (SWIFT Data issues)

update
 #msit_CommissionStatement
set
 BusinessCode = ag.Firm
from
 #msit_CommissionStatement cs 
 inner join mstt_agents ag on ag.code = cs.businesscode
where
 ag.agenttype not in (2,46,49)
--MPC: 16/04/08 -- END OF SR9 REMOVED CODE
*/
 
-- Insert StandOrderDesc 
 
