 StandingOrderDesc = PP.StandingOrderCodeDesc 
from 
 msit_CommissionReportingClassCodes CRCC, 
 PARALLEL_mstt_PaymentsPending PP					-- AG 24/02/2010
where 
 #msit_CommissionStatement.CommissionType = CRCC.SwiftCode and 
 #msit_CommissionStatement.PendingPaymentId = PP.ID and 
 CRCC.SwiftField = 'CommissionType' and 
 CRCC.ReportingClassCode = 'S' 
 
