 #msit_CommissionStatement
set 
 StandingOrderText = SO.Description 
from 
 msit_CommAgentStandingOrders SO 
where 
 #msit_CommissionStatement.AgentCode = SO.AgentCode and 
 #msit_CommissionStatement.AgtStandingOrderID = SO.ID 

--Upd #4
update 
 #msit_CommissionStatement
set 
 StandingOrderText = null 
