-- Update StandOrderDesc 

--Upd #5
update 
 #msit_CommissionStatement
set 
 StandingOrderDesc = CRCC.SwiftDescription 
from 
 msit_CommissionReportingClassCodes CRCC 
where 
 #msit_CommissionStatement.CommissionType = CRCC.SwiftCode and 
 CRCC.SwiftField = 'CommissionType' and 
 isnull(#msit_CommissionStatement.StandingOrderDesc,'X') = 'X' and 
 isnull(#msit_CommissionStatement.StandingOrderText,'X') = 'X' 
 
