-- Insert Reporting Class Code for non-Standing Order Types

--Upd #6
update 
 #msit_CommissionStatement
set 
 ReportingClassCode = isnull(RC.ReportingClassCode,'1') 			--MPC: 29/02/2008 (5)
from 
 #msit_CommissionStatement CS										--MPC: 29/02/2008 (5)
 left outer join msit_CommissionReportingClassCodes RC 				--MPC: 29/02/2008 (5)
	on CS.CommissionType = RC.SwiftCode								--MPC: 29/02/2008 (5)
where 
-- #msit_CommissionStatement.CommissionType *= RC.SwiftCode and 	--MPC: 29/02/2008 (5)
 RC.SwiftField = 'CommissionType' 
 and RC.ReportingClasscode <> 'S'									--MPC: 29/02/2008 (5)

