-- Insert Reporting Class Code for Standing Orders only 

--Upd #7
update 
 #msit_CommissionStatement
set 
 ReportingClassCode = isnull(RC.ReportingClassCode,'2') 			--MPC: 29/02/2008 (5)
from 
 #msit_CommissionStatement CS										--MPC: 29/02/2008 (5)
 inner join msit_CommissionReportingClassCodes RS 					--MPC: 29/02/2008 (5)
	on CS.CommissionType = RS.SwiftCode and 						--MPC: 29/02/2008 (5)
	   RS.SwiftField = 'CommissionType' and 						--MPC: 29/02/2008 (5)
	   RS.ReportingClasscode = 'S' 									--MPC: 29/02/2008 (5)
 left outer join msit_CommissionReportingClassCodes RC 				--MPC: 29/02/2008 (5)
	on CS.StandingOrderCode = (RC.SwiftCode * 1)					--MPC: 29/02/2008 (5)
where 
-- #msit_CommissionStatement.StandingOrderCode *= (RC.SwiftCode * 1) and--MPC: 29/02/2008 (5)
-- #msit_CommissionStatement.ReportingClassCode = 'S' and 			--MPC: 29/02/2008 (5)
-- CS.ReportingClassCode is NULL and			 					--MPC: 29/02/2008 (5)
 RC.SwiftField = 'StandingOrderCode' 
 
