 #msit_CommissionStatement
set
-- CommissionsID = CO.ID,	-- Ticket 108
 AgentSplit = CO.Agent_Perc,	-- Ticket 108
 FranchiseSplit = 
 case when CO.DistributionAllowance = '0' then '0' 
 else CO.FixedAmount / CO.DistributionAllowance 
 end, 
-- APE = CO.APE, 	-- WI260 APE processing moved to end	
 FranchiseUpliftRate = case
-- Ticket143            when mstt_CommissionStatement.FranchiseUpliftRate = 0 then case when CommProviderCode = 'MORTGAGE' then CO.FranchiseUpliftPercent - 20 else CO.FranchiseUpliftPercent end
-- Ticket143            else case when CommProviderCode = 'MORTGAGE' then mstt_CommissionStatement.FranchiseUpliftRate - 20 else mstt_CommissionStatement.FranchiseUpliftRate end
                        when #msit_CommissionStatement.FranchiseUpliftRate = 0 then case when co.ProductGroupCode = 3 then CO.FranchiseUpliftPercent - 20 else CO.FranchiseUpliftPercent end	--Ticket143
			else case when co.ProductGroupCode = 3 then #msit_CommissionStatement.FranchiseUpliftRate - 20 else #msit_CommissionStatement.FranchiseUpliftRate end			--Ticket143
                       end
from
 mstt_Commissions CO
where CO.ID = CommissionsID	-- Ticket 108

