-- Update CommissionRate 
 
--Sel #6
select 
 PT.[Id], 
 case when isnull(PT.RenewalRate,'0') > '0' then PT.RenewalRate 
 else isnull(CC.RenewalRate,'0') end RenewalRate 
into 
 #CommRate 
from 
 mstt_PolicyTransactions PT, 
( 
select 
 CC2.CodeCommissionShapeID, 
 CC2.RenewalRate 
from 
 msit_CodeCommissionShapeRateHistory CC2, 
( 
select 
 CC.CodeCommissionShapeID, 
 max(CC.DateEffective) DateEffective 
from 
 msit_CodeCommissionShapeRateHistory CC, 
 mstt_PolicyTransactions PT 
where 
 CC.CodeCommissionShapeID = PT.CodeCommissionShapeID and 
 CC.DateEffective < = PT.TransactionDate group by 
 CC.CodeCommissionShapeID 
) CC3 
where 
 CC2.CodeCommissionShapeID = CC3.CodeCommissionShapeID and 
 CC2.DateEffective = CC3.DateEffective 
) CC 
where 
 PT.CodeCommissionShapeID = CC.CodeCommissionShapeID 


