--Upd #26
update 
 #msit_CommissionStatement
set 
 FirstID = EX4.FirstID 
from 
 #Expectations4 EX4 
where 
 #msit_CommissionStatement.TransactionID = EX4.TransactionID 
 
-- select the latest ExpectationId for each transaction 
 
--Sel #12
select 
 EX.TransactionID, 
 max(EX.ID) LastID 
into 
 #Expectations5 
from 
 #TransExcept EX 
where 
 EX.[Count] = 'Y' 
group by 
 EX.TransactionID 
 
-- Update LastID with the ID above 

--Upd #27
update 
 #msit_CommissionStatement
set 
 LastID = EX5.LastID 
from 
 #Expectations5 EX5 
where 
 #msit_CommissionStatement.TransactionID = EX5.TransactionID 
 
-- count the number of Expectation ID's for each transaction 
 
--Sel #13
select 
 EX.transactionid, 
 count(EX.ID) count 
into 
 #Expectations6 
from 
 #TransExcept EX 
where 
 EX.[Count] = 'Y' 
group by 
 transactionid 
 
