update 
 #msit_CommissionStatement
set 
 CommSacrificePct = 
 case  when round(TotDue,2) <= 0 then 0						--MPC: 22/03/2010 
 else (CommSacrificeAmt * 100) / TotDue  end 
where 
 PayBasisCode < > 'T' and round(CommSacrificeAmt,2) > 0		--MPC: 22/03/2010

