	InIssued = 	 Amount
where 
 PayBasisCode = 'T' and 
 CommissionType = '1' 

--Upd #36
update 
 #msit_CommissionStatement
set 
 InIssued = Amount 
where 
 CommissionType = 2 or		-- WI260
