 (CommissionType = 17 and (FrequencyCode = 6 or PayBasisCode = 'T' or ExpectCount = 1))
-- Treat Type 17 movements on SP and IT cases as valid for NBI (INIssued)

------------------------------ 
-- Set Enhancement Rate
------------------------------
--Upd #37
update 
 #msit_CommissionStatement
set 
 EnhancementRate = '1' 
where 
 CommissionType in ('4','10','15','16','18','19') 
 
--Upd #38
update 
 #msit_CommissionStatement
set 
--Ticket143 EnhancementRate = case CommProviderCode when 'MORTGAGE' then 0 else ((BaseAmount + UpliftAmount) / BaseAmount) end
 EnhancementRate = case when ph.productgroupcode = 3 then 0 else ((BaseAmount + UpliftAmount) / BaseAmount) end		--Ticket143
from #msit_CommissionStatement cs
inner join mstt_producthierarchy ph on ph.productcode = cs.productcode		-- Ticket143
where 
 cs.CommissionType not in ('4','10','15','16','18','19') and 
 cs.UpliftAmount > '0' and 
 cs.BaseAmount > '0' 
 
--Upd #39
update 
 #msit_CommissionStatement
set 
--Ticket143 EnhancementRate = case CommProviderCode when 'MORTGAGE' then 0 else FranchiseUpliftRate/100 end
 EnhancementRate = case when ph.productgroupcode = 3 then 0 else FranchiseUpliftRate/100 end	--Ticket143
from #msit_CommissionStatement cs
inner join mstt_producthierarchy ph on ph.productcode = cs.productcode		-- Ticket143
where 
 cs.CommissionType not in ('4','10','15','16','18','19') and 
 cs.EnhancementRate < = '0' and 
 cs.FranchiseUpliftRate >= '100' 
 
--Upd #40
update 
 #msit_CommissionStatement
set 
 EnhancementRate = '1' from #msit_CommissionStatement cs
inner join mstt_producthierarchy ph on ph.productcode = cs.productcode		-- Ticket143
where 
 cs.EnhancementRate = '0' and
--Ticket143 CommProviderCode <> 'MORTGAGE'
 ph.productgroupcode <> 3			--Ticket143

 
