update 
 #msit_CommissionStatement
set 
 INAccrued = Amount 
where 
 (PayBasisCode < > 'T' or CommissionType in ('4','10','15','16','18','19')) 
 
--Upd #42
update 
 #msit_CommissionStatement
set 
 InStillToAccrue = case
                    when ExpectationID = LastID then '0'
                    else (TotDue * case when TotDue < 0 then -1 else 1 end) - AccruedToDate
                   end 
where 
 PayBasisCode < > 'T' and 
 CommissionType = '1' 
 
--Upd #43
update 
 #msit_CommissionStatement
set 
 InIndemnity = Amount 
where 
 PayBasisCode = 'T' and 
 CommissionType not in ('4','10','15','16','18','19') 

