-- Insert EX calculations 

--Upd #45
update
 #msit_CommissionStatement
set
-- Treat Type 17 movements on SP and IT cases as valid for NBI (EXIssued)
 EXIssued        = case
						when cs.CommissionType not in ('1','2','17') or isnull(cs.INIssued,0) = 0 then '0'			--WI260
--Ticket143				when (CommProviderCode = 'MORTGAGE' or  PayBasisCode  = 'T' or ExpectCount = '1') then BaseAmount	--WI260
     					when isnull(cs.BaseAmount,0) <> 0 and (ph.productgroupcode = 3 or cs.PayBasisCode  = 'T' or cs.FrequencyCode = 6 or cs.ExpectCount = '1') then cs.BaseAmount * 
													case -- PR 3/12/2008 change for Regular Premium ISAs
														when cs.productcode = 'ISA' and  cs.FrequencyCode = '2' and PayBasisCode  <> 'T' then 60 
														else 1
													end
						when cs.EnhancementRate > '0' then cs.INIssued / cs.EnhancementRate
						else '0'
                   end,
 EXAccrued       = case
						when isnull(cs.BaseAmount,0) <> 0 and cs.PayBasisCode <> 'T' then cs.BaseAmount
	     				when cs.EnhancementRate > 0 then cs.INAccrued / cs.EnhancementRate
						else '0'
                   end,
 EXStillToAccrue = case
--Ticket143				when CommProviderCode = 'MORTGAGE' then '0'
						when ph.productgroupcode = 3 then '0'	--Ticket143
						when cs.EnhancementRate  > '0' then cs.INStillToAccrue / cs.EnhancementRate
						else '0'
                   end,
 EXIndemnity     = case
						when isnull(cs.BaseAmount,0) <> 0 and cs.PayBasisCode = 'T' then cs.BaseAmount
						when cs.EnhancementRate > 0 then cs.INIndemnity / cs.EnhancementRate
						else '0'
                   end

from #msit_CommissionStatement cs
inner join mstt_producthierarchy ph on ph.productcode = cs.productcode			-- Ticket143

