-- Insert Payments To Bank 

/*===========================================================================================
    IDENTIFY ReportBACSEXport Rows to be Processed based on @Mode and @MovementStartDate
===========================================================================================*/
 
CREATE TABLE #BACSChanges (ID int)
CREATE INDEX #B ON #BACSCHANGES (ID)

IF @Mode = 'FULL'
BEGIN

	Insert into #BACSChanges
	Select DISTINCT ID 
	From sa_swift_ReportBACSExport
--	Order by ID										AG 30/03/2010

	select @RowCount = @@rowcount
	set @ProcessMessage = 'FULL - IdentifyBACSExportMovements : Count = ' + convert(varchar(10), @RowCount) 								
	exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client

END		--@Mode = 'FULL'

IF @Mode = 'MOVE'
BEGIN

	Insert	into #BACSChanges
	Select	DISTINCT PKID 
	FROM	owt_TransformationMovements
	Where	DriverTableName = 'sa_swift_ReportBACSExport'
	and		CommissionStatement = 'Y'			-- AG 30/03/2010

	select @RowCount = @@rowcount
	set @ProcessMessage = 'MOVE - IdentifyBACSExportMovements : Count = ' + convert(varchar(10), @RowCount) 								
	exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client

END		--@Mode = 'MOVE'
 
--MPC 21/01/2010 End of Identify BACS Export Movements processing

