-- PR 25/03/2010 When BACDate was set earlier (for reportingclasscode 1/2/3) hours/mins/secs
--               were left on the record.  These now to be removed
update 
 #msit_CommissionStatement
set 
 Month = CSP.Month,
 BACSDate = case 
				when ReportingClassCode = 4 then BACSDate
				else dateadd(dd,0,datediff(dd,0,BACSDate))
			end
from
 msit_CommissionStatementPeriods CSP
where
 #msit_CommissionStatement.CreateDate between CSP.PeriodStartDate and CSP.PeriodEndDate


