 #msit_CommissionStatement
set
 LastAccrualinMonth = 'Y'
from #msit_CommissionStatement cs
inner join #LastPaymentID t1 on t1.transactionid = cs.transactionid and t1.month = cs.month 
and t1.lastid = cs.pendingpaymentid and t1.agentcode = cs.agentcode	-- Ticket 205
where FrequencyCode in (2,5) 
and PayBasisCode in ('F','L') 
and CommissionType = '1' 

