update #nbiTable															--MPC :29/02/2008 (4)
set APE = 0,APEFlag = 'E'													--MPC :29/02/2008 (4)
from #NBITable t1															--MPC :29/02/2008 (4)
left outer join #PrevAPE2 t2 on t1.tranid = t2.tranid and t1.agent = t2.agent and t1.ppid = t2.ppid	--MPC :29/02/2008 (4)
where cast(t1.apetotal as decimal(15,2)) < 0 and cast(t1.nbitotal as decimal(15,2)) >= 0 		--MPC :29/02/2008 (4)
and t1.apeflag = 'Z' and t1.APE <> 0										--MPC :29/02/2008 (4)

--Upd #68
select t1.ppid,t1.tranid,t1.agent,sum(isnull(t2.ape,0)) as PrevAPE			--MPC :29/02/2008 (4)
into #PrevAPE3																--MPC :29/02/2008 (4)
from #NBITable t1															--MPC :29/02/2008 (4)
inner join #NBITable t2 on t2.tranid = t1.tranid and t2.agent = t1.agent 	--MPC :29/02/2008 (4)
and cast(t2.ppid as decimal(15,0)) < cast(t1.ppid as decimal(15,0))			--MPC :29/02/2008 (4)
group by t1.ppid,t1.tranid,t1.agent											--MPC :29/02/2008 (4)
order by t1.ppid,t1.tranid,t1.agent											--MPC :29/02/2008 (4)

--Upd #69
update #nbiTable															--MPC :29/02/2008 (4)
set APETotal = cast((t1.APE + isnull(t2.PrevAPE,0)) as decimal(15,2))		--MPC :29/02/2008 (4)
from #NbiTable t1															--MPC :29/02/2008 (4)
left outer join #PrevAPE3 t2 on t1.tranid = t2.tranid and t1.agent = t2.agent and t1.ppid = t2.ppid	--MPC :29/02/2008 (4)

--Upd #70
update #msit_CommissionStatement
set APE = t1.APE
from #NBITable t1 
inner join #msit_CommissionStatement cs on cs.pendingpaymentid = t1.ppid
where t1.APE <> 0

drop table #tranAPE
drop table #nbitable
drop table #prevnbi
drop table #prevape
drop table #prevape2
drop table #prevape3															--MPC :29/02/2008 (4)

set @ProcessMessage = 'ApplyAPE'												--MPC:21/01/2010
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client	--MPC:21/01/2010

--End of APE Processing

--MPC:21/01/2010  DatabaseUPDATE Changes - START
/*-----------------------------------------------------------------------------------------------
	PERFORM DATABASE UPDATES
-----------------------------------------------------------------------------------------------*/

IF @Mode = 'FULL'	--Full Refresh - Truncate Table, Drop Indexes, Insert then Create Undexes
BEGIN

	truncate table PARALLEL_msit_CommissionStatement

	if indexproperty(object_id('PARALLEL_msit_CommissionStatement'),'BusinessCode','IndexID') is not null
		DROP  INDEX PARALLEL_msit_CommissionStatement.BusinessCode 

	if indexproperty(object_id('PARALLEL_msit_CommissionStatement'),'IX_OAReports','IndexID') is not null
		DROP  INDEX PARALLEL_msit_CommissionStatement.IX_OAReports

	if indexproperty(object_id('PARALLEL_msit_CommissionStatement'),'IX_OAStatus','IndexID') is not null
		DROP  INDEX PARALLEL_msit_CommissionStatement.IX_OAStatus

	if indexproperty(object_id('PARALLEL_msit_CommissionStatement'),'IX_AgentCode','IndexID') is not null
		DROP  INDEX PARALLEL_msit_CommissionStatement.IX_AgentCode

	if indexproperty(object_id('PARALLEL_msit_CommissionStatement'),'PendingPaymentId','IndexID') is not null
		DROP  INDEX PARALLEL_msit_CommissionStatement.PendingPaymentId

	if indexproperty(object_id('PARALLEL_msit_CommissionStatement'),'PARALLEL_msit_CommissionStatement_IDX_ID','IndexID') is not null	-- Clustered so drop last
		DROP  INDEX PARALLEL_msit_CommissionStatement.PARALLEL_msit_CommissionStatement_IDX_ID 

END --  @Mode = 'FULL'

IF @Mode = 'MOVE'		--Delete existing rows in Movements List then Insert new Movements	--MPC:21/01/2010
BEGIN					--MPC:21/01/2010

	--DELETE Movements only
	DELETE FROM PARALLEL_msit_CommissionStatement		--MPC:21/01/2010
	WHERE (ReportingClassCode <> 4 AND PendingPaymentID IN (Select ID From #AGMFILChanges))	-- Changed Payment		--MPC 21/01/2010
	   OR (ReportingClassCode = 4  AND BACSExportID IN (Select ID From #BACSChanges))		-- Changed BACS Payment	--MPC 21/01/2010

	select @RowCount = @@rowcount						--MPC:21/01/2010
	set @ProcessMessage = 'Delete Data : Count = ' + convert(varchar(10), @RowCount) 	--MPC:21/01/2010
	exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client		--MPC:21/01/2010

END --@Mode = 'MOVE'		--MPC:21/01/2010

--Main Insert
insert into PARALLEL_msit_CommissionStatement(
[AgentCode], [PaymentType], [StandingOrderCode], [StandingOrderDesc], [StandingOrderText], 
[CommissionType], [JournalEntryCode], [JournalEntryDesc], [ReportingClassCode], 
[ReportingClassDesc], [BusinessCode], [SellerName], [FranchiseName], [CommProviderCode], 
[CommProviderDesc], [PaymentDate], [BACSDate], [PaymentStatus], [Amount], [DebitCredit], 
[ExtPolicyNumber], [ClientSurname], [ClientForenames], [ProductCode], [StartDate], 
[FrequencyCode], [FrequencyDesc], [Premium], [CommissionRate], [InitialPeriod], 
[FranchiseUpliftRate], [PayBasisCode], [PayBasisDesc], [CommSacrificeAmt], 
[CommSacrificePct], [AgentSplit], [FranchiseSplit], [CommFeeCode], [CommFeeType], 
[CommReason], [TotDue], [FirstID], [LastID], [ExpectCount], [TotPaid], [AccruedToDate], 
[BaseAmount], [UpliftAmount], [EnhancementRate], [INIssued], [INAccrued], 
[INStilltoAccrue], [INIndemnity], [EXIssued], [EXAccrued], [EXStilltoAccrue], 
[EXIndemnity], [DistributorRef], [DueDate], [AuthDate], [PaidListDate], [AgentPaymentsID], 
[PendingPaymentID], [ExpectationID], [TransactionID], [PolicyID], [ClientID], 
[CommissionsID], [AgtStandingOrderID], [CaseID], [APE], [CreateDate], [Month], -- [ID], 
[ProviderName], [ProviderCode], [SuspendComm], [CommShapeID], [LastAccrualinMonth], [OAStatus], --MPC:16/04/08 SR9
[ABCValue],[ABCRate],[SchemeNum],[BACSExportID]		--MPC: 21/01/2010	-- PR:16/03/09 and 13/05/08
)
select 
[AgentCode], [PaymentType], [StandingOrderCode], [StandingOrderDesc], [StandingOrderText], 
[CommissionType], [JournalEntryCode], [JournalEntryDesc], [ReportingClassCode], 
[ReportingClassDesc], [BusinessCode], [SellerName], [FranchiseName], [CommProviderCode], 
[CommProviderDesc], [PaymentDate], [BACSDate], [PaymentStatus], [Amount], [DebitCredit], 
[ExtPolicyNumber], [ClientSurname], [ClientForenames], [ProductCode], [StartDate], 
[FrequencyCode], [FrequencyDesc], [Premium], [CommissionRate], [InitialPeriod], 
[FranchiseUpliftRate], [PayBasisCode], [PayBasisDesc], [CommSacrificeAmt], 
[CommSacrificePct], [AgentSplit], [FranchiseSplit], [CommFeeCode], [CommFeeType], 
[CommReason], [TotDue], [FirstID], [LastID], [ExpectCount], [TotPaid], [AccruedToDate], 
[BaseAmount], [UpliftAmount], [EnhancementRate], [INIssued], [INAccrued], 
[INStilltoAccrue], [INIndemnity], [EXIssued], [EXAccrued], [EXStilltoAccrue], 
[EXIndemnity], [DistributorRef], [DueDate], [AuthDate], [PaidListDate], [AgentPaymentsID], 
[PendingPaymentID], [ExpectationID], [TransactionID], [PolicyID], [ClientID], 
[CommissionsID], [AgtStandingOrderID], [CaseID], [APE], [CreateDate], [Month], -- [ID], 
[ProviderName], [ProviderCode], [SuspendComm], [CommShapeID], [LastAccrualinMonth], [OAStatus], --MPC:16/04/08 SR9
[ABCValue],[ABCRate],[SchemeNum],[BACSExportID]		--MPC: 21/01/2010				-- PR:16/03/09 and 13/05/08
from #msit_CommissionStatement						--MPC: 21/01/2010
--ORDER BY ReportingClassCode,PendingPaymentID,AgentPaymentsID,BACSExportID			--MPC 21/01/2010	AG 30/03/2010

select @RowCount = @@rowcount
set @ProcessMessage = 'InsertData : Count = ' + convert(varchar(10), @RowCount)		--MPC:21/01/2010
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client		--MPC:21/01/2010

IF @Mode = 'FULL'	--Full Refresh: Create Undexes	--MPC:21/01/2010
BEGIN												--MPC:21/01/2010

	if indexproperty(object_id('PARALLEL_msit_CommissionStatement'),'PARALLEL_msit_CommissionStatement_IDX_ID','IndexID') is null	-- Clustered so create first
		CREATE  CLUSTERED INDEX [PARALLEL_msit_CommissionStatement_IDX_ID] ON [dbo].[PARALLEL_msit_CommissionStatement]([ID]) ON [PRIMARY]

	if indexproperty(object_id('PARALLEL_msit_CommissionStatement'),'BusinessCode','IndexID') is null
		CREATE  INDEX [BusinessCode] ON [dbo].[PARALLEL_msit_CommissionStatement]([BusinessCode]) ON [PRIMARY]

	if indexproperty(object_id('PARALLEL_msit_CommissionStatement'),'IX_OAReports','IndexID') is null
		CREATE  INDEX [IX_OAReports] ON [dbo].[PARALLEL_msit_CommissionStatement]([BusinessCode], [ID], [ProductCode]) ON [PRIMARY]

	if indexproperty(object_id('PARALLEL_msit_CommissionStatement'),'IX_OAStatus','IndexID') is null
		CREATE  INDEX [IX_OAStatus]  ON [dbo].[PARALLEL_msit_CommissionStatement]([OAStatus], [BusinessCode], [Month]) ON [PRIMARY]

	if indexproperty(object_id('PARALLEL_msit_CommissionStatement'),'IX_AgentCode','IndexID') is null
		CREATE  INDEX [IX_AgentCode] ON [dbo].[PARALLEL_msit_CommissionStatement]([AgentCode]) ON [PRIMARY]

	if indexproperty(object_id('PARALLEL_msit_CommissionStatement'),'PendingPaymentId','IndexID') is null
		CREATE  INDEX [PendingPaymentId] ON [dbo].[PARALLEL_msit_CommissionStatement]([PendingPaymentId]) ON [PRIMARY]

	set @ProcessMessage = 'CREATE INDEXES'											--MPC:21/01/2010
	exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client	--MPC:21/01/2010

	--Create Indexes

END --  @Mode = 'FULL'

IF @Mode = 'MOVE'											--Update Statistics	--MPC:21/01/2010
BEGIN														--MPC:21/01/2010

	UPDATE STATISTICS PARALLEL_msit_CommissionStatement		--MPC:21/01/2010

	set @ProcessMessage = 'UPDATE STATISTICS'										--MPC:21/01/2010
	exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client	--MPC:21/01/2010

END --@Mode = 'MOVE'

--MPC:21/01/2010  DatabaseUPDATE Changes - END

drop table #msit_CommissionStatement

--END
exec msp_ProcessLog @PhaseEnd, @ProcName, null, @Module, @Client		--MPC:21/01/2010






GO
/****** Object:  StoredProcedure [dbo].[PARALLEL_msp_OpenworkAdviserListingSwift]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
CREATE procedure [dbo].[PARALLEL_msp_OpenworkAdviserListingSwift]
  @Client   varchar(50),            --MPC:25/01/2010
  @Module   varchar(50),            --MPC:25/01/2010
  @Mode   varchar(4)    --'FULL' or 'MOVE'  --MPC:25/01/2010

as

--########################################################################
-- Copyright (c) MOORE STEPHENS, 2002 All rights reserved
--
-- Object  : procedure
-- Name    : PARALLEL_msp_OpenworkAdviserListingSwift.sql
-- Owner   : MR
-- Created : 24/11/2006
--
-- Call as 
--  PARALLEL_msp_OpenworkAdviserListingSwift 'Openwork', 'Open Access','MOVE'
-- OR
--  PARALLEL_msp_OpenworkAdviserListingSwift 'Openwork', 'Open Access','FULL'
--
--########################################################################

/*
  Mike Cawood 08/06/2007
  Ticket 143 - Assign Mortgage Overrides based on Product Code not Provider

  Mike Cawood 08/10/2007
  Ticket 108 - Assign APE calculated on msit_CommissionStatement

  Alan Groves 23/01/2008
  Performance improvements:
  1)  Indexes dropped before DELETE then CREATED after INSERT.
  2)  Index on AgentCode added to table msit_CommissionStatement in proc msp_CommissionStatement
    to make INSERT faster.

  Alan Groves 25/01/2008
  performance improvements:
  1) DROP the clustered index last to ensure the NonClus indexes aren't rebuilt - this really happens!
  2) DROP "source" index before DELETE as the execution plan with no indexes is simpler.
  Note that the CREATE INDEX statements are already in the right sequence.

  Mike Cawood 16/04/2008 
  SR9 - Only include Entries where OAStatus = 'Valid'
  SR9 - Zeroise APE if LeagueInclude flag on ProductHierarchy is not 'Y'

  Paul Robathan May 2008
  ABC Currency Project.  Insert ABC Value/Rate from msit_commissionstatement

  Paul Robathan Mar 2009
  Add SchemeNum and ProductGroup to the table for showing on Open Access

  Paul Robathan - 27th Apr 2009
  Margin on Trail.  Set Commission Rate for Trail Cases split with Openwork to show pre split value
  i.e. if rate 80% agent 20% openwork then show Agent comm Rate as 100%

  Mike Cawood - 25 January 2010
  a) Performance Improvements. New Run Control parameter @mode added with two settings:

    'FULL': This triggers the full refresh of the Swift data held on the
        msit_OpenworkAdviserListing table using the primary keys held on the 
        owt_TransformationMovements table. All existing Swift rows (identified by
        Source of 'Openwork 2006') are deleted. The load table indexes are dropped 
        and recreated after the insert.

    'MOVE': In this mode only those Swift rows that are linked to daily movements of the
        driver sa_swift_S_AGMFIL table are processed. The primary keys of these movements 
        are held on the owt_TransformationMovements table with DriverTableName of
        'sa_swift_S_AGMFIL' (as thses movements are used to drive updates to the rows on
        the msit_CommissionStatement table with ReportingClassCode of 1). 
        All msit_CommissionStatement rows with Source of 'Openwork 2006' whose SourceID 
        matches to a primary key held on the movements table are deleted and then 
        inserted from the new data generated by the procedure. 
        Indexes are not dropped/created in this mode.
  
  b) Process Log processing introduced.

  Mike Cawood - 9 February 2010 
  a)  Fix to Delete step of Movements mode.

  Mike Cawood - 10 February 2010 
  a)  Fix to use PARALLEL version of msit_CommissionStatement.
  b)  Fix to use msit_CommissionStatement ID's captured on owt_TransformationMovements
    as driver for Delete step of 'MOVE' Mode. These ID's relate to the 
    sa_swift_S_AGMFIL movements captured on owt_TransformationMovements.

  Alan Groves - 30 March 2010
  a)  Used flag "AdviserListing" to reduce number of rows to process in "MOVE" mode.

  Alan Groves - 16 April 2010
  a)  CREATE and DROP indexes conditionally to improve robustness.
 
*/

--MPC:25/01/2010 New ProcessLog Start
declare   @PhaseStart     varchar(50),
      @PhaseEnd     varchar(50),
      @ProcName     varchar(100),
      @ProgressModule   varchar(50),
      @RowCount     int,
      
      @ProcessMessage   varchar(100)

set @ProcName   = object_name(@@procid) + ' - ' + @Mode
set @PhaseStart   = 'START'
set @PhaseEnd   = 'END'
set @ProgressModule = 'OAL'

exec msp_ProcessLog @PhaseStart, @ProcName, null, @Module, @Client
--MPC:25/01/2010 New ProcessLog End

declare @OpenworkMarginPotCode  nvarchar(10),   -- PR 27/4/2009
    @OpenworkMarginScriptDate  datetime     -- PR 27/4/2009

set @OpenworkMarginPotCode = (select Rtrim(longdescription) from msit_MIWarehouseCodesAndDescriptions 
          where columnname = 'OpenworkMarginOnTrail' and description = 'AgentCode') -- PR 27/04/2009
set @OpenworkMarginScriptDate = (select cast(longdescription as datetime) from msit_MIWarehouseCodesAndDescriptions 
          where  columnname = 'OpenworkMarginOnTrail' and description = 'ScriptDate') -- PR 27/04/2009

/******************************************************************************************************************
    FULL REFRESH MODE
******************************************************************************************************************/

IF @Mode = 'FULL'   --MPC:25/01/2010
BEGIN         --MPC:25/01/2010

  if indexproperty(object_id('PARALLEL_msit_OpenworkAdviserListing'),'PARALLEL_BusinessCode','IndexID') is not null
    DROP INDEX PARALLEL_msit_OpenworkAdviserListing.PARALLEL_BusinessCode

  if indexproperty(object_id('PARALLEL_msit_OpenworkAdviserListing'),'PARALLEL_IX_OpenworkAdviserListing_Month','IndexID') is not null
    DROP INDEX PARALLEL_msit_OpenworkAdviserListing.PARALLEL_IX_OpenworkAdviserListing_Month

  if indexproperty(object_id('PARALLEL_msit_OpenworkAdviserListing'),'PARALLEL_IX_OpenworkAdviserListing_Policy','IndexID') is not null
    DROP INDEX PARALLEL_msit_OpenworkAdviserListing.PARALLEL_IX_OpenworkAdviserListing_Policy

  if indexproperty(object_id('PARALLEL_msit_OpenworkAdviserListing'),'PARALLEL_IX_OpenworkAdviserListing_alID','IndexID') is not null
    DROP INDEX PARALLEL_msit_OpenworkAdviserListing.PARALLEL_IX_OpenworkAdviserListing_alID

  if indexproperty(object_id('PARALLEL_msit_OpenworkAdviserListing'),'PARALLEL_IX_OpenworkAdviserListing_TransactionID','IndexID') is not null
    DROP INDEX PARALLEL_msit_OpenworkAdviserListing.PARALLEL_IX_OpenworkAdviserListing_TransactionID

  if indexproperty(object_id('PARALLEL_msit_OpenworkAdviserListing'),'PARALLEL_IX_OpenworkdviserListing_Source','IndexID') is not null
    DROP INDEX PARALLEL_msit_OpenworkAdviserListing.PARALLEL_IX_OpenworkdviserListing_Source

  if indexproperty(object_id('PARALLEL_msit_OpenworkAdviserListing'),'PARALLEL_IX_OpenworkAdviserListing_SchemeNum','IndexID') is not null
    DROP INDEX PARALLEL_msit_OpenworkAdviserListing.PARALLEL_IX_OpenworkAdviserListing_SchemeNum    -- PR 16 Mar 2009

  if indexproperty(object_id('PARALLEL_msit_OpenworkAdviserListing'),'PARALLEL_IX_OpenworkAdviserListing_SourceId','IndexID') is not null
    DROP INDEX PARALLEL_msit_OpenworkAdviserListing.PARALLEL_IX_OpenworkAdviserListing_SourceId     --MPC:25/01/2010

  if indexproperty(object_id('PARALLEL_msit_OpenworkAdviserListing'),'PARALLEL_IX_msit_OpenworkAdviserListing','IndexID') is not null
    DROP INDEX PARALLEL_msit_OpenworkAdviserListing.PARALLEL_IX_msit_OpenworkAdviserListing -- Clustered index so drop last for efficiency

  set @ProcessMessage = @Mode + ' - 01) End DROP INDEX'             --MPC:25/01/2010
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client  --MPC:25/01/2010

  Delete PARALLEL_msit_OpenworkAdviserListing
  where Source = 'Openwork 2006'

  select @RowCount = @@rowcount                           --MPC:25/01/2010
  set @ProcessMessage = @Mode + ' - 02) End DELETE : Count = ' + convert(varchar(10), @RowCount) --MPC:25/01/2010
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client    --MPC:25/01/2010

  -- INSERT SWIFT DATA
  insert into
   PARALLEL_msit_OpenworkAdviserListing
  select
   BusinessCode     = cs.BusinessCode,
   BusinessName     = cs.FranchiseName,
   SellerCode       = cs.AgentCode,
   SellerName       = cast(cs.SellerName as varchar(50)) + ' - ' + cs.AgentCode,
   SellerForename   = case
             when charindex(' ', a.FirstNames) = 0 then a.FirstNames
             else rtrim(substring(a.FirstNames, 1, charindex(' ', a.FirstNames)))
            end,
   SellerSurname    = a.[Name],
   Client           = cast(cs.ClientSurname as varchar(60)) + case when cs.ClientForenames is null then '' else ' ' + cast(cs.ClientForenames as varchar(1)) end,
   ClientForname    = case
             when charindex(' ', cs.ClientForenames) = 0 then cs.ClientForenames
             else rtrim(substring(cs.ClientForenames, 1, charindex(' ', cs.ClientForenames)))
            end,
   ClientSurname    = cs.ClientSurname,
   BACSDate         = cs.BACSDate,
   Policy           = cs.ExtPolicyNumber,
   CaseId           = cs.CaseId,
  -- ProdType         = case when CommProviderCode = 'MORTGAGE' then cs.CommProviderCode  --Ticket143
   ProdType         = case when ph.productgroupcode = 3 then cs.CommProviderCode    --Ticket143
        else cs.ProductCode end,
   StartDate        = cs.StartDate,
   PaymentDate      = cs.PaymentDate,
   Frequency        = cast(cs.FrequencyDesc as varchar(1)),
   Premium          = cs.Premium,
   APE    = case                  --SR9: MPC 16/04/08
         when isnull(ph.LeagueIncludeFlag,'N') = 'Y' then  isnull(cs.APE,0.0) --SR9: MPC 16/04/08
         else 0.0               --SR9: MPC 16/04/08
         end,                   --SR9: MPC 16/04/08
  -- APE             = isnull(cs.APE,0.0),      --Ticket 108  --SR9: MPC 16/04/08
  -- APE              = case              --Ticket 108
  --                     when cs.INIssued > 0 or cs.INIndemnity > 0 then cs.APE   --Ticket 108
  --                     else 0.0           --Ticket 108
  --                    end,              --Ticket 108
   CommRate         = cs.CommissionRate,
   InitialPeriod    = cs.InitialPeriod,
   PayBasis         = cast(cs.PayBasisDesc as varchar(10)),
   Sacrifice        = cs.CommSacrificeAmt,
   --AgentSplit       = cs.AgentSplit,        -- PR 27/04/09
   AgentSplit       = case 
        when (cs.AgentSplit between 1 and 99) and cs.CommissionType in (10) and DueDate >= @OpenworkMarginScriptDate then
           isnull((cs.AgentSplit/(100-
            isnull((select Agent_Perc from mstt_PaymentsPending where agent_code = @OpenworkMarginPotCode and 
                   TransactionID=cs.TransactionID and pacc_ID=cs.expectationid),0))) * 100, cs.AgentSplit)
        else
          cs.AgentSplit
        end,

   FeeType          = cast(cs.CommFeeType as varchar(10)),
  -- Remarks          = case when CommProviderCode = 'MORTGAGE'   --Ticket143
   Remarks          = case when ph.productgroupcode = 3     --Ticket143 
        then (select substring(cd.Description,1,150) from msit_MIWarehouseCodesandDescriptions cd
        WHERE cd.ColumnName = 'CodeCommissionShapeID'
        and cd.Code = cs.CommShapeID)
        else cs.CommReason end,
   Provider         =  cs.ProviderName,                    
   ProviderCode     = cs.ProviderCode,
   SourceID         = cs.[Id],
   ListPosition     = NULL,
   [Month]          = cs.[Month],
   Source           = 'Openwork 2006',
   TotDue_Base      = isnull(cs.EXIssued, 0.0),
   Accrued_Base     = isnull(cs.EXAccrued, 0.0),
   StillToAccr_Base = isnull(cs.EXStilltoAccrue, 0.0),
   ITAdvanced_Base  = isnull(cs.EXIndemnity, 0.0),
   EnhancementRate  = isnull(cs.FranchiseUpliftRate, 0.0),
   TotDue_Enhd      = isnull(cs.INIssued, 0.0),
   Accrued_Enhd     = isnull(cs.INAccrued, 0.0),
   StillToAccr_Enhd = isnull(cs.INStilltoAccrue, 0.0),
   ITAdvanced_Endh  = isnull(cs.INIndemnity, 0.0),
   TotalPayment     = isnull(cs.INAccrued, 0.0) + isnull(cs.INIndemnity, 0.0),
   DistributorRef   = cs.DistributorRef,
   CreateDate   = cs.CreateDate,      -- WI260
   TransactionID    = cs.TransactionID,   -- WI260
   ABCValue       = cs.ABCValue,      --PR ABC May 2008
   ABCRate        =  cs.ABCRate,      --PR ABC May 2008
   SchemeNum        =  cs.SchemeNum,    --PR Mar 2009
   ProductGroup   = case        --PR Mar 2009
              when ph.StructuredProduct = 'Y' then 'Structured' 
              else COALESCE(ph.productgroupname,'Unknown')
            end
   from
   PARALLEL_msit_CommissionStatement cs
   inner join mstt_Agents a on cs.AgentCode = a.Code
   left outer join mstt_producthierarchy ph on ph.productcode = cs.productcode  --Ticket143
  where
   cs.ReportingClassCode = 1
   and cs.OAStatus = 'Valid'                            --MPC: 16/04/2008 SR9

  select @RowCount = @@rowcount                         --MPC:25/01/2010
  set @ProcessMessage = @Mode + ' - 03) End INSERT : Count = ' + convert(varchar(10), @RowCount) --MPC:25/01/2010
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client  --MPC:25/01/2010

  if indexproperty(object_id('PARALLEL_msit_OpenworkAdviserListing'),'PARALLEL_IX_msit_OpenworkAdviserListing','IndexID') is null
    CREATE  CLUSTERED  INDEX [PARALLEL_IX_msit_OpenworkAdviserListing] ON [dbo].[PARALLEL_msit_OpenworkAdviserListing]([BusinessCode], [Month], [Source]) ON [PRIMARY] -- Needs to be first!

  if indexproperty(object_id('PARALLEL_msit_OpenworkAdviserListing'),'PARALLEL_BusinessCode','IndexID') is null
    CREATE  INDEX [PARALLEL_BusinessCode] ON [dbo].[PARALLEL_msit_OpenworkAdviserListing]([BusinessCode]) ON [PRIMARY]

  if indexproperty(object_id('PARALLEL_msit_OpenworkAdviserListing'),'PARALLEL_IX_OpenworkAdviserListing_Month','IndexID') is null
    CREATE  INDEX [PARALLEL_IX_OpenworkAdviserListing_Month] ON [dbo].[PARALLEL_msit_OpenworkAdviserListing]([Month]) ON [PRIMARY]

  if indexproperty(object_id('PARALLEL_msit_OpenworkAdviserListing'),'PARALLEL_IX_OpenworkdviserListing_Source','IndexID') is null
    CREATE  INDEX [PARALLEL_IX_OpenworkdviserListing_Source] ON [dbo].[PARALLEL_msit_OpenworkAdviserListing]([Source]) ON [PRIMARY]

  if indexproperty(object_id('PARALLEL_msit_OpenworkAdviserListing'),'PARALLEL_IX_OpenworkAdviserListing_Policy','IndexID') is null
    CREATE  INDEX [PARALLEL_IX_OpenworkAdviserListing_Policy] ON [dbo].[PARALLEL_msit_OpenworkAdviserListing]([Policy]) ON [PRIMARY]

  if indexproperty(object_id('PARALLEL_msit_OpenworkAdviserListing'),'PARALLEL_IX_OpenworkAdviserListing_alID','IndexID') is null
    CREATE  INDEX [PARALLEL_IX_OpenworkAdviserListing_alID] ON [dbo].[PARALLEL_msit_OpenworkAdviserListing]([alID]) ON [PRIMARY]

  if indexproperty(object_id('PARALLEL_msit_OpenworkAdviserListing'),'PARALLEL_IX_OpenworkAdviserListing_TransactionID','IndexID') is null
    CREATE  INDEX [PARALLEL_IX_OpenworkAdviserListing_TransactionID] ON [dbo].[PARALLEL_msit_OpenworkAdviserListing]([TransactionID]) ON [PRIMARY]

  if indexproperty(object_id('PARALLEL_msit_OpenworkAdviserListing'),'PARALLEL_IX_OpenworkAdviserListing_SchemeNum','IndexID') is null
    CREATE  INDEX [PARALLEL_IX_OpenworkAdviserListing_SchemeNum] ON [dbo].[PARALLEL_msit_OpenworkAdviserListing]([SchemeNum]) ON [PRIMARY]  -- PR Mar 2009

  if indexproperty(object_id('PARALLEL_msit_OpenworkAdviserListing'),'PARALLEL_IX_OpenworkAdviserListing_SourceId','IndexID') is null
    CREATE  INDEX [PARALLEL_IX_OpenworkAdviserListing_SourceId] ON [dbo].[PARALLEL_msit_OpenworkAdviserListing]([Source],[SourceId]) ON [PRIMARY]  --MPC:25/01/2010

  set @ProcessMessage = @Mode + ' - 04) End CREATE INDEX'             --MPC:25/01/2010
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client  --MPC:25/01/2010

END   --@Mode = 'FULL'    --MPC:25/01/2010

/******************************************************************************************************************
    MOVEMENTS ONLY MODE
******************************************************************************************************************/

--MPC:25/01/2010  Movements Only - START
IF @Mode = 'MOVE'   
BEGIN

  -- AG 30/03/2010 Start
  --Delete PARALLEL_msit_OpenworkAdviserListing
  --Where Source = 'Openwork 2006'
  --and SourceID IN (Select Distinct PKID From owt_TransformationMovements        --MPC:10/02/2010
  --           where DriverTableName = 'msit_CommissionStatement')      --MPC:10/02/2010

  Delete  OAL
  from  PARALLEL_msit_OpenworkAdviserListing OAL
      inner join owt_TransformationMovements TM on TM.PKID = OAL.SourceID 
  Where OAL.Source = 'Openwork 2006'
  and   TM.DriverTableName = 'msit_CommissionStatement'
  and   TM.AdviserListing = 'Y'
  -- AG 30/03/2010 End

  select @RowCount = @@rowcount                           
  set @ProcessMessage = @Mode + ' - 01) End DELETE : Count = ' + convert(varchar(10), @RowCount) 
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client        

  -- INSERT SWIFT DATA
  insert into
   PARALLEL_msit_OpenworkAdviserListing
  select
   BusinessCode     = cs.BusinessCode,
   BusinessName     = cs.FranchiseName,
   SellerCode       = cs.AgentCode,
   SellerName       = cast(cs.SellerName as varchar(50)) + ' - ' + cs.AgentCode,
   SellerForename   = case
             when charindex(' ', a.FirstNames) = 0 then a.FirstNames
             else rtrim(substring(a.FirstNames, 1, charindex(' ', a.FirstNames)))
            end,
   SellerSurname    = a.[Name],
   Client           = cast(cs.ClientSurname as varchar(60)) + case when cs.ClientForenames is null then '' else ' ' + cast(cs.ClientForenames as varchar(1)) end,
   ClientForname    = case
             when charindex(' ', cs.ClientForenames) = 0 then cs.ClientForenames
             else rtrim(substring(cs.ClientForenames, 1, charindex(' ', cs.ClientForenames)))
            end,
   ClientSurname    = cs.ClientSurname,
   BACSDate         = cs.BACSDate,
   Policy           = cs.ExtPolicyNumber,
   CaseId           = cs.CaseId,
  -- ProdType         = case when CommProviderCode = 'MORTGAGE' then cs.CommProviderCode  --Ticket143
   ProdType         = case when ph.productgroupcode = 3 then cs.CommProviderCode    --Ticket143
        else cs.ProductCode end,
   StartDate        = cs.StartDate,
   PaymentDate      = cs.PaymentDate,
   Frequency        = cast(cs.FrequencyDesc as varchar(1)),
   Premium          = cs.Premium,
   APE    = case                  --SR9: MPC 16/04/08
         when isnull(ph.LeagueIncludeFlag,'N') = 'Y' then  isnull(cs.APE,0.0) --SR9: MPC 16/04/08
         else 0.0               --SR9: MPC 16/04/08
         end,                 --SR9: MPC 16/04/08
  -- APE             = isnull(cs.APE,0.0),            --Ticket 108  --SR9: MPC 16/04/08
  -- APE              = case                --Ticket 108
  --                     when cs.INIssued > 0 or cs.INIndemnity > 0 then cs.APE   --Ticket 108
  --                     else 0.0               --Ticket 108
  --                    end,                --Ticket 108
   CommRate         = cs.CommissionRate,
   InitialPeriod    = cs.InitialPeriod,
   PayBasis         = cast(cs.PayBasisDesc as varchar(10)),
   Sacrifice        = cs.CommSacrificeAmt,
   --AgentSplit       = cs.AgentSplit,    -- PR 27/04/09
   AgentSplit       = case 
        when (cs.AgentSplit between 1 and 99) and cs.CommissionType in (10) and DueDate >= @OpenworkMarginScriptDate then
           isnull((cs.AgentSplit/(100-
            isnull((select Agent_Perc from mstt_PaymentsPending where agent_code = @OpenworkMarginPotCode and 
                   TransactionID=cs.TransactionID and pacc_ID=cs.expectationid),0))) * 100, cs.AgentSplit)
        else
          cs.AgentSplit
        end,

   FeeType          = cast(cs.CommFeeType as varchar(10)),
  -- Remarks          = case when CommProviderCode = 'MORTGAGE'   --Ticket143
   Remarks          = case when ph.productgroupcode = 3   --Ticket143 
        then (select substring(cd.Description,1,150) from msit_MIWarehouseCodesandDescriptions cd
        WHERE cd.ColumnName = 'CodeCommissionShapeID'
        and cd.Code = cs.CommShapeID)
        else cs.CommReason end,
   Provider         =  cs.ProviderName,                    
   ProviderCode     = cs.ProviderCode,
   SourceID         = cs.[Id],
   ListPosition     = NULL,
   [Month]          = cs.[Month],
   Source           = 'Openwork 2006',
   TotDue_Base      = isnull(cs.EXIssued, 0.0),
   Accrued_Base     = isnull(cs.EXAccrued, 0.0),
   StillToAccr_Base = isnull(cs.EXStilltoAccrue, 0.0),
   ITAdvanced_Base  = isnull(cs.EXIndemnity, 0.0),
   EnhancementRate  = isnull(cs.FranchiseUpliftRate, 0.0),
   TotDue_Enhd      = isnull(cs.INIssued, 0.0),
   Accrued_Enhd     = isnull(cs.INAccrued, 0.0),
   StillToAccr_Enhd = isnull(cs.INStilltoAccrue, 0.0),
   ITAdvanced_Endh  = isnull(cs.INIndemnity, 0.0),
   TotalPayment     = isnull(cs.INAccrued, 0.0) + isnull(cs.INIndemnity, 0.0),
   DistributorRef   = cs.DistributorRef,
   CreateDate   = cs.CreateDate,    -- WI260
   TransactionID    = cs.TransactionID,     -- WI260
   ABCValue       = cs.ABCValue,      --PR ABC May 2008
   ABCRate        =  cs.ABCRate,      --PR ABC May 2008
   SchemeNum        =  cs.SchemeNum,    --PR Mar 2009
   ProductGroup   = case        --PR Mar 2009
              when ph.StructuredProduct = 'Y' then 'Structured' 
              else COALESCE(ph.productgroupname,'Unknown')
            end
   from
   PARALLEL_msit_CommissionStatement cs
   inner join mstt_Agents a on cs.AgentCode = a.Code
   left outer join mstt_producthierarchy ph on ph.productcode = cs.productcode    --Ticket143
  where
   cs.ReportingClassCode = 1
   and cs.OAStatus = 'Valid'            --MPC: 16/04/2008 SR9
   -- PKID occurs lots of times for criteria, therefore a conventional join would have created dupes.
   and cs.PendingPaymentID IN (Select Distinct PKID From owt_TransformationMovements  --MPC:25/01/2010
                 where  DriverTableName = 'sa_swift_S_AGMFIL'     --MPC:25/01/2010
                 and  AdviserListing = 'Y')             -- AG 30/03/2010

  select @RowCount = @@rowcount                           
  set @ProcessMessage = @Mode + ' - 02) End INSERT : Count = ' + convert(varchar(10), @RowCount)
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client    

  UPDATE STATISTICS PARALLEL_msit_OpenworkAdviserListing

  set @ProcessMessage = @Mode + ' - 04) End UPDATE STATISTICS'            --MPC:25/01/2010
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client    --MPC:25/01/2010

END   --@Mode = 'MOVE'

--MPC:25/01/2010  Movements Only - END

/******************************************************************************************************************
    END of PROCESSING
******************************************************************************************************************/

--END
exec msp_ProcessLog @PhaseEnd, @ProcName, null, @Module, @Client    --MPC:25/01/2010









GO
/****** Object:  StoredProcedure [dbo].[PARALLEL_mstp_Commissions]    Script Date: 7/3/2026 3:44:25 PM ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO

/*********************************************************************************************************

-- Object  : procedure
-- Name    : PARALLEL_mstp_Commissions.sql
-- Owner   : CTT
-- Created : 26/10/2005
--
-- Call as 
--  PARALLEL_mstp_Commissions 'Openwork', 'Open Access','MOVE'
-- OR
--  PARALLEL_mstp_Commissions 'Openwork', 'Open Access','FULL'
--

Copyright (C) Moore Stephens Consulting Limited 2005

Date    Amended By  Change Details
========  ==========  ==============
16/01/08  M Cawood  Ensure APE and Turnover are positive on Splits

13/02/08  A Groves  Performance Improvements:
          1) Moved a number of updates into the insert
          2) If AdminMethod is changed to 'A' then AdminMethodDescription is also changed.
          3) Indexes dropped before final INSERT into mstt_Commissions then re-created. 
             This will improve INSERT speed and re-calc index statistics.
          4) Added TransactionDateTrunc to #mstt_Commissions to enable index to be used 
             when updating Agent History.

        Bug fix: Join mstt_CommTranInitialDate on ID not TransactionID (TransactionMonth).

22/04/08  M Cawood  SR9 Changes to derivation of FIRM
          1) Only use Valid TASHH records to derive Firm
          2) If no Valid TASHH apply Firm from AgentHierarchy with default of mstt_Agents.Firm
          3) Performance improvements

18/09/09  M Cawood  SR10 Changes - new OBP OriginatingSource codes
          1) Set Description to SWIFT msit_CodeOriginatingSources.CODE

25/01/10  M Cawood  Performance Improvements

  1) Use parameters to call Process Log displaying row counts where relevant.
  2) Replace msit_S_AGTCOM by sa_swift_S_AGTCOM.
  3) Replace msit_transagentsplithierarchyhistory by sa_swift_transagentsplithierarchyhistory.
  4) Replace msit_AgentHierarchyHistory by sa_swift_AgentHierarchyHistory.
  5) Performance Improvements. New Run Control parameter @mode added with two settings:

    'FULL': This triggers the full refresh of the mstt_Commissions table using the
        primary keys held on the owt_TransformationMovements table. All existing rows 
        are deleted. The load table indexes are dropped and recreated after the insert.

    'MOVE': In this mode only those rows that are linked to daily movements of the Driver
        sa_swift_S_AGTCOM table are processed. The primary keys of these movements 
        are held on the owt_TransformationMovements table with DriverTableName of
        'sa_swift_S_AGTCOM'. All mstt_Commission rows with whose ID matches to a primary 
        key held on the movements table are deleted and then inserted from the new data 
        generated by the procedure. Indexes are not dropped/created in this mode.

30/03/2010  A Groves  Use flag owt_TransformationMovements.CommissionSplits to minimise the
            number of rows to process.
26/08/2010  A Groves  Change reference of table mstt_swift_TransAgentSplitHierarchyHistory
            to sa_swift_TransAgentSplitHierarchyHistory
*************************************************************************************************************/
CREATE PROCEDURE [dbo].[PARALLEL_mstp_Commissions]
  @Client   varchar(50),            --MPC:25/01/2010
  @Module   varchar(50),            --MPC:25/01/2010
  @Mode   varchar(4)    --'FULL' or 'MOVE'  --MPC:25/01/2010

AS

--MPC:25/01/2010 New ProcessLog Start
declare   @PhaseStart     varchar(50),
      @PhaseEnd     varchar(50),
      @ProcName     varchar(100),
      @ProgressModule   varchar(50),
      @RowCount     int,
      @ProcessMessage   varchar(100)

set @ProcName   = object_name(@@procid) + ' - ' + @Mode
set @PhaseStart   = 'START'
set @PhaseEnd   = 'END'
set @ProgressModule = 'COM'

exec msp_ProcessLog @PhaseStart, @ProcName, null, @Module, @Client
--exec msp_ProcessLog 'COM', 'Start', null, 'COM', 'Openwork'

--MPC:25/01/2010 New ProcessLog End

--MPC:25/01/2010 New Movements Processing - START
/******************************************************************************************************************
    DERIVE MOVEMENTS
******************************************************************************************************************/
CREATE TABLE #AGTCOMChanges (ID int)
CREATE INDEX #X ON #AGTCOMCHANGES (ID)

CREATE TABLE #TASHHChanges (ID int)
CREATE INDEX #X ON #TASHHCHANGES (ID)

IF @Mode = 'FULL' --FULL Reload of Table
BEGIN

  Insert INTO #AGTCOMCHANGES
  Select Distinct ID 
  from sa_swift_S_AGTCOM 

  select @RowCount = @@rowcount
  set @ProcessMessage = @Mode + ' - Identify S_AGTCOM Movements : Count = ' + convert(varchar(10), @RowCount)   
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client

  Insert INTO #TASHHCHANGES
  Select Distinct ID 
  from sa_swift_TransAgentSplitHierarchyHistory 

  select @RowCount = @@rowcount
  set @ProcessMessage =  @Mode + ' - Identify TASHH Movements : Count = ' + convert(varchar(10), @RowCount)   
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client

END --@Mode = 'FULL'

IF @Mode = 'MOVE' --Process Movements only
BEGIN

  Insert  INTO #AGTCOMCHANGES
  Select  DISTINCT PKID as ID
  FROM  owt_TransformationMovements
  Where DriverTableName = 'sa_swift_S_AGTCOM'
  and   CommissionSplits = 'Y'            -- AG 30/03/2010

  select @RowCount = @@rowcount
  set @ProcessMessage = @Mode + ' - Identify S_AGTCOM Movements : Count = ' + convert(varchar(10), @RowCount)   
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client

  Insert  INTO #TASHHCHANGES
  Select  DISTINCT PKID as ID
  FROM  owt_TransformationMovements
  Where DriverTableName = 'sa_swift_TransAgentSplitHierarchyHistory'
  and   CommissionSplits = 'Y'            -- AG 30/03/2010

  select @RowCount = @@rowcount
  set @ProcessMessage = @Mode + ' - Identify TASHH Movements : Count = ' + convert(varchar(10), @RowCount)    
  exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client

END   --@Mode = 'MOVE'
--MPC:25/01/2010 New Movements Processing - END

--START of SR9(1) :MPC 22/04/08
select TASHH.ID,
case 
when (franchiseagentcode is null and accessagentcode is null and directlyauthorisedagentcode is null) then 'E01'
when (franchiseagentcode is not null and accessagentcode is not null) then 'E02'
when (franchiseagentcode is not null and directlyauthorisedagentcode is not null) then 'E03'
when (accessagentcode is not null and directlyauthorisedagentcode is not null) then 'E04'
when (franchiseagentcode is not null and franchiseagentcode not in (select code from mstt_agents where agenttype = 2) ) then 'E05'
when (accessagentcode is not null and accessagentcode not in (select code from mstt_agents where agenttype = 46) ) then 'E06'
when (directlyauthorisedagentcode is not null and directlyauthorisedagentcode not in (select code from mstt_agents where agenttype = 49) ) then 'E07'
when (manager2code is null or manager2code not in (select code from mstt_agents where agenttype = 53) ) then 'E08'
when (organisationagentcode is null or organisationagentcode not in (select code from mstt_agents where agenttype = 19) ) then 'E09'
when (companyagentcode is null or companyagentcode not in (select code from mstt_agents where agenttype = 42) ) then 'E10'
end as ErrCode
into #InvalidTASHH
from sa_swift_transagentsplithierarchyhistory TASHH --MPC:25/01/2010
inner join #TASHHCHANGES X ON X.ID = TASHH.ID     --MPC:25/01/2010
where ACTIVE = 1 and ( 
   (franchiseagentcode is null and accessagentcode is null and directlyauthorisedagentcode is null)
or (franchiseagentcode is not null and accessagentcode is not null) 
or (franchiseagentcode is not null and directlyauthorisedagentcode is not null) 
or (accessagentcode is not null and directlyauthorisedagentcode is not null)
or (franchiseagentcode is not null and franchiseagentcode not in (select code from mstt_agents where agenttype = 2) )
or (accessagentcode is not null and accessagentcode not in (select code from mstt_agents where agenttype = 46) )
or (directlyauthorisedagentcode is not null and directlyauthorisedagentcode not in (select code from mstt_agents where agenttype = 49) )
or (manager2code is null or manager2code not in (select code from mstt_agents where agenttype = 53) )
or (organisationagentcode is null or organisationagentcode not in (select code from mstt_agents where agenttype = 19) )
or (companyagentcode is null or companyagentcode not in (select code from mstt_agents where agenttype = 42) )
)
order by TASHH.ID

select @RowCount = @@rowcount     --MPC:25/01/2010
set @ProcessMessage = @Mode + ' - Invalid TASHH : Count = ' + convert(varchar(10), @RowCount) --MPC:25/01/2010  
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client  --MPC:25/01/2010

create clustered index idx_ID on #InvalidTASHH(ID)

-- END of SR9(1)  :MPC 22/04/08

select *, TransactionDate as TransactionDateTrunc 
into #mstt_Commissions from mstt_Commissions 
WHERE 1=0

--Get the data from the Import Table
insert into #mstt_Commissions
  (
  AGENT_CODE, 
  AGENT_PERC, 
  ID, 
  CommissionType, 
  CommissionTypeDesc, 
  BasedOn, 
  BasedOnDesc,  
  FixedAmount, 
  PaymentBasis, 
  GrossOrNet, 
  PolicyID, 
  ProductCode, 
  CLIENT_NUM, 
  JOINT_NUM, 
  TransactionID, 
  TransactionDate,
  TransactionDateTrunc, 
  TransactionWrittenDate, 
  PolTranTransactionDate,
  PolTranTransactionWrittenDate,
  PolTranTransType, 
  ProposalDate,
  APE, 
  SplitMargin,
  CodeCommissionShapeID,
  AdminMethod,
  AdminMethodDescription,
  BusinessReason,
  BusinessReasonDescription,
  Frequency,
  CommType,
  OriginatingSource,
  OriginatingSourceDescription,
  FranchiseUpliftPercent, 
  BaseAmount, 
  UpliftAmount, 
  StrategicAllianceAgentCode, 
  AccessAgentCode, 
  FranchiseAgentCode, 
  CompanyAgentCode, 
  OrganisationAgentCode, 
  DirectlyAuthorisedAgentCode, 
  Manager1Code, 
  Manager2Code, 
  Manager3Code, 
  Manager4Code, 
  FranchiseSize, 
  PracticeTypeCode,
  ProductType,
  ReportingProductCode,
  ProductSubGroupCode,
  ProductGroupCode,
  ProductCategoryCode,
  ProductProviderCode,
  ReportingProductProviderCode,
  CommRepProductProviderCode,
  Firm,
  CommissionMonth,
  IssuedDate,
  TransactionMonth
  )
select 
  a.AGENT_CODE, 
  a.AGENT_PERC, 
  a.ID, 
  a.CommissionType, 
  (select dl.Description            --CommissionTypeDesc 
   from msdt_DropLists dl
   where  convert(varchar(50),a.CommissionType) = dl.Code 
   and  dl.CodeType = 'CommissionType'), 
  a.BasedOn, 
  (select dl.Description            --BasedOnDesc 
   from msdt_DropLists dl
   where  convert(varchar(50),a.BasedOn) = dl.Code  
   and  dl.CodeType = 'CommissionBasedOn'),
  a.FixedAmount, 
  a.PaymentBasis, 
  a.GrossOrNet, 
  pt.PolicyID as PolicyID,                    --From mstt_PolicyTransactions, linked via TransactionID 
  coalesce(pt.CommProductCode, p.ProductCode) as ProductCode, --From mstt_Policies, linked via PolicyID
  p.CLIENT_NUM as CLIENT_NUM,                 --From mstt_Policies, linked via PolicyID
  p.JOINT_NUM as JOINT_NUM,                   --From mstt_Policies, linked via PolicyID
  a.TransactionID, 
  CommTranInitDate.TransactionDate as TransactionDate, --From mstt_CommTranInitialDate: CR 58 
  dateadd(d, 0, datediff(d, 0, CommTranInitDate.TransactionDate)) as TransactionDateTrunc,
  case pt.TransType             --TransactionDateTrunc has time element set to zero
     when 39 then CommTranInitDate.TransactionDate
     else pt.WrittenDate          --SR9(3) :MPC 22/04/08
  end as TransactionWrittenDate,              --From mstt_CommTranInitialDate: CR 58
  pt.TransactionDate as PolTranTransactionDate, --From mstt_PolicyTransactions, linked via TransactionID - CR 58
  pt.TransactionWrittenDate as PolTranTransactionWrittenDate, --From mstt_PolicyTransactions, linked via TransactionID - CR 58
  pt.TransType as PolTranTransType,           --From mstt_PolicyTransactions, linked via TransactionID 
  pt.ProposalDate as ProposalDate,            --From mstt_PolicyTransactions, linked via TransactionID 
  abs(pt.APE * (a.AGENT_PERC / 100)) as APE,  --From mstt_PolicyTransactions, linked via TransactionID :MPC 16/01/08
  null as SplitMargin,                        --Derived below
  pt.CodeCommissionShapeID as CodeCommissionShapeID, --From mstt_PolicyTransactions, linked via TransactionID 
  coalesce(pt.AdminMethod, 'A') as AdminMethod, --From mstt_PolicyTransactions, linked via TransactionID
              --ID262 - Set null AdminMethod to 'A' so that it is included as New Business
  (select dl.Description      --AdminMethodDescription
   from msdt_DropLists dl
   where  coalesce(pt.AdminMethod, 'A') = dl.Code 
   and  dl.CodeType = 'AdminMethod'),     
--  MICodesAndDescs.Description as BusinessReason, --From msit_MIWarehouseCodesAndDescriptions
  (Select Description from msit_MIWarehouseCodesAndDescriptions 
  where ColumnName = 'WH-AdminMethod' and Code = coalesce(pt.AdminMethod, 'A')) as BusinessReason,  --SR9(3) :MPC 22/04/08
--  MICodesAndDescs.LongDescription as BusinessReasonDescription, --From msit_MIWarehouseCodesAndDescriptions
  (Select LongDescription from msit_MIWarehouseCodesAndDescriptions 
  where ColumnName = 'WH-AdminMethod' and Code = coalesce(pt.AdminMethod, 'A')) as BusinessReasonDescription, --SR9(3) :MPC 22/04/08
  pt.Frequency as Frequency,                  --From mstt_PolicyTransactions, linked via TransactionID 
  pt.CommType as CommType,                    --From mstt_PolicyTransactions, linked via TransactionID 
  p.OriginatingSource as OriginatingSource,   --From mstt_Policies, linked via PolicyID 
--  (select dl.Description            --OriginatingSourceDescription    --SR10(1) : MPC 18/09/09
--   from msdt_DropLists dl                           --SR10(1) : MPC 18/09/09
--   where  convert(varchar(50),p.OriginatingSource) = dl.Code            --SR10(1) : MPC 18/09/09
--   and  dl.CodeType = 'OriginatingSource'),                   --SR10(1) : MPC 18/09/09
  CASE                    --SR10(1) : MPC 18/09/09
    WHEN OS.ID is not NULL THEN OS.Code   --SR10(1) : MPC 18/09/09
    ELSE 'Unknown'              --SR10(1) : MPC 18/09/09
  END,  --OriginatingSourceDescription    --SR10(1) : MPC 18/09/09
  a.FranchiseUpliftPercent, 
  a.BaseAmount, 
  a.UpliftAmount,
  tashh.StrategicAllianceAgentCode as StrategicAllianceAgentCode, --From mstt_TransAgentSplitHierarchyHistory, join on AgentCode, TransactionID, CommissionType
  tashh.AccessAgentCode as AccessAgentCode,   --From mstt_TransAgentSplitHierarchyHistory, join on AgentCode, TransactionID, CommissionType
  tashh.FranchiseAgentCode as FranchiseAgentCode, --From mstt_TransAgentSplitHierarchyHistory, join on AgentCode, TransactionID, CommissionType
  tashh.CompanyAgentCode as CompanyAgentCode, --From mstt_TransAgentSplitHierarchyHistory, join on AgentCode, TransactionID, CommissionType
  null as OrganisationAgentCode,              --From mstt_TransAgentSplitHierarchyHistory, join on AgentCode, TransactionID, CommissionType
  tashh.DirectlyAuthorisedAgentCode as DirectlyAuthorisedAgentCode, --From mstt_TransAgentSplitHierarchyHistory, join on AgentCode, TransactionID, CommissionType
  tashh.Manager1Code as Manager1Code,         --From mstt_TransAgentSplitHierarchyHistory, join on AgentCode, TransactionID, CommissionType
  tashh.Manager2Code as Manager2Code,         --From mstt_TransAgentSplitHierarchyHistory, join on AgentCode, TransactionID, CommissionType
  ag.Manager3Code,    --SR9(3) :MPC 22/04/08   --From mstt_AgentsHistory, joining on AgentCode and TransactionDate between ValidFromDate and ValidToDate
  ag.Manager4Code,    --SR9(3) :MPC 22/04/08   --From mstt_AgentsHistory, joining on AgentCode and TransactionDate between ValidFromDate and ValidToDate
  ag.FranchiseSize,   --SR9(3) :MPC 22/04/08   --From mstt_AgentsHistory, joining on AgentCode and TransactionDate between ValidFromDate and ValidToDate
  ag.PracticeTypeCode,    --SR9(3) :MPC 22/04/08   --From mstt_AgentsHistory, joining on AgentCode and TransactionDate between ValidFromDate and ValidToDate
  ph.ProductType as ProductType,              --From mstt_ProductHierarchy, joining on ProductCode
  ph.ReportingProductCode as ReportingProductCode, --From mstt_ProductHierarchy, joining on ProductCode
  ph.ProductSubGroupCode as ProductSubGroupCode, --From mstt_ProductHierarchy, joining on ProductCode
  ph.ProductGroupCode as ProductGroupCode,    --From mstt_ProductHierarchy, joining on ProductCode
  ph.ProductCategoryCode as ProductCategoryCode, --From mstt_ProductHierarchy, joining on ProductCode
  ph.ProductProviderCode as ProductProviderCode, --From mstt_ProductHierarchy, joining on ProductCode
  ph.ReportingProductProviderCode as ReportingProductProviderCode, --From mstt_ProductHierarchy, joining on ProductCode
  ph.CommRepProductProviderCode as CommRepProductProviderCode, --From mstt_ProductHierarchy, joining on ProductCode
/*  
--START of SR9(2) :MPC 22/04/08
  (select Coalesce(tashh.FranchiseAgentCode,  --Firm 
           tashh.AccessAgentCode, 
           tashh.DirectlyAuthorisedAgentCode, 
           tashh.StrategicAllianceAgentCode)
   from   mstt_Agents agents
   where  Coalesce(tashh.FranchiseAgentCode, 
           tashh.AccessAgentCode, 
           tashh.DirectlyAuthorisedAgentCode, 
           tashh.StrategicAllianceAgentCode) = agents.Code
   and  agents.AgentType in (2,46,49)),
*/  
  CASE
  when ag.agenttype in (2,46,49,52,53,54,55) then a.agent_code
  when tashh.id is not null and t1.id is null 
  then Coalesce(tashh.FranchiseAgentCode, tashh.AccessAgentCode, tashh.DirectlyAuthorisedAgentCode, tashh.StrategicAllianceAgentCode)
  end as FIRM,
--END of SR9(2) :MPC 22/04/08
--  ptm.MinMonth, --CommissionMonth  ID19   --SR9(3) :MPC 22/04/08
  pt.CommissionMonth,       --SR9(3) :MPC 22/04/08
  pt.IssuedDate,          --SR9(3) :MPC 22/04/08
  pt.CommissionMonth as TransactionMonth    --SR9(3) :MPC 22/04/08
from sa_swift_S_AGTCOM a      --MPC:25/01/2010
  inner join #AGTCOMCHANGES X ON X.ID = A.ID    --MPC:25/01/2010
  left outer join mstt_PolicyTransactions pt on a.TransactionID = pt.ID
  left outer join mstt_CommTranInitialDate CommTranInitDate on a.ID = CommTranInitDate.ID
  left outer join mstt_agents ag on ag.code = a.agent_code  --SR9(2)
--  left outer join (select PolTrnMinCommMth.ID, min(PolTrnMinCommMth.CommissionMonth) MinMonth --SR9(3) :MPC 22/04/08
--        from   mstt_PolicyTransactions PolTrnMinCommMth         --SR9(3) :MPC 22/04/08
--        group  by PolTrnMinCommMth.ID) ptm on a.TransactionID = ptm.ID    --SR9(3) :MPC 22/04/08
  left outer join mstt_Policies p on pt.PolicyID = p.POL_NUM
  left outer join sa_swift_TransAgentSplitHierarchyHistory tashh
       on a.Agent_Code  = tashh.AgentCode
      and a.TransactionID   = tashh.TransactionID
      and a.CommissionType  = tashh.CommissionType
      and tashh.Active  = 1               
  left outer join #InvalidTASHH t1 on t1.ID = tashh.ID    --SR9(2)
  left outer join mstt_ProductHierarchy ph on coalesce(pt.CommProductCode, p.ProductCode) = ph.ProductCode
  left outer join msit_CodeOriginatingSources OS on OS.ID = p.OriginatingSource --SR10(1) : MPC 18/09/09
--  left outer join msit_MIWarehouseCodesAndDescriptions MICodesAndDescs    --SR9(3) :MPC 22/04/08
--       on MICodesAndDescs.ColumnName = 'WH-AdminMethod'     --SR9(3) :MPC 22/04/08
--      and MICodesAndDescs.Code = coalesce(pt.AdminMethod, 'A')  --SR9(3) :MPC 22/04/08

select @RowCount = @@rowcount     --MPC:25/01/2010
set @ProcessMessage = @Mode + ' - Select from sa_swift_S_AGTCOM : Count = ' + convert(varchar(10), @RowCount) --MPC:25/01/2010  
exec msp_ProcessLog @PhaseEnd, @ProcessMessage, null, @ProgressModule, @Client  --MPC:25/01/2010

