--Set the SplitMargin
select isnull(TransactionID, -99) as TransactionId, sum(FixedAmount) as Margin
into #Margins
from #mstt_Commissions
where GrossOrNet = 'N'
and FixedAmount <> 0
and CommissionType = 1  --MPC:25/01/10
group by TransactionID

exec msp_ProcessLog @PhaseEnd, 'get #Margins', null, @ProgressModule, @Client

alter table #Margins add constraint PK_Margins PRIMARY KEY (TransactionID) 

exec msp_ProcessLog @PhaseEnd, 'pk on #margins', null, @ProgressModule, @Client

--SR9(3) Start  :MPC 22/04/08
update c
set SplitMargin = case when c.GrossOrNet = 'G' then isnull(m.Margin,0) * (c.Agent_Perc / 100) else 0.0 end, 
    SalesMargin = case when c.GrossOrNet = 'G' then isnull(m.Margin,0) * (c.Agent_Perc / 100) else 0.0 end, 
    DistributionAllowance = case when c.GrossOrNet = 'G' then isnull(FixedAmount,0) + (isnull(m.Margin,0) * (c.Agent_Perc / 100)) else 0.0 end, --SR9(3)
    Turnover = case                       
    when c.GrossOrNet = 'G' and isnull(p.APE_Flag,'N') <> 'Y' then abs( isnull(FixedAmount,0) + (isnull(m.Margin,0) * (c.Agent_Perc / 100)) )         
    when c.GrossOrNet = 'G' and isnull(p.APE_Flag,'N') = 'Y' then abs(c.APE)              
    else 0.0
    end,
    APE = case when c.GrossOrNet = 'G' and isnull(p.APE_Flag,'N') = 'Y' then abs(c.APE) else 0.0 end
from #mstt_Commissions c
left outer join #Margins m on c.TransactionID = m.TransactionID 
left outer join mstt_ProductHierarchy p on c.ProductCode = p.ProductCode
where CommissionType = 1  --MPC:27/01/10
--where c.GrossOrNet = 'G'
--SR9(3) End  :MPC 22/04/08

exec msp_ProcessLog @PhaseEnd, 'Update Measures', null, @ProgressModule, @Client  --SR9(3) :MPC 22/04/08

drop table #Margins

