from #mstt_Commissions c

exec msp_ProcessLog 'COM', 'update DistAllow', null, 'COM', 'Openwork'

--Set the Turnover field
update c
set Turnover = case 
    when p.APE_Flag <> 'Y' then abs(DistributionAllowance)  --Mortgages and GI :MPC 16/01/08
    when p.APE_Flag = 'Y' then abs(APE)     --Non-Mortgages and GI :MPC 16/01/08
    end
from #mstt_Commissions c inner join mstt_ProductHierarchy p on c.ProductCode = p.ProductCode

exec msp_ProcessLog 'COM', 'update turnover 1+2', null, 'COM', 'Openwork'

--'Clean up' several fields for 'Margin' (ie 'NET') records.
update c
set APE = 0,
  DistributionAllowance = 0,
  SalesMargin = 0,
  SplitMargin = 0,
  Turnover = 0
from #mstt_Commissions c
where c.GrossOrNet = 'N'

