--Full Refresh - Truncate Table, Drop Indexes, Insert then Create Undexes
IF @Mode = 'FULL' --MPC:25/01/2010
BEGIN       --MPC:25/01/2010

  --Clear the target table first
  Truncate Table PARALLEL_mstt_Commissions

  DROP INDEX PARALLEL_mstt_Commissions.PARALLEL_IX_mstt_Commissions_Agent_Code 
  DROP INDEX PARALLEL_mstt_Commissions.PARALLEL_IX_mstt_Commissions_PolicyID 
  DROP INDEX PARALLEL_mstt_Commissions.PARALLEL_IX_mstt_Commissions_TransactionID
  --DROP INDEX mstt_Commissions.IX_mstt_Commissions_Multiple    --SR9(3) :MPC 22/04/08
  --DROP INDEX mstt_Commissions.IX_mstt_Commissions_Trial1    --SR9(3) :MPC 22/04/08
